    fn start_agent_model_discovery_task(&mut self, system: &AgentSystemSpec, force: bool) {
        if !matches!(
            system.transport,
            AgentSystemTransport::NativeOpenai | AgentSystemTransport::NativeOpenaiCompat
        ) {
            return;
        }
        let Some(base_url) = self.selected_agent_runtime_base_url(system) else {
            return;
        };
        let Some(source_key) = self.selected_agent_model_discovery_source_key(system) else {
            return;
        };
        if !force {
            if let Some(task) = &self.agent_model_discovery_task {
                if task.source_key == source_key {
                    return;
                }
            }
            if self.agent_model_discovery_source_key == source_key
                && !self.agent_discovered_models.is_empty()
            {
                return;
            }
        }
        self.agent_model_discovery_source_key = source_key.clone();
        self.agent_model_discovery_status = format!("Discovering models at {base_url} ...");
        self.agent_model_discovery_task = None;
        let api_key = self.agent_openai_api_key.trim().to_string();
        let api_key = if api_key.is_empty() {
            None
        } else {
            Some(api_key)
        };
        let (tx, rx) = mpsc::channel::<AgentModelDiscoveryTaskMessage>();
        self.agent_model_discovery_task = Some(AgentModelDiscoveryTask {
            started: Instant::now(),
            source_key: source_key.clone(),
            receiver: rx,
        });
        std::thread::spawn(move || {
            let result = discover_openai_models(&base_url, api_key.as_deref());
            let _ = tx.send(AgentModelDiscoveryTaskMessage::Done { source_key, result });
        });
    }

    fn selected_agent_system_availability(
        &self,
        system: &AgentSystemSpec,
    ) -> (bool, Option<String>) {
        let resolved = self.selected_agent_system_with_session_overrides(system);
        let availability = agent_system_availability(&resolved);
        if availability.available {
            return (true, availability.reason);
        }
        if matches!(system.transport, AgentSystemTransport::NativeOpenai)
            && !self.agent_openai_api_key.trim().is_empty()
        {
            return (
                true,
                Some("using GUI-supplied OpenAI API key for this session".to_string()),
            );
        }
        (false, availability.reason)
    }

    fn start_agent_assistant_request(&mut self) {
        if self.agent_task.is_some() {
            self.agent_status = "Agent request is already running".to_string();
            return;
        }
        self.refresh_agent_system_catalog();
        if !self.agent_catalog_error.is_empty() {
            self.agent_status = format!("Agent catalog error: {}", self.agent_catalog_error);
            return;
        }
        let system_id = self.agent_system_id.trim().to_string();
        if system_id.is_empty() {
            self.agent_status = "Select an agent system first".to_string();
            return;
        }
        let Some(selected_system) = self.selected_agent_system() else {
            self.agent_status = "Selected agent system is not available in catalog".to_string();
            return;
        };
        let (available, reason) = self.selected_agent_system_availability(&selected_system);
        if !available {
            self.agent_status = format!(
                "Selected agent system is unavailable: {}",
                reason.unwrap_or_else(|| "unknown reason".to_string())
            );
            return;
        }
        let prompt = self.agent_prompt.trim().to_string();
        if prompt.is_empty() {
            self.agent_status = "Agent prompt cannot be empty".to_string();
            return;
        }
        let timeout_seconds = match self.parse_agent_timeout_seconds() {
            Ok(value) => value,
            Err(err) => {
                self.agent_status = err;
                return;
            }
        };
        let connect_timeout_seconds = match self.parse_agent_connect_timeout_seconds() {
            Ok(value) => value,
            Err(err) => {
                self.agent_status = err;
                return;
            }
        };
        let read_timeout_seconds = match self.parse_agent_read_timeout_seconds() {
            Ok(value) => value,
            Err(err) => {
                self.agent_status = err;
                return;
            }
        };
        let max_retries = match self.parse_agent_max_retries() {
            Ok(value) => value,
            Err(err) => {
                self.agent_status = err;
                return;
            }
        };
        let max_response_bytes = match self.parse_agent_max_response_bytes() {
            Ok(value) => value,
            Err(err) => {
                self.agent_status = err;
                return;
            }
        };
        let mut model_override = normalize_agent_model_name(self.agent_model_override.trim());
        let discovered_pick =
            normalize_agent_model_name(&self.agent_discovered_model_pick).filter(|picked| {
                self.agent_discovered_models
                    .iter()
                    .any(|item| item == picked)
            });
        if model_override.is_none() && discovered_pick.is_some() {
            model_override = discovered_pick.clone();
        }
        if matches!(
            selected_system.transport,
            AgentSystemTransport::NativeOpenaiCompat
        ) && model_override.is_none()
        {
            if discovered_pick.is_some() {
                model_override = discovered_pick;
            } else {
                let catalog_model = normalize_agent_model_name(
                    selected_system.model.as_deref().unwrap_or_default(),
                );
                if let Some(catalog_model) = catalog_model {
                    if !self.agent_discovered_models.is_empty()
                        && !self
                            .agent_discovered_models
                            .iter()
                            .any(|value| value == &catalog_model)
                    {
                        self.agent_status = format!(
                            "Catalog model '{catalog_model}' is not available on current endpoint. Select a discovered model or set Model override."
                        );
                        return;
                    }
                } else {
                    self.agent_status =
                        "Model is unspecified. Discover models and select one, or set Model override."
                            .to_string();
                    return;
                }
            }
        }

        let state_summary = if self.agent_include_state_summary {
            Some(self.engine.read().unwrap().summarize_state())
        } else {
            None
        };
        let catalog_path = self.agent_catalog_path.trim().to_string();
        let openai_api_key = self.agent_openai_api_key.trim().to_string();
        let base_url_override = self.agent_base_url_override.trim().to_string();
        let model_override = model_override.unwrap_or_default();
        let timeout_override = timeout_seconds
            .map(|value| value.to_string())
            .unwrap_or_default();
        let connect_timeout_override = connect_timeout_seconds
            .map(|value| value.to_string())
            .unwrap_or_default();
        let read_timeout_override = read_timeout_seconds
            .map(|value| value.to_string())
            .unwrap_or_default();
        let max_retries_override = max_retries
            .map(|value| value.to_string())
            .unwrap_or_default();
        let max_response_bytes_override = max_response_bytes
            .map(|value| value.to_string())
            .unwrap_or_default();
        let job_id = self.alloc_background_job_id();
        let (tx, rx) = mpsc::channel::<AgentAskTaskMessage>();
        self.agent_status = if let Some(timeout) = timeout_seconds {
            format!(
                "Asking agent '{}' in background (timeout={}s, retries={})",
                system_id,
                timeout,
                max_retries.unwrap_or(2)
            )
        } else {
            format!("Asking agent '{}' in background", system_id)
        };
        self.push_job_event(
            BackgroundJobKind::AgentAssist,
            BackgroundJobEventPhase::Started,
            Some(job_id),
            format!("Agent request started for system '{}'", system_id),
        );
        self.agent_task = Some(AgentAskTask {
            job_id,
            started: Instant::now(),
            receiver: rx,
        });
        std::thread::spawn(move || {
            let mut env_overrides = HashMap::new();
            if !openai_api_key.is_empty() {
                env_overrides.insert(OPENAI_API_KEY_ENV.to_string(), openai_api_key);
            }
            if !base_url_override.is_empty() {
                env_overrides.insert(AGENT_BASE_URL_ENV.to_string(), base_url_override);
            }
            if !model_override.is_empty() {
                env_overrides.insert(AGENT_MODEL_ENV.to_string(), model_override);
            }
            if !timeout_override.is_empty() {
                env_overrides.insert(AGENT_TIMEOUT_SECS_ENV.to_string(), timeout_override);
            }
            if !connect_timeout_override.is_empty() {
                env_overrides.insert(
                    AGENT_CONNECT_TIMEOUT_SECS_ENV.to_string(),
                    connect_timeout_override,
                );
            }
            if !read_timeout_override.is_empty() {
                env_overrides.insert(
                    AGENT_READ_TIMEOUT_SECS_ENV.to_string(),
                    read_timeout_override,
                );
            }
            if !max_retries_override.is_empty() {
                env_overrides.insert(AGENT_MAX_RETRIES_ENV.to_string(), max_retries_override);
            }
            if !max_response_bytes_override.is_empty() {
                env_overrides.insert(
                    AGENT_MAX_RESPONSE_BYTES_ENV.to_string(),
                    max_response_bytes_override,
                );
            }
            let result = invoke_agent_support_with_env_overrides(
                Some(catalog_path.as_str()),
                &system_id,
                &prompt,
                state_summary.as_ref(),
                if env_overrides.is_empty() {
                    None
                } else {
                    Some(&env_overrides)
                },
            );
            let _ = tx.send(AgentAskTaskMessage::Done { job_id, result });
        });
    }

    fn execute_agent_suggested_command(
        &mut self,
        index_1based: usize,
        command_text: &str,
        trigger: &str,
    ) {
        let trimmed = command_text.trim();
        if trimmed.is_empty() {
            self.agent_status = format!("Suggestion #{index_1based} is empty");
            return;
        }
        let command = match parse_shell_line(trimmed) {
            Ok(command) => command,
            Err(err) => {
                self.agent_status = format!("Suggestion #{index_1based} parse error: {err}");
                self.agent_execution_log.push(AgentCommandExecutionRecord {
                    index_1based,
                    command: trimmed.to_string(),
                    trigger: trigger.to_string(),
                    ok: false,
                    state_changed: false,
                    summary: format!("parse error: {err}"),
                    executed_at_unix_ms: Self::now_unix_ms(),
                });
                return;
            }
        };
        if matches!(command, ShellCommand::AgentsAsk { .. }) {
            self.agent_status = format!(
                "Suggestion #{index_1based} rejected: agent-to-agent 'agents ask' is blocked"
            );
            self.agent_execution_log.push(AgentCommandExecutionRecord {
                index_1based,
                command: trimmed.to_string(),
                trigger: trigger.to_string(),
                ok: false,
                state_changed: false,
                summary: "agent-to-agent agents ask blocked".to_string(),
                executed_at_unix_ms: Self::now_unix_ms(),
            });
            return;
        }
        if let Some(summary) = self.try_apply_shell_ui_intent(&command) {
            self.agent_status = format!("Suggestion #{index_1based}: {summary}");
            self.agent_execution_log.push(AgentCommandExecutionRecord {
                index_1based,
                command: trimmed.to_string(),
                trigger: trigger.to_string(),
                ok: true,
                state_changed: false,
                summary,
                executed_at_unix_ms: Self::now_unix_ms(),
            });
            if self.agent_execution_log.len() > 100 {
                let drain = self.agent_execution_log.len() - 100;
                self.agent_execution_log.drain(0..drain);
            }
            return;
        }
        let options = ShellExecutionOptions {
            allow_screenshots: false,
            allow_agent_commands: false,
        };
        let run = {
            let mut guard = self.engine.write().unwrap();
            execute_shell_command_with_options(&mut guard, &command, &options)
        };
        match run {
            Ok(run) => {
                if run.state_changed {
                    self.lineage_cache_valid = false;
                }
                let summary = if run.state_changed {
                    "executed (state changed)".to_string()
                } else {
                    "executed".to_string()
                };
                self.agent_status = format!("Suggestion #{index_1based}: {summary}");
                self.agent_execution_log.push(AgentCommandExecutionRecord {
                    index_1based,
                    command: trimmed.to_string(),
                    trigger: trigger.to_string(),
                    ok: true,
                    state_changed: run.state_changed,
                    summary,
                    executed_at_unix_ms: Self::now_unix_ms(),
                });
            }
            Err(err) => {
                self.agent_status = format!("Suggestion #{index_1based} failed: {err}");
                self.agent_execution_log.push(AgentCommandExecutionRecord {
                    index_1based,
                    command: trimmed.to_string(),
                    trigger: trigger.to_string(),
                    ok: false,
                    state_changed: false,
                    summary: err,
                    executed_at_unix_ms: Self::now_unix_ms(),
                });
            }
        }
        if self.agent_execution_log.len() > 100 {
            let drain = self.agent_execution_log.len() - 100;
            self.agent_execution_log.drain(0..drain);
        }
    }

    fn try_apply_shell_ui_intent(&mut self, command: &ShellCommand) -> Option<String> {
        let ShellCommand::UiIntent {
            action,
            target,
            genome_id,
            helper_mode,
            catalog_path,
            cache_dir,
            filter,
            species,
            latest,
        } = command
        else {
            return None;
        };
        let mut selected_genome_id = genome_id
            .as_deref()
            .map(str::trim)
            .filter(|v| !v.is_empty())
            .map(str::to_string);
        if matches!(target, UiIntentTarget::PreparedReferences) {
            self.apply_prepared_reference_intent_scope(*helper_mode, catalog_path, cache_dir);
            if selected_genome_id.is_none() {
                match self.resolve_prepared_reference_intent_selection(
                    *helper_mode,
                    catalog_path.clone(),
                    cache_dir.clone(),
                    filter.clone(),
                    species.clone(),
                    *latest,
                ) {
                    Ok(Some(resolved)) => {
                        selected_genome_id = Some(resolved);
                    }
                    Ok(None) => {}
                    Err(err) => {
                        self.app_status = format!(
                            "Could not resolve prepared-reference selection for ui intent: {err}"
                        );
                    }
                }
            }
        }
        if let Some(genome_id) = selected_genome_id
            .as_deref()
            .map(str::trim)
            .filter(|v| !v.is_empty())
        {
            self.genome_id = genome_id.to_string();
            self.invalidate_genome_genes();
        }
        match target {
            UiIntentTarget::PreparedReferences => self.open_reference_genome_inspector_dialog(),
            UiIntentTarget::PrepareReferenceGenome => self.open_reference_genome_prepare_dialog(),
            UiIntentTarget::RetrieveGenomeSequence => self.open_reference_genome_retrieve_dialog(),
            UiIntentTarget::BlastGenomeSequence => self.open_reference_genome_blast_dialog(),
            UiIntentTarget::ImportGenomeTrack => self.open_genome_bed_track_dialog(),
            UiIntentTarget::AgentAssistant => self.open_agent_assistant_dialog(),
            UiIntentTarget::PrepareHelperGenome => self.open_helper_genome_prepare_dialog(),
            UiIntentTarget::RetrieveHelperSequence => self.open_helper_genome_retrieve_dialog(),
            UiIntentTarget::BlastHelperSequence => self.open_helper_genome_blast_dialog(),
        }
        let mut summary = format!("ui intent {} '{}'", action.as_str(), target.as_str());
        if let Some(genome_id) = selected_genome_id {
            summary.push_str(&format!(" (selected_genome_id={genome_id})"));
        }
        Some(summary)
    }

    fn apply_prepared_reference_intent_scope(
        &mut self,
        helper_mode: bool,
        catalog_path: &Option<String>,
        cache_dir: &Option<String>,
    ) {
        let scope = if helper_mode {
            GenomeDialogScope::Helper
        } else {
            GenomeDialogScope::Reference
        };
        let normalized_catalog = catalog_path
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string);
        let normalized_cache = cache_dir
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string);
        self.sync_active_genome_scope_paths_from_fields();
        self.genome_dialog_scope = scope;
        let (scope_catalog, scope_cache) = self.scope_genome_paths_resolved(scope);
        let next_catalog = normalized_catalog.unwrap_or(scope_catalog);
        let next_cache = normalized_cache.unwrap_or(scope_cache);
        let catalog_changed = self.genome_catalog_path != next_catalog;
        let cache_changed = self.genome_cache_dir != next_cache;
        self.genome_catalog_path = next_catalog.clone();
        self.genome_cache_dir = next_cache.clone();
        self.set_scope_genome_paths(scope, next_catalog, next_cache);
        if catalog_changed || cache_changed {
            self.invalidate_genome_genes();
        }
    }

    fn resolve_prepared_reference_intent_selection(
        &self,
        helper_mode: bool,
        catalog_path: Option<String>,
        cache_dir: Option<String>,
        filter: Option<String>,
        species: Option<String>,
        latest: bool,
    ) -> Result<Option<String>, String> {
        let mut engine = self.engine.write().unwrap();
        let run = execute_shell_command_with_options(
            &mut engine,
            &ShellCommand::UiPreparedGenomes {
                helper_mode,
                catalog_path,
                cache_dir,
                filter,
                species,
                latest,
            },
            &ShellExecutionOptions::default(),
        )?;
        Ok(run
            .output
            .get("selected_genome_id")
            .and_then(|value| value.as_str())
            .map(str::to_string))
    }

    fn execute_agent_auto_suggestions(&mut self, response: &AgentResponse) {
        for (idx, suggestion) in response.suggested_commands.iter().enumerate() {
            if suggestion.execution == AgentExecutionIntent::Auto {
                self.execute_agent_suggested_command(idx + 1, &suggestion.command, "auto");
            }
        }
    }

    fn poll_agent_assistant_task(&mut self, ctx: &egui::Context) {
        if self.agent_task.is_none() {
            return;
        }
        ctx.request_repaint_after(Duration::from_millis(100));
        let mut done: Option<(u64, Result<AgentInvocationOutcome, String>)> = None;
        if let Some(task) = &self.agent_task {
            match task.receiver.try_recv() {
                Ok(AgentAskTaskMessage::Done { job_id, result }) => {
                    done = Some((job_id, result));
                }
                Err(mpsc::TryRecvError::Empty) => {}
                Err(mpsc::TryRecvError::Disconnected) => {
                    done = Some((task.job_id, Err("Agent worker disconnected".to_string())));
                }
            }
        }
        if let Some((job_id, outcome)) = done {
            let elapsed = self
                .agent_task
                .as_ref()
                .map(|task| task.started.elapsed().as_secs_f64())
                .unwrap_or(0.0);
            self.agent_task = None;
            match outcome {
                Ok(invocation) => {
                    let suggestion_count = invocation.response.suggested_commands.len();
                    self.agent_status = format!(
                        "Agent response received in {:.1}s (suggestions={})",
                        elapsed, suggestion_count
                    );
                    self.push_job_event(
                        BackgroundJobKind::AgentAssist,
                        BackgroundJobEventPhase::Completed,
                        Some(job_id),
                        format!(
                            "Agent '{}' completed in {:.1}s (suggestions={})",
                            invocation.system_id, elapsed, suggestion_count
                        ),
                    );
                    let response = invocation.response.clone();
                    self.agent_last_invocation = Some(invocation);
                    if self.agent_allow_auto_exec {
                        self.execute_agent_auto_suggestions(&response);
                    }
                }
                Err(err) => {
                    self.agent_status =
                        format!("Agent request failed after {:.1}s: {}", elapsed, err);
                    self.push_job_event(
                        BackgroundJobKind::AgentAssist,
                        BackgroundJobEventPhase::Failed,
                        Some(job_id),
                        format!("Agent request failed in {:.1}s: {}", elapsed, err),
                    );
                }
            }
        }
    }

    fn poll_agent_model_discovery_task(&mut self, ctx: &egui::Context) {
        if self.agent_model_discovery_task.is_none() {
            return;
        }
        ctx.request_repaint_after(Duration::from_millis(100));
        let mut done: Option<(String, Result<Vec<String>, String>)> = None;
        if let Some(task) = &self.agent_model_discovery_task {
            match task.receiver.try_recv() {
                Ok(AgentModelDiscoveryTaskMessage::Done { source_key, result }) => {
                    done = Some((source_key, result));
                }
                Err(mpsc::TryRecvError::Empty) => {}
                Err(mpsc::TryRecvError::Disconnected) => {
                    done = Some((
                        task.source_key.clone(),
                        Err("Model discovery worker disconnected".to_string()),
                    ));
                }
            }
        }
        if let Some((source_key, result)) = done {
            let elapsed = self
                .agent_model_discovery_task
                .as_ref()
                .map(|task| task.started.elapsed().as_secs_f64())
                .unwrap_or(0.0);
            self.agent_model_discovery_task = None;
            if source_key != self.agent_model_discovery_source_key {
                return;
            }
            match result {
                Ok(models) => {
                    self.agent_discovered_models = models;
                    if self.agent_discovered_models.is_empty() {
                        self.agent_model_discovery_status =
                            format!("Model discovery returned no models ({:.1}s)", elapsed);
                        self.agent_discovered_model_pick.clear();
                    } else {
                        if !self
                            .agent_discovered_models
                            .iter()
                            .any(|item| item == &self.agent_discovered_model_pick)
                        {
                            self.agent_discovered_model_pick.clear();
                        }
                        self.agent_model_discovery_status = format!(
                            "Discovered {} model(s) in {:.1}s",
                            self.agent_discovered_models.len(),
                            elapsed
                        );
                    }
                }
                Err(err) => {
                    self.agent_discovered_models.clear();
                    self.agent_discovered_model_pick.clear();
                    self.agent_model_discovery_status =
                        format!("Model discovery failed after {:.1}s: {}", elapsed, err);
                }
            }
        }
    }

    fn invalidate_genome_genes(&mut self) {
        self.genome_genes.clear();
        self.genome_genes_error.clear();
        self.genome_genes_loaded_key = None;
        self.genome_selected_gene = None;
        self.genome_gene_filter_page = 0;
        self.genome_biotype_filter.clear();
        self.genome_retrieve_contig_suggestions.clear();
    }

    fn genome_genes_loaded_key(&self) -> String {
        format!(
            "{}|{}|{}",
            self.genome_catalog_path_resolved(),
            self.genome_cache_dir_opt().unwrap_or_default(),
            self.genome_id.trim()
        )
    }

    fn ensure_genome_genes_loaded(&mut self) {
        let genome_id = self.genome_id.trim().to_string();
        if genome_id.is_empty() {
            self.invalidate_genome_genes();
            return;
        }
        let key = self.genome_genes_loaded_key();
        if self
            .genome_genes_loaded_key
            .as_ref()
            .map(|v| v == &key)
            .unwrap_or(false)
        {
            return;
        }
        self.genome_genes.clear();
        self.genome_selected_gene = None;
        self.genome_genes_error.clear();
        let catalog_path = self.genome_catalog_path_resolved();
        let cache_dir = self.genome_cache_dir_opt();
        let loaded = GenomeCatalog::from_json_file(&catalog_path)
            .and_then(|catalog| catalog.list_gene_regions(&genome_id, cache_dir.as_deref()));
        match loaded {
            Ok(genes) => {
                self.genome_genes = genes;
                self.sync_genome_biotype_filter();
            }
            Err(e) => {
                self.genome_genes_error = e;
                self.genome_biotype_filter.clear();
            }
        }
        self.genome_genes_loaded_key = Some(key);
    }

    fn sync_genome_biotype_filter(&mut self) {
        let mut discovered: Vec<String> = self
            .genome_genes
            .iter()
            .filter_map(|gene| gene.biotype.as_ref())
            .map(|v| v.trim())
            .filter(|v| !v.is_empty())
            .map(str::to_string)
            .collect();
        discovered.sort();
        discovered.dedup();

        let mut next: HashMap<String, bool> = HashMap::with_capacity(discovered.len());
        for biotype in discovered {
            let enabled = self
                .genome_biotype_filter
                .get(&biotype)
                .copied()
                .unwrap_or(true);
            next.insert(biotype, enabled);
        }
        self.genome_biotype_filter = next;
    }

    fn unprepared_genomes_for_prepare_dialog(&self) -> Result<Vec<String>, String> {
        let catalog_path = self.genome_catalog_path_resolved();
        let catalog = GenomeCatalog::from_json_file(&catalog_path)?;
        let cache_dir = self.genome_cache_dir_opt();
        let mut names: Vec<String> = vec![];
        for name in catalog.list_genomes() {
            match catalog.is_prepared(&name, cache_dir.as_deref()) {
                Ok(false) => names.push(name),
                Ok(true) => {}
                Err(e) => {
                    return Err(format!(
                        "Could not check preparation status for '{name}': {e}"
                    ));
                }
            }
        }
        Ok(names)
    }

    fn prepared_genomes_for_retrieve_dialog(&self) -> Result<Vec<String>, String> {
        let catalog_path = self.genome_catalog_path_resolved();
        let catalog = GenomeCatalog::from_json_file(&catalog_path)?;
        let cache_dir = self.genome_cache_dir_opt();
        let mut names: Vec<String> = vec![];
        for name in catalog.list_genomes() {
            match catalog.is_prepared(&name, cache_dir.as_deref()) {
                Ok(true) => names.push(name),
                Ok(false) => {}
                Err(e) => {
                    return Err(format!(
                        "Could not check preparation status for '{name}': {e}"
                    ));
                }
            }
        }
        Ok(names)
    }

    fn project_sequence_ids_for_blast(&self) -> Vec<String> {
        let mut seq_ids: Vec<String> = self
            .engine
            .read()
            .unwrap()
            .state()
            .sequences
            .keys()
            .cloned()
            .collect();
        seq_ids.sort_unstable();
        seq_ids
    }

    fn blast_pool_options(&self) -> Vec<BlastPoolOption> {
        let engine = self.engine.read().unwrap();
        let state = engine.state();
        let mut options: Vec<BlastPoolOption> = state
            .container_state
            .containers
            .values()
            .filter_map(|container| {
                if container.members.len() <= 1 {
                    return None;
                }
                let mut members: Vec<String> = container
                    .members
                    .iter()
                    .filter(|seq_id| state.sequences.contains_key(*seq_id))
                    .cloned()
                    .collect();
                if members.len() <= 1 {
                    return None;
                }
                members.sort_unstable();
                members.dedup();
                let name = container
                    .name
                    .as_ref()
                    .map(|v| v.trim())
                    .filter(|v| !v.is_empty())
                    .unwrap_or("-");
                Some(BlastPoolOption {
                    container_id: container.container_id.clone(),
                    label: format!(
                        "{} (kind={:?}, name={}, n={})",
                        container.container_id,
                        container.kind,
                        name,
                        members.len()
                    ),
                    members,
                })
            })
            .collect();
        options.sort_by(|a, b| a.container_id.cmp(&b.container_id));
        options
    }

    fn selected_genome_source_plan(&self) -> Result<Option<GenomeSourcePlan>, String> {
        let genome_id = self.genome_id.trim();
        if genome_id.is_empty() {
            return Ok(None);
        }
        let catalog_path = self.genome_catalog_path_resolved();
        let catalog = GenomeCatalog::from_json_file(&catalog_path)?;
        let cache_dir = self.genome_cache_dir_opt();
        let plan = catalog.source_plan(genome_id, cache_dir.as_deref())?;
        Ok(Some(plan))
    }

    fn format_genome_source_plan_summary(plan: &GenomeSourcePlan) -> String {
        let mut parts = vec![format!(
            "sources: sequence={} | annotation={}",
            plan.sequence_source_type, plan.annotation_source_type
        )];
        if let Some(length_bp) = plan.nucleotide_length_bp {
            parts.push(format!("length={length_bp} bp"));
        }
        if let Some(mass_da) = plan.molecular_mass_da {
            let source = plan
                .molecular_mass_source
                .as_deref()
                .unwrap_or("unknown_source");
            parts.push(format!("mass={mass_da:.3e} Da ({source})"));
        }
        parts.join(" | ")
    }

    fn choose_genome_from_catalog(ui: &mut Ui, genome_id: &mut String, names: &[String]) -> bool {
        let mut changed = false;
        let selected_text = if names.iter().any(|name| name == genome_id) {
            genome_id.clone()
        } else if names.is_empty() {
            "(no genomes available)".to_string()
        } else {
            "(choose genome)".to_string()
        };
        egui::ComboBox::from_label("genome")
            .selected_text(selected_text)
            .show_ui(ui, |ui| {
                for name in names {
                    if ui.selectable_value(genome_id, name.clone(), name).changed() {
                        changed = true;
                    }
                }
            });
        changed
    }

    fn format_op_result_status(
        prefix: &str,
        created: &[String],
        warnings: &[String],
        messages: &[String],
    ) -> String {
        let created_text = if created.is_empty() {
            "-".to_string()
        } else {
            created.join(", ")
        };
        let warnings_text = if warnings.is_empty() {
            "-".to_string()
        } else {
            warnings.join(" | ")
        };
        let messages_text = if messages.is_empty() {
            "-".to_string()
        } else {
            messages.join(" | ")
        };
        format!(
            "{prefix}\ncreated: {created_text}\nwarnings: {warnings_text}\nmessages: {messages_text}"
        )
    }

    fn format_extract_region_status(result: &OpResult) -> String {
        let mut text = Self::format_op_result_status(
            "Extract region: ok",
            &result.created_seq_ids,
            &result.warnings,
            &result.messages,
        );
        if let Some(telemetry) = result.genome_annotation_projection.as_ref() {
            let cap = telemetry
                .max_features_cap
                .map(|value| value.to_string())
                .unwrap_or_else(|| "-".to_string());
            text.push_str(&format!(
                "\nannotation: requested={} effective={} attached={} dropped={} cap={}",
                telemetry.requested_scope,
                telemetry.effective_scope,
                telemetry.attached_feature_count,
                telemetry.dropped_feature_count,
                cap
            ));
            text.push_str(&format!(
                "\nannotation kinds: genes={} transcripts={} exons={} cds={}",
                telemetry.genes_attached,
                telemetry.transcripts_attached,
                telemetry.exons_attached,
                telemetry.cds_attached
            ));
            if let Some(reason) = telemetry
                .fallback_reason
                .as_deref()
                .map(str::trim)
                .filter(|value| !value.is_empty())
            {
                text.push_str(&format!("\nannotation fallback reason: {reason}"));
            }
        }
        text
    }

    fn collect_prepared_genome_inspections(
        &self,
    ) -> Result<(Vec<PreparedGenomeInspection>, Vec<String>), String> {
        let catalog_path = self.genome_catalog_path_resolved();
        let catalog = GenomeCatalog::from_json_file(&catalog_path)?;
        let cache_dir = self.genome_cache_dir_opt();
        let mut inspections: Vec<PreparedGenomeInspection> = vec![];
        let mut errors: Vec<String> = vec![];
        for genome_id in catalog.list_genomes() {
            match catalog.inspect_prepared_genome(&genome_id, cache_dir.as_deref()) {
                Ok(Some(inspection)) => inspections.push(inspection),
                Ok(None) => {}
                Err(e) => errors.push(format!("{genome_id}: {e}")),
            }
        }
        inspections.sort_by(|a, b| a.genome_id.cmp(&b.genome_id));
        Ok((inspections, errors))
    }

    fn prepared_genome_chromosome_records(
        &self,
        genome_id: &str,
    ) -> Result<Vec<GenomeChromosomeRecord>, String> {
        let catalog_path = self.genome_catalog_path_resolved();
        let catalog = GenomeCatalog::from_json_file(&catalog_path)?;
        let cache_dir = self.genome_cache_dir_opt();
        catalog.list_chromosome_lengths(genome_id, cache_dir.as_deref())
    }

    fn render_chromosome_length_lines(ui: &mut Ui, chromosomes: &[GenomeChromosomeRecord]) {
        if chromosomes.is_empty() {
            ui.small("No chromosomes/contigs found in FASTA index.");
            return;
        }
        let longest_bp = chromosomes
            .iter()
            .map(|record| record.length_bp)
            .max()
            .unwrap_or(1)
            .max(1);
        let total_bp: u128 = chromosomes.iter().fold(0u128, |acc, record| {
            acc.saturating_add(record.length_bp as u128)
        });
        ui.small(format!(
            "contigs: {} | longest: {} ({} bp) | total span: {} bp",
            chromosomes.len(),
            chromosomes[0].chromosome,
            chromosomes[0].length_bp,
            total_bp
        ));
        egui::ScrollArea::vertical()
            .max_height(280.0)
            .show(ui, |ui| {
                scroll_input_policy::apply_scrollarea_keyboard_navigation(
                    ui,
                    scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                );
                for record in chromosomes {
                    ui.horizontal(|ui| {
                        ui.add_sized(
                            [220.0, 0.0],
                            egui::Label::new(
                                egui::RichText::new(record.chromosome.clone()).monospace(),
                            ),
                        );
                        ui.add_sized(
                            [120.0, 0.0],
                            egui::Label::new(format!("{} bp", record.length_bp)),
                        );
                        let width = ui.available_width().max(80.0);
                        let (rect, response) =
                            ui.allocate_exact_size(egui::vec2(width, 14.0), egui::Sense::hover());
                        let ratio = (record.length_bp as f32 / longest_bp as f32).clamp(0.0, 1.0);
                        let line_width = (rect.width() * ratio.max(0.005)).max(1.0);
                        let y = rect.center().y;
                        ui.painter().line_segment(
                            [
                                Pos2::new(rect.left(), y),
                                Pos2::new(rect.left() + line_width, y),
                            ],
                            egui::Stroke::new(2.0, egui::Color32::from_rgb(80, 130, 175)),
                        );
                        response.on_hover_text(format!(
                            "{} bp ({:.2}% of longest)",
                            record.length_bp,
                            ratio * 100.0
                        ));
                    });
                }
            });
    }

    fn format_bytes_compact(bytes: u64) -> String {
        const UNITS: [&str; 5] = ["B", "KB", "MB", "GB", "TB"];
        let mut value = bytes as f64;
        let mut unit = 0usize;
        while value >= 1024.0 && unit + 1 < UNITS.len() {
            value /= 1024.0;
            unit += 1;
        }
        if unit == 0 {
            format!("{bytes} {}", UNITS[unit])
        } else {
            format!("{value:.2} {}", UNITS[unit])
        }
    }

    fn format_short_sha1(value: &Option<String>) -> String {
        value
            .as_ref()
            .map(|v| v.trim())
            .filter(|v| !v.is_empty())
            .map(|v| {
                if v.len() > 12 {
                    v[..12].to_string()
                } else {
                    v.to_string()
                }
            })
            .unwrap_or_else(|| "-".to_string())
    }

    fn parse_prepare_timeout_seconds(&self) -> Result<Option<u64>, String> {
        let raw = self.genome_prepare_timeout_secs.trim();
        if raw.is_empty() {
            return Ok(None);
        }
        let parsed = raw
            .parse::<u64>()
            .map_err(|e| format!("Invalid timeout seconds '{}': {}", raw, e))?;
        if parsed == 0 {
            return Ok(None);
        }
        Ok(Some(parsed))
    }

    fn summarize_binary_probe(
        probe: &crate::genomes::ExternalBinaryPreflightProbe,
        include_version: bool,
    ) -> String {
        let version = if include_version {
            probe
                .version
                .as_ref()
                .map(|v| format!(" version={}", v))
                .unwrap_or_default()
        } else {
            String::new()
        };
        if probe.found {
            let path = probe
                .resolved_path
                .as_deref()
                .unwrap_or(probe.executable.as_str());
            let probe_note = if probe.version_probe_ok {
                ""
            } else {
                " (version probe failed)"
            };
            format!("found path={}{}{}", path, version, probe_note)
        } else {
            let error = probe.error.as_deref().unwrap_or("not found");
            format!("missing executable={} ({})", probe.executable, error)
        }
    }

    fn format_prepare_failure_status(
        message: &str,
        elapsed_secs: f64,
        cancellation_requested: bool,
        timeout_seconds: Option<u64>,
    ) -> String {
        let lower = message.to_ascii_lowercase();
        let timed_out_hint = lower.contains("timed out") || lower.contains("timeout");
        let cancelled_hint = lower.contains("cancelled") || lower.contains("canceled");
        let timebox_elapsed = timeout_seconds
            .map(|limit| elapsed_secs >= limit as f64)
            .unwrap_or(false);
        if timed_out_hint || (!cancellation_requested && cancelled_hint && timebox_elapsed) {
            format!(
                "Prepare genome timed out after {:.1}s: {}",
                elapsed_secs, message
            )
        } else if cancellation_requested || cancelled_hint {
            format!(
                "Prepare genome cancelled after {:.1}s: {}",
                elapsed_secs, message
            )
        } else {
            format!(
                "Prepare genome failed after {:.1}s: {}",
                elapsed_secs, message
            )
        }
    }

    fn start_prepare_reference_genome(&mut self) {
        if self.genome_prepare_task.is_some() {
            self.genome_prepare_status = "Genome preparation is already running".to_string();
            return;
        }
        let genome_id = self.genome_id.trim().to_string();
        if genome_id.is_empty() {
            self.genome_prepare_status = "Select a genome first".to_string();
            return;
        }
        let timeout_seconds = match self.parse_prepare_timeout_seconds() {
            Ok(value) => value,
            Err(e) => {
                self.genome_prepare_status = e;
                return;
            }
        };
        let binary_preflight = self
            .engine
            .read()
            .unwrap()
            .blast_external_binary_preflight_report();
        let makeblastdb_preflight =
            Self::summarize_binary_probe(&binary_preflight.makeblastdb, true);
        let catalog_path = self.genome_catalog_path_opt();
        let cache_dir = self.genome_cache_dir_opt();
        let cancel_requested = Arc::new(AtomicBool::new(false));
        let job_id = self.alloc_background_job_id();
        let (tx, rx) = mpsc::channel::<GenomePrepareTaskMessage>();
        self.genome_prepare_progress = None;
        self.genome_prepare_status = if let Some(timeout) = timeout_seconds {
            format!(
                "Preparing genome '{genome_id}' in background (timeout: {} s). You can keep using the UI.\npreflight makeblastdb: {}",
                timeout, makeblastdb_preflight
            )
        } else {
            format!(
                "Preparing genome '{genome_id}' in background. You can keep using the UI.\npreflight makeblastdb: {}",
                makeblastdb_preflight
            )
        };
        self.push_job_event(
            BackgroundJobKind::PrepareGenome,
            BackgroundJobEventPhase::Started,
            Some(job_id),
            format!(
                "Prepare genome started: {} (makeblastdb preflight: {})",
                genome_id, makeblastdb_preflight
            ),
        );
        self.genome_prepare_task = Some(GenomePrepareTask {
            job_id,
            started: Instant::now(),
            cancel_requested: cancel_requested.clone(),
            timeout_seconds,
            receiver: rx,
        });
        std::thread::spawn(move || {
            let tx_progress = tx.clone();
            let cancel_flag = cancel_requested.clone();
            let mut last_phase = String::new();
            let mut last_percent_tenths: Option<i64> = None;
            let mut last_bytes_bucket: u64 = 0;
            let mut progress_forwarder = move |p: PrepareGenomeProgress| -> bool {
                if cancel_flag.load(Ordering::Relaxed) {
                    return false;
                }
                let phase_changed = p.phase != last_phase;
                let percent_tenths = p.percent.map(|v| (v * 10.0).floor() as i64);
                let percent_progressed = percent_tenths
                    .map(|value| last_percent_tenths.map(|prev| value > prev).unwrap_or(true))
                    .unwrap_or(false);
                let bytes_bucket = p.bytes_done / (8 * 1024 * 1024);
                let bytes_progressed = bytes_bucket > last_bytes_bucket;
                let done = p.phase == "ready"
                    || p.percent
                        .map(|v| (v - 100.0).abs() < f64::EPSILON)
                        .unwrap_or(false);
                if phase_changed || percent_progressed || bytes_progressed || done {
                    last_phase = p.phase.clone();
                    if let Some(v) = percent_tenths {
                        last_percent_tenths = Some(v);
                    }
                    last_bytes_bucket = bytes_bucket;
                    let _ = tx_progress.send(GenomePrepareTaskMessage::Progress {
                        job_id,
                        progress: p,
                    });
                }
                true
            };
            let outcome = GentleEngine::prepare_reference_genome_once(
                &genome_id,
                catalog_path.as_deref(),
                cache_dir.as_deref(),
                timeout_seconds,
                &mut progress_forwarder,
            )
            .map(|report| OpResult {
                op_id: "background-prepare-genome".to_string(),
                created_seq_ids: vec![],
                changed_seq_ids: vec![],
                warnings: report.warnings.clone(),
                messages: vec![GentleEngine::format_prepare_genome_message(
                    &genome_id,
                    cache_dir.as_deref(),
                    &report,
                )],
                genome_annotation_projection: None,
                sequence_alignment: None,
            });
            let _ = tx.send(GenomePrepareTaskMessage::Done {
                job_id,
                result: outcome,
            });
        });
    }

    fn poll_prepare_reference_genome_task(&mut self, ctx: &egui::Context) {
        if self.genome_prepare_task.is_none() {
            return;
        }
        ctx.request_repaint_after(Duration::from_millis(100));
        let mut done: Option<(u64, Result<OpResult, EngineError>)> = None;
        let mut stale_job_ids: Vec<u64> = vec![];
        if let Some(task) = &self.genome_prepare_task {
            let active_job_id = task.job_id;
            const MAX_MESSAGES_PER_TICK: usize = 128;
            for _ in 0..MAX_MESSAGES_PER_TICK {
                match task.receiver.try_recv() {
                    Ok(GenomePrepareTaskMessage::Progress { job_id, progress }) => {
                        if job_id != active_job_id {
                            if !stale_job_ids.contains(&job_id) {
                                stale_job_ids.push(job_id);
                            }
                            continue;
                        }
                        self.genome_prepare_progress = Some(progress.clone());
                        let canceling = task.cancel_requested.load(Ordering::Relaxed);
                        self.genome_prepare_status = format!(
                            "Preparing genome '{}': {} ({}){}",
                            progress.genome_id,
                            progress.phase,
                            progress.item,
                            if canceling {
                                " (cancellation requested)"
                            } else {
                                ""
                            }
                        );
                    }
                    Ok(GenomePrepareTaskMessage::Done { job_id, result }) => {
                        if job_id != active_job_id {
                            if !stale_job_ids.contains(&job_id) {
                                stale_job_ids.push(job_id);
                            }
                            continue;
                        }
                        done = Some((job_id, result));
                        break;
                    }
                    Err(mpsc::TryRecvError::Empty) => break,
                    Err(mpsc::TryRecvError::Disconnected) => {
                        done = Some((
                            active_job_id,
                            Err(EngineError {
                                code: ErrorCode::Internal,
                                message: "Genome preparation worker disconnected".to_string(),
                            }),
                        ));
                        break;
                    }
                }
            }
        }
        for stale_job_id in stale_job_ids {
            self.push_job_event(
                BackgroundJobKind::PrepareGenome,
                BackgroundJobEventPhase::IgnoredStale,
                Some(stale_job_id),
                "Ignored stale prepare-genome worker message",
            );
        }
        if let Some((job_id, outcome)) = done {
            let (elapsed, cancellation_requested, timeout_seconds) = self
                .genome_prepare_task
                .as_ref()
                .map(|task| {
                    (
                        task.started.elapsed().as_secs_f64(),
                        task.cancel_requested.load(Ordering::Relaxed),
                        task.timeout_seconds,
                    )
                })
                .unwrap_or((0.0, false, None));
            self.genome_prepare_task = None;
            match outcome {
                Ok(result) => {
                    let prefix = if cancellation_requested {
                        "Prepare genome finished after cancellation request"
                    } else {
                        "Prepare genome: ok"
                    };
                    self.genome_prepare_status = format!(
                        "{}\nelapsed: {:.1}s",
                        Self::format_op_result_status(
                            prefix,
                            &result.created_seq_ids,
                            &result.warnings,
                            &result.messages
                        ),
                        elapsed
                    );
                    self.invalidate_genome_genes();
                    self.push_job_event(
                        BackgroundJobKind::PrepareGenome,
                        BackgroundJobEventPhase::Completed,
                        Some(job_id),
                        format!("{prefix} in {:.1}s", elapsed),
                    );
                }
                Err(e) => {
                    self.genome_prepare_status = Self::format_prepare_failure_status(
                        &e.message,
                        elapsed,
                        cancellation_requested,
                        timeout_seconds,
                    );
                    self.push_job_event(
                        BackgroundJobKind::PrepareGenome,
                        BackgroundJobEventPhase::Failed,
                        Some(job_id),
                        format!("Prepare genome ended in {:.1}s: {}", elapsed, e.message),
                    );
                }
            }
        }
    }

    fn poll_genome_track_import_task(&mut self, ctx: &egui::Context) {
        if self.genome_track_import_task.is_none() {
            return;
        }
        ctx.request_repaint_after(Duration::from_millis(100));
        let mut done: Option<(u64, Result<OpResult, EngineError>)> = None;
        let mut stale_job_ids: Vec<u64> = vec![];
        if let Some(task) = &self.genome_track_import_task {
            let active_job_id = task.job_id;
            const MAX_MESSAGES_PER_TICK: usize = 256;
            for _ in 0..MAX_MESSAGES_PER_TICK {
                match task.receiver.try_recv() {
                    Ok(GenomeTrackImportTaskMessage::Progress { job_id, progress }) => {
                        if job_id != active_job_id {
                            if !stale_job_ids.contains(&job_id) {
                                stale_job_ids.push(job_id);
                            }
                            continue;
                        }
                        self.genome_track_import_progress = Some(progress.clone());
                        let canceling = task.cancel_requested.load(Ordering::Relaxed);
                        self.genome_track_status = format!(
                            "Importing {} track for '{}': parsed={}, imported={}, skipped={}{}",
                            progress.source,
                            progress.seq_id,
                            progress.parsed_records,
                            progress.imported_features,
                            progress.skipped_records,
                            if canceling {
                                " (cancellation requested)"
                            } else {
                                ""
                            }
                        );
                    }
                    Ok(GenomeTrackImportTaskMessage::Done { job_id, result }) => {
                        if job_id != active_job_id {
                            if !stale_job_ids.contains(&job_id) {
                                stale_job_ids.push(job_id);
                            }
                            continue;
                        }
                        done = Some((job_id, result));
                        break;
                    }
                    Err(mpsc::TryRecvError::Empty) => break,
                    Err(mpsc::TryRecvError::Disconnected) => {
                        done = Some((
                            active_job_id,
                            Err(EngineError {
                                code: ErrorCode::Internal,
                                message: "Genome track import worker disconnected".to_string(),
                            }),
                        ));
                        break;
                    }
                }
            }
        }
        for stale_job_id in stale_job_ids {
            self.push_job_event(
                BackgroundJobKind::TrackImport,
                BackgroundJobEventPhase::IgnoredStale,
                Some(stale_job_id),
                "Ignored stale track-import worker message",
            );
        }

        if let Some((job_id, outcome)) = done {
            let elapsed = self
                .genome_track_import_task
                .as_ref()
                .map(|task| task.started.elapsed().as_secs_f64())
                .unwrap_or(0.0);
            let cancellation_requested = self
                .genome_track_import_task
                .as_ref()
                .map(|task| task.cancel_requested.load(Ordering::Relaxed))
                .unwrap_or(false);
            self.genome_track_import_task = None;
            self.genome_track_import_progress = None;
            match outcome {
                Ok(result) => {
                    let prefix = if cancellation_requested {
                        "Import track finished after cancellation request"
                    } else {
                        "Import track: ok"
                    };
                    self.genome_track_status = format!(
                        "{}\nelapsed: {:.1}s",
                        Self::format_op_result_status(
                            prefix,
                            &result.created_seq_ids,
                            &result.warnings,
                            &result.messages,
                        ),
                        elapsed
                    );
                    let refreshed_windows = if result.changed_seq_ids.is_empty() {
                        self.refresh_sequence_windows_from_engine_state()
                    } else {
                        self.refresh_sequence_windows_for_seq_ids(&result.changed_seq_ids)
                    };
                    if refreshed_windows > 0 {
                        self.genome_track_status.push_str(&format!(
                            "\nrefreshed {} open sequence window(s)",
                            refreshed_windows
                        ));
                        ctx.request_repaint();
                    }
                    self.push_job_event(
                        BackgroundJobKind::TrackImport,
                        BackgroundJobEventPhase::Completed,
                        Some(job_id),
                        format!("{prefix} in {:.1}s", elapsed),
                    );
                }
                Err(e) => {
                    self.genome_track_status =
                        format!("Import track failed after {:.1}s: {}", elapsed, e.message);
                    self.push_job_event(
                        BackgroundJobKind::TrackImport,
                        BackgroundJobEventPhase::Failed,
                        Some(job_id),
                        format!("Track import failed in {:.1}s: {}", elapsed, e.message),
                    );
                }
            }
        }
    }

    fn merge_json_objects_recursive(
        base: &mut serde_json::Map<String, serde_json::Value>,
        overlay: &serde_json::Map<String, serde_json::Value>,
    ) {
        for (key, value) in overlay {
            match (base.get_mut(key), value) {
                (
                    Some(serde_json::Value::Object(existing)),
                    serde_json::Value::Object(incoming),
                ) => {
                    Self::merge_json_objects_recursive(existing, incoming);
                }
                _ => {
                    base.insert(key.clone(), value.clone());
                }
            }
        }
    }

    fn build_genome_blast_request_override_json(
        &self,
    ) -> Result<Option<serde_json::Value>, String> {
        let mut merged = serde_json::Map::<String, serde_json::Value>::new();
        if let Some(preset) = self.genome_blast_options_preset.as_request_override_json() {
            let Some(obj) = preset.as_object() else {
                return Err(
                    "Internal preset error: BLAST preset payload is not a JSON object".to_string(),
                );
            };
            Self::merge_json_objects_recursive(&mut merged, obj);
        }
        if let Some(structured_thresholds) =
            self.build_structured_blast_thresholds_override_json()?
        {
            let Some(obj) = structured_thresholds.as_object() else {
                return Err("Internal threshold error: structured BLAST thresholds payload is not a JSON object".to_string());
            };
            Self::merge_json_objects_recursive(&mut merged, obj);
        }
        let raw_advanced = self.genome_blast_options_json.trim();
        if !raw_advanced.is_empty() {
            let parsed: serde_json::Value = serde_json::from_str(raw_advanced)
                .map_err(|e| format!("Invalid advanced BLAST options JSON: {e}"))?;
            let Some(obj) = parsed.as_object() else {
                return Err("Advanced BLAST options must decode to a JSON object".to_string());
            };
            Self::merge_json_objects_recursive(&mut merged, obj);
        }
        if merged.is_empty() {
            Ok(None)
        } else {
            Ok(Some(serde_json::Value::Object(merged)))
        }
    }

    fn build_structured_blast_thresholds_override_json(
        &self,
    ) -> Result<Option<serde_json::Value>, String> {
        let mut thresholds = serde_json::Map::<String, serde_json::Value>::new();

        if self.genome_blast_threshold_use_max_evalue {
            let parsed = self
                .genome_blast_threshold_max_evalue
                .trim()
                .parse::<f64>()
                .map_err(|e| format!("Invalid max_evalue value: {e}"))?;
            if !parsed.is_finite() || parsed < 0.0 {
                return Err("max_evalue must be a finite number >= 0.0".to_string());
            }
            thresholds.insert("max_evalue".to_string(), serde_json::Value::from(parsed));
        }

        if self.genome_blast_threshold_use_min_identity_percent {
            let parsed = self
                .genome_blast_threshold_min_identity_percent
                .trim()
                .parse::<f64>()
                .map_err(|e| format!("Invalid min_identity_percent value: {e}"))?;
            if !parsed.is_finite() || !(0.0..=100.0).contains(&parsed) {
                return Err("min_identity_percent must be within [0, 100]".to_string());
            }
            thresholds.insert(
                "min_identity_percent".to_string(),
                serde_json::Value::from(parsed),
            );
        }

        if self.genome_blast_threshold_use_min_query_coverage_percent {
            let parsed = self
                .genome_blast_threshold_min_query_coverage_percent
                .trim()
                .parse::<f64>()
                .map_err(|e| format!("Invalid min_query_coverage_percent value: {e}"))?;
            if !parsed.is_finite() || !(0.0..=100.0).contains(&parsed) {
                return Err("min_query_coverage_percent must be within [0, 100]".to_string());
            }
            thresholds.insert(
                "min_query_coverage_percent".to_string(),
                serde_json::Value::from(parsed),
            );
        }

        if self.genome_blast_threshold_use_min_alignment_length_bp {
            let parsed = self
                .genome_blast_threshold_min_alignment_length_bp
                .trim()
                .parse::<usize>()
                .map_err(|e| format!("Invalid min_alignment_length_bp value: {e}"))?;
            if parsed == 0 {
                return Err("min_alignment_length_bp must be >= 1".to_string());
            }
            thresholds.insert(
                "min_alignment_length_bp".to_string(),
                serde_json::Value::from(parsed),
            );
        }

        if self.genome_blast_threshold_use_min_bit_score {
            let parsed = self
                .genome_blast_threshold_min_bit_score
                .trim()
                .parse::<f64>()
                .map_err(|e| format!("Invalid min_bit_score value: {e}"))?;
            if !parsed.is_finite() || parsed < 0.0 {
                return Err("min_bit_score must be a finite number >= 0.0".to_string());
            }
            thresholds.insert("min_bit_score".to_string(), serde_json::Value::from(parsed));
        }

        if self.genome_blast_threshold_unique_best_hit {
            thresholds.insert("unique_best_hit".to_string(), serde_json::Value::from(true));
        }

        if thresholds.is_empty() {
            Ok(None)
        } else {
            Ok(Some(serde_json::json!({ "thresholds": thresholds })))
        }
    }

    fn resolve_genome_blast_options_preview(
        &self,
        request_override_json: Option<&serde_json::Value>,
    ) -> Result<crate::engine::BlastResolvedOptions, String> {
        let task_name = self.genome_blast_task_name.trim();
        let legacy_task = if task_name.is_empty() {
            None
        } else {
            Some(task_name)
        };
        let legacy_max_hits = Some(self.genome_blast_max_hits.max(1));
        let engine = self.engine.read().unwrap();
        engine
            .resolve_blast_options_for_request(request_override_json, legacy_task, legacy_max_hits)
            .map_err(|e| e.message)
    }

    fn format_blast_thresholds_summary(
        thresholds: &crate::engine::BlastThresholdOptions,
    ) -> String {
        let mut parts: Vec<String> = vec![];
        if let Some(v) = thresholds.max_evalue {
            parts.push(format!("max_evalue={v:.3e}"));
        }
        if let Some(v) = thresholds.min_identity_percent {
            parts.push(format!("min_identity={v:.2}%"));
        }
        if let Some(v) = thresholds.min_query_coverage_percent {
            parts.push(format!("min_qcov={v:.2}%"));
        }
        if let Some(v) = thresholds.min_alignment_length_bp {
            parts.push(format!("min_aln_bp={v}"));
        }
        if let Some(v) = thresholds.min_bit_score {
            parts.push(format!("min_bit_score={v:.2}"));
        }
        if let Some(v) = thresholds.unique_best_hit {
            parts.push(format!("unique_best_hit={v}"));
        }
        if parts.is_empty() {
            "none".to_string()
        } else {
            parts.join(", ")
        }
    }

    fn start_reference_genome_blast(&mut self) {
        if self.genome_blast_task.is_some() {
            self.genome_blast_status = "A BLAST task is already running".to_string();
            return;
        }

        let genome_id = self.genome_id.trim().to_string();
        if genome_id.is_empty() {
            self.genome_blast_status = "Select a prepared genome first".to_string();
            return;
        }

        let blast_queries: Vec<(String, String)> = match self.genome_blast_source_mode {
            GenomeBlastSourceMode::Manual => {
                let query = self.genome_blast_query_manual.trim().to_string();
                if query.is_empty() {
                    self.genome_blast_status =
                        "Provide a query sequence for manual BLAST mode".to_string();
                    return;
                }
                vec![("manual_query".to_string(), query)]
            }
            GenomeBlastSourceMode::ProjectSequence => {
                let seq_id = self.genome_blast_query_seq_id.trim().to_string();
                if seq_id.is_empty() {
                    self.genome_blast_status = "Select a project sequence to blast".to_string();
                    return;
                }
                let sequence = {
                    let engine = self.engine.read().unwrap();
                    let Some(dna) = engine.state().sequences.get(&seq_id) else {
                        self.genome_blast_status =
                            format!("Selected sequence '{}' is no longer available", seq_id);
                        return;
                    };
                    dna.get_forward_string()
                };
                if sequence.is_empty() {
                    self.genome_blast_status = format!(
                        "Selected sequence '{}' has no bases and cannot be blasted",
                        seq_id
                    );
                    return;
                }
                vec![(seq_id, sequence)]
            }
            GenomeBlastSourceMode::ProjectPool => {
                let pool_id = self.genome_blast_query_pool_id.trim().to_string();
                if pool_id.is_empty() {
                    self.genome_blast_status =
                        "Select a project pool/container to blast".to_string();
                    return;
                }
                let mut queries: Vec<(String, String)> = vec![];
                {
                    let engine = self.engine.read().unwrap();
                    let state = engine.state();
                    let Some(container) = state.container_state.containers.get(&pool_id) else {
                        self.genome_blast_status =
                            format!("Selected pool/container '{}' does not exist", pool_id);
                        return;
                    };
                    for seq_id in &container.members {
                        let Some(dna) = state.sequences.get(seq_id) else {
                            continue;
                        };
                        let seq = dna.get_forward_string();
                        if seq.is_empty() {
                            continue;
                        }
                        queries.push((seq_id.clone(), seq));
                    }
                }
                if queries.is_empty() {
                    self.genome_blast_status = format!(
                        "Selected pool/container '{}' has no blastable sequence members",
                        pool_id
                    );
                    return;
                }
                queries
            }
        };

        let total_queries = blast_queries.len();
        let catalog_path = self.genome_catalog_path_opt();
        let cache_dir = self.genome_cache_dir_opt();
        let legacy_max_hits = self.genome_blast_max_hits.max(1);
        let blast_task_name = self.genome_blast_task_name.trim().to_string();
        let legacy_task_arg = if blast_task_name.is_empty() {
            None
        } else {
            Some(blast_task_name)
        };
        let request_override_json = match self.build_genome_blast_request_override_json() {
            Ok(v) => v,
            Err(e) => {
                self.genome_blast_status = e;
                return;
            }
        };
        let resolved_preview =
            match self.resolve_genome_blast_options_preview(request_override_json.as_ref()) {
                Ok(v) => v,
                Err(e) => {
                    self.genome_blast_status = format!("BLAST options preflight failed: {e}");
                    return;
                }
            };
        let binary_preflight = self
            .engine
            .read()
            .unwrap()
            .blast_external_binary_preflight_report();
        let blastn_preflight = Self::summarize_binary_probe(&binary_preflight.blastn, true);
        let makeblastdb_preflight =
            Self::summarize_binary_probe(&binary_preflight.makeblastdb, false);
        let blastn_bin_for_status = binary_preflight.blastn.executable.clone();
        let project_state_snapshot = self.engine.read().unwrap().state().clone();
        let job_id = self.alloc_background_job_id();
        let (tx, rx) = mpsc::channel::<GenomeBlastTaskMessage>();
        let cancel_requested = Arc::new(AtomicBool::new(false));
        self.genome_blast_results.clear();
        self.genome_blast_selected_result = 0;
        self.genome_blast_progress_fraction = Some(0.0);
        self.genome_blast_progress_label = format!("0 / {total_queries}");
        self.genome_blast_status = format!(
            "Running BLAST for {} quer{} in background\npreflight blastn: {}\npreflight makeblastdb: {}",
            total_queries,
            if total_queries == 1 { "y" } else { "ies" },
            blastn_preflight,
            makeblastdb_preflight
        );
        self.push_job_event(
            BackgroundJobKind::BlastGenome,
            BackgroundJobEventPhase::Started,
            Some(job_id),
            format!(
                "BLAST started: genome='{}', queries={}, task='{}', max_hits={}, thresholds={}, request_override={}, blastn_preflight={}, makeblastdb_preflight={}",
                genome_id,
                total_queries,
                resolved_preview.task,
                resolved_preview.max_hits,
                Self::format_blast_thresholds_summary(&resolved_preview.thresholds),
                if request_override_json.is_some() {
                    "yes"
                } else {
                    "no"
                },
                blastn_preflight,
                makeblastdb_preflight
            ),
        );
        self.genome_blast_task = Some(GenomeBlastTask {
            job_id,
            started: Instant::now(),
            cancel_requested: cancel_requested.clone(),
            receiver: rx,
        });
        std::thread::spawn(move || {
            let mut reports: Vec<GenomeBlastQueryResult> = vec![];
            let mut failed_queries: Vec<String> = vec![];
            let mut cancelled = false;
            let cancel_flag = cancel_requested.clone();
            let task_name_for_status = resolved_preview.task.clone();
            let max_hits_for_status = resolved_preview.max_hits;

            for (idx, (label, query)) in blast_queries.into_iter().enumerate() {
                if cancel_flag.load(Ordering::Relaxed) {
                    let _ = tx.send(GenomeBlastTaskMessage::Status {
                        job_id,
                        status: format!("BLAST cancellation acknowledged before query '{}'", label),
                    });
                    cancelled = true;
                    break;
                }
                let _ = tx.send(GenomeBlastTaskMessage::Progress {
                    job_id,
                    done_queries: idx,
                    total_queries,
                    current_query_label: label.clone(),
                });

                let query_length = query.len();
                let invocation_template = format!(
                    "{} -db <prepared_db_prefix> -query <temp_query.fa> -task {} -max_target_seqs {}",
                    blastn_bin_for_status, task_name_for_status, max_hits_for_status
                );
                let _ = tx.send(GenomeBlastTaskMessage::Status {
                    job_id,
                    status: format!(
                        "BLAST query '{}' started ({} bp)\ninvocation template: {}",
                        label, query_length, invocation_template
                    ),
                });

                let query_started = Instant::now();
                let (query_tx, query_rx) =
                    mpsc::channel::<Result<GenomeBlastReport, EngineError>>();
                let catalog_for_query = catalog_path.clone();
                let cache_for_query = cache_dir.clone();
                let genome_for_query = genome_id.clone();
                let task_for_query = legacy_task_arg.clone();
                let request_override_for_query = request_override_json.clone();
                let project_state_for_query = project_state_snapshot.clone();
                let cancel_for_query = cancel_flag.clone();
                std::thread::spawn(move || {
                    let blast_engine = GentleEngine::from_state(project_state_for_query);
                    let mut should_cancel = || cancel_for_query.load(Ordering::Relaxed);
                    let outcome = blast_engine
                        .blast_reference_genome_with_project_and_request_options_and_cancel(
                            catalog_for_query.as_deref(),
                            &genome_for_query,
                            &query,
                            request_override_for_query.as_ref(),
                            task_for_query.as_deref(),
                            Some(legacy_max_hits),
                            cache_for_query.as_deref(),
                            &mut should_cancel,
                        );
                    let _ = query_tx.send(outcome);
                });

                let report_result = loop {
                    match query_rx.recv_timeout(Duration::from_millis(250)) {
                        Ok(outcome) => break outcome,
                        Err(mpsc::RecvTimeoutError::Timeout) => {
                            let cancel_suffix = if cancel_flag.load(Ordering::Relaxed) {
                                " (cancellation requested)"
                            } else {
                                ""
                            };
                            let _ = tx.send(GenomeBlastTaskMessage::Status {
                                job_id,
                                status: format!(
                                    "BLAST query '{}' running ({:.1}s){}\ninvocation template: {}",
                                    label,
                                    query_started.elapsed().as_secs_f32(),
                                    cancel_suffix,
                                    invocation_template
                                ),
                            });
                        }
                        Err(mpsc::RecvTimeoutError::Disconnected) => {
                            break Err(EngineError {
                                code: ErrorCode::Io,
                                message: "BLAST worker disconnected".to_string(),
                            });
                        }
                    }
                };

                match report_result {
                    Ok(report) => {
                        let invocation = Self::format_blast_command_line(
                            &report.blastn_executable,
                            &report.command,
                        );
                        let _ = tx.send(GenomeBlastTaskMessage::Status {
                            job_id,
                            status: format!(
                                "BLAST query '{}' completed in {:.1}s (hits={})\ninvocation: {}",
                                label,
                                query_started.elapsed().as_secs_f32(),
                                report.hit_count,
                                invocation
                            ),
                        });
                        reports.push(GenomeBlastQueryResult {
                            query_label: label.clone(),
                            query_length,
                            report,
                        });
                    }
                    Err(e) => {
                        if crate::genomes::is_blast_cancelled_error(&e.message)
                            || cancel_flag.load(Ordering::Relaxed)
                        {
                            let _ = tx.send(GenomeBlastTaskMessage::Status {
                                job_id,
                                status: format!(
                                    "BLAST cancelled while running query '{}' after {:.1}s",
                                    label,
                                    query_started.elapsed().as_secs_f32()
                                ),
                            });
                            cancelled = true;
                            break;
                        }
                        let _ = tx.send(GenomeBlastTaskMessage::Status {
                            job_id,
                            status: format!(
                                "BLAST query '{}' failed after {:.1}s: {}",
                                label,
                                query_started.elapsed().as_secs_f32(),
                                e.message
                            ),
                        });
                        failed_queries.push(format!("{label}: {}", e.message));
                    }
                }
                let _ = tx.send(GenomeBlastTaskMessage::Progress {
                    job_id,
                    done_queries: idx + 1,
                    total_queries,
                    current_query_label: label,
                });
            }

            let completed_queries = reports.len() + failed_queries.len();
            let done_result = if cancelled {
                Err(format!(
                    "BLAST cancelled by user after {} / {} quer{}",
                    completed_queries,
                    total_queries,
                    if total_queries == 1 { "y" } else { "ies" }
                ))
            } else if reports.is_empty() && !failed_queries.is_empty() {
                Err(format!(
                    "BLAST failed for all queries: {}",
                    failed_queries.join(" | ")
                ))
            } else {
                Ok(GenomeBlastBatchResult {
                    reports,
                    failed_queries,
                })
            };
            let _ = tx.send(GenomeBlastTaskMessage::Done {
                job_id,
                result: done_result,
            });
        });
    }

    fn poll_reference_genome_blast_task(&mut self, ctx: &egui::Context) {
        if self.genome_blast_task.is_none() {
            return;
        }
        ctx.request_repaint_after(Duration::from_millis(100));
        let mut done: Option<(u64, Result<GenomeBlastBatchResult, String>)> = None;
        let mut stale_job_ids: Vec<u64> = vec![];
        if let Some(task) = &self.genome_blast_task {
            let active_job_id = task.job_id;
            const MAX_MESSAGES_PER_TICK: usize = 128;
            for _ in 0..MAX_MESSAGES_PER_TICK {
                match task.receiver.try_recv() {
                    Ok(GenomeBlastTaskMessage::Progress {
                        job_id,
                        done_queries,
                        total_queries,
                        current_query_label,
                    }) => {
                        if job_id != active_job_id {
                            if !stale_job_ids.contains(&job_id) {
                                stale_job_ids.push(job_id);
                            }
                            continue;
                        }
                        let fraction = if total_queries == 0 {
                            0.0
                        } else {
                            (done_queries as f32 / total_queries as f32).clamp(0.0, 1.0)
                        };
                        let canceling = task.cancel_requested.load(Ordering::Relaxed);
                        self.genome_blast_progress_fraction = Some(fraction);
                        self.genome_blast_progress_label = format!(
                            "{done_queries} / {total_queries} ({current_query_label}){}",
                            if canceling { " [cancel requested]" } else { "" }
                        );
                    }
                    Ok(GenomeBlastTaskMessage::Status { job_id, status }) => {
                        if job_id != active_job_id {
                            if !stale_job_ids.contains(&job_id) {
                                stale_job_ids.push(job_id);
                            }
                            continue;
                        }
                        self.genome_blast_status = status;
                    }
                    Ok(GenomeBlastTaskMessage::Done { job_id, result }) => {
                        if job_id != active_job_id {
                            if !stale_job_ids.contains(&job_id) {
                                stale_job_ids.push(job_id);
                            }
                            continue;
                        }
                        done = Some((job_id, result));
                        break;
                    }
                    Err(mpsc::TryRecvError::Empty) => break,
                    Err(mpsc::TryRecvError::Disconnected) => {
                        done = Some((active_job_id, Err("BLAST worker disconnected".to_string())));
                        break;
                    }
                }
            }
        }
        for stale_job_id in stale_job_ids {
            self.push_job_event(
                BackgroundJobKind::BlastGenome,
                BackgroundJobEventPhase::IgnoredStale,
                Some(stale_job_id),
                "Ignored stale BLAST worker message",
            );
        }

        if let Some((job_id, outcome)) = done {
            let elapsed = self
                .genome_blast_task
                .as_ref()
                .map(|task| task.started.elapsed().as_secs_f64())
                .unwrap_or(0.0);
            let cancellation_requested = self
                .genome_blast_task
                .as_ref()
                .map(|task| task.cancel_requested.load(Ordering::Relaxed))
                .unwrap_or(false);
            self.genome_blast_task = None;
            self.genome_blast_progress_fraction = None;
            self.genome_blast_progress_label.clear();

            match outcome {
                Ok(batch) => {
                    self.genome_blast_results = batch.reports;
                    if self.genome_blast_results.is_empty() {
                        self.genome_blast_selected_result = 0;
                    } else if self.genome_blast_selected_result >= self.genome_blast_results.len() {
                        self.genome_blast_selected_result = 0;
                    }
                    let hit_total: usize = self
                        .genome_blast_results
                        .iter()
                        .map(|r| r.report.hit_count)
                        .sum();
                    if cancellation_requested {
                        self.genome_blast_status = format!(
                            "BLAST finished after cancellation request in {:.1}s: {} query result(s), {} total hit(s)",
                            elapsed,
                            self.genome_blast_results.len(),
                            hit_total
                        );
                        self.push_job_event(
                            BackgroundJobKind::BlastGenome,
                            BackgroundJobEventPhase::Completed,
                            Some(job_id),
                            format!(
                                "BLAST finished after cancellation request in {:.1}s: {} result(s), {} hit(s)",
                                elapsed,
                                self.genome_blast_results.len(),
                                hit_total
                            ),
                        );
                    } else if batch.failed_queries.is_empty() {
                        self.genome_blast_status = format!(
                            "BLAST finished in {:.1}s: {} query result(s), {} total hit(s)",
                            elapsed,
                            self.genome_blast_results.len(),
                            hit_total
                        );
                        self.push_job_event(
                            BackgroundJobKind::BlastGenome,
                            BackgroundJobEventPhase::Completed,
                            Some(job_id),
                            format!(
                                "BLAST completed in {:.1}s: {} result(s), {} hit(s)",
                                elapsed,
                                self.genome_blast_results.len(),
                                hit_total
                            ),
                        );
                    } else {
                        self.genome_blast_status = format!(
                            "BLAST finished in {:.1}s: {} query result(s), {} total hit(s), {} failed query(ies): {}",
                            elapsed,
                            self.genome_blast_results.len(),
                            hit_total,
                            batch.failed_queries.len(),
                            batch.failed_queries.join(" | ")
                        );
                        self.push_job_event(
                            BackgroundJobKind::BlastGenome,
                            BackgroundJobEventPhase::Failed,
                            Some(job_id),
                            format!(
                                "BLAST completed in {:.1}s with {} failed quer{}",
                                elapsed,
                                batch.failed_queries.len(),
                                if batch.failed_queries.len() == 1 {
                                    "y"
                                } else {
                                    "ies"
                                }
                            ),
                        );
                    }
                }
                Err(e) => {
                    self.genome_blast_results.clear();
                    self.genome_blast_selected_result = 0;
                    if cancellation_requested
                        || crate::genomes::is_blast_cancelled_error(&e)
                        || e.to_ascii_lowercase().contains("cancel")
                    {
                        self.genome_blast_status =
                            format!("BLAST cancelled after {:.1}s: {}", elapsed, e);
                    } else {
                        self.genome_blast_status =
                            format!("BLAST failed after {:.1}s: {}", elapsed, e);
                    }
                    self.push_job_event(
                        BackgroundJobKind::BlastGenome,
                        BackgroundJobEventPhase::Failed,
                        Some(job_id),
                        format!("BLAST failed in {:.1}s: {}", elapsed, e),
                    );
                }
            }
        }
    }

    fn target_seq_id_for_blast_result(&self, result: &GenomeBlastQueryResult) -> Option<String> {
        let candidate = result.query_label.trim();
        if candidate.is_empty() {
            return None;
        }
        if self
            .engine
            .read()
            .unwrap()
            .state()
            .sequences
            .contains_key(candidate)
        {
            Some(candidate.to_string())
        } else {
            None
        }
    }

    fn import_selected_blast_hits_as_track(&mut self) {
        let Some(result) = self
            .genome_blast_results
            .get(self.genome_blast_selected_result)
            .cloned()
        else {
            self.genome_blast_status = "No BLAST result is selected".to_string();
            return;
        };
        let Some(seq_id) = self.target_seq_id_for_blast_result(&result) else {
            self.genome_blast_status = format!(
                "Cannot import BLAST hits for query '{}' because it is not a current project sequence ID",
                result.query_label
            );
            return;
        };
        if result.report.hits.is_empty() {
            self.genome_blast_status = format!(
                "No BLAST hits available for '{}' to import",
                result.query_label
            );
            return;
        }

        let hits = result
            .report
            .hits
            .iter()
            .map(|hit| BlastHitFeatureInput {
                subject_id: hit.subject_id.clone(),
                query_start_1based: hit.query_start,
                query_end_1based: hit.query_end,
                subject_start_1based: hit.subject_start,
                subject_end_1based: hit.subject_end,
                identity_percent: hit.identity_percent,
                bit_score: hit.bit_score,
                evalue: hit.evalue,
                query_coverage_percent: hit.query_coverage_percent,
            })
            .collect::<Vec<_>>();
        let track_name = {
            let trimmed = self.genome_blast_import_track_name.trim();
            if trimmed.is_empty() {
                None
            } else {
                Some(trimmed.to_string())
            }
        };
        let op = Operation::ImportBlastHitsTrack {
            seq_id: seq_id.clone(),
            hits,
            track_name,
            clear_existing: Some(self.genome_blast_import_clear_existing),
            blast_provenance: Some(BlastInvocationProvenance {
                genome_id: result.report.genome_id.clone(),
                query_label: result.query_label.clone(),
                query_length: result.query_length,
                max_hits: result.report.max_hits,
                task: result.report.task.clone(),
                blastn_executable: result.report.blastn_executable.clone(),
                blast_db_prefix: result.report.blast_db_prefix.clone(),
                command: result.report.command.clone(),
                command_line: Self::format_blast_command_line(
                    &result.report.blastn_executable,
                    &result.report.command,
                ),
                catalog_path: self.genome_catalog_path_opt(),
                cache_dir: self.genome_cache_dir_opt(),
                options_override_json: result.report.options_override_json.clone(),
                effective_options_json: result.report.effective_options_json.clone(),
            }),
        };
        match self.engine.write().unwrap().apply(op) {
            Ok(result) => {
                self.genome_blast_status = Self::format_op_result_status(
                    &format!("Import BLAST hits to '{}': ok", seq_id),
                    &result.created_seq_ids,
                    &result.warnings,
                    &result.messages,
                );
            }
            Err(e) => {
                self.genome_blast_status = format!("Import BLAST hits failed: {}", e.message);
            }
        }
    }

    fn select_gene_record(&mut self, gene_index: usize) {
        let Some(gene) = self.genome_genes.get(gene_index) else {
            return;
        };
        self.genome_selected_gene = Some(gene_index);
        self.genome_chromosome = gene.chromosome.clone();
        self.genome_start_1based = gene.start_1based.to_string();
        self.genome_end_1based = gene.end_1based.to_string();
        self.genome_retrieve_contig_suggestions.clear();
        if self.genome_output_id.trim().is_empty() {
            self.genome_output_id = Self::default_retrieve_genome_output_id(&self.genome_id, gene);
        }
    }

    fn normalize_output_id_token(raw: &str) -> String {
        let mut out = String::new();
        let mut previous_underscore = false;
        for ch in raw.chars() {
            if ch.is_ascii_alphanumeric() {
                out.push(ch.to_ascii_lowercase());
                previous_underscore = false;
            } else if !previous_underscore {
                out.push('_');
                previous_underscore = true;
            }
        }
        let trimmed = out.trim_matches('_');
        if trimmed.is_empty() {
            "region".to_string()
        } else {
            trimmed.to_string()
        }
    }

    fn default_retrieve_genome_output_id(genome_id: &str, gene: &GenomeGeneRecord) -> String {
        let label = gene
            .gene_name
            .as_deref()
            .or(gene.gene_id.as_deref())
            .unwrap_or("gene");
        format!(
            "{}_{}_{}_{}",
            Self::normalize_output_id_token(genome_id),
            Self::normalize_output_id_token(label),
            gene.start_1based,
            gene.end_1based
        )
    }

    fn gene_record_matches_regex(gene: &GenomeGeneRecord, regex: &Regex) -> bool {
        gene.gene_name
            .as_ref()
            .map(|name| regex.is_match(name))
            .unwrap_or(false)
            || gene
                .gene_id
                .as_ref()
                .map(|id| regex.is_match(id))
                .unwrap_or(false)
            || regex.is_match(&gene.chromosome)
    }

    fn gene_record_matches_filter(gene: &GenomeGeneRecord, regex: Option<&Regex>) -> bool {
        if let Some(re) = regex {
            return Self::gene_record_matches_regex(gene, re);
        }
        true
    }

    fn gene_record_matches_biotype_filter(&self, gene: &GenomeGeneRecord) -> bool {
        if self.genome_biotype_filter.is_empty() {
            return true;
        }
        let Some(raw_biotype) = gene.biotype.as_ref() else {
            return true;
        };
        let biotype = raw_biotype.trim();
        if biotype.is_empty() {
            return true;
        }
        self.genome_biotype_filter
            .get(biotype)
            .copied()
            .unwrap_or(true)
    }

    fn gene_record_label(gene: &GenomeGeneRecord) -> String {
        let mut name = gene
            .gene_name
            .clone()
            .or(gene.gene_id.clone())
            .unwrap_or_else(|| "unnamed_gene".to_string());
        if let (Some(gene_name), Some(gene_id)) = (&gene.gene_name, &gene.gene_id) {
            if gene_name != gene_id {
                name = format!("{gene_name} ({gene_id})");
            }
        }
        let strand = gene
            .strand
            .map(|s| s.to_string())
            .unwrap_or_else(|| ".".to_string());
        let biotype = gene
            .biotype
            .as_ref()
            .map(|v| v.trim())
            .filter(|v| !v.is_empty())
            .unwrap_or("-");
        format!(
            "{}: {}:{}-{} ({}, {})",
            name, gene.chromosome, gene.start_1based, gene.end_1based, strand, biotype
        )
    }

    fn selected_gene_query_and_occurrence(&self) -> Option<(String, usize)> {
        let selected_idx = self.genome_selected_gene?;
        let selected_gene = self.genome_genes.get(selected_idx)?;
        let query = selected_gene
            .gene_id
            .as_ref()
            .or(selected_gene.gene_name.as_ref())
            .cloned()?;
        let mut occurrence = 0usize;
        for (idx, gene) in self.genome_genes.iter().enumerate() {
            let matches_query = gene
                .gene_id
                .as_ref()
                .map(|id| id.eq_ignore_ascii_case(&query))
                .unwrap_or(false)
                || gene
                    .gene_name
                    .as_ref()
                    .map(|name| name.eq_ignore_ascii_case(&query))
                    .unwrap_or(false);
            if matches_query {
                occurrence += 1;
            }
            if idx == selected_idx {
                break;
            }
        }
        if occurrence == 0 {
            None
        } else {
            Some((query, occurrence))
        }
    }

    fn filtered_gene_candidate_indices(&self) -> (Vec<usize>, bool, Option<String>) {
        let limit = self.genome_gene_filter_limit.max(1);
        let mut indices: Vec<usize> = Vec::with_capacity(limit.min(2048));
        let mut overflow = false;
        let needle = self.genome_gene_filter.trim();
        let regex = if needle.is_empty() {
            None
        } else {
            match RegexBuilder::new(needle).case_insensitive(true).build() {
                Ok(re) => Some(re),
                Err(e) => {
                    return (vec![], false, Some(format!("Invalid regex: {e}")));
                }
            }
        };
        for (idx, gene) in self.genome_genes.iter().enumerate() {
            if Self::gene_record_matches_filter(gene, regex.as_ref())
                && self.gene_record_matches_biotype_filter(gene)
            {
                if indices.len() < limit {
                    indices.push(idx);
                } else {
                    overflow = true;
                    break;
                }
            }
        }
        (indices, overflow, None)
    }

    fn normalize_coordinate_field(value: &mut String) {
        value.retain(|ch| ch.is_ascii_digit());
        if value.len() > 10 {
            value.truncate(10);
        }
    }

    fn sync_genome_annotation_scope_controls(&mut self) {
        if !self.genome_include_genomic_annotation {
            self.genome_annotation_scope = GenomeAnnotationScope::None;
        } else if matches!(self.genome_annotation_scope, GenomeAnnotationScope::None) {
            self.genome_annotation_scope = GenomeAnnotationScope::Core;
        }
    }

    fn extract_reference_genome_gene(&mut self) {
        let genome_id = self.genome_id.trim().to_string();
        if genome_id.is_empty() {
            self.genome_retrieve_status = "Select a genome first".to_string();
            self.genome_retrieve_contig_suggestions.clear();
            return;
        }
        let Some((gene_query, occurrence)) = self.selected_gene_query_and_occurrence() else {
            self.genome_retrieve_status =
                "Select a gene with a gene_id or gene_name first".to_string();
            self.genome_retrieve_contig_suggestions.clear();
            return;
        };
        let output_id = if self.genome_output_id.trim().is_empty() {
            None
        } else {
            Some(self.genome_output_id.trim().to_string())
        };
        self.sync_genome_annotation_scope_controls();
        let annotation_scope = self.genome_annotation_scope;
        let max_annotation_features = if self.genome_max_annotation_features.trim().is_empty() {
            None
        } else {
            match self.genome_max_annotation_features.trim().parse::<usize>() {
                Ok(parsed) => Some(parsed),
                Err(_) => {
                    self.genome_retrieve_status = "max annotation features must be a non-negative integer (empty = unlimited)".to_string();
                    self.genome_retrieve_contig_suggestions.clear();
                    return;
                }
            }
        };
        let op = Operation::ExtractGenomeGene {
            genome_id,
            gene_query,
            occurrence: Some(occurrence),
            output_id,
            annotation_scope: Some(annotation_scope),
            max_annotation_features,
            include_genomic_annotation: Some(self.genome_include_genomic_annotation),
            catalog_path: self.genome_catalog_path_opt(),
            cache_dir: self.genome_cache_dir_opt(),
        };
        let chromosome_for_suggestions = self.genome_chromosome.trim().to_string();
        let result = { self.engine.write().unwrap().apply(op) };
        match result {
            Ok(r) => {
                for seq_id in &r.created_seq_ids {
                    self.open_sequence_window(seq_id);
                }
                self.genome_retrieve_status = Self::format_op_result_status(
                    "Extract gene: ok",
                    &r.created_seq_ids,
                    &r.warnings,
                    &r.messages,
                );
                self.genome_retrieve_contig_suggestions.clear();
            }
            Err(e) => {
                self.genome_retrieve_status = format!("Extract gene failed: {}", e.message);
                self.update_retrieve_contig_suggestions_from_error(
                    &chromosome_for_suggestions,
                    &e.message,
                );
            }
        }
    }

    fn extract_reference_genome_region(&mut self) {
        let genome_id = self.genome_id.trim().to_string();
        if genome_id.is_empty() {
            self.genome_retrieve_status = "Select a genome first".to_string();
            self.genome_retrieve_contig_suggestions.clear();
            return;
        }
        let chromosome = self.genome_chromosome.trim().to_string();
        if chromosome.is_empty() {
            self.genome_retrieve_status = "Chromosome cannot be empty".to_string();
            self.genome_retrieve_contig_suggestions.clear();
            return;
        }
        let (start_1based, end_1based) = match (
            self.genome_start_1based.trim().parse::<usize>(),
            self.genome_end_1based.trim().parse::<usize>(),
        ) {
            (Ok(start), Ok(end)) if start > 0 && end >= start => (start, end),
            _ => {
                self.genome_retrieve_status =
                    "Invalid interval; require start >= 1 and end >= start".to_string();
                self.genome_retrieve_contig_suggestions.clear();
                return;
            }
        };
        let output_id = if self.genome_output_id.trim().is_empty() {
            None
        } else {
            Some(self.genome_output_id.trim().to_string())
        };
        self.sync_genome_annotation_scope_controls();
        let annotation_scope = self.genome_annotation_scope;
        let max_annotation_features = if self.genome_max_annotation_features.trim().is_empty() {
            None
        } else {
            match self.genome_max_annotation_features.trim().parse::<usize>() {
                Ok(parsed) => Some(parsed),
                Err(_) => {
                    self.genome_retrieve_status = "max annotation features must be a non-negative integer (empty = unlimited)".to_string();
                    self.genome_retrieve_contig_suggestions.clear();
                    return;
                }
            }
        };
        let catalog_path = self.genome_catalog_path_opt();
        let extract_op = Operation::ExtractGenomeRegion {
            genome_id: genome_id.clone(),
            chromosome: chromosome.clone(),
            start_1based,
            end_1based,
            output_id,
            annotation_scope: Some(annotation_scope),
            max_annotation_features,
            include_genomic_annotation: Some(self.genome_include_genomic_annotation),
            catalog_path,
            cache_dir: self.genome_cache_dir_opt(),
        };
        let result = { self.engine.write().unwrap().apply(extract_op) };
        match result {
            Ok(r) => {
                for seq_id in &r.created_seq_ids {
                    self.open_sequence_window(seq_id);
                }
                self.genome_retrieve_status = Self::format_extract_region_status(&r);
                self.genome_retrieve_contig_suggestions.clear();
            }
            Err(e) => {
                self.genome_retrieve_status = format!("Extract region failed: {}", e.message);
                self.update_retrieve_contig_suggestions_from_error(&chromosome, &e.message);
            }
        }
    }

    fn uniprot_optional_trimmed(value: &str) -> Option<String> {
        let trimmed = value.trim();
        if trimmed.is_empty() {
            None
        } else {
            Some(trimmed.to_string())
        }
    }

    fn fetch_genbank_accession_from_dialog(&mut self) {
        let accession = self.genbank_accession.trim().to_string();
        if accession.is_empty() {
            self.genbank_status = "GenBank accession cannot be empty".to_string();
            return;
        }
        let op = Operation::FetchGenBankAccession {
            accession: accession.clone(),
            as_id: Self::uniprot_optional_trimmed(&self.genbank_as_id),
        };
        let result = { self.engine.write().unwrap().apply(op) };
        match result {
            Ok(result) => {
                for seq_id in &result.created_seq_ids {
                    self.open_sequence_window(seq_id);
                }
                if self.genbank_as_id.trim().is_empty() {
                    self.genbank_as_id = accession;
                }
                self.genbank_status = Self::format_op_result_status(
                    "GenBank fetch: ok",
                    &result.created_seq_ids,
                    &result.warnings,
                    &result.messages,
                );
            }
            Err(err) => {
                self.genbank_status = format!("GenBank fetch failed: {}", err.message);
            }
        }
    }

    fn sort_uniprot_entries_recent(mut rows: Vec<UniprotEntrySummary>) -> Vec<UniprotEntrySummary> {
        rows.sort_by(|left, right| {
            right
                .imported_at_unix_ms
                .cmp(&left.imported_at_unix_ms)
                .then_with(|| left.entry_id.cmp(&right.entry_id))
        });
        rows
    }

    fn recent_uniprot_entries_for_dialog(&self, limit: usize) -> Vec<UniprotEntrySummary> {
        let rows = self.engine.read().unwrap().list_uniprot_entries();
        let mut rows = Self::sort_uniprot_entries_recent(rows);
        let cap = limit.max(1);
        if rows.len() > cap {
            rows.truncate(cap);
        }
        rows
    }

    fn fetch_uniprot_entry_from_dialog(&mut self) {
        let query = self.uniprot_query.trim().to_string();
        if query.is_empty() {
            self.uniprot_status = "UniProt query cannot be empty".to_string();
            return;
        }
        let op = Operation::FetchUniprotSwissProt {
            query: query.clone(),
            entry_id: Self::uniprot_optional_trimmed(&self.uniprot_entry_id),
        };
        match self.engine.write().unwrap().apply(op) {
            Ok(result) => {
                if self.uniprot_entry_id.trim().is_empty() {
                    self.uniprot_entry_id = query;
                }
                self.uniprot_status = Self::format_op_result_status(
                    "UniProt fetch: ok",
                    &result.created_seq_ids,
                    &result.warnings,
                    &result.messages,
                );
            }
            Err(err) => {
                self.uniprot_status = format!("UniProt fetch failed: {}", err.message);
            }
        }
    }

    fn import_uniprot_swiss_prot_from_dialog(&mut self) {
        let path = self.uniprot_swiss_path.trim().to_string();
        if path.is_empty() {
            self.uniprot_status = "SWISS-PROT file path cannot be empty".to_string();
            return;
        }
        let op = Operation::ImportUniprotSwissProt {
            path,
            entry_id: Self::uniprot_optional_trimmed(&self.uniprot_entry_id),
        };
        match self.engine.write().unwrap().apply(op) {
            Ok(result) => {
                self.uniprot_status = Self::format_op_result_status(
                    "UniProt import: ok",
                    &result.created_seq_ids,
                    &result.warnings,
                    &result.messages,
                );
            }
            Err(err) => {
                self.uniprot_status = format!("UniProt import failed: {}", err.message);
            }
        }
    }

    fn fetch_uniprot_linked_genbank_from_dialog(&mut self) {
        let entry_id = self.uniprot_entry_id.trim().to_string();
        if entry_id.is_empty() {
            self.uniprot_status = "entry_id is required for linked GenBank fetch".to_string();
            return;
        }
        let op = Operation::FetchUniprotLinkedGenBank {
            entry_id,
            accession: Self::uniprot_optional_trimmed(&self.uniprot_linked_accession),
            as_id: Self::uniprot_optional_trimmed(&self.uniprot_linked_as_id),
        };
        let result = { self.engine.write().unwrap().apply(op) };
        match result {
            Ok(result) => {
                for seq_id in &result.created_seq_ids {
                    self.open_sequence_window(seq_id);
                }
                if let Some(seq_id) = result.created_seq_ids.first() {
                    self.uniprot_map_seq_id = seq_id.clone();
                }
                self.uniprot_status = Self::format_op_result_status(
                    "UniProt linked GenBank fetch: ok",
                    &result.created_seq_ids,
                    &result.warnings,
                    &result.messages,
                );
            }
            Err(err) => {
                self.uniprot_status =
                    format!("UniProt linked GenBank fetch failed: {}", err.message);
            }
        }
    }

    fn project_uniprot_entry_from_dialog(&mut self) {
        let entry_id = self.uniprot_entry_id.trim().to_string();
        if entry_id.is_empty() {
            self.uniprot_status = "entry_id is required for projection".to_string();
            return;
        }
        let seq_ids = self.project_sequence_ids_for_blast();
        if seq_ids.is_empty() {
            self.uniprot_status =
                "No sequence is loaded. Load/import sequence data before mapping.".to_string();
            return;
        }
        let seq_id = if self.uniprot_map_seq_id.trim().is_empty() {
            seq_ids[0].clone()
        } else {
            self.uniprot_map_seq_id.trim().to_string()
        };
        if !seq_ids.iter().any(|candidate| candidate == &seq_id) {
            self.uniprot_status = format!(
                "Sequence '{}' is not available anymore; pick an existing sequence",
                seq_id
            );
            return;
        }
        self.uniprot_map_seq_id = seq_id.clone();
        let op = Operation::ProjectUniprotToGenome {
            seq_id,
            entry_id,
            projection_id: Self::uniprot_optional_trimmed(&self.uniprot_map_projection_id),
            transcript_id: Self::uniprot_optional_trimmed(&self.uniprot_map_transcript_id),
        };
        match self.engine.write().unwrap().apply(op) {
            Ok(result) => {
                self.uniprot_status = Self::format_op_result_status(
                    "UniProt projection: ok",
                    &result.created_seq_ids,
                    &result.warnings,
                    &result.messages,
                );
            }
            Err(err) => {
                self.uniprot_status = format!("UniProt projection failed: {}", err.message);
            }
        }
    }

    fn render_genbank_dialog(&mut self, ctx: &egui::Context) {
        if !self.show_genbank_dialog {
            return;
        }
        let mut open = self.show_genbank_dialog;
        let mut close_requested = false;
        egui::Window::new("GenBank Accession Fetch")
            .open(&mut open)
            .collapsible(false)
            .resizable(true)
            .default_size(Vec2::new(760.0, 240.0))
            .min_size(Vec2::new(640.0, 220.0))
            .show(ctx, |ui| {
                ui.horizontal(|ui| {
                    if ui
                        .button("Help")
                        .on_hover_text("Open GUI help and bring it to the front")
                        .clicked()
                    {
                        self.open_help_doc(HelpDoc::Gui);
                    }
                    if ui
                        .button("Close")
                        .on_hover_text("Close this GenBank window (Cmd/Ctrl+W)")
                        .clicked()
                    {
                        close_requested = true;
                    }
                });
                ui.separator();
                ui.label(
                    "Fetch one GenBank accession through NCBI EFetch and import it as a project sequence.",
                );
                ui.horizontal(|ui| {
                    ui.label("accession");
                    ui.text_edit_singleline(&mut self.genbank_accession)
                        .on_hover_text("GenBank accession (for example AY738222 or NC_000001)");
                    if ui
                        .button("Fetch")
                        .on_hover_text("Fetch accession and import sequence into the project")
                        .clicked()
                    {
                        self.fetch_genbank_accession_from_dialog();
                    }
                });
                ui.horizontal(|ui| {
                    ui.label("as_id");
                    ui.text_edit_singleline(&mut self.genbank_as_id).on_hover_text(
                        "Optional project sequence id override (auto-uses accession when empty)",
                    );
                });
                ui.small("Examples: AY738222, NC_000001");
                ui.small(
                    "If network fetch is unavailable, use File -> Open Sequence... with a local GenBank file.",
                );
                if !self.genbank_status.trim().is_empty() {
                    ui.separator();
                    ui.monospace(self.genbank_status.clone());
                }
            });
        if close_requested {
            open = false;
        }
        if Self::viewport_close_requested_or_shortcut(ctx) {
            open = false;
        }
        self.show_genbank_dialog = open;
    }

    fn render_uniprot_dialog_contents(&mut self, ui: &mut Ui) {
        let seq_ids = self.project_sequence_ids_for_blast();
        if !seq_ids.is_empty() {
            let selected = self.uniprot_map_seq_id.trim();
            if selected.is_empty() || !seq_ids.iter().any(|candidate| candidate == selected) {
                self.uniprot_map_seq_id = seq_ids[0].clone();
            }
        }

        ui.horizontal(|ui| {
            if ui
                .button("Help")
                .on_hover_text("Open GUI help and bring it to the front")
                .clicked()
            {
                self.open_help_doc(HelpDoc::Gui);
            }
            if ui
                .button("Close")
                .on_hover_text("Close this UniProt window (Cmd/Ctrl+W)")
                .clicked()
            {
                self.show_uniprot_dialog = false;
            }
        });
        ui.separator();
        ui.label(
            "Fetch/import UniProt SWISS-PROT entries and project annotated features onto transcript/CDS coordinates.",
        );
        ui.horizontal(|ui| {
            ui.label("entry_id");
            ui.text_edit_singleline(&mut self.uniprot_entry_id)
                .on_hover_text("Stable entry identifier in this project (used by projection)");
        });
        ui.small(
            "Optional override for fetch/import. Required for projection; if empty after fetch, query is used.",
        );
        ui.small(
            "Protein sequence import into DNA windows is intentionally disabled in this release.",
        );
        ui.separator();
        ui.label("Online fetch");
        ui.horizontal(|ui| {
            ui.label("query");
            ui.text_edit_singleline(&mut self.uniprot_query)
                .on_hover_text(
                    "UniProt accession or entry ID to fetch (for example P04637 or TP53_HUMAN)",
                );
            if ui
                .button("Fetch")
                .on_hover_text("Fetch UniProt SWISS-PROT text by accession or UniProt entry ID")
                .clicked()
            {
                self.fetch_uniprot_entry_from_dialog();
            }
        });
        ui.small("Examples: P04637, TP53_HUMAN");
        ui.separator();
        ui.label("Offline import (SWISS-PROT text)");
        ui.horizontal(|ui| {
            ui.label("path");
            ui.text_edit_singleline(&mut self.uniprot_swiss_path)
                .on_hover_text("Local path to a SWISS-PROT text file (.txt/.dat)");
            if ui
                .button("Browse...")
                .on_hover_text("Pick a local SWISS-PROT text file")
                .clicked()
            {
                if let Some(path) = rfd::FileDialog::new()
                    .add_filter("SWISS-PROT text", &["txt", "dat"])
                    .add_filter("Text", &["txt"])
                    .pick_file()
                {
                    self.uniprot_swiss_path = path.display().to_string();
                }
            }
            if ui
                .button("Import")
                .on_hover_text("Import local SWISS-PROT text into project metadata")
                .clicked()
            {
                self.import_uniprot_swiss_prot_from_dialog();
            }
        });
        ui.separator();
        ui.label("Project entry to sequence");
        if seq_ids.is_empty() {
            ui.colored_label(
                egui::Color32::from_rgb(190, 70, 70),
                "No project sequence available. Load/import one first.",
            );
            ui.horizontal(|ui| {
                ui.label("seq_id");
                ui.text_edit_singleline(&mut self.uniprot_map_seq_id)
                    .on_hover_text("Target sequence ID for projection (must exist in project)");
            });
        } else {
            egui::ComboBox::from_label("seq_id")
                .selected_text(self.uniprot_map_seq_id.clone())
                .show_ui(ui, |ui| {
                    for seq_id in &seq_ids {
                        ui.selectable_value(&mut self.uniprot_map_seq_id, seq_id.clone(), seq_id);
                    }
                })
                .response
                .on_hover_text("Select the target sequence for UniProt projection");
        }
        ui.horizontal(|ui| {
            ui.label("projection_id");
            ui.text_edit_singleline(&mut self.uniprot_map_projection_id)
                .on_hover_text("Optional projection record ID (auto-generated when empty)");
            ui.label("transcript");
            ui.text_edit_singleline(&mut self.uniprot_map_transcript_id)
                .on_hover_text("Optional transcript filter (for example ENST... )");
        });
        if ui
            .button("Project To Sequence")
            .on_hover_text(
                "Map UniProt feature intervals through transcript/CDS onto genomic coordinates",
            )
            .clicked()
        {
            self.project_uniprot_entry_from_dialog();
        }
        ui.separator();
        ui.label("Linked nucleotide retrieval (EMBL/GenBank crossref)");
        ui.horizontal(|ui| {
            ui.label("accession");
            ui.text_edit_singleline(&mut self.uniprot_linked_accession)
                .on_hover_text(
                    "Optional accession override (empty = auto from UniProt DR EMBL/GenBank)",
                );
            ui.label("as_id");
            ui.text_edit_singleline(&mut self.uniprot_linked_as_id)
                .on_hover_text("Optional project sequence id override");
            if ui
                .button("Fetch Linked GenBank")
                .on_hover_text("Fetch nucleotide entry linked from UniProt and import as sequence")
                .clicked()
            {
                self.fetch_uniprot_linked_genbank_from_dialog();
            }
        });
        ui.separator();
        let recent_entries = self.recent_uniprot_entries_for_dialog(12);
        ui.label(format!(
            "Recent imported entries ({})",
            recent_entries.len()
        ));
        if recent_entries.is_empty() {
            ui.small("No UniProt entries imported in this project yet.");
        } else {
            egui::ScrollArea::vertical()
                .max_height(180.0)
                .show(ui, |ui| {
                    scroll_input_policy::apply_scrollarea_keyboard_navigation(
                        ui,
                        scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                    );
                    egui::Grid::new("uniprot_recent_entries_grid")
                        .striped(true)
                        .show(ui, |ui| {
                            ui.strong("entry_id");
                            ui.strong("accession");
                            ui.strong("primary_id");
                            ui.strong("AA");
                            ui.strong("imported_ms");
                            ui.strong("source");
                            ui.strong("action");
                            ui.end_row();
                            for row in recent_entries.iter() {
                                ui.monospace(&row.entry_id);
                                ui.monospace(&row.accession);
                                ui.label(&row.primary_id);
                                ui.label(row.sequence_length.to_string());
                                ui.label(row.imported_at_unix_ms.to_string());
                                ui.label(&row.source);
                                if ui
                                    .small_button("Select")
                                    .on_hover_text(
                                        "Use this row as the active entry_id for projection",
                                    )
                                    .clicked()
                                {
                                    self.uniprot_entry_id = row.entry_id.clone();
                                    if self.uniprot_query.trim().is_empty()
                                        && !row.accession.trim().is_empty()
                                    {
                                        self.uniprot_query = row.accession.clone();
                                    }
                                }
                                ui.end_row();
                            }
                        });
                });
        }
        if !self.uniprot_status.trim().is_empty() {
            ui.separator();
            ui.monospace(self.uniprot_status.clone());
        }
    }

    fn render_uniprot_dialog(&mut self, ctx: &egui::Context) {
        if !self.show_uniprot_dialog {
            return;
        }

        let builder = egui::ViewportBuilder::default()
            .with_title("UniProt Mapping")
            .with_inner_size([940.0, 520.0])
            .with_min_inner_size([780.0, 420.0]);
        ctx.show_viewport_immediate(Self::uniprot_viewport_id(), builder, |ctx, class| {
            self.note_viewport_focus_if_active(ctx, Self::uniprot_viewport_id());
            if class == egui::ViewportClass::Embedded {
                let mut open = self.show_uniprot_dialog;
                egui::Window::new("UniProt Mapping")
                    .open(&mut open)
                    .collapsible(false)
                    .resizable(true)
                    .default_size(Vec2::new(940.0, 520.0))
                    .min_size(Vec2::new(780.0, 420.0))
                    .show(ctx, |ui| {
                        self.render_uniprot_dialog_contents(ui);
                    });
                self.show_uniprot_dialog = open;
                return;
            }

            egui::CentralPanel::default().show(ctx, |ui| {
                self.render_uniprot_dialog_contents(ui);
            });

            if Self::viewport_close_requested_or_shortcut(ctx) {
                self.show_uniprot_dialog = false;
            }
        });
    }

    fn render_reference_genome_prepare_contents(&mut self, ui: &mut Ui) {
        self.refresh_genome_catalog_list();
        self.render_specialist_window_nav(ui);
        let scope = self.genome_dialog_scope;
        ui.label(format!(
            "Download and index a {} once.",
            scope.description()
        ));
        ui.horizontal(|ui| {
            ui.label("catalog");
            ui.text_edit_singleline(&mut self.genome_catalog_path);
            if ui
                .button("Browse...")
                .on_hover_text("Browse filesystem and fill this path")
                .clicked()
            {
                if let Some(path) = rfd::FileDialog::new()
                    .add_filter("JSON", &["json"])
                    .pick_file()
                {
                    self.genome_catalog_path = path.display().to_string();
                }
            }
        });
        ui.horizontal(|ui| {
            ui.label("cache_dir");
            ui.text_edit_singleline(&mut self.genome_cache_dir);
            if ui
                .button("Browse...")
                .on_hover_text("Browse filesystem and fill this path")
                .clicked()
            {
                if let Some(path) = rfd::FileDialog::new().pick_folder() {
                    self.genome_cache_dir = path.display().to_string();
                }
            }
        });
        ui.horizontal(|ui| {
            ui.label("timeout_sec");
            ui.add(
                egui::TextEdit::singleline(&mut self.genome_prepare_timeout_secs)
                    .desired_width(90.0),
            );
            ui.small("optional; empty or 0 means no timebox");
        });
        if !self.genome_catalog_error.is_empty() {
            ui.colored_label(
                egui::Color32::from_rgb(190, 70, 70),
                format!("Catalog error: {}", self.genome_catalog_error),
            );
        }
        let all_genomes = self.genome_catalog_genomes.clone();
        let preparable_genomes = match self.unprepared_genomes_for_prepare_dialog() {
            Ok(names) => names,
            Err(e) => {
                ui.colored_label(
                    egui::Color32::from_rgb(190, 70, 70),
                    format!("Prepared-state check error: {e}"),
                );
                vec![]
            }
        };
        let preparable_set: HashSet<String> = preparable_genomes.iter().cloned().collect();
        let mut selection_changed = false;
        let selected_text = if self.genome_id.trim().is_empty() {
            "Select genome".to_string()
        } else {
            self.genome_id.clone()
        };
        egui::ComboBox::from_label("genome")
            .selected_text(selected_text)
            .show_ui(ui, |ui| {
                for genome_name in &all_genomes {
                    let is_preparable = preparable_set.contains(genome_name);
                    let item_label = if is_preparable {
                        genome_name.clone()
                    } else {
                        format!("{genome_name} (already prepared)")
                    };
                    ui.add_enabled_ui(is_preparable, |ui| {
                        if ui
                            .selectable_label(self.genome_id == *genome_name, item_label)
                            .clicked()
                        {
                            self.genome_id = genome_name.clone();
                            selection_changed = true;
                            ui.close();
                        }
                    });
                }
            });
        if selection_changed {
            self.invalidate_genome_genes();
        }
        match self.selected_genome_source_plan() {
            Ok(Some(plan)) => {
                ui.small(Self::format_genome_source_plan_summary(&plan));
            }
            Ok(None) => {}
            Err(e) => {
                ui.colored_label(
                    egui::Color32::from_rgb(190, 70, 70),
                    format!("Source-plan error: {e}"),
                );
            }
        }
        if preparable_genomes.is_empty() {
            ui.label("All genomes in this catalog are already prepared.");
        }
        let selected_preparable = preparable_genomes.iter().any(|n| n == &self.genome_id);
        if !self.genome_id.trim().is_empty() && !selected_preparable {
            ui.label("Selected genome is already prepared and cannot be selected here.");
        }
        let running = self.genome_prepare_task.is_some();
        if let Some(task) = &self.genome_prepare_task {
            ui.horizontal(|ui| {
                ui.add(egui::Spinner::new());
                let mut status = format!(
                    "Prepare task running ({:.1}s)",
                    task.started.elapsed().as_secs_f32()
                );
                if let Some(timeout) = task.timeout_seconds {
                    status.push_str(&format!(", timeout={}s", timeout));
                }
                if task.cancel_requested.load(Ordering::Relaxed) {
                    status.push_str(", cancellation requested");
                }
                ui.label(status);
            });
        }
        ui.horizontal(|ui| {
            if ui
                .add_enabled(
                    !running && selected_preparable,
                    egui::Button::new("Prepare Genome"),
                )
                .on_hover_text(format!(
                    "Download and index the selected {}",
                    scope.description()
                ))
                .clicked()
            {
                self.start_prepare_reference_genome();
            }
            if ui
                .button("Close")
                .on_hover_text("Close this dialog")
                .clicked()
            {
                self.show_reference_genome_prepare_dialog = false;
            }
            if self.genome_prepare_task.is_some() {
                if ui
                    .button("Cancel Prepare")
                    .on_hover_text("Request cancellation of the running prepare task.")
                    .clicked()
                {
                    self.request_prepare_task_cancel("prepare dialog");
                }
            }
        });
        if let Some(progress) = &self.genome_prepare_progress {
            let fraction = progress
                .percent
                .map(|p| (p / 100.0) as f32)
                .or_else(|| {
                    progress.bytes_total.and_then(|total| {
                        if total == 0 {
                            None
                        } else {
                            Some((progress.bytes_done as f32 / total as f32).clamp(0.0, 1.0))
                        }
                    })
                })
                .unwrap_or(0.0);
            ui.add(
                egui::ProgressBar::new(fraction)
                    .show_percentage()
                    .text(format!("{}: {}", progress.phase, progress.item)),
            );
            let bytes_total = progress
                .bytes_total
                .map(|b| b.to_string())
                .unwrap_or_else(|| "?".to_string());
            ui.label(format!("bytes: {} / {}", progress.bytes_done, bytes_total));
        }
        if !self.genome_prepare_status.is_empty() {
            ui.separator();
            ui.monospace(&self.genome_prepare_status);
        }
    }

    fn render_reference_genome_prepare_dialog(&mut self, ctx: &egui::Context) {
        if !self.show_reference_genome_prepare_dialog {
            return;
        }
        let title = self.genome_dialog_scope.prepare_title();

        let builder = egui::ViewportBuilder::default()
            .with_title(title)
            .with_inner_size([760.0, 560.0])
            .with_min_inner_size([520.0, 360.0]);
        ctx.show_viewport_immediate(Self::prepare_genome_viewport_id(), builder, |ctx, class| {
            self.note_viewport_focus_if_active(ctx, Self::prepare_genome_viewport_id());
            if class == egui::ViewportClass::Embedded {
                let mut open = self.show_reference_genome_prepare_dialog;
                egui::Window::new(title)
                    .open(&mut open)
                    .collapsible(false)
                    .resizable(true)
                    .default_size(Vec2::new(760.0, 560.0))
                    .show(ctx, |ui| {
                        self.render_reference_genome_prepare_contents(ui);
                    });
                self.show_reference_genome_prepare_dialog = open;
                return;
            }

            egui::CentralPanel::default().show(ctx, |ui| {
                self.render_reference_genome_prepare_contents(ui);
            });

            if Self::viewport_close_requested_or_shortcut(ctx) {
                self.show_reference_genome_prepare_dialog = false;
            }
        });
    }

    fn render_reference_genome_retrieve_contents(&mut self, ui: &mut Ui) {
        ui.push_id("retrieve_genome_dialog_contents", |ui| {
            let scope = self.genome_dialog_scope;
            self.render_specialist_window_nav(ui);
            ui.label(format!(
                "Retrieve region sequences from a prepared {}.",
                scope.description()
            ));
            ui.horizontal(|ui| {
                ui.label("catalog");
                ui.text_edit_singleline(&mut self.genome_catalog_path);
                if ui
                    .button("Browse...")
                    .on_hover_text("Browse filesystem and fill this path")
                    .clicked()
                {
                    if let Some(path) = rfd::FileDialog::new()
                        .add_filter("JSON", &["json"])
                        .pick_file()
                    {
                        self.genome_catalog_path = path.display().to_string();
                    }
                }
            });
            ui.horizontal(|ui| {
                ui.label("cache_dir");
                ui.text_edit_singleline(&mut self.genome_cache_dir);
                if ui
                    .button("Browse...")
                    .on_hover_text("Browse filesystem and fill this path")
                    .clicked()
                {
                    if let Some(path) = rfd::FileDialog::new().pick_folder() {
                        self.genome_cache_dir = path.display().to_string();
                    }
                }
            });
            if !self.genome_catalog_error.is_empty() {
                ui.colored_label(
                    egui::Color32::from_rgb(190, 70, 70),
                    format!("Catalog error: {}", self.genome_catalog_error),
                );
            }
            let prepared_genomes = match self.prepared_genomes_for_retrieve_dialog() {
                Ok(names) => names,
                Err(e) => {
                    ui.colored_label(
                        egui::Color32::from_rgb(190, 70, 70),
                        format!("Prepared-state check error: {e}"),
                    );
                    vec![]
                }
            };
            if !prepared_genomes.is_empty() && !prepared_genomes.contains(&self.genome_id) {
                self.genome_id = prepared_genomes[0].clone();
                self.invalidate_genome_genes();
            }
            let selection_changed =
                Self::choose_genome_from_catalog(ui, &mut self.genome_id, &prepared_genomes);
            if selection_changed {
                self.invalidate_genome_genes();
            }
            match self.selected_genome_source_plan() {
                Ok(Some(plan)) => {
                    ui.small(Self::format_genome_source_plan_summary(&plan));
                }
                Ok(None) => {}
                Err(e) => {
                    ui.colored_label(
                        egui::Color32::from_rgb(190, 70, 70),
                        format!("Source-plan error: {e}"),
                    );
                }
            }
            if prepared_genomes.is_empty() {
                ui.label(scope.empty_prepared_hint());
            } else {
                self.ensure_genome_genes_loaded();
                if !self.genome_genes_error.is_empty() {
                    ui.colored_label(
                        egui::Color32::from_rgb(190, 70, 70),
                        format!("Gene index error: {}", self.genome_genes_error),
                    );
                }
                ui.separator();
                ui.horizontal(|ui| {
                    ui.label("Gene filter");
                    let response = ui.text_edit_singleline(&mut self.genome_gene_filter);
                    if response.changed() {
                        self.genome_gene_filter_page = 0;
                    }
                    if ui
                        .button("Clear")
                        .on_hover_text("Clear the gene filter text")
                        .clicked()
                    {
                        self.genome_gene_filter.clear();
                        self.genome_gene_filter_page = 0;
                    }
                });
                ui.small("Supports case-insensitive regex (for example: ^TP53$).");
                ui.horizontal(|ui| {
                    ui.label("Top matches");
                    if ui
                        .add(
                            egui::DragValue::new(&mut self.genome_gene_filter_limit)
                                .speed(100.0)
                                .range(100..=100_000),
                        )
                        .changed()
                    {
                        self.genome_gene_filter_page = 0;
                    }
                });
                if !self.genome_biotype_filter.is_empty() {
                    ui.separator();
                    ui.label("Biotype filter");
                    ui.horizontal(|ui| {
                        if ui
                            .button("All")
                            .on_hover_text("Enable all biotypes")
                            .clicked()
                        {
                            for enabled in self.genome_biotype_filter.values_mut() {
                                *enabled = true;
                            }
                            self.genome_gene_filter_page = 0;
                        }
                        if ui
                            .button("None")
                            .on_hover_text("Disable all biotypes")
                            .clicked()
                        {
                            for enabled in self.genome_biotype_filter.values_mut() {
                                *enabled = false;
                            }
                            self.genome_gene_filter_page = 0;
                        }
                    });
                    let mut biotypes: Vec<String> =
                        self.genome_biotype_filter.keys().cloned().collect();
                    biotypes.sort();
                    egui::ScrollArea::vertical()
                        .id_salt("retrieve_genome_biotype_scroll")
                        .max_height(120.0)
                        .show(ui, |ui| {
                            scroll_input_policy::apply_scrollarea_keyboard_navigation(
                                ui,
                                scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                            );
                            for biotype in biotypes {
                                if let Some(enabled) = self.genome_biotype_filter.get_mut(&biotype)
                                {
                                    if ui.checkbox(enabled, &biotype).changed() {
                                        self.genome_gene_filter_page = 0;
                                    }
                                }
                            }
                        });
                }
                let (filtered_indices, overflow, regex_error) = self.filtered_gene_candidate_indices();
                if let Some(error) = regex_error {
                    ui.colored_label(egui::Color32::from_rgb(190, 70, 70), error);
                }
                const GENE_PAGE_SIZE: usize = 100;
                let page_count =
                    ((filtered_indices.len() + GENE_PAGE_SIZE - 1) / GENE_PAGE_SIZE).max(1);
                if self.genome_gene_filter_page >= page_count {
                    self.genome_gene_filter_page = page_count.saturating_sub(1);
                }
                let page_start = self.genome_gene_filter_page * GENE_PAGE_SIZE;
                let page_end = (page_start + GENE_PAGE_SIZE).min(filtered_indices.len());
                let shown_note = if overflow {
                    format!(" (limited to top {} matches)", self.genome_gene_filter_limit)
                } else {
                    String::new()
                };
                ui.label(format!(
                    "Genes: {} candidate{} / {} total",
                    filtered_indices.len(),
                    shown_note,
                    self.genome_genes.len()
                ));
                ui.horizontal(|ui| {
                    if ui
                        .add_enabled(
                            self.genome_gene_filter_page > 0,
                            egui::Button::new("Prev"),
                        )
                        .on_hover_text("Show previous page of gene matches")
                        .clicked()
                    {
                        self.genome_gene_filter_page -= 1;
                    }
                    ui.label(format!(
                        "Page {}/{}",
                        self.genome_gene_filter_page + 1,
                        page_count
                    ));
                    if ui
                        .add_enabled(
                            self.genome_gene_filter_page + 1 < page_count,
                            egui::Button::new("Next"),
                        )
                        .on_hover_text("Show next page of gene matches")
                        .clicked()
                    {
                        self.genome_gene_filter_page += 1;
                    }
                });
                egui::ScrollArea::vertical()
                    .id_salt("retrieve_genome_gene_list_scroll")
                    .max_height(220.0)
                    .show(ui, |ui| {
                        scroll_input_policy::apply_scrollarea_keyboard_navigation(
                            ui,
                            scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                        );
                        for idx in filtered_indices
                            .iter()
                            .copied()
                            .skip(page_start)
                            .take(page_end.saturating_sub(page_start))
                        {
                            let label = Self::gene_record_label(&self.genome_genes[idx]);
                            let selected = self.genome_selected_gene == Some(idx);
                            if ui.selectable_label(selected, label).clicked() {
                                self.select_gene_record(idx);
                            }
                        }
                    });
                ui.separator();
                ui.horizontal(|ui| {
                    ui.label("chr");
                    if ui
                        .text_edit_singleline(&mut self.genome_chromosome)
                        .changed()
                    {
                        self.genome_retrieve_contig_suggestions.clear();
                    }
                    ui.label("start_1based");
                    let start_changed = ui
                        .add(
                            egui::TextEdit::singleline(&mut self.genome_start_1based)
                                .id_salt("retrieve_genome_start_1based_field")
                                .desired_width(120.0)
                                .char_limit(10),
                        )
                        .changed();
                    if start_changed {
                        Self::normalize_coordinate_field(&mut self.genome_start_1based);
                    }
                    ui.label("end_1based");
                    let end_changed = ui
                        .add(
                            egui::TextEdit::singleline(&mut self.genome_end_1based)
                                .id_salt("retrieve_genome_end_1based_field")
                                .desired_width(120.0)
                                .char_limit(10),
                        )
                        .changed();
                    if end_changed {
                        Self::normalize_coordinate_field(&mut self.genome_end_1based);
                    }
                });
                ui.horizontal(|ui| {
                    ui.label("output_id");
                    ui.text_edit_singleline(&mut self.genome_output_id);
                    if ui
                        .checkbox(
                            &mut self.genome_include_genomic_annotation,
                            "include genomic annotation",
                        )
                        .on_hover_text(
                            "Attach overlapping genomic annotation when extracting selected genes or explicit regions",
                        )
                        .changed()
                    {
                        self.sync_genome_annotation_scope_controls();
                    }
                    if ui
                        .add_enabled(
                            self.genome_selected_gene.is_some(),
                            egui::Button::new("Extract Selected Gene"),
                        )
                        .on_hover_text(
                            "Extract the currently selected gene from the prepared reference",
                        )
                        .clicked()
                    {
                        self.extract_reference_genome_gene();
                    }
                    if ui
                        .button("Extract Region")
                        .on_hover_text("Extract the explicit chromosome start/end interval")
                        .clicked()
                    {
                        self.extract_reference_genome_region();
                    }
                });
                ui.horizontal(|ui| {
                    ui.label("annotation scope");
                    let previous_scope = self.genome_annotation_scope;
                    let scope_combo =
                        egui::ComboBox::from_id_salt("retrieve_genome_annotation_scope")
                            .selected_text(self.genome_annotation_scope.as_str())
                            .show_ui(ui, |ui| {
                                ui.selectable_value(
                                    &mut self.genome_annotation_scope,
                                    GenomeAnnotationScope::None,
                                    "none",
                                );
                                ui.selectable_value(
                                    &mut self.genome_annotation_scope,
                                    GenomeAnnotationScope::Core,
                                    "core",
                                );
                                ui.selectable_value(
                                    &mut self.genome_annotation_scope,
                                    GenomeAnnotationScope::Full,
                                    "full",
                                );
                            });
                    scope_combo.response.on_hover_text(
                        "Projection policy for annotation transfer: none, core gene/transcript context, or full",
                    );
                    if self.genome_annotation_scope != previous_scope {
                        self.genome_include_genomic_annotation =
                            !matches!(self.genome_annotation_scope, GenomeAnnotationScope::None);
                    }
                    ui.label("max annotation features");
                    let cap_changed = ui
                        .add(
                            egui::TextEdit::singleline(&mut self.genome_max_annotation_features)
                                .desired_width(120.0)
                                .hint_text("empty = unlimited"),
                        )
                        .on_hover_text("Optional safety cap. 0 means unlimited explicit cap.")
                        .changed();
                    if cap_changed {
                        self.genome_max_annotation_features
                            .retain(|ch| ch.is_ascii_digit());
                    }
                });
            }
            if !self.genome_retrieve_status.is_empty() {
                ui.separator();
                ui.monospace(&self.genome_retrieve_status);
                if let Some(suggested) = self.genome_retrieve_contig_suggestions.first().cloned() {
                    ui.horizontal(|ui| {
                        if ui
                            .button(format!("Apply suggested contig '{}'", suggested))
                            .on_hover_text(
                                "Copy the best matching prepared contig/chromosome into the chr field",
                            )
                            .clicked()
                        {
                            self.genome_chromosome = suggested.clone();
                            self.genome_retrieve_status = format!(
                                "Applied suggested contig '{}' to chr field. Re-run extraction.",
                                suggested
                            );
                            self.genome_retrieve_contig_suggestions.clear();
                        }
                        let alternatives = self
                            .genome_retrieve_contig_suggestions
                            .iter()
                            .skip(1)
                            .take(4)
                            .cloned()
                            .collect::<Vec<_>>();
                        if !alternatives.is_empty() {
                            ui.small(format!("alternatives: {}", alternatives.join(", ")));
                        }
                    });
                }
            }
        });
    }

    fn render_reference_genome_retrieve_dialog(&mut self, ctx: &egui::Context) {
        if !self.show_reference_genome_retrieve_dialog {
            return;
        }
        self.refresh_genome_catalog_list();
        let title = self.genome_dialog_scope.retrieve_title();

        let builder = egui::ViewportBuilder::default()
            .with_title(title)
            .with_inner_size([980.0, 760.0])
            .with_min_inner_size([860.0, 520.0]);
        ctx.show_viewport_immediate(
            Self::retrieve_genome_viewport_id(),
            builder,
            |ctx, class| {
                self.note_viewport_focus_if_active(ctx, Self::retrieve_genome_viewport_id());
                if class == egui::ViewportClass::Embedded {
                    let mut open = self.show_reference_genome_retrieve_dialog;
                    egui::Window::new(title)
                        .open(&mut open)
                        .collapsible(false)
                        .resizable(true)
                        .default_size(Vec2::new(980.0, 760.0))
                        .min_size(Vec2::new(860.0, 520.0))
                        .show(ctx, |ui| {
                            self.render_reference_genome_retrieve_contents(ui);
                        });
                    self.show_reference_genome_retrieve_dialog = open;
                    return;
                }

                egui::CentralPanel::default().show(ctx, |ui| {
                    self.render_reference_genome_retrieve_contents(ui);
                });

                if Self::viewport_close_requested_or_shortcut(ctx) {
                    self.show_reference_genome_retrieve_dialog = false;
                }
            },
        );
    }

    fn format_blast_command_line(executable: &str, args: &[String]) -> String {
        let exe = executable.trim();
        if args.is_empty() {
            return exe.to_string();
        }
        if exe.is_empty() {
            return args.join(" ");
        }
        format!("{exe} {}", args.join(" "))
    }

    fn render_blast_query_result(ui: &mut Ui, result: &GenomeBlastQueryResult) {
        let report = &result.report;
        ui.label(format!(
            "Query: {} ({} bp) | Genome: {} | Hits: {}",
            result.query_label, result.query_length, report.genome_id, report.hit_count
        ));
        ui.label(format!(
            "Task: {} | max_hits: {}",
            report.task, report.max_hits
        ));
        ui.monospace(format!("blastn: {}", report.blastn_executable));
        ui.monospace(format!("db: {}", report.blast_db_prefix));
        let invocation =
            Self::format_blast_command_line(&report.blastn_executable, &report.command);
        if !invocation.trim().is_empty() {
            ui.monospace(format!("invocation: {invocation}"));
        }
        if let Some(request) = report.options_override_json.as_ref() {
            if let Ok(compact) = serde_json::to_string(request) {
                ui.monospace(format!("request_options: {compact}"));
            }
        }
        if let Some(effective) = report.effective_options_json.as_ref() {
            if let Ok(compact) = serde_json::to_string(effective) {
                ui.monospace(format!("effective_options: {compact}"));
            }
        }
        if !report.warnings.is_empty() {
            ui.separator();
            ui.label("Warnings");
            for warning in &report.warnings {
                ui.monospace(format!("- {}", warning));
            }
        }
        if !report.stderr.trim().is_empty() {
            ui.separator();
            ui.label("BLAST stderr");
            ui.monospace(report.stderr.trim().to_string());
        }
        ui.separator();
        ui.label("Hits");
        let max_rows = 200usize;
        let shown_hits = report.hits.len().min(max_rows);
        if shown_hits < report.hits.len() {
            ui.small(format!(
                "Showing first {} of {} hits",
                shown_hits,
                report.hits.len()
            ));
        }
        egui::ScrollArea::both().max_height(280.0).show(ui, |ui| {
            scroll_input_policy::apply_scrollarea_keyboard_navigation(
                ui,
                scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
            );
            egui::Grid::new(format!("blast_hits_{}", result.query_label))
                .striped(true)
                .show(ui, |ui| {
                    ui.strong("subject");
                    ui.strong("%identity");
                    ui.strong("aln_len");
                    ui.strong("q_range");
                    ui.strong("s_range");
                    ui.strong("evalue");
                    ui.strong("bit_score");
                    ui.strong("qcov%");
                    ui.end_row();
                    for hit in report.hits.iter().take(max_rows) {
                        ui.monospace(hit.subject_id.clone());
                        ui.label(format!("{:.2}", hit.identity_percent));
                        ui.label(hit.alignment_length.to_string());
                        ui.label(format!("{}-{}", hit.query_start, hit.query_end));
                        ui.label(format!("{}-{}", hit.subject_start, hit.subject_end));
                        ui.label(format!("{:.3e}", hit.evalue));
                        ui.label(format!("{:.2}", hit.bit_score));
                        ui.label(
                            hit.query_coverage_percent
                                .map(|v| format!("{v:.1}"))
                                .unwrap_or_else(|| "-".to_string()),
                        );
                        ui.end_row();
                    }
                });
        });
    }

    fn render_reference_genome_blast_contents(&mut self, ui: &mut Ui) {
        self.refresh_genome_catalog_list();
        let scope = self.genome_dialog_scope;
        self.render_specialist_window_nav(ui);
        let sequence_ids = self.project_sequence_ids_for_blast();
        if !sequence_ids.is_empty() && !sequence_ids.contains(&self.genome_blast_query_seq_id) {
            self.genome_blast_query_seq_id = sequence_ids[0].clone();
        }
        let pool_options = self.blast_pool_options();
        if !pool_options
            .iter()
            .any(|pool| pool.container_id == self.genome_blast_query_pool_id)
        {
            self.genome_blast_query_pool_id = pool_options
                .first()
                .map(|pool| pool.container_id.clone())
                .unwrap_or_default();
        }

        ui.label(format!(
            "Run BLAST against a prepared {} index.",
            scope.description()
        ));
        ui.separator();
        ui.strong("1. Target");
        ui.horizontal(|ui| {
            ui.label("catalog");
            ui.text_edit_singleline(&mut self.genome_catalog_path);
            if ui
                .button("Browse...")
                .on_hover_text("Browse filesystem and fill this path")
                .clicked()
            {
                if let Some(path) = rfd::FileDialog::new()
                    .add_filter("JSON", &["json"])
                    .pick_file()
                {
                    self.genome_catalog_path = path.display().to_string();
                }
            }
        });
        ui.horizontal(|ui| {
            ui.label("cache_dir");
            ui.text_edit_singleline(&mut self.genome_cache_dir);
            if ui
                .button("Browse...")
                .on_hover_text("Browse filesystem and fill this path")
                .clicked()
            {
                if let Some(path) = rfd::FileDialog::new().pick_folder() {
                    self.genome_cache_dir = path.display().to_string();
                }
            }
        });
        if !self.genome_catalog_error.is_empty() {
            ui.colored_label(
                egui::Color32::from_rgb(190, 70, 70),
                format!("Catalog error: {}", self.genome_catalog_error),
            );
        }

        let prepared_genomes = match self.prepared_genomes_for_retrieve_dialog() {
            Ok(names) => names,
            Err(e) => {
                ui.colored_label(
                    egui::Color32::from_rgb(190, 70, 70),
                    format!("Prepared-state check error: {e}"),
                );
                vec![]
            }
        };
        if !prepared_genomes.is_empty() && !prepared_genomes.contains(&self.genome_id) {
            self.genome_id = prepared_genomes[0].clone();
            self.invalidate_genome_genes();
        }
        let selection_changed =
            Self::choose_genome_from_catalog(ui, &mut self.genome_id, &prepared_genomes);
        if selection_changed {
            self.invalidate_genome_genes();
        }
        match self.selected_genome_source_plan() {
            Ok(Some(plan)) => {
                ui.small(Self::format_genome_source_plan_summary(&plan));
            }
            Ok(None) => {}
            Err(e) => {
                ui.colored_label(
                    egui::Color32::from_rgb(190, 70, 70),
                    format!("Source-plan error: {e}"),
                );
            }
        }
        if prepared_genomes.is_empty() {
            ui.label(scope.empty_prepared_hint());
        }

        ui.separator();
        ui.strong("2. Input");
        ui.label("Query source");
        ui.horizontal(|ui| {
            ui.selectable_value(
                &mut self.genome_blast_source_mode,
                GenomeBlastSourceMode::Manual,
                "Manual sequence",
            );
            ui.selectable_value(
                &mut self.genome_blast_source_mode,
                GenomeBlastSourceMode::ProjectSequence,
                "Project sequence",
            );
            ui.selectable_value(
                &mut self.genome_blast_source_mode,
                GenomeBlastSourceMode::ProjectPool,
                "Project pool",
            );
        });
        match self.genome_blast_source_mode {
            GenomeBlastSourceMode::Manual => {
                ui.label("Query sequence (IUPAC DNA letters)");
                ui.add(
                    egui::TextEdit::multiline(&mut self.genome_blast_query_manual)
                        .desired_rows(4)
                        .hint_text("Paste query sequence here"),
                );
            }
            GenomeBlastSourceMode::ProjectSequence => {
                if sequence_ids.is_empty() {
                    ui.label("No sequences are loaded in this project.");
                } else {
                    egui::ComboBox::from_label("sequence")
                        .selected_text(if self.genome_blast_query_seq_id.trim().is_empty() {
                            "(choose sequence)"
                        } else {
                            self.genome_blast_query_seq_id.as_str()
                        })
                        .show_ui(ui, |ui| {
                            for seq_id in &sequence_ids {
                                ui.selectable_value(
                                    &mut self.genome_blast_query_seq_id,
                                    seq_id.clone(),
                                    seq_id,
                                );
                            }
                        });
                }
            }
            GenomeBlastSourceMode::ProjectPool => {
                if pool_options.is_empty() {
                    ui.label("No sequence pools/containers with >1 sequence are available.");
                } else {
                    egui::ComboBox::from_label("pool/container")
                        .selected_text(if self.genome_blast_query_pool_id.trim().is_empty() {
                            "(choose pool)"
                        } else {
                            self.genome_blast_query_pool_id.as_str()
                        })
                        .show_ui(ui, |ui| {
                            for pool in &pool_options {
                                ui.selectable_value(
                                    &mut self.genome_blast_query_pool_id,
                                    pool.container_id.clone(),
                                    pool.label.clone(),
                                );
                            }
                        });
                    if let Some(pool) = pool_options
                        .iter()
                        .find(|pool| pool.container_id == self.genome_blast_query_pool_id)
                    {
                        ui.small(format!(
                            "Selected pool will run {} query sequence(s).",
                            pool.members.len()
                        ));
                    }
                }
            }
        }

        ui.separator();
        ui.strong("3. Options");
        ui.horizontal(|ui| {
            ui.label("max_hits");
            ui.add(
                egui::DragValue::new(&mut self.genome_blast_max_hits)
                    .range(1..=1000)
                    .speed(1.0),
            );
            ui.label("task");
            egui::ComboBox::from_id_salt("genome_blast_task_combo")
                .selected_text(self.genome_blast_task_name.clone())
                .show_ui(ui, |ui| {
                    ui.selectable_value(
                        &mut self.genome_blast_task_name,
                        "blastn-short".to_string(),
                        "blastn-short",
                    );
                    ui.selectable_value(
                        &mut self.genome_blast_task_name,
                        "blastn".to_string(),
                        "blastn",
                    );
                });
        });
        ui.horizontal(|ui| {
            ui.label("preset");
            egui::ComboBox::from_id_salt("genome_blast_options_preset_combo")
                .selected_text(self.genome_blast_options_preset.label())
                .show_ui(ui, |ui| {
                    ui.selectable_value(
                        &mut self.genome_blast_options_preset,
                        GenomeBlastOptionsPreset::None,
                        GenomeBlastOptionsPreset::None.label(),
                    );
                    ui.selectable_value(
                        &mut self.genome_blast_options_preset,
                        GenomeBlastOptionsPreset::StrictIdentityCoverage,
                        GenomeBlastOptionsPreset::StrictIdentityCoverage.label(),
                    );
                    ui.selectable_value(
                        &mut self.genome_blast_options_preset,
                        GenomeBlastOptionsPreset::UniqueBestHit,
                        GenomeBlastOptionsPreset::UniqueBestHit.label(),
                    );
                    ui.selectable_value(
                        &mut self.genome_blast_options_preset,
                        GenomeBlastOptionsPreset::HighStringency,
                        GenomeBlastOptionsPreset::HighStringency.label(),
                    );
                });
            if ui
                .button("Load JSON...")
                .on_hover_text("Load advanced BLAST options JSON from file")
                .clicked()
            {
                if let Some(path) = rfd::FileDialog::new()
                    .add_filter("JSON", &["json"])
                    .pick_file()
                {
                    match fs::read_to_string(&path) {
                        Ok(text) => {
                            self.genome_blast_options_json = text;
                        }
                        Err(e) => {
                            self.genome_blast_status = format!(
                                "Could not read BLAST options file '{}': {}",
                                path.display(),
                                e
                            );
                        }
                    }
                }
            }
        });
        ui.group(|ui| {
            ui.label("Structured threshold controls");
            egui::Grid::new("genome_blast_structured_threshold_grid")
                .num_columns(3)
                .spacing([8.0, 4.0])
                .show(ui, |ui| {
                    ui.checkbox(
                        &mut self.genome_blast_threshold_use_max_evalue,
                        "max_evalue",
                    );
                    ui.add_enabled(
                        self.genome_blast_threshold_use_max_evalue,
                        egui::TextEdit::singleline(&mut self.genome_blast_threshold_max_evalue)
                            .desired_width(140.0)
                            .hint_text("1e-6"),
                    );
                    ui.small("finite >= 0");
                    ui.end_row();

                    ui.checkbox(
                        &mut self.genome_blast_threshold_use_min_identity_percent,
                        "min_identity_percent",
                    );
                    ui.add_enabled(
                        self.genome_blast_threshold_use_min_identity_percent,
                        egui::TextEdit::singleline(
                            &mut self.genome_blast_threshold_min_identity_percent,
                        )
                        .desired_width(140.0)
                        .hint_text("97.0"),
                    );
                    ui.small("0..100");
                    ui.end_row();

                    ui.checkbox(
                        &mut self.genome_blast_threshold_use_min_query_coverage_percent,
                        "min_query_coverage_percent",
                    );
                    ui.add_enabled(
                        self.genome_blast_threshold_use_min_query_coverage_percent,
                        egui::TextEdit::singleline(
                            &mut self.genome_blast_threshold_min_query_coverage_percent,
                        )
                        .desired_width(140.0)
                        .hint_text("80.0"),
                    );
                    ui.small("0..100");
                    ui.end_row();

                    ui.checkbox(
                        &mut self.genome_blast_threshold_use_min_alignment_length_bp,
                        "min_alignment_length_bp",
                    );
                    ui.add_enabled(
                        self.genome_blast_threshold_use_min_alignment_length_bp,
                        egui::TextEdit::singleline(
                            &mut self.genome_blast_threshold_min_alignment_length_bp,
                        )
                        .desired_width(140.0)
                        .hint_text("20"),
                    );
                    ui.small(">= 1");
                    ui.end_row();

                    ui.checkbox(
                        &mut self.genome_blast_threshold_use_min_bit_score,
                        "min_bit_score",
                    );
                    ui.add_enabled(
                        self.genome_blast_threshold_use_min_bit_score,
                        egui::TextEdit::singleline(&mut self.genome_blast_threshold_min_bit_score)
                            .desired_width(140.0)
                            .hint_text("40.0"),
                    );
                    ui.small("finite >= 0");
                    ui.end_row();

                    ui.checkbox(
                        &mut self.genome_blast_threshold_unique_best_hit,
                        "unique_best_hit",
                    );
                    ui.small("-");
                    ui.small("require exactly one hit after filtering");
                    ui.end_row();
                });
            ui.horizontal(|ui| {
                if ui
                    .button("Reset thresholds")
                    .on_hover_text("Clear all structured threshold controls")
                    .clicked()
                {
                    self.genome_blast_threshold_use_max_evalue = false;
                    self.genome_blast_threshold_max_evalue.clear();
                    self.genome_blast_threshold_use_min_identity_percent = false;
                    self.genome_blast_threshold_min_identity_percent.clear();
                    self.genome_blast_threshold_use_min_query_coverage_percent = false;
                    self.genome_blast_threshold_min_query_coverage_percent
                        .clear();
                    self.genome_blast_threshold_use_min_alignment_length_bp = false;
                    self.genome_blast_threshold_min_alignment_length_bp.clear();
                    self.genome_blast_threshold_use_min_bit_score = false;
                    self.genome_blast_threshold_min_bit_score.clear();
                    self.genome_blast_threshold_unique_best_hit = false;
                }
            });
        });
        ui.label("advanced options JSON (object; merged after preset + structured controls)");
        ui.add(
            egui::TextEdit::multiline(&mut self.genome_blast_options_json)
                .desired_rows(4)
                .hint_text("{\"thresholds\":{\"min_identity_percent\":97.0}}"),
        );
        match self.build_genome_blast_request_override_json() {
            Ok(request_override_json) => {
                if let Some(v) = request_override_json.as_ref() {
                    match self.resolve_genome_blast_options_preview(Some(v)) {
                        Ok(resolved) => {
                            ui.small(format!(
                                "Effective options preview: task='{}', max_hits={}, thresholds={}",
                                resolved.task,
                                resolved.max_hits,
                                Self::format_blast_thresholds_summary(&resolved.thresholds)
                            ));
                        }
                        Err(e) => {
                            ui.colored_label(
                                egui::Color32::from_rgb(190, 70, 70),
                                format!("Options validation error: {e}"),
                            );
                        }
                    }
                } else {
                    match self.resolve_genome_blast_options_preview(None) {
                        Ok(resolved) => {
                            ui.small(format!(
                                "Effective options preview: task='{}', max_hits={}, thresholds={}",
                                resolved.task,
                                resolved.max_hits,
                                Self::format_blast_thresholds_summary(&resolved.thresholds)
                            ));
                        }
                        Err(e) => {
                            ui.colored_label(
                                egui::Color32::from_rgb(190, 70, 70),
                                format!("Options validation error: {e}"),
                            );
                        }
                    }
                }
            }
            Err(e) => {
                ui.colored_label(
                    egui::Color32::from_rgb(190, 70, 70),
                    format!("Options JSON error: {e}"),
                );
            }
        }

        ui.separator();
        ui.strong("4. Execution");
        let running = self.genome_blast_task.is_some();
        ui.horizontal(|ui| {
            if ui
                .add_enabled(
                    !running && !prepared_genomes.is_empty(),
                    egui::Button::new("Run BLAST"),
                )
                .on_hover_text("Run BLAST query and collect hits for the selected prepared genome")
                .clicked()
            {
                self.start_reference_genome_blast();
            }
            if ui
                .add_enabled(running, egui::Button::new("Cancel BLAST"))
                .on_hover_text("Request cancellation of the running BLAST task")
                .clicked()
            {
                self.request_blast_task_cancel("blast dialog");
            }
            if ui
                .button("Clear Results")
                .on_hover_text("Clear all BLAST query results from this dialog")
                .clicked()
            {
                self.genome_blast_results.clear();
                self.genome_blast_selected_result = 0;
            }
            if ui
                .button("Close")
                .on_hover_text("Close this dialog")
                .clicked()
            {
                self.show_reference_genome_blast_dialog = false;
            }
        });

        if let Some(fraction) = self.genome_blast_progress_fraction {
            ui.add(
                egui::ProgressBar::new(fraction.clamp(0.0, 1.0))
                    .show_percentage()
                    .text(self.genome_blast_progress_label.clone()),
            );
        }
        if !self.genome_blast_status.is_empty() {
            ui.separator();
            ui.monospace(self.genome_blast_status.clone());
        }
        if !self.genome_blast_results.is_empty() {
            ui.separator();
            ui.strong("5. Results");
            if self.genome_blast_selected_result >= self.genome_blast_results.len() {
                self.genome_blast_selected_result = 0;
            }
            if self.genome_blast_results.len() > 1 {
                egui::ComboBox::from_label("Query result")
                    .selected_text(
                        self.genome_blast_results[self.genome_blast_selected_result]
                            .query_label
                            .clone(),
                    )
                    .show_ui(ui, |ui| {
                        for (idx, result) in self.genome_blast_results.iter().enumerate() {
                            let label = format!(
                                "{} (hits={})",
                                result.query_label, result.report.hit_count
                            );
                            ui.selectable_value(&mut self.genome_blast_selected_result, idx, label);
                        }
                    });
            }
            if let Some(result) = self
                .genome_blast_results
                .get(self.genome_blast_selected_result)
                .cloned()
            {
                let target_seq_id = self.target_seq_id_for_blast_result(&result);
                ui.separator();
                ui.label("Import BLAST hits as features");
                ui.horizontal(|ui| {
                    ui.label("track_name");
                    ui.text_edit_singleline(&mut self.genome_blast_import_track_name);
                    ui.checkbox(
                        &mut self.genome_blast_import_clear_existing,
                        "Clear existing BLAST-hit features first",
                    );
                });
                let can_import = target_seq_id.is_some() && !result.report.hits.is_empty();
                let button = ui
                    .add_enabled(can_import, egui::Button::new("Import Hits To Sequence"))
                    .on_hover_text(
                        "Import current BLAST hit intervals as features on the target sequence",
                    );
                if button.clicked() {
                    self.import_selected_blast_hits_as_track();
                }
                if let Some(seq_id) = target_seq_id {
                    ui.small(format!("Import target sequence: {seq_id}"));
                } else {
                    ui.small(
                        "Hit import requires query label to match an existing project sequence ID.",
                    );
                }
                Self::render_blast_query_result(ui, &result);
            }
        }
    }

    fn render_reference_genome_blast_dialog(&mut self, ctx: &egui::Context) {
        if !self.show_reference_genome_blast_dialog {
            return;
        }
        let title = self.genome_dialog_scope.blast_title();

        let builder = egui::ViewportBuilder::default()
            .with_title(title)
            .with_inner_size([980.0, 700.0])
            .with_min_inner_size([640.0, 420.0]);
        ctx.show_viewport_immediate(Self::blast_genome_viewport_id(), builder, |ctx, class| {
            self.note_viewport_focus_if_active(ctx, Self::blast_genome_viewport_id());
            if class == egui::ViewportClass::Embedded {
                let mut open = self.show_reference_genome_blast_dialog;
                egui::Window::new(title)
                    .open(&mut open)
                    .collapsible(false)
                    .resizable(true)
                    .default_size(Vec2::new(980.0, 700.0))
                    .show(ctx, |ui| {
                        self.render_reference_genome_blast_contents(ui);
                    });
                self.show_reference_genome_blast_dialog = open;
                return;
            }

            egui::CentralPanel::default().show(ctx, |ui| {
                self.render_reference_genome_blast_contents(ui);
            });

            if Self::viewport_close_requested_or_shortcut(ctx) {
                self.show_reference_genome_blast_dialog = false;
            }
        });
    }

    fn render_reference_genome_inspector_dialog(&mut self, ctx: &egui::Context) {
        if !self.show_reference_genome_inspector_dialog {
            return;
        }
        self.refresh_genome_catalog_list();
        let scope = self.genome_dialog_scope;
        let title = if matches!(scope, GenomeDialogScope::Helper) {
            "Prepared Helper Genomes"
        } else {
            "Prepared Genome References"
        };
        let mut open = self.show_reference_genome_inspector_dialog;
        egui::Window::new(title)
            .open(&mut open)
            .collapsible(false)
            .resizable(true)
            .show(ctx, |ui| {
                self.render_specialist_window_nav(ui);
                ui.label(format!(
                    "Inspect prepared {} installations and integrity metadata.",
                    scope.description()
                ));
                ui.horizontal(|ui| {
                    ui.label("catalog");
                    ui.text_edit_singleline(&mut self.genome_catalog_path);
                    if ui
                        .button("Browse...")
                        .on_hover_text("Browse filesystem and fill this path")
                        .clicked()
                    {
                        if let Some(path) = rfd::FileDialog::new()
                            .add_filter("JSON", &["json"])
                            .pick_file()
                        {
                            self.genome_catalog_path = path.display().to_string();
                        }
                    }
                });
                ui.horizontal(|ui| {
                    ui.label("cache_dir");
                    ui.text_edit_singleline(&mut self.genome_cache_dir);
                    if ui
                        .button("Browse...")
                        .on_hover_text("Browse filesystem and fill this path")
                        .clicked()
                    {
                        if let Some(path) = rfd::FileDialog::new().pick_folder() {
                            self.genome_cache_dir = path.display().to_string();
                        }
                    }
                });
                if !self.genome_catalog_error.is_empty() {
                    ui.colored_label(
                        egui::Color32::from_rgb(190, 70, 70),
                        format!("Catalog error: {}", self.genome_catalog_error),
                    );
                }
                match self.collect_prepared_genome_inspections() {
                    Ok((inspections, errors)) => {
                        let total_size: u64 = inspections.iter().map(|r| r.total_size_bytes).sum();
                        ui.label(format!(
                            "Prepared references: {} | total size: {}",
                            inspections.len(),
                            Self::format_bytes_compact(total_size)
                        ));
                        if inspections.is_empty() {
                            ui.label("No prepared references found for this catalog/cache.");
                        } else {
                            egui::ScrollArea::vertical()
                                .max_height(320.0)
                                .show(ui, |ui| {
                                    scroll_input_policy::apply_scrollarea_keyboard_navigation(
                                        ui,
                                        scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                                    );
                                    egui::Grid::new("prepared_genome_inspector_grid")
                                        .striped(true)
                                        .num_columns(8)
                                        .show(ui, |ui| {
                                            ui.strong("Genome");
                                            ui.strong("Size");
                                            ui.strong("Ready");
                                            ui.strong("Sources");
                                            ui.strong("SHA1 seq/ann");
                                            ui.strong("Installed");
                                            ui.strong("Path");
                                            ui.strong("");
                                            ui.end_row();
                                            for inspection in &inspections {
                                                ui.label(&inspection.genome_id);
                                                ui.label(Self::format_bytes_compact(
                                                    inspection.total_size_bytes,
                                                ));
                                                ui.label(format!(
                                                    "seq:{} ann:{} fai:{} gene:{}",
                                                    if inspection.sequence_present {
                                                        "y"
                                                    } else {
                                                        "n"
                                                    },
                                                    if inspection.annotation_present {
                                                        "y"
                                                    } else {
                                                        "n"
                                                    },
                                                    if inspection.fasta_index_ready {
                                                        "y"
                                                    } else {
                                                        "n"
                                                    },
                                                    if inspection.gene_index_ready {
                                                        "y"
                                                    } else {
                                                        "n"
                                                    }
                                                ));
                                                ui.label(format!(
                                                    "{}/{}",
                                                    inspection.sequence_source_type,
                                                    inspection.annotation_source_type
                                                ));
                                                ui.label(format!(
                                                    "{}/{}",
                                                    Self::format_short_sha1(
                                                        &inspection.sequence_sha1
                                                    ),
                                                    Self::format_short_sha1(
                                                        &inspection.annotation_sha1
                                                    )
                                                ));
                                                ui.label(
                                                    inspection.installed_at_unix_ms.to_string(),
                                                );
                                                let path_label = inspection.install_dir.clone();
                                                ui.label(
                                                    egui::RichText::new(path_label)
                                                        .monospace()
                                                        .small(),
                                                );
                                                if ui
                                                    .small_button("Retrieve")
                                                    .on_hover_text(
                                                        "Open retrieval dialog preselected for this prepared genome",
                                                    )
                                                    .clicked()
                                                {
                                                    self.genome_id = inspection.genome_id.clone();
                                                    self.invalidate_genome_genes();
                                                    self.open_retrieve_genome_dialog_for_scope(
                                                        self.genome_dialog_scope,
                                                    );
                                                }
                                                ui.end_row();
                                            }
                                        });
                                });

                            ui.separator();
                            ui.label("Chromosome inspector");
                            let prepared_ids: Vec<String> =
                                inspections.iter().map(|i| i.genome_id.clone()).collect();
                            if !prepared_ids.is_empty()
                                && !prepared_ids.iter().any(|id| id == &self.genome_id)
                            {
                                self.genome_id = prepared_ids[0].clone();
                            }
                            ui.horizontal(|ui| {
                                ui.label("genome");
                                egui::ComboBox::from_id_salt("prepared_genome_chromosome_inspect")
                                    .selected_text(if self.genome_id.trim().is_empty() {
                                        "<select genome>"
                                    } else {
                                        self.genome_id.as_str()
                                    })
                                    .show_ui(ui, |ui| {
                                        for genome_id in &prepared_ids {
                                            ui.selectable_value(
                                                &mut self.genome_id,
                                                genome_id.clone(),
                                                genome_id,
                                            );
                                        }
                                    });
                                if ui
                                    .small_button("Use In Retrieve")
                                    .on_hover_text(
                                        "Open retrieval dialog preselected for this genome",
                                    )
                                    .clicked()
                                {
                                    self.invalidate_genome_genes();
                                    self.open_retrieve_genome_dialog_for_scope(
                                        self.genome_dialog_scope,
                                    );
                                }
                            });
                            if !self.genome_id.trim().is_empty() {
                                match self.prepared_genome_chromosome_records(&self.genome_id) {
                                    Ok(chromosomes) => {
                                        Self::render_chromosome_length_lines(ui, &chromosomes);
                                    }
                                    Err(e) => {
                                        ui.colored_label(
                                            egui::Color32::from_rgb(190, 70, 70),
                                            format!("Chromosome inspector error: {e}"),
                                        );
                                    }
                                }
                            }
                        }
                        if !errors.is_empty() {
                            ui.separator();
                            ui.colored_label(
                                egui::Color32::from_rgb(190, 70, 70),
                                "Inspection errors:",
                            );
                            for err in errors {
                                ui.colored_label(egui::Color32::from_rgb(190, 70, 70), err);
                            }
                        }
                    }
                    Err(e) => {
                        ui.colored_label(
                            egui::Color32::from_rgb(190, 70, 70),
                            format!("Inspector error: {e}"),
                        );
                    }
                }
            });
        self.show_reference_genome_inspector_dialog = open;
    }

    fn render_genome_bed_track_contents(&mut self, ui: &mut Ui) {
        self.render_specialist_window_nav(ui);
        let anchor_summaries = self.anchored_sequence_anchor_summaries_for_tracks();
        let anchored_seq_ids = anchor_summaries
            .iter()
            .map(|summary| summary.seq_id.clone())
            .collect::<Vec<_>>();
        let import_running = self.genome_track_import_task.is_some();
        if !anchored_seq_ids.is_empty() && !anchored_seq_ids.contains(&self.genome_track_seq_id) {
            self.genome_track_seq_id = anchored_seq_ids[0].clone();
        }

        ui.label("Map genome signal tracks onto genome-anchored sequences.");
        ui.small("Supports .bed/.bed.gz and .bw/.bigWig input files.");
        ui.small(format!(
            "Anchored sequences available: {}",
            anchored_seq_ids.len()
        ));

        if anchored_seq_ids.is_empty() {
            ui.colored_label(
                egui::Color32::from_rgb(190, 70, 70),
                "No genome-anchored sequence is available. Extract a genome region or gene first.",
            );
        } else {
            ui.horizontal(|ui| {
                ui.label("sequence");
                egui::ComboBox::from_id_salt("genome_track_seq_id_combo")
                    .selected_text(if self.genome_track_seq_id.trim().is_empty() {
                        "<select sequence>"
                    } else {
                        self.genome_track_seq_id.as_str()
                    })
                    .show_ui(ui, |ui| {
                        for seq_id in &anchored_seq_ids {
                            ui.selectable_value(
                                &mut self.genome_track_seq_id,
                                seq_id.clone(),
                                seq_id,
                            );
                        }
                    });
                let selected_resp = self.track_hover_status(
                    ui.add_enabled(
                        !anchored_seq_ids.is_empty() && !import_running,
                        egui::Button::new("Import To Selected"),
                    )
                    .on_hover_text(
                        "Import this BED/BigWig/VCF signal file onto only the currently selected anchored sequence.",
                    ),
                    "Genome Tracks > Import Selected",
                );
                if selected_resp.clicked() {
                    self.import_genome_bed_track_for_selected_sequence();
                }
            });
            if let Some(anchor) = self.describe_sequence_genome_anchor(&self.genome_track_seq_id) {
                ui.small(format!("selected anchor: {anchor}"));
            }
            ui.small(
                "Tip: Keep this window open. Change 'sequence' and click 'Import To Selected' again to reuse the same track file for another anchored sequence.",
            );
        }

        let detected_source = GenomeTrackSource::from_path(&self.genome_track_path);
        ui.horizontal(|ui| {
            ui.label("source");
            egui::ComboBox::from_id_salt("genome_track_source_selection")
                .selected_text(self.genome_track_source_selection.label())
                .show_ui(ui, |ui| {
                    ui.selectable_value(
                        &mut self.genome_track_source_selection,
                        GenomeTrackSourceSelection::Auto,
                        GenomeTrackSourceSelection::Auto.label(),
                    );
                    ui.selectable_value(
                        &mut self.genome_track_source_selection,
                        GenomeTrackSourceSelection::Bed,
                        GenomeTrackSourceSelection::Bed.label(),
                    );
                    ui.selectable_value(
                        &mut self.genome_track_source_selection,
                        GenomeTrackSourceSelection::BigWig,
                        GenomeTrackSourceSelection::BigWig.label(),
                    );
                    ui.selectable_value(
                        &mut self.genome_track_source_selection,
                        GenomeTrackSourceSelection::Vcf,
                        GenomeTrackSourceSelection::Vcf.label(),
                    );
                });
            ui.small(format!("Detected extension: {}", detected_source.label()));
        });

        ui.horizontal(|ui| {
            ui.label("track_path");
            ui.text_edit_singleline(&mut self.genome_track_path);
            let browse_track_resp = self.track_hover_status(
                ui.button("Browse...")
                    .on_hover_text("Browse filesystem and fill this path"),
                "Genome Tracks > Browse Track Path",
            );
            if browse_track_resp.clicked() {
                if let Some(path) = rfd::FileDialog::new()
                    .add_filter("Signal tracks", &["bed", "gz", "bw", "bigwig", "vcf"])
                    .pick_file()
                {
                    self.genome_track_path = path.display().to_string();
                    if self.genome_track_name.trim().is_empty() {
                        self.genome_track_name = Self::track_name_default_from_path(&path);
                    }
                }
            }
        });
        let resolved_source = self
            .genome_track_source_selection
            .resolve(&self.genome_track_path);
        ui.small(format!(
            "Resolved source format for import: {}",
            resolved_source.label()
        ));
        ui.horizontal(|ui| {
            ui.label("track_name");
            ui.text_edit_singleline(&mut self.genome_track_name);
            ui.small("(optional)");
        });
        ui.horizontal(|ui| {
            ui.label("min_score");
            ui.add(
                egui::TextEdit::singleline(&mut self.genome_track_min_score).desired_width(90.0),
            );
            ui.label("max_score");
            ui.add(
                egui::TextEdit::singleline(&mut self.genome_track_max_score).desired_width(90.0),
            );
        });
        ui.checkbox(
            &mut self.genome_track_clear_existing,
            "Clear existing imported track features first",
        );
        if let Some(selected_anchor) = anchor_summaries
            .iter()
            .find(|summary| summary.seq_id == self.genome_track_seq_id)
        {
            let matching_anchor_count = anchor_summaries
                .iter()
                .filter(|candidate| Self::anchors_share_mapping_group(candidate, selected_anchor))
                .count();
            let projected_targets = anchored_seq_ids.len();
            let mapping_status = if matching_anchor_count == projected_targets {
                "all anchored sequences match selected genome/chromosome"
            } else {
                "mixed anchors detected; import still applies to all anchored sequences"
            };
            let track_path = self.genome_track_path.trim().to_string();
            let path_exists = !track_path.is_empty() && Path::new(&track_path).is_file();
            let projected_track_name = {
                let trimmed = self.genome_track_name.trim();
                if trimmed.is_empty() {
                    resolved_source.label().to_string()
                } else {
                    trimmed.to_string()
                }
            };

            ui.group(|ui| {
                ui.strong("Import Preflight");
                ui.small(format!(
                    "anchor: {}:{}:{}..{} (strand {})",
                    selected_anchor.genome_id,
                    selected_anchor.chromosome,
                    selected_anchor.start_1based,
                    selected_anchor.end_1based,
                    selected_anchor
                        .strand
                        .map(|s| s.to_string())
                        .unwrap_or_else(|| "?".to_string())
                ));
                ui.small(format!(
                    "matching status: {} / {} anchored sequences share this mapping group ({})",
                    matching_anchor_count, projected_targets, mapping_status
                ));
                ui.small(format!(
                    "projected tracks: {} target sequence(s) with track '{}'",
                    projected_targets, projected_track_name
                ));
                if path_exists {
                    ui.small(format!("track file: {}", track_path));
                } else {
                    ui.colored_label(
                        egui::Color32::from_rgb(190, 70, 70),
                        "track file: missing or unreadable path",
                    );
                }
                ui.horizontal(|ui| {
                    let toggle_resp = ui
                        .checkbox(
                            &mut self.genome_track_preflight_track_subscription,
                            "Track this file for auto-sync",
                        )
                        .on_hover_text(
                            "When enabled, this file is added to tracked subscriptions and auto-applied to newly anchored sequences.",
                        );
                    if toggle_resp.hovered() {
                        self.hover_status_name =
                            "Genome Tracks > Track Subscription Toggle".to_string();
                    }
                    let response = ui
                        .add_enabled(
                            !anchored_seq_ids.is_empty() && !import_running && path_exists,
                            egui::Button::new("Apply To All Anchored Now"),
                        )
                        .on_hover_text(
                            "One-click import to all anchored sequences using the current preflight settings.",
                        );
                    let response = self.track_hover_status(
                        response,
                        "Genome Tracks > Apply To All Anchored Now",
                    );
                    if response.clicked() {
                        self.import_genome_bed_track_for_all_anchored_sequences(
                            self.genome_track_preflight_track_subscription,
                        );
                    }
                });
            });
        }
        if self.genome_track_import_task.is_some() {
            let elapsed_secs = self
                .genome_track_import_task
                .as_ref()
                .map(|task| task.started.elapsed().as_secs_f32())
                .unwrap_or(0.0);
            let progress_snapshot = self.genome_track_import_progress.clone();
            ui.horizontal(|ui| {
                ui.add(egui::Spinner::new());
                if let Some(progress) = &progress_snapshot {
                    ui.label(format!(
                        "Running import: {} '{}' parsed={} imported={} skipped={} ({:.1}s)",
                        progress.source,
                        progress.path,
                        progress.parsed_records,
                        progress.imported_features,
                        progress.skipped_records,
                        elapsed_secs
                    ));
                } else {
                    ui.label(format!("Running import task... ({:.1}s)", elapsed_secs));
                }
                let cancel_import_resp = self.track_hover_status(
                    ui.button("Cancel Import").on_hover_text(
                        "Request cancellation. Imported features up to the cancellation point are kept.",
                    ),
                    "Genome Tracks > Cancel Import",
                );
                if cancel_import_resp.clicked() {
                    self.request_track_import_task_cancel("genome tracks dialog");
                }
            });
        }
        ui.horizontal(|ui| {
            let all_once_resp = self.track_hover_status(
                ui.add_enabled(
                    !anchored_seq_ids.is_empty() && !import_running,
                    egui::Button::new("Import To All Anchored (One-Time)"),
                )
                .on_hover_text(
                    "Import once onto every currently anchored sequence. No subscription is saved for future extracts.",
                ),
                "Genome Tracks > Import All Anchored One-Time",
            );
            if all_once_resp.clicked()
            {
                self.import_genome_bed_track_for_all_anchored_sequences(false);
            }
            let all_track_resp = self.track_hover_status(
                ui.add_enabled(
                    !anchored_seq_ids.is_empty() && !import_running,
                    egui::Button::new("Import To All Anchored + Track"),
                )
                .on_hover_text(
                    "Import onto all current anchored sequences and save this file as a tracked subscription for automatic future auto-sync.",
                ),
                "Genome Tracks > Import All Anchored And Track",
            );
            if all_track_resp.clicked()
            {
                self.import_genome_bed_track_for_all_anchored_sequences(true);
            }
        });

        ui.separator();
        ui.label("Tracked genome signal files for auto-sync to new anchored sequences");
        ui.horizontal(|ui| {
            ui.label("Filter")
                .on_hover_text(Self::tracked_file_filter_help_text());
            ui.add(
                egui::TextEdit::singleline(&mut self.genome_track_subscription_filter)
                    .hint_text("path, track, source")
                    .desired_width(280.0),
            )
            .on_hover_text(Self::tracked_file_filter_help_text());
            if ui
                .add_enabled(
                    !self.genome_track_subscription_filter.trim().is_empty(),
                    egui::Button::new("Clear"),
                )
                .clicked()
            {
                self.genome_track_subscription_filter.clear();
            }
        });
        ui.horizontal_wrapped(|ui| {
            ui.small("Presets:");
            for preset in [
                "source:bed",
                "source:bigwig",
                "source:vcf",
                "path:.bed",
                "track:chip",
            ] {
                if ui.small_button(preset).clicked() {
                    Self::append_filter_term(&mut self.genome_track_subscription_filter, preset);
                }
            }
        });

        let mut apply_now_index: Option<usize> = None;
        let mut remove_index: Option<usize> = None;
        if self.genome_bed_track_subscriptions.is_empty() {
            ui.small("No tracked files yet.");
        } else {
            let subscription_rows = self.genome_bed_track_subscriptions.clone();
            let filter_text = self.genome_track_subscription_filter.trim().to_string();
            let filtered_rows = subscription_rows
                .iter()
                .enumerate()
                .filter(|(_, subscription)| {
                    Self::subscription_matches_filter(subscription, &filter_text)
                })
                .collect::<Vec<_>>();
            ui.small(format!(
                "Showing {} of {} tracked files",
                filtered_rows.len(),
                subscription_rows.len()
            ));
            if filtered_rows.is_empty() {
                ui.small("No tracked files match the current filter.");
            }
            egui::Grid::new("genome_bed_track_subscriptions_grid")
                .striped(true)
                .show(ui, |ui| {
                    ui.strong("Type");
                    ui.strong("Path");
                    ui.strong("Track");
                    ui.strong("Score Range");
                    ui.strong("Clear Existing");
                    ui.strong("Actions");
                    ui.end_row();
                    for (index, subscription) in filtered_rows {
                        ui.label(subscription.source.label());
                        ui.monospace(subscription.path.as_str());
                        ui.label(
                            subscription
                                .track_name
                                .clone()
                                .unwrap_or_else(|| "-".to_string()),
                        );
                        ui.label(format!(
                            "{}..{}",
                            subscription
                                .min_score
                                .map(|v| format!("{v:.3}"))
                                .unwrap_or_else(|| "-".to_string()),
                            subscription
                                .max_score
                                .map(|v| format!("{v:.3}"))
                                .unwrap_or_else(|| "-".to_string())
                        ));
                        ui.label(if subscription.clear_existing {
                            "yes"
                        } else {
                            "no"
                        });
                        ui.horizontal(|ui| {
                            let apply_resp = self.track_hover_status(
                                ui.add_enabled(!import_running, egui::Button::new("Apply now"))
                                    .on_hover_text(
                                        "Re-apply this tracked file to all currently anchored sequences now.",
                                    ),
                                "Genome Tracks > Apply Tracked File",
                            );
                            if apply_resp.clicked()
                            {
                                apply_now_index = Some(index);
                            }
                            let remove_resp = self.track_hover_status(
                                ui.add_enabled(!import_running, egui::Button::new("Remove"))
                                    .on_hover_text(
                                        "Remove this tracked subscription (does not remove already imported features).",
                                    ),
                                "Genome Tracks > Remove Tracked File",
                            );
                            if remove_resp.clicked()
                            {
                                remove_index = Some(index);
                            }
                        });
                        ui.end_row();
                    }
                });
        }

        if let Some(index) = apply_now_index {
            self.apply_tracked_bed_subscription_to_all_anchored(index);
        }
        if let Some(index) = remove_index {
            let result = self
                .engine
                .write()
                .unwrap()
                .remove_genome_track_subscription(index);
            match result {
                Ok(removed) => {
                    self.load_bed_track_subscriptions_from_state();
                    self.genome_track_status = format!(
                        "Removed tracked {} '{}'",
                        removed.source.label(),
                        removed.path
                    );
                }
                Err(e) => {
                    self.genome_track_status =
                        format!("Could not remove tracked file: {}", e.message);
                }
            }
        }
        if !self.genome_bed_track_subscriptions.is_empty() {
            let clear_resp = self.track_hover_status(
                ui.add_enabled(!import_running, egui::Button::new("Clear Tracked Files"))
                    .on_hover_text(
                        "Remove all tracked subscriptions (does not remove already imported features).",
                    ),
                "Genome Tracks > Clear Tracked Files",
            );
            if clear_resp.clicked() {
                self.engine
                    .write()
                    .unwrap()
                    .clear_genome_track_subscriptions();
                self.load_bed_track_subscriptions_from_state();
                self.genome_track_status = "Cleared all tracked files".to_string();
            }
        }

        if !self.genome_track_autosync_status.is_empty() {
            ui.separator();
            ui.monospace(&self.genome_track_autosync_status);
        }
        if !self.genome_track_status.is_empty() {
            ui.separator();
            ui.monospace(&self.genome_track_status);
        }
    }

    fn render_genome_bed_track_dialog(&mut self, ctx: &egui::Context) {
        if !self.show_genome_bed_track_dialog {
            return;
        }
        let builder = egui::ViewportBuilder::default()
            .with_title("Import Genome Tracks")
            .with_inner_size([980.0, 620.0])
            .with_min_inner_size([620.0, 320.0]);
        ctx.show_viewport_immediate(Self::bed_track_viewport_id(), builder, |ctx, class| {
            self.note_viewport_focus_if_active(ctx, Self::bed_track_viewport_id());
            if class == egui::ViewportClass::Embedded {
                let mut open = self.show_genome_bed_track_dialog;
                egui::Window::new("Import Genome Tracks")
                    .open(&mut open)
                    .collapsible(false)
                    .resizable(true)
                    .default_size(Vec2::new(980.0, 620.0))
                    .show(ctx, |ui| self.render_genome_bed_track_contents(ui));
                self.show_genome_bed_track_dialog = open;
                return;
            }

            egui::CentralPanel::default().show(ctx, |ui| {
                self.render_genome_bed_track_contents(ui);
            });

            if Self::viewport_close_requested_or_shortcut(ctx) {
                self.show_genome_bed_track_dialog = false;
            }
        });
    }

    fn render_planning_contents(&mut self, ui: &mut Ui) {
        self.render_specialist_window_nav(ui);
        ui.label(
            "Planning meta-layer controls for time/cost/local-fit routine ranking and advisory sync suggestions.",
        );
        ui.small(
            "Effective merge precedence: global -> confirmed_agent_overlay -> project_override",
        );
        ui.horizontal(|ui| {
            if ui
                .button("Reload From Engine")
                .on_hover_text("Refresh all planning editor buffers from current project state")
                .clicked()
            {
                self.refresh_planning_editor_buffers_from_engine();
                self.planning_status = "Reloaded planning buffers from engine state".to_string();
            }
            if ui
                .button("Close")
                .on_hover_text("Close planning window")
                .clicked()
            {
                self.show_planning_dialog = false;
            }
        });
        ui.separator();

        ui.heading("Profiles");
        ui.small("Empty editor text means clear on Apply.");

        ui.label("Global profile");
        ui.add(
            egui::TextEdit::multiline(&mut self.planning_profile_global_json)
                .desired_rows(7)
                .desired_width(f32::INFINITY),
        );
        ui.horizontal(|ui| {
            if ui
                .button("Apply Global")
                .on_hover_text("Set planning profile scope 'global' from this JSON")
                .clicked()
            {
                let payload = self.planning_profile_global_json.clone();
                self.apply_planning_profile_json(PlanningProfileScope::Global, &payload);
            }
            if ui
                .button("Clear Global")
                .on_hover_text("Clear planning profile scope 'global'")
                .clicked()
            {
                self.clear_planning_profile_scope(PlanningProfileScope::Global);
            }
        });

        ui.separator();
        ui.label("Confirmed agent overlay profile");
        ui.add(
            egui::TextEdit::multiline(&mut self.planning_profile_overlay_json)
                .desired_rows(7)
                .desired_width(f32::INFINITY),
        );
        ui.horizontal(|ui| {
            if ui
                .button("Apply Agent Overlay")
                .on_hover_text(
                    "Set planning profile scope 'confirmed_agent_overlay' from this JSON",
                )
                .clicked()
            {
                let payload = self.planning_profile_overlay_json.clone();
                self.apply_planning_profile_json(
                    PlanningProfileScope::ConfirmedAgentOverlay,
                    &payload,
                );
            }
            if ui
                .button("Clear Agent Overlay")
                .on_hover_text("Clear planning profile scope 'confirmed_agent_overlay'")
                .clicked()
            {
                self.clear_planning_profile_scope(PlanningProfileScope::ConfirmedAgentOverlay);
            }
        });

        ui.separator();
        ui.label("Project override profile");
        ui.add(
            egui::TextEdit::multiline(&mut self.planning_profile_project_json)
                .desired_rows(7)
                .desired_width(f32::INFINITY),
        );
        ui.horizontal(|ui| {
            if ui
                .button("Apply Project Override")
                .on_hover_text("Set planning profile scope 'project_override' from this JSON")
                .clicked()
            {
                let payload = self.planning_profile_project_json.clone();
                self.apply_planning_profile_json(PlanningProfileScope::ProjectOverride, &payload);
            }
            if ui
                .button("Clear Project Override")
                .on_hover_text("Clear planning profile scope 'project_override'")
                .clicked()
            {
                self.clear_planning_profile_scope(PlanningProfileScope::ProjectOverride);
            }
        });

        ui.separator();
        ui.label("Effective profile (read-only)");
        let mut effective_profile_json = {
            let engine = self.engine.read().unwrap();
            Self::pretty_json_or_fallback(&engine.planning_effective_profile())
        };
        ui.add_enabled(
            false,
            egui::TextEdit::multiline(&mut effective_profile_json)
                .desired_rows(7)
                .desired_width(f32::INFINITY),
        );

        ui.separator();
        ui.heading("Objective");
        ui.add(
            egui::TextEdit::multiline(&mut self.planning_objective_json)
                .desired_rows(7)
                .desired_width(f32::INFINITY),
        );
        ui.horizontal(|ui| {
            if ui
                .button("Apply Objective")
                .on_hover_text("Set planning objective from this JSON")
                .clicked()
            {
                let payload = self.planning_objective_json.clone();
                self.apply_planning_objective_json(&payload);
            }
            if ui
                .button("Clear Objective")
                .on_hover_text("Clear planning objective and use engine defaults")
                .clicked()
            {
                self.clear_planning_objective();
            }
        });

        ui.separator();
        ui.heading("Sync Suggestions");
        ui.small(
            "Register advisory planning patches as pending pull/push suggestions before explicit accept/reject.",
        );
        ui.horizontal(|ui| {
            ui.label("source");
            ui.add(egui::TextEdit::singleline(&mut self.planning_sync_source).desired_width(180.0));
            ui.label("confidence");
            ui.add(
                egui::TextEdit::singleline(&mut self.planning_sync_confidence).desired_width(80.0),
            );
            ui.label("snapshot");
            ui.add(
                egui::TextEdit::singleline(&mut self.planning_sync_snapshot_id)
                    .desired_width(180.0),
            );
        });
        ui.horizontal(|ui| {
            ui.label("message");
            ui.add(
                egui::TextEdit::singleline(&mut self.planning_sync_message)
                    .desired_width(f32::INFINITY),
            );
        });
        ui.label("sync payload JSON ({ profile_patch?, objective_patch? })");
        ui.add(
            egui::TextEdit::multiline(&mut self.planning_sync_payload_json)
                .desired_rows(6)
                .desired_width(f32::INFINITY),
        );
        ui.horizontal(|ui| {
            if ui
                .button("Register Pull Suggestion")
                .on_hover_text("Create pending suggestion with direction=pull")
                .clicked()
            {
                self.register_planning_sync_suggestion("pull");
            }
            if ui
                .button("Register Push Suggestion")
                .on_hover_text("Create pending suggestion with direction=push")
                .clicked()
            {
                self.register_planning_sync_suggestion("push");
            }
        });

        ui.separator();
        ui.horizontal(|ui| {
            ui.label("suggestion filter");
            egui::ComboBox::from_id_salt("planning_suggestions_filter")
                .selected_text(Self::planning_filter_label(
                    self.planning_suggestions_filter,
                ))
                .show_ui(ui, |ui| {
                    ui.selectable_value(&mut self.planning_suggestions_filter, None, "all");
                    ui.selectable_value(
                        &mut self.planning_suggestions_filter,
                        Some(PlanningSuggestionStatus::Pending),
                        "pending",
                    );
                    ui.selectable_value(
                        &mut self.planning_suggestions_filter,
                        Some(PlanningSuggestionStatus::Accepted),
                        "accepted",
                    );
                    ui.selectable_value(
                        &mut self.planning_suggestions_filter,
                        Some(PlanningSuggestionStatus::Rejected),
                        "rejected",
                    );
                });
            ui.label("reject reason");
            ui.add(
                egui::TextEdit::singleline(&mut self.planning_rejection_reason)
                    .desired_width(260.0),
            );
        });
        let (sync_status, suggestions) = {
            let engine = self.engine.read().unwrap();
            (
                engine.planning_sync_status(),
                engine.list_planning_suggestions(self.planning_suggestions_filter),
            )
        };
        ui.small(format!(
            "sync status: pending={} | last_pull={:?} | last_push={:?} | source={} | snapshot={} | last_error={}",
            sync_status.pending_suggestion_count,
            sync_status.last_pull_at_unix_ms,
            sync_status.last_push_at_unix_ms,
            sync_status
                .last_source
                .as_deref()
                .unwrap_or("-"),
            sync_status
                .last_snapshot_id
                .as_deref()
                .unwrap_or("-"),
            sync_status.last_error.as_deref().unwrap_or("-")
        ));

        if suggestions.is_empty() {
            ui.small("No planning suggestions for this filter.");
        } else {
            let mut accept_id: Option<String> = None;
            let mut reject_id: Option<String> = None;
            egui::ScrollArea::vertical()
                .id_salt("planning_suggestions_scroll")
                .max_height(320.0)
                .show(ui, |ui| {
                    scroll_input_policy::apply_scrollarea_keyboard_navigation(
                        ui,
                        scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                    );
                    for suggestion in suggestions.iter().rev() {
                        ui.group(|ui| {
                            ui.horizontal_wrapped(|ui| {
                                ui.monospace(&suggestion.suggestion_id);
                                ui.label(format!("status={}", suggestion.status.as_str()));
                                ui.label(format!("direction={}", suggestion.direction));
                                ui.label(format!("source={}", suggestion.source));
                                if let Some(confidence) = suggestion.confidence {
                                    ui.label(format!("confidence={confidence:.2}"));
                                }
                                ui.label(format!("created={}", suggestion.created_at_unix_ms));
                                if let Some(resolved_at) = suggestion.resolved_at_unix_ms {
                                    ui.label(format!("resolved={resolved_at}"));
                                }
                            });
                            if let Some(message) = suggestion.message.as_deref() {
                                if !message.trim().is_empty() {
                                    ui.small(format!("message: {message}"));
                                }
                            }
                            if let Some(reason) = suggestion.rejection_reason.as_deref() {
                                if !reason.trim().is_empty() {
                                    ui.small(format!("rejection_reason: {reason}"));
                                }
                            }
                            let mut diff_json = Self::pretty_json_or_fallback(&suggestion.diff);
                            ui.add_enabled(
                                false,
                                egui::TextEdit::multiline(&mut diff_json)
                                    .desired_rows(4)
                                    .desired_width(f32::INFINITY),
                            );
                            if suggestion.status == PlanningSuggestionStatus::Pending {
                                ui.horizontal(|ui| {
                                    if ui
                                        .button("Accept")
                                        .on_hover_text(
                                            "Accept this suggestion and merge patch into active planning state",
                                        )
                                        .clicked()
                                    {
                                        accept_id = Some(suggestion.suggestion_id.clone());
                                    }
                                    if ui
                                        .button("Reject")
                                        .on_hover_text(
                                            "Reject this suggestion with optional reason text",
                                        )
                                        .clicked()
                                    {
                                        reject_id = Some(suggestion.suggestion_id.clone());
                                    }
                                });
                            }
                        });
                    }
                });
            if let Some(suggestion_id) = accept_id {
                self.accept_planning_suggestion(&suggestion_id);
            }
            if let Some(suggestion_id) = reject_id {
                self.reject_planning_suggestion(&suggestion_id);
            }
        }

        if !self.planning_status.trim().is_empty() {
            ui.separator();
            ui.monospace(self.planning_status.clone());
        }
    }

    fn render_planning_dialog(&mut self, ctx: &egui::Context) {
        if !self.show_planning_dialog {
            return;
        }
        let mut open = self.show_planning_dialog;
        let builder = egui::ViewportBuilder::default()
            .with_title("Planning")
            .with_inner_size([980.0, 760.0])
            .with_min_inner_size([700.0, 520.0]);
        ctx.show_viewport_immediate(Self::planning_viewport_id(), builder, |ctx, class| {
            self.note_viewport_focus_if_active(ctx, Self::planning_viewport_id());
            if class == egui::ViewportClass::Embedded {
                egui::Window::new("Planning")
                    .open(&mut open)
                    .collapsible(false)
                    .resizable(true)
                    .default_size(Vec2::new(980.0, 760.0))
                    .show(ctx, |ui| self.render_planning_contents(ui));
            } else {
                egui::CentralPanel::default().show(ctx, |ui| {
                    self.render_planning_contents(ui);
                });
                if Self::viewport_close_requested_or_shortcut(ctx) {
                    open = false;
                }
            }
        });
        if ctx.input(|i| i.key_pressed(Key::Escape)) {
            open = false;
        }
        self.show_planning_dialog = open;
    }

    fn render_routine_assistant_contents(&mut self, ui: &mut Ui) {
        self.render_specialist_window_nav(ui);
        ui.label(
            "Apply cloning routines through one staged flow driven by shared engine commands.",
        );
        ui.small(
            "Flow: goal -> candidate routines -> compare alternatives -> parameter bindings -> preflight -> transactional run -> run-bundle export",
        );
        ui.separator();

        let selected_routine = self.routine_assistant_selected_routine();
        let has_selected = selected_routine.is_some();
        let has_preflight = self.routine_assistant_preflight_output.is_some();
        let has_execute = self.routine_assistant_execute_output.is_some();

        let stage_order = [
            RoutineAssistantStage::GoalAndCandidates,
            RoutineAssistantStage::Compare,
            RoutineAssistantStage::Parameters,
            RoutineAssistantStage::Preflight,
            RoutineAssistantStage::ExecuteAndExport,
        ];
        ui.horizontal_wrapped(|ui| {
            for stage in stage_order {
                let enabled = match stage {
                    RoutineAssistantStage::GoalAndCandidates => true,
                    RoutineAssistantStage::Compare => has_selected,
                    RoutineAssistantStage::Parameters => has_selected,
                    RoutineAssistantStage::Preflight => has_preflight,
                    RoutineAssistantStage::ExecuteAndExport => has_execute,
                };
                let resp = ui.add_enabled(
                    enabled,
                    egui::Button::new(stage.label())
                        .selected(self.routine_assistant_stage == stage),
                );
                if resp.clicked() {
                    self.routine_assistant_stage = stage;
                }
            }
        });
        if !self.routine_assistant_status.trim().is_empty() {
            ui.separator();
            ui.monospace(self.routine_assistant_status.trim());
        }
        ui.separator();

        match self.routine_assistant_stage {
            RoutineAssistantStage::GoalAndCandidates => {
                ui.horizontal(|ui| {
                    ui.label("goal");
                    ui.text_edit_singleline(&mut self.routine_assistant_goal);
                });
                ui.horizontal(|ui| {
                    ui.label("query");
                    ui.text_edit_singleline(&mut self.routine_assistant_query);
                    if ui
                        .button("Find Candidates")
                        .on_hover_text(
                            "Query routine catalog by goal/query text and load candidate routines",
                        )
                        .clicked()
                    {
                        self.refresh_routine_assistant_candidates();
                    }
                    if ui
                        .button("Reset")
                        .on_hover_text("Clear selected routine and staged assistant outputs")
                        .clicked()
                    {
                        self.routine_assistant_selected_routine_id.clear();
                        self.routine_assistant_compare_routine_id.clear();
                        self.routine_assistant_bindings.clear();
                        self.routine_assistant_explain_output = None;
                        self.routine_assistant_compare_output = None;
                        self.routine_assistant_preflight_output = None;
                        self.routine_assistant_execute_output = None;
                        self.routine_assistant_stage = RoutineAssistantStage::GoalAndCandidates;
                        self.routine_assistant_status =
                            "Routine Assistant: reset staged state".to_string();
                    }
                });
                ui.separator();
                if self.routine_assistant_candidates.is_empty() {
                    ui.small("No routine candidates loaded. Use 'Find Candidates'.");
                } else {
                    let mut choose_routine: Option<String> = None;
                    egui::ScrollArea::vertical()
                        .max_height(360.0)
                        .show(ui, |ui| {
                            for routine in &self.routine_assistant_candidates {
                                ui.group(|ui| {
                                    ui.horizontal(|ui| {
                                        ui.strong(format!(
                                            "{} ({})",
                                            routine.title, routine.routine_id
                                        ));
                                        ui.label(format!(
                                            "[family: {}, status: {}]",
                                            routine.family, routine.status
                                        ));
                                        if ui
                                            .button("Select")
                                            .on_hover_text(
                                                "Choose this routine as primary candidate and move to alternative comparison",
                                            )
                                            .clicked()
                                        {
                                            choose_routine = Some(routine.routine_id.clone());
                                        }
                                    });
                                    if let Some(summary) = routine.summary.as_deref() {
                                        ui.small(summary);
                                    }
                                    if let Some(purpose) = routine.purpose.as_deref() {
                                        ui.small(format!("purpose: {purpose}"));
                                    }
                                });
                            }
                        });
                    if let Some(routine_id) = choose_routine {
                        self.routine_assistant_selected_routine_id = routine_id;
                        self.routine_assistant_compare_routine_id.clear();
                        self.routine_assistant_explain_output = None;
                        self.routine_assistant_compare_output = None;
                        self.routine_assistant_preflight_output = None;
                        self.routine_assistant_execute_output = None;
                        self.sync_routine_assistant_bindings_for_selected();
                        self.load_routine_assistant_explain();
                        self.routine_assistant_stage = RoutineAssistantStage::Compare;
                    }
                }
            }
            RoutineAssistantStage::Compare => {
                let Some(routine) = selected_routine else {
                    ui.small("Select a primary routine first in stage 1.");
                    return;
                };
                ui.strong(format!(
                    "Primary routine: {} ({})",
                    routine.title, routine.routine_id
                ));
                if let Some(summary) = routine.summary.as_deref() {
                    ui.small(summary);
                }
                ui.horizontal(|ui| {
                    if ui
                        .button("Reload Explanation")
                        .on_hover_text(
                            "Fetch routine explainability payload from shared routines explain command",
                        )
                        .clicked()
                    {
                        self.load_routine_assistant_explain();
                    }
                    if ui
                        .button("Continue to Parameters")
                        .on_hover_text("Proceed with typed parameter binding form")
                        .clicked()
                    {
                        self.routine_assistant_stage = RoutineAssistantStage::Parameters;
                    }
                });
                ui.separator();
                let alternatives = self
                    .routine_assistant_explain_output
                    .as_ref()
                    .and_then(|value| value.get("alternatives"))
                    .and_then(|value| value.as_array())
                    .cloned()
                    .unwrap_or_default();
                if alternatives.is_empty() {
                    ui.small("No explicit alternatives listed for this routine.");
                } else {
                    ui.horizontal(|ui| {
                        ui.label("compare against");
                        egui::ComboBox::from_id_salt("routine_assistant_compare_combo")
                            .selected_text(if self.routine_assistant_compare_routine_id.is_empty() {
                                "(select alternative)"
                            } else {
                                self.routine_assistant_compare_routine_id.as_str()
                            })
                            .show_ui(ui, |ui| {
                                for row in &alternatives {
                                    if let Some(routine_id) =
                                        row.get("routine_id").and_then(|value| value.as_str())
                                    {
                                        let title = row
                                            .get("title")
                                            .and_then(|value| value.as_str())
                                            .unwrap_or(routine_id);
                                        let label = format!("{title} ({routine_id})");
                                        if ui
                                            .selectable_label(
                                                self.routine_assistant_compare_routine_id
                                                    .eq_ignore_ascii_case(routine_id),
                                                label,
                                            )
                                            .clicked()
                                        {
                                            self.routine_assistant_compare_routine_id =
                                                routine_id.to_string();
                                        }
                                    }
                                }
                            });
                        if ui
                            .button("Compare")
                            .on_hover_text(
                                "Run shared routines compare command and display deterministic difference matrix",
                            )
                            .clicked()
                        {
                            self.load_routine_assistant_compare();
                        }
                    });
                }
                if let Some(compare) = &self.routine_assistant_compare_output {
                    ui.separator();
                    if let Some(rows) = compare
                        .get("comparison")
                        .and_then(|value| value.get("difference_matrix"))
                        .and_then(|value| value.as_array())
                    {
                        ui.strong("Difference matrix");
                        egui::Grid::new("routine_assistant_compare_grid")
                            .striped(true)
                            .show(ui, |ui| {
                                ui.strong("axis");
                                ui.strong("primary");
                                ui.strong("alternative");
                                ui.end_row();
                                for row in rows {
                                    let axis = row
                                        .get("axis")
                                        .and_then(|value| value.as_str())
                                        .unwrap_or("-");
                                    let left = row
                                        .get("left")
                                        .and_then(|value| value.as_str())
                                        .unwrap_or("-");
                                    let right = row
                                        .get("right")
                                        .and_then(|value| value.as_str())
                                        .unwrap_or("-");
                                    ui.monospace(axis);
                                    ui.label(left);
                                    ui.label(right);
                                    ui.end_row();
                                }
                            });
                    }
                }
            }
            RoutineAssistantStage::Parameters => {
                let Some(routine) = selected_routine else {
                    ui.small("Select a primary routine first in stage 1.");
                    return;
                };
                self.sync_routine_assistant_bindings_for_selected();
                ui.strong(format!(
                    "Template: {} (routine: {})",
                    routine.template_name, routine.routine_id
                ));
                if !routine.requires.is_empty() {
                    ui.label("requires");
                    for req in &routine.requires {
                        ui.small(format!("- {req}"));
                    }
                }
                self.render_routine_assistant_gibson_linearization_notice(ui, &routine);
                ui.separator();
                egui::Grid::new("routine_assistant_bindings_grid")
                    .striped(true)
                    .show(ui, |ui| {
                        ui.strong("input");
                        ui.strong("value");
                        ui.strong("type");
                        ui.end_row();
                        for port in &routine.input_ports {
                            let port_id = port
                                .get("port_id")
                                .and_then(|value| value.as_str())
                                .map(str::trim)
                                .unwrap_or("");
                            if port_id.is_empty() {
                                continue;
                            }
                            let kind = port
                                .get("kind")
                                .and_then(|value| value.as_str())
                                .unwrap_or("-");
                            let required = port
                                .get("required")
                                .and_then(|value| value.as_bool())
                                .unwrap_or(false);
                            let description = port
                                .get("description")
                                .and_then(|value| value.as_str())
                                .unwrap_or("");
                            let label = if required {
                                format!("{port_id} *")
                            } else {
                                port_id.to_string()
                            };
                            ui.label(label).on_hover_text(description);
                            let mut entry = self
                                .routine_assistant_bindings
                                .get(port_id)
                                .cloned()
                                .unwrap_or_default();
                            let edit_resp = ui.text_edit_singleline(&mut entry);
                            if edit_resp.changed() {
                                self.routine_assistant_bindings
                                    .insert(port_id.to_string(), entry.clone());
                                self.routine_assistant_preflight_output = None;
                                self.routine_assistant_execute_output = None;
                            }
                            if kind.eq_ignore_ascii_case("sequence") {
                                let compact = entry.trim();
                                let (type_text, text_color) = if compact.is_empty() {
                                    ("sequence".to_string(), egui::Color32::GRAY)
                                } else if let Some((circular, length_bp)) =
                                    self.routine_assistant_sequence_topology_for_seq_id(compact)
                                {
                                    if circular {
                                        (
                                            format!("sequence | circular | {length_bp} bp"),
                                            egui::Color32::from_rgb(190, 70, 70),
                                        )
                                    } else {
                                        (
                                            format!("sequence | linear | {length_bp} bp"),
                                            egui::Color32::from_rgb(70, 130, 80),
                                        )
                                    }
                                } else {
                                    (
                                        "sequence | missing".to_string(),
                                        egui::Color32::from_rgb(190, 70, 70),
                                    )
                                };
                                ui.label(
                                    egui::RichText::new(type_text).monospace().color(text_color),
                                );
                            } else {
                                ui.monospace(kind);
                            }
                            ui.end_row();
                        }
                    });
                ui.separator();
                ui.horizontal(|ui| {
                    if ui
                        .button("Back to Compare")
                        .on_hover_text("Return to routine alternative comparison")
                        .clicked()
                    {
                        self.routine_assistant_stage = RoutineAssistantStage::Compare;
                    }
                    if ui
                        .button("Run Preflight")
                        .on_hover_text(
                            "Run macros template-run --validate-only through shared shell executor",
                        )
                        .clicked()
                    {
                        self.run_routine_assistant_preflight();
                    }
                });
            }
            RoutineAssistantStage::Preflight => {
                if let Some(routine) = selected_routine {
                    self.render_routine_assistant_gibson_linearization_notice(ui, &routine);
                    ui.separator();
                }
                if let Some(output) = &self.routine_assistant_preflight_output {
                    let can_execute = output
                        .get("can_execute")
                        .and_then(|value| value.as_bool())
                        .unwrap_or(false);
                    ui.strong(format!(
                        "Preflight status: {}",
                        if can_execute {
                            "can execute"
                        } else {
                            "blocking errors"
                        }
                    ));
                    if let Some(preflight) = output.get("preflight") {
                        if let Some(errors) =
                            preflight.get("errors").and_then(|value| value.as_array())
                        {
                            if !errors.is_empty() {
                                ui.label("errors");
                                for err in errors {
                                    if let Some(text) = err.as_str() {
                                        ui.colored_label(
                                            egui::Color32::from_rgb(190, 70, 70),
                                            format!("- {text}"),
                                        );
                                    }
                                }
                            }
                        }
                        if let Some(warnings) =
                            preflight.get("warnings").and_then(|value| value.as_array())
                        {
                            if !warnings.is_empty() {
                                ui.label("warnings");
                                for warning in warnings {
                                    if let Some(text) = warning.as_str() {
                                        ui.small(format!("- {text}"));
                                    }
                                }
                            }
                        }
                    }
                } else {
                    ui.small("No preflight output yet. Run preflight in stage 3.");
                }
                ui.separator();
                ui.horizontal(|ui| {
                    if ui
                        .button("Back to Parameters")
                        .on_hover_text("Edit typed bindings before running again")
                        .clicked()
                    {
                        self.routine_assistant_stage = RoutineAssistantStage::Parameters;
                    }
                    let exec_resp = ui.add_enabled(
                        self.routine_assistant_can_execute(),
                        egui::Button::new("Run Transactional"),
                    );
                    if exec_resp
                        .on_hover_text(
                            "Execute macros template-run --transactional using current bindings",
                        )
                        .clicked()
                    {
                        self.run_routine_assistant_execute();
                    }
                });
            }
            RoutineAssistantStage::ExecuteAndExport => {
                if let Some(output) = &self.routine_assistant_execute_output {
                    let macro_instance = output
                        .get("macro_instance_id")
                        .and_then(|value| value.as_str())
                        .unwrap_or("-");
                    ui.strong("Transactional run completed");
                    ui.monospace(format!("macro_instance_id: {macro_instance}"));
                    if let Some(run) = output.get("run") {
                        let created = run
                            .get("created")
                            .and_then(|value| value.as_array())
                            .map(|rows| rows.len())
                            .unwrap_or(0);
                        let changed = run
                            .get("changed")
                            .and_then(|value| value.as_array())
                            .map(|rows| rows.len())
                            .unwrap_or(0);
                        ui.small(format!("created: {created}, changed: {changed}"));
                    }
                } else {
                    ui.small("No transactional run output yet.");
                }
                ui.separator();
                ui.horizontal(|ui| {
                    if ui
                        .button("Back to Preflight")
                        .on_hover_text("Inspect or re-run preflight checks")
                        .clicked()
                    {
                        self.routine_assistant_stage = RoutineAssistantStage::Preflight;
                    }
                    if ui
                        .button("Export Run Bundle")
                        .on_hover_text(
                            "Export deterministic process run bundle (inputs, parameter changes, operation log, outputs)",
                        )
                        .clicked()
                    {
                        self.export_routine_assistant_run_bundle();
                    }
                });
            }
        }
    }

    fn render_routine_assistant_dialog(&mut self, ctx: &egui::Context) {
        if !self.show_routine_assistant_dialog {
            return;
        }
        let mut open = self.show_routine_assistant_dialog;
        let builder = egui::ViewportBuilder::default()
            .with_title("Routine Assistant")
            .with_inner_size([980.0, 720.0])
            .with_min_inner_size([720.0, 480.0]);
        ctx.show_viewport_immediate(
            Self::routine_assistant_viewport_id(),
            builder,
            |ctx, class| {
                self.note_viewport_focus_if_active(ctx, Self::routine_assistant_viewport_id());
                if class == egui::ViewportClass::Embedded {
                    egui::Window::new("Routine Assistant")
                        .open(&mut open)
                        .collapsible(false)
                        .resizable(true)
                        .default_size(Vec2::new(980.0, 720.0))
                        .show(ctx, |ui| self.render_routine_assistant_contents(ui));
                } else {
                    egui::CentralPanel::default().show(ctx, |ui| {
                        self.render_routine_assistant_contents(ui);
                    });
                    if Self::viewport_close_requested_or_shortcut(ctx) {
                        open = false;
                    }
                }
            },
        );
        if ctx.input(|i| i.key_pressed(Key::Escape)) {
            open = false;
        }
        self.show_routine_assistant_dialog = open;
    }

    fn render_agent_assistant_contents(&mut self, ui: &mut Ui) {
        self.refresh_agent_system_catalog();
        self.render_specialist_window_nav(ui);
        ui.label("Ask an agent system for project support, then execute suggested GENtle shell commands per reply.");
        ui.horizontal(|ui| {
            ui.label("catalog");
            ui.text_edit_singleline(&mut self.agent_catalog_path);
            if ui
                .button("Browse...")
                .on_hover_text("Browse filesystem and fill this path")
                .clicked()
            {
                if let Some(path) = rfd::FileDialog::new()
                    .add_filter("JSON", &["json"])
                    .pick_file()
                {
                    self.agent_catalog_path = path.display().to_string();
                    self.agent_catalog_loaded_path.clear();
                    self.refresh_agent_system_catalog();
                }
            }
        });
        if !self.agent_catalog_error.is_empty() {
            ui.colored_label(
                egui::Color32::from_rgb(190, 70, 70),
                format!("Catalog error: {}", self.agent_catalog_error),
            );
        }
        ui.horizontal(|ui| {
            ui.label("system");
            egui::ComboBox::from_id_salt("agent_system_combo")
                .selected_text(if self.agent_system_id.trim().is_empty() {
                    "(choose system)"
                } else {
                    self.agent_system_id.as_str()
                })
                .show_ui(ui, |ui| {
                    for system in &self.agent_systems {
                        let (available, reason) = self.selected_agent_system_availability(system);
                        let label = if available {
                            format!("{} ({})", system.label, system.id)
                        } else {
                            format!("{} ({}) [unavailable]", system.label, system.id)
                        };
                        let mut response = ui.add(
                            egui::Button::new(label).selected(self.agent_system_id == system.id),
                        );
                        if !available {
                            response = response.on_hover_text(
                                reason.unwrap_or_else(|| "agent system unavailable".to_string()),
                            );
                        }
                        if response.clicked() {
                            self.agent_system_id = system.id.clone();
                        }
                    }
                });
        });
        let mut selected_available = false;
        if let Some(system) = self.selected_agent_system() {
            let (available, reason) = self.selected_agent_system_availability(&system);
            selected_available = available;
            if let Some(description) = system.description.as_deref() {
                let trimmed = description.trim();
                if !trimmed.is_empty() {
                    ui.small(trimmed);
                }
            }
            ui.small(format!("transport: {}", system.transport.as_str()));
            if !system.command.is_empty() {
                ui.small(format!("command: {}", system.command.join(" ")));
            }
            if matches!(
                system.transport,
                AgentSystemTransport::NativeOpenai | AgentSystemTransport::NativeOpenaiCompat
            ) {
                if let Some(source_key) = self.selected_agent_model_discovery_source_key(&system) {
                    if self.agent_model_discovery_source_key != source_key {
                        self.agent_model_discovery_source_key = source_key;
                        self.agent_model_discovery_task = None;
                        self.agent_discovered_models.clear();
                        self.agent_discovered_model_pick.clear();
                        self.agent_model_discovery_status.clear();
                    }
                    if normalize_agent_model_name(self.agent_model_override.trim()).is_none()
                        && self.agent_model_discovery_task.is_none()
                        && self.agent_discovered_models.is_empty()
                    {
                        self.start_agent_model_discovery_task(&system, false);
                    }
                }
                let catalog_base_url = system
                    .base_url
                    .as_deref()
                    .map(str::trim)
                    .filter(|value| !value.is_empty())
                    .unwrap_or("(transport default)");
                if self.agent_base_url_override.trim().is_empty() {
                    ui.small(format!("base URL: {catalog_base_url}"));
                } else {
                    ui.small(format!(
                        "base URL: {} (session override)",
                        self.agent_base_url_override.trim()
                    ));
                }
                let catalog_model = system
                    .model
                    .as_deref()
                    .map(str::trim)
                    .and_then(normalize_agent_model_name)
                    .unwrap_or_else(|| OPENAI_COMPAT_UNSPECIFIED_MODEL.to_string());
                let model_override = normalize_agent_model_name(self.agent_model_override.trim());
                if let Some(model_override) = model_override {
                    ui.small(format!("model: {model_override} (session override)"));
                } else if matches!(system.transport, AgentSystemTransport::NativeOpenaiCompat)
                    && normalize_agent_model_name(&self.agent_discovered_model_pick).is_some()
                {
                    ui.small(format!(
                        "model: {} (selected discovered model)",
                        self.agent_discovered_model_pick.trim()
                    ));
                } else {
                    ui.small(format!("model: {catalog_model}"));
                }
            } else {
                self.agent_model_discovery_task = None;
                self.agent_discovered_models.clear();
                self.agent_discovered_model_pick.clear();
                self.agent_model_discovery_source_key.clear();
                self.agent_model_discovery_status.clear();
            }
            if !available {
                ui.colored_label(
                    egui::Color32::from_rgb(190, 70, 70),
                    format!(
                        "Unavailable: {}",
                        reason.unwrap_or_else(|| "unknown reason".to_string())
                    ),
                );
            }
        } else if self.agent_systems.is_empty() {
            ui.small("No systems loaded from this catalog.");
        }
        ui.horizontal(|ui| {
            ui.label("OpenAI API key");
            ui.add(
                egui::TextEdit::singleline(&mut self.agent_openai_api_key)
                    .password(true)
                    .hint_text("sk-..."),
            );
            if ui
                .button("Clear Key")
                .on_hover_text("Clear session-only API key override")
                .clicked()
            {
                self.agent_openai_api_key.clear();
            }
        });
        ui.horizontal(|ui| {
            ui.label("Base URL override");
            ui.add(
                egui::TextEdit::singleline(&mut self.agent_base_url_override)
                    .hint_text("http://localhost:11964/v1"),
            );
            if ui
                .button("Clear URL")
                .on_hover_text("Clear session-only base URL override")
                .clicked()
            {
                self.agent_base_url_override.clear();
            }
        });
        ui.horizontal(|ui| {
            ui.label("Model override");
            ui.add(
                egui::TextEdit::singleline(&mut self.agent_model_override).hint_text("unspecified"),
            );
            if ui
                .button("Clear Model")
                .on_hover_text("Clear session-only model override")
                .clicked()
            {
                self.agent_model_override.clear();
            }
        });
        ui.horizontal(|ui| {
            ui.label("timeout_sec");
            ui.add(
                egui::TextEdit::singleline(&mut self.agent_timeout_secs)
                    .desired_width(100.0)
                    .hint_text("default"),
            );
            if ui
                .button("Clear Timeout")
                .on_hover_text("Use default timeout")
                .clicked()
            {
                self.agent_timeout_secs.clear();
            }
        });
        ui.horizontal(|ui| {
            ui.label("connect_timeout_sec");
            ui.add(
                egui::TextEdit::singleline(&mut self.agent_connect_timeout_secs)
                    .desired_width(90.0)
                    .hint_text("default"),
            );
            ui.label("read_timeout_sec");
            ui.add(
                egui::TextEdit::singleline(&mut self.agent_read_timeout_secs)
                    .desired_width(90.0)
                    .hint_text("default"),
            );
            if ui
                .button("Clear HTTP Timeouts")
                .on_hover_text("Use default connect/read timeouts")
                .clicked()
            {
                self.agent_connect_timeout_secs.clear();
                self.agent_read_timeout_secs.clear();
            }
        });
        ui.horizontal(|ui| {
            ui.label("max_retries");
            ui.add(
                egui::TextEdit::singleline(&mut self.agent_max_retries)
                    .desired_width(90.0)
                    .hint_text("default"),
            );
            ui.label("max_response_bytes");
            ui.add(
                egui::TextEdit::singleline(&mut self.agent_max_response_bytes)
                    .desired_width(120.0)
                    .hint_text("default"),
            );
            if ui
                .button("Clear Limits")
                .on_hover_text("Use default retry/response-size limits")
                .clicked()
            {
                self.agent_max_retries.clear();
                self.agent_max_response_bytes.clear();
            }
        });
        if let Some(system) = self.selected_agent_system() {
            if matches!(
                system.transport,
                AgentSystemTransport::NativeOpenai | AgentSystemTransport::NativeOpenaiCompat
            ) {
                ui.horizontal(|ui| {
                    if ui
                        .button("Discover Models")
                        .on_hover_text("Query local/server model list from current base URL")
                        .clicked()
                    {
                        self.start_agent_model_discovery_task(&system, true);
                    }
                    if let Some(task) = &self.agent_model_discovery_task {
                        ui.add(egui::Spinner::new());
                        ui.small(format!(
                            "Discovering models ({:.1}s)",
                            task.started.elapsed().as_secs_f32()
                        ));
                    }
                });
                if !self.agent_discovered_models.is_empty() {
                    ui.horizontal(|ui| {
                        ui.label("Discovered model");
                        egui::ComboBox::from_id_salt("agent_discovered_model_combo")
                            .selected_text(if self.agent_discovered_model_pick.trim().is_empty() {
                                "(choose model)"
                            } else {
                                self.agent_discovered_model_pick.as_str()
                            })
                            .show_ui(ui, |ui| {
                                for model in &self.agent_discovered_models {
                                    ui.selectable_value(
                                        &mut self.agent_discovered_model_pick,
                                        model.clone(),
                                        model,
                                    );
                                }
                            });
                    });
                    ui.small(
                        "If Model override is unspecified, the selected discovered model is used.",
                    );
                }
                if !self.agent_model_discovery_status.trim().is_empty() {
                    ui.small(self.agent_model_discovery_status.clone());
                }
            }
        }
        ui.small(
            "Session only: if set, this key overrides OPENAI_API_KEY for agent requests started from this GUI window.",
        );
        ui.small(
            "Session only: Base URL override applies to native_openai/native_openai_compat. For local roots (e.g. http://localhost:11964), GENtle tries /chat/completions and /v1/chat/completions on that same base URL.",
        );
        ui.small(
            "Session only: Model override applies to native_openai/native_openai_compat and maps to GENTLE_AGENT_MODEL. Value 'unspecified' means no override.",
        );
        ui.small(
            "Session only: timeout_sec maps to GENTLE_AGENT_TIMEOUT_SECS and applies to agent requests (stdio and native transports).",
        );
        ui.small(
            "Session only: connect_timeout_sec/read_timeout_sec map to GENTLE_AGENT_CONNECT_TIMEOUT_SECS/GENTLE_AGENT_READ_TIMEOUT_SECS.",
        );
        ui.small(
            "Session only: max_retries/max_response_bytes map to GENTLE_AGENT_MAX_RETRIES/GENTLE_AGENT_MAX_RESPONSE_BYTES.",
        );
        ui.horizontal(|ui| {
            ui.checkbox(
                &mut self.agent_include_state_summary,
                "Include project state summary in request",
            );
            ui.checkbox(
                &mut self.agent_allow_auto_exec,
                "Auto-run suggestions marked as 'auto'",
            );
        });
        if !agent_prompt_template_options()
            .iter()
            .any(|(id, _)| *id == self.agent_prompt_template_id)
        {
            self.agent_prompt_template_id = AGENT_PROMPT_TEMPLATE_DEFAULT_ID.to_string();
        }
        ui.horizontal(|ui| {
            ui.label("Prompt template");
            egui::ComboBox::from_id_salt("agent_prompt_template_combo")
                .selected_text(agent_prompt_template_label(&self.agent_prompt_template_id))
                .show_ui(ui, |ui| {
                    for (id, label) in agent_prompt_template_options() {
                        ui.selectable_value(
                            &mut self.agent_prompt_template_id,
                            (*id).to_string(),
                            *label,
                        );
                    }
                });
            if ui
                .button("Insert")
                .on_hover_text("Replace current prompt with selected template")
                .clicked()
            {
                self.agent_prompt =
                    agent_prompt_template_text(&self.agent_prompt_template_id).to_string();
            }
            if ui
                .button("Append")
                .on_hover_text("Append selected template below current prompt")
                .clicked()
            {
                let template_text = agent_prompt_template_text(&self.agent_prompt_template_id);
                if self.agent_prompt.trim().is_empty() {
                    self.agent_prompt = template_text.to_string();
                } else {
                    if !self.agent_prompt.ends_with('\n') {
                        self.agent_prompt.push('\n');
                    }
                    self.agent_prompt.push('\n');
                    self.agent_prompt.push_str(template_text);
                }
            }
        });
        ui.label("Prompt");
        ui.add(
            egui::TextEdit::multiline(&mut self.agent_prompt)
                .desired_rows(6)
                .desired_width(f32::INFINITY),
        );
        let running = self.agent_task.is_some();
        ui.horizontal(|ui| {
            if ui
                .add_enabled(
                    !running && selected_available,
                    egui::Button::new("Ask Agent"),
                )
                .on_hover_text("Send prompt to selected agent system")
                .clicked()
            {
                self.start_agent_assistant_request();
            }
            if ui
                .button("Clear Response")
                .on_hover_text("Clear latest agent response and status")
                .clicked()
            {
                self.agent_last_invocation = None;
                self.agent_status.clear();
            }
            if ui
                .button("Clear Execution Log")
                .on_hover_text("Clear local execution history for agent suggestions")
                .clicked()
            {
                self.agent_execution_log.clear();
            }
            if ui
                .button("Close")
                .on_hover_text("Close this dialog")
                .clicked()
            {
                self.show_agent_assistant_dialog = false;
            }
        });
        if let Some(task) = &self.agent_task {
            ui.horizontal(|ui| {
                ui.add(egui::Spinner::new());
                ui.label(format!(
                    "Agent request running ({:.1}s)",
                    task.started.elapsed().as_secs_f32()
                ));
            });
        }
        if !self.agent_status.is_empty() {
            ui.separator();
            ui.monospace(self.agent_status.clone());
        }

        if let Some(invocation) = self.agent_last_invocation.clone() {
            ui.separator();
            ui.label(format!(
                "Latest response from {} ({})",
                invocation.system_label, invocation.system_id
            ));
            ui.small(format!(
                "elapsed={} ms | transport={} | exit_code={:?}",
                invocation.elapsed_ms, invocation.transport, invocation.exit_code
            ));
            ui.small(format!(
                "runtime: timeout={}s | connect={:?}s | read={:?}s | max_retries={} | max_response_bytes={}",
                invocation.runtime.timeout_secs,
                invocation.runtime.connect_timeout_secs,
                invocation.runtime.read_timeout_secs,
                invocation.runtime.max_retries,
                invocation.runtime.max_response_bytes
            ));
            if !invocation.runtime.endpoint_candidates.is_empty() {
                ui.small(format!(
                    "endpoint candidates: {}",
                    invocation.runtime.endpoint_candidates.join(" | ")
                ));
            }
            if !invocation.runtime.attempted_endpoints.is_empty() {
                ui.small(format!(
                    "attempted endpoints: {}",
                    invocation.runtime.attempted_endpoints.join(" | ")
                ));
            }
            if let Some(selected_endpoint) = invocation.runtime.selected_endpoint.as_deref() {
                ui.small(format!("selected endpoint: {}", selected_endpoint));
            }
            if !invocation.response.assistant_message.trim().is_empty() {
                ui.group(|ui| {
                    ui.strong("Agent message");
                    ui.label(invocation.response.assistant_message.trim());
                });
            }
            if !invocation.response.questions.is_empty() {
                ui.group(|ui| {
                    ui.strong("Agent questions");
                    for question in &invocation.response.questions {
                        ui.label(format!("- {}", question));
                    }
                });
            }
            if invocation.response.suggested_commands.is_empty() {
                ui.small("No executable suggestions in this reply.");
            } else {
                ui.separator();
                ui.strong("Suggested commands");
                let mut run_request: Option<(usize, String)> = None;
                egui::Grid::new("agent_suggested_commands_grid")
                    .striped(true)
                    .show(ui, |ui| {
                        ui.strong("#");
                        ui.strong("Intent");
                        ui.strong("Command");
                        ui.strong("Rationale");
                        ui.strong("Action");
                        ui.end_row();
                        for (idx, suggestion) in invocation
                            .response
                            .suggested_commands
                            .iter()
                            .enumerate()
                        {
                            let index_1based = idx + 1;
                            ui.label(index_1based.to_string());
                            ui.label(suggestion.execution.as_str());
                            ui.monospace(suggestion.command.as_str());
                            ui.label(suggestion.rationale.clone().unwrap_or_default());
                            let can_run = !suggestion.command.trim().is_empty()
                                && suggestion.execution != AgentExecutionIntent::Chat;
                            let run_resp = ui
                                .add_enabled(can_run, egui::Button::new("Run"))
                                .on_hover_text(
                                    "Execute this suggested command using GENtle shared shell parser/executor",
                                );
                            if run_resp.clicked() {
                                run_request = Some((index_1based, suggestion.command.clone()));
                            }
                            ui.end_row();
                        }
                    });
                if let Some((index_1based, command)) = run_request {
                    self.execute_agent_suggested_command(index_1based, &command, "manual");
                }
            }
            if !invocation.raw_stderr.trim().is_empty() {
                ui.separator();
                ui.strong("Agent stderr");
                let mut stderr = invocation.raw_stderr.clone();
                ui.add(
                    egui::TextEdit::multiline(&mut stderr)
                        .desired_rows(4)
                        .desired_width(f32::INFINITY),
                );
            }
        }

        if !self.agent_execution_log.is_empty() {
            ui.separator();
            ui.strong("Execution log");
            egui::ScrollArea::vertical()
                .max_height(180.0)
                .show(ui, |ui| {
                    scroll_input_policy::apply_scrollarea_keyboard_navigation(
                        ui,
                        scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                    );
                    for entry in self.agent_execution_log.iter().rev() {
                        ui.label(format!(
                            "#{} [{}] {} | {} | changed={} | t={}",
                            entry.index_1based,
                            entry.trigger,
                            if entry.ok { "ok" } else { "error" },
                            entry.command,
                            entry.state_changed,
                            entry.executed_at_unix_ms
                        ));
                        ui.small(entry.summary.clone());
                    }
                });
        }
    }

    fn render_agent_assistant_dialog(&mut self, ctx: &egui::Context) {
        if !self.show_agent_assistant_dialog {
            return;
        }
        let builder = egui::ViewportBuilder::default()
            .with_title("Agent Assistant")
            .with_inner_size([980.0, 720.0])
            .with_min_inner_size([640.0, 420.0]);
        ctx.show_viewport_immediate(
            Self::agent_assistant_viewport_id(),
            builder,
            |ctx, class| {
                self.note_viewport_focus_if_active(ctx, Self::agent_assistant_viewport_id());
                if class == egui::ViewportClass::Embedded {
                    let mut open = self.show_agent_assistant_dialog;
                    egui::Window::new("Agent Assistant")
                        .open(&mut open)
                        .collapsible(false)
                        .resizable(true)
                        .default_size(Vec2::new(980.0, 720.0))
                        .show(ctx, |ui| self.render_agent_assistant_contents(ui));
                    self.show_agent_assistant_dialog = open;
                    return;
                }

                egui::CentralPanel::default().show(ctx, |ui| {
                    self.render_agent_assistant_contents(ui);
                });

                if Self::viewport_close_requested_or_shortcut(ctx) {
                    self.show_agent_assistant_dialog = false;
                }
            },
        );
    }

    fn refresh_project_restriction_enzymes(&mut self, resource_path: &str) -> Result<usize> {
        let enzymes = enzymes::load_restriction_enzymes_from_path(resource_path)?;
        let mut engine = self.engine.write().unwrap();
        for dna in engine.state_mut().sequences.values_mut() {
            enzymes.clone_into(dna.restriction_enzymes_mut());
            dna.update_computed_features();
        }
        Ok(enzymes.len())
    }

    fn prompt_import_rebase_resource(&mut self) {
        if let Some(path) = rfd::FileDialog::new()
            .add_filter("REBASE withrefm", &["txt", "withrefm", "f19", "f20", "f21"])
            .pick_file()
        {
            let input = path.display().to_string();
            match resource_sync::sync_rebase(
                &input,
                Some(resource_sync::DEFAULT_REBASE_RESOURCE_PATH),
                false,
            ) {
                Ok(report) => {
                    let seq_count = self.engine.read().unwrap().state().sequences.len();
                    let refresh_status = self.refresh_project_restriction_enzymes(&report.output);
                    match refresh_status {
                        Ok(loaded_count) => println!(
                            "Imported REBASE from '{}' ({} enzymes); active set now {} enzymes, refreshed {} sequence(s)",
                            report.source, report.item_count, loaded_count, seq_count
                        ),
                        Err(e) => eprintln!(
                            "Imported REBASE from '{}', but could not refresh loaded sequences: {}",
                            report.source, e
                        ),
                    }
                }
                Err(e) => eprintln!("Could not import REBASE from '{}': {}", input, e),
            }
        }
    }

    fn prompt_import_jaspar_resource(&mut self) {
        if let Some(path) = rfd::FileDialog::new()
            .add_filter("JASPAR motif matrix", &["txt", "jaspar", "pfm"])
            .pick_file()
        {
            let input = path.display().to_string();
            match resource_sync::sync_jaspar(
                &input,
                Some(resource_sync::DEFAULT_JASPAR_RESOURCE_PATH),
            ) {
                Ok(report) => {
                    tf_motifs::reload();
                    println!(
                        "Imported JASPAR from '{}' ({} motifs) to '{}'",
                        report.source, report.item_count, report.output
                    );
                }
                Err(e) => eprintln!("Could not import JASPAR from '{}': {}", input, e),
            }
        }
    }

    fn import_workflow_macro_templates_from_path(&mut self, path: &str) {
        let command = ShellCommand::MacrosTemplateImport {
            path: path.to_string(),
        };
        let options = ShellExecutionOptions::from_env();
        let run = {
            let mut engine = self.engine.write().expect("Engine lock poisoned");
            execute_shell_command_with_options(&mut engine, &command, &options)
        };
        match run {
            Ok(out) => {
                let imported_count = out
                    .output
                    .get("imported_count")
                    .and_then(|v| v.as_u64())
                    .unwrap_or(0);
                let source_file_count = out
                    .output
                    .get("source_files")
                    .and_then(|v| v.as_array())
                    .map(|rows| rows.len())
                    .unwrap_or(0);
                self.app_status = format!(
                    "Imported {imported_count} workflow macro template(s) from '{path}' ({source_file_count} source file(s))"
                );
            }
            Err(err) => {
                self.app_status = format!("Macro template import failed for '{path}': {err}");
            }
        }
    }

    fn prompt_import_workflow_macro_templates_file(&mut self) {
        if let Some(path) = rfd::FileDialog::new()
            .add_filter("JSON", &["json"])
            .pick_file()
        {
            self.import_workflow_macro_templates_from_path(&path.display().to_string());
        }
    }

    fn prompt_import_workflow_macro_templates_directory(&mut self) {
        if let Some(path) = rfd::FileDialog::new().pick_folder() {
            self.import_workflow_macro_templates_from_path(&path.display().to_string());
        }
    }

    fn humanize_catalog_label(raw: &str) -> String {
        let normalized = raw.replace('_', " ").replace('-', " ");
        let mut out_words = vec![];
        for word in normalized.split_whitespace() {
            let mut chars = word.chars();
            let Some(first) = chars.next() else {
                continue;
            };
            let mut out = first.to_uppercase().collect::<String>();
            out.push_str(chars.as_str());
            out_words.push(out);
        }
        if out_words.is_empty() {
            raw.to_string()
        } else {
            out_words.join(" ")
        }
    }

    fn collect_cloning_pattern_catalog_entries(
        root: &Path,
    ) -> Result<Vec<CloningPatternCatalogEntry>, String> {
        if !root.exists() {
            return Err(format!("Catalog path '{}' does not exist", root.display()));
        }
        if !root.is_dir() {
            return Err(format!(
                "Catalog path '{}' is not a directory",
                root.display()
            ));
        }
        Self::collect_cloning_pattern_catalog_entries_from_dir(root)
    }

    fn collect_cloning_pattern_catalog_entries_from_dir(
        dir: &Path,
    ) -> Result<Vec<CloningPatternCatalogEntry>, String> {
        let mut out = vec![];
        let mut entries = fs::read_dir(dir)
            .map_err(|e| format!("Could not read catalog directory '{}': {e}", dir.display()))?
            .filter_map(|entry| entry.ok())
            .collect::<Vec<_>>();
        entries.sort_by_key(|entry| entry.file_name().to_string_lossy().to_string());
        for entry in entries {
            let path = entry.path();
            if path.is_dir() {
                let children = Self::collect_cloning_pattern_catalog_entries_from_dir(&path)?;
                if children.is_empty() {
                    continue;
                }
                let label = Self::humanize_catalog_label(&entry.file_name().to_string_lossy());
                out.push(CloningPatternCatalogEntry {
                    label,
                    path: path.display().to_string(),
                    is_file: false,
                    children,
                });
                continue;
            }
            if !path
                .extension()
                .and_then(|ext| ext.to_str())
                .is_some_and(|ext| ext.eq_ignore_ascii_case("json"))
            {
                continue;
            }
            let stem = path
                .file_stem()
                .and_then(|s| s.to_str())
                .map(|s| s.to_string())
                .unwrap_or_else(|| entry.file_name().to_string_lossy().to_string());
            out.push(CloningPatternCatalogEntry {
                label: Self::humanize_catalog_label(&stem),
                path: path.display().to_string(),
                is_file: true,
                children: vec![],
            });
        }
        Ok(out)
    }

    fn render_cloning_pattern_catalog_menu_entries(
        ui: &mut Ui,
        entries: &[CloningPatternCatalogEntry],
        selected_path: &mut Option<String>,
    ) {
        for entry in entries {
            if entry.is_file {
                let response = ui
                    .button(entry.label.clone())
                    .on_hover_text(format!("Import macro template(s) from {}", entry.path));
                if response.clicked() {
                    *selected_path = Some(entry.path.clone());
                }
            } else {
                let label = format!("{}/", entry.label);
                ui.menu_button(label, |ui| {
                    Self::render_cloning_pattern_catalog_menu_entries(
                        ui,
                        &entry.children,
                        selected_path,
                    );
                });
            }
        }
    }

    fn execute_shared_shell_command_json(
        &mut self,
        command: &ShellCommand,
    ) -> std::result::Result<(serde_json::Value, bool), String> {
        let options = ShellExecutionOptions::from_env();
        let run = {
            let mut engine = self.engine.write().expect("Engine lock poisoned");
            execute_shell_command_with_options(&mut engine, command, &options)
        }?;
        if run.state_changed {
            self.lineage_cache_valid = false;
        }
        Ok((run.output, run.state_changed))
    }

    fn list_cloning_routines(
        &mut self,
        family: Option<&str>,
        status: Option<&str>,
        query: Option<&str>,
    ) -> std::result::Result<Vec<CloningRoutineCatalogRow>, String> {
        let command = ShellCommand::RoutinesList {
            catalog_path: Some(DEFAULT_CLONING_ROUTINE_CATALOG_PATH.to_string()),
            family: family
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(|value| value.to_string()),
            status: status
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(|value| value.to_string()),
            tag: None,
            query: query
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(|value| value.to_string()),
        };
        let (output, _) = self.execute_shared_shell_command_json(&command)?;
        let routines_json = output
            .get("routines")
            .cloned()
            .unwrap_or_else(|| serde_json::json!([]));
        serde_json::from_value::<Vec<CloningRoutineCatalogRow>>(routines_json)
            .map_err(|e| format!("Could not parse routine catalog output: {e}"))
    }

    fn refresh_routine_assistant_candidates(&mut self) {
        let query = self.routine_assistant_query.trim().to_string();
        let fallback = self.routine_assistant_goal.trim().to_string();
        let effective_query = if query.is_empty() { fallback } else { query };
        match self.list_cloning_routines(
            None,
            None,
            if effective_query.is_empty() {
                None
            } else {
                Some(effective_query.as_str())
            },
        ) {
            Ok(rows) => {
                self.routine_assistant_candidates = rows;
                if !self.routine_assistant_selected_routine_id.trim().is_empty()
                    && !self.routine_assistant_candidates.iter().any(|row| {
                        row.routine_id
                            .eq_ignore_ascii_case(self.routine_assistant_selected_routine_id.trim())
                    })
                {
                    self.routine_assistant_selected_routine_id.clear();
                    self.routine_assistant_compare_routine_id.clear();
                    self.routine_assistant_bindings.clear();
                    self.routine_assistant_explain_output = None;
                    self.routine_assistant_compare_output = None;
                    self.routine_assistant_preflight_output = None;
                    self.routine_assistant_execute_output = None;
                }
                self.routine_assistant_status = format!(
                    "Routine Assistant: loaded {} candidate routine(s)",
                    self.routine_assistant_candidates.len()
                );
            }
            Err(err) => {
                self.routine_assistant_candidates.clear();
                self.routine_assistant_status =
                    format!("Routine Assistant: could not list routines: {err}");
            }
        }
    }

    fn routine_assistant_selected_routine(&self) -> Option<CloningRoutineCatalogRow> {
        let selected_id = self.routine_assistant_selected_routine_id.trim();
        if selected_id.is_empty() {
            return None;
        }
        self.routine_assistant_candidates
            .iter()
            .find(|row| row.routine_id.eq_ignore_ascii_case(selected_id))
            .cloned()
    }

    fn routine_assistant_input_port_ids(routine: &CloningRoutineCatalogRow) -> Vec<String> {
        routine
            .input_ports
            .iter()
            .filter_map(|port| {
                port.get("port_id")
                    .and_then(|value| value.as_str())
                    .map(str::trim)
                    .filter(|value| !value.is_empty())
                    .map(|value| value.to_string())
            })
            .collect::<Vec<_>>()
    }

    fn routine_assistant_sequence_port_ids(routine: &CloningRoutineCatalogRow) -> Vec<String> {
        routine
            .input_ports
            .iter()
            .filter_map(|port| {
                let kind = port
                    .get("kind")
                    .and_then(|value| value.as_str())
                    .map(str::trim)
                    .unwrap_or("");
                if !kind.eq_ignore_ascii_case("sequence") {
                    return None;
                }
                port.get("port_id")
                    .and_then(|value| value.as_str())
                    .map(str::trim)
                    .filter(|value| !value.is_empty())
                    .map(|value| value.to_string())
            })
            .collect::<Vec<_>>()
    }

    fn routine_assistant_bound_sequence_topologies_for_routine(
        &self,
        routine: &CloningRoutineCatalogRow,
    ) -> Vec<RoutineAssistantBoundSequenceTopology> {
        let sequence_ports = Self::routine_assistant_sequence_port_ids(routine)
            .into_iter()
            .collect::<HashSet<_>>();
        if sequence_ports.is_empty() {
            return vec![];
        }
        let Ok(engine) = self.engine.read() else {
            return vec![];
        };
        self.routine_assistant_bindings
            .iter()
            .filter_map(|(port_id, value)| {
                if !sequence_ports.contains(port_id) {
                    return None;
                }
                let seq_id = value.trim();
                if seq_id.is_empty() {
                    return None;
                }
                let dna = engine.state().sequences.get(seq_id)?;
                Some(RoutineAssistantBoundSequenceTopology {
                    port_id: port_id.clone(),
                    seq_id: seq_id.to_string(),
                    circular: dna.is_circular(),
                    length_bp: dna.len(),
                })
            })
            .collect::<Vec<_>>()
    }

    fn routine_assistant_sequence_topology_for_seq_id(
        &self,
        seq_id: &str,
    ) -> Option<(bool, usize)> {
        let compact = seq_id.trim();
        if compact.is_empty() {
            return None;
        }
        let engine = self.engine.read().ok()?;
        let dna = engine.state().sequences.get(compact)?;
        Some((dna.is_circular(), dna.len()))
    }

    fn routine_assistant_is_gibson_family(routine: &CloningRoutineCatalogRow) -> bool {
        if routine.family.trim().eq_ignore_ascii_case("gibson") {
            return true;
        }
        let routine_id = routine.routine_id.to_ascii_lowercase();
        let template_name = routine.template_name.to_ascii_lowercase();
        routine_id.contains("gibson") || template_name.contains("gibson")
    }

    fn routine_assistant_gibson_circular_blocking_error(
        binding: &RoutineAssistantBoundSequenceTopology,
    ) -> String {
        format!(
            "Gibson requires linear fragments: binding '{}' on port '{}' is circular ({} bp).",
            binding.seq_id, binding.port_id, binding.length_bp
        )
    }

    fn routine_assistant_gibson_circular_blocking_preflight_output(
        &self,
        routine: &CloningRoutineCatalogRow,
        binding: &RoutineAssistantBoundSequenceTopology,
    ) -> serde_json::Value {
        let error = Self::routine_assistant_gibson_circular_blocking_error(binding);
        serde_json::json!({
            "schema": "gentle.macro_template_preflight.v1",
            "can_execute": false,
            "routine_id": routine.routine_id,
            "template_name": routine.template_name,
            "preflight": {
                "contract_source": "routine_assistant.gibson_linearization_guard.v1",
                "errors": [error],
                "warnings": [
                    "Use 'Linearize Vector...' to create a linear branch before preflight/execute."
                ]
            }
        })
    }

    fn routine_assistant_gibson_circular_binding_for_routine(
        &self,
        routine: &CloningRoutineCatalogRow,
    ) -> Option<RoutineAssistantBoundSequenceTopology> {
        if !Self::routine_assistant_is_gibson_family(routine) {
            return None;
        }
        let circular_inputs = self
            .routine_assistant_bound_sequence_topologies_for_routine(routine)
            .into_iter()
            .filter(|row| row.circular)
            .collect::<Vec<_>>();
        if circular_inputs.is_empty() {
            return None;
        }
        for preferred_port in ["vector_seq_id", "backbone_seq_id", "right_seq_id"] {
            if let Some(row) = circular_inputs
                .iter()
                .find(|row| row.port_id.eq_ignore_ascii_case(preferred_port))
            {
                return Some(row.clone());
            }
        }
        if let Some(row) = circular_inputs.iter().find(|row| {
            let lower = row.port_id.to_ascii_lowercase();
            lower.contains("vector") || lower.contains("backbone")
        }) {
            return Some(row.clone());
        }
        circular_inputs.into_iter().next()
    }

    fn render_routine_assistant_gibson_linearization_notice(
        &mut self,
        ui: &mut Ui,
        routine: &CloningRoutineCatalogRow,
    ) {
        let Some(binding) = self.routine_assistant_gibson_circular_binding_for_routine(routine)
        else {
            return;
        };
        let error = Self::routine_assistant_gibson_circular_blocking_error(&binding);
        ui.group(|ui| {
            ui.colored_label(egui::Color32::from_rgb(190, 70, 70), error);
            ui.small(
                "One-click fix: create a branched copy, force linear topology, and re-bind this input.",
            );
            if ui
                .button("Linearize Vector...")
                .on_hover_text(
                    "Create a branched linear copy of the bound circular sequence and rebind this Gibson input to that copy.",
                )
                .clicked()
            {
                let port_id = binding.port_id.clone();
                let seq_id = binding.seq_id.clone();
                match self.routine_assistant_linearize_binding_sequence(&port_id, &seq_id) {
                    Ok(new_id) => {
                        self.routine_assistant_status = format!(
                            "Routine Assistant: linearized '{}' as '{}' and rebound '{}'",
                            seq_id, new_id, port_id
                        );
                    }
                    Err(err) => {
                        self.routine_assistant_status =
                            format!("Routine Assistant linearization failed: {err}");
                    }
                }
            }
        });
    }

    fn routine_assistant_linearize_binding_sequence(
        &mut self,
        port_id: &str,
        seq_id: &str,
    ) -> std::result::Result<String, String> {
        let compact_port = port_id.trim();
        if compact_port.is_empty() {
            return Err("Linearize Vector requires a non-empty binding port".to_string());
        }
        let compact_seq = seq_id.trim();
        if compact_seq.is_empty() {
            return Err("Linearize Vector requires a non-empty sequence ID".to_string());
        }
        let (exists, is_circular) = {
            let engine = self
                .engine
                .read()
                .map_err(|_| "Engine lock poisoned while checking sequence topology".to_string())?;
            match engine.state().sequences.get(compact_seq) {
                Some(dna) => (true, dna.is_circular()),
                None => (false, false),
            }
        };
        if !exists {
            return Err(format!(
                "Linearize Vector could not find sequence '{}'",
                compact_seq
            ));
        }
        if !is_circular {
            return Err(format!(
                "Sequence '{}' is already linear; no linearization needed",
                compact_seq
            ));
        }

        let suggested_id = format!("{}_linear", compact_seq);
        let branch_payload = serde_json::to_string(&Operation::Branch {
            input: compact_seq.to_string(),
            output_id: Some(suggested_id.clone()),
        })
        .map_err(|e| format!("Could not serialize Branch operation: {e}"))?;
        let (branch_output, branch_changed) =
            self.execute_shared_shell_command_json(&ShellCommand::Op {
                payload: branch_payload,
            })?;
        if !branch_changed {
            return Err("Linearize Vector branch operation did not change state".to_string());
        }
        let created_id = branch_output
            .get("result")
            .and_then(|value| value.get("created_seq_ids"))
            .and_then(|value| value.as_array())
            .and_then(|rows| rows.first())
            .and_then(|row| row.as_str())
            .map(|value| value.to_string())
            .unwrap_or(suggested_id);

        let topo_payload = serde_json::to_string(&Operation::SetTopology {
            seq_id: created_id.clone(),
            circular: false,
        })
        .map_err(|e| format!("Could not serialize SetTopology operation: {e}"))?;
        let (_topology_output, topology_changed) =
            self.execute_shared_shell_command_json(&ShellCommand::Op {
                payload: topo_payload,
            })?;
        if !topology_changed {
            return Err(format!(
                "Linearize Vector could not set linear topology for '{}'",
                created_id
            ));
        }

        self.routine_assistant_bindings
            .insert(compact_port.to_string(), created_id.clone());
        self.routine_assistant_preflight_output = None;
        self.routine_assistant_execute_output = None;
        Ok(created_id)
    }

    fn sync_routine_assistant_bindings_for_selected(&mut self) {
        let Some(routine) = self.routine_assistant_selected_routine() else {
            self.routine_assistant_bindings.clear();
            return;
        };
        let allowed = Self::routine_assistant_input_port_ids(&routine)
            .into_iter()
            .collect::<HashSet<_>>();
        self.routine_assistant_bindings
            .retain(|key, _| allowed.contains(key));
        for key in allowed {
            self.routine_assistant_bindings.entry(key).or_default();
        }
    }

    fn routine_assistant_bindings_compact(&self) -> HashMap<String, String> {
        self.routine_assistant_bindings
            .iter()
            .filter_map(|(key, value)| {
                let compact = value.trim();
                if compact.is_empty() {
                    None
                } else {
                    Some((key.clone(), compact.to_string()))
                }
            })
            .collect::<HashMap<_, _>>()
    }

    fn load_routine_assistant_explain(&mut self) {
        let selected_id = self
            .routine_assistant_selected_routine_id
            .trim()
            .to_string();
        if selected_id.is_empty() {
            self.routine_assistant_status =
                "Routine Assistant: select a primary routine first".to_string();
            return;
        }
        let command = ShellCommand::RoutinesExplain {
            catalog_path: Some(DEFAULT_CLONING_ROUTINE_CATALOG_PATH.to_string()),
            routine_id: selected_id.clone(),
        };
        match self.execute_shared_shell_command_json(&command) {
            Ok((output, _)) => {
                self.routine_assistant_explain_output = Some(output.clone());
                if self.routine_assistant_compare_routine_id.trim().is_empty() {
                    if let Some(alt_id) = output
                        .get("alternatives")
                        .and_then(|value| value.as_array())
                        .and_then(|rows| rows.first())
                        .and_then(|row| row.get("routine_id"))
                        .and_then(|value| value.as_str())
                    {
                        self.routine_assistant_compare_routine_id = alt_id.trim().to_string();
                    }
                }
                self.routine_assistant_status =
                    format!("Routine Assistant: loaded explanation for '{selected_id}'");
            }
            Err(err) => {
                self.routine_assistant_status = format!("Routine Assistant explain failed: {err}");
            }
        }
    }

    fn load_routine_assistant_compare(&mut self) {
        let left = self
            .routine_assistant_selected_routine_id
            .trim()
            .to_string();
        let right = self.routine_assistant_compare_routine_id.trim().to_string();
        if left.is_empty() || right.is_empty() {
            self.routine_assistant_status =
                "Routine Assistant: select both primary and comparison routines".to_string();
            return;
        }
        let command = ShellCommand::RoutinesCompare {
            catalog_path: Some(DEFAULT_CLONING_ROUTINE_CATALOG_PATH.to_string()),
            left_routine_id: left.clone(),
            right_routine_id: right.clone(),
        };
        match self.execute_shared_shell_command_json(&command) {
            Ok((output, _)) => {
                self.routine_assistant_compare_output = Some(output);
                self.routine_assistant_status =
                    format!("Routine Assistant: compared '{left}' vs '{right}'");
            }
            Err(err) => {
                self.routine_assistant_status = format!("Routine Assistant compare failed: {err}");
            }
        }
    }

    fn ensure_routine_assistant_template_imported(
        &mut self,
        routine: &CloningRoutineCatalogRow,
    ) -> std::result::Result<(), String> {
        let Some(path) = routine
            .template_path
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
        else {
            return Err(format!(
                "Routine '{}' has no template_path configured",
                routine.routine_id
            ));
        };
        let command = ShellCommand::MacrosTemplateImport {
            path: path.to_string(),
        };
        self.execute_shared_shell_command_json(&command).map(|_| ())
    }

    fn run_routine_assistant_preflight(&mut self) {
        let Some(routine) = self.routine_assistant_selected_routine() else {
            self.routine_assistant_status =
                "Routine Assistant: select a routine before preflight".to_string();
            return;
        };
        if let Some(binding) = self.routine_assistant_gibson_circular_binding_for_routine(&routine)
        {
            self.routine_assistant_preflight_output = Some(
                self.routine_assistant_gibson_circular_blocking_preflight_output(
                    &routine, &binding,
                ),
            );
            self.routine_assistant_execute_output = None;
            self.routine_assistant_stage = RoutineAssistantStage::Preflight;
            self.routine_assistant_status = format!(
                "Routine Assistant preflight blocked: '{}' on '{}' is circular",
                binding.seq_id, binding.port_id
            );
            return;
        }
        if let Err(err) = self.ensure_routine_assistant_template_imported(&routine) {
            self.routine_assistant_status = format!("Routine Assistant preflight failed: {err}");
            return;
        }
        let command = ShellCommand::MacrosTemplateRun {
            name: routine.template_name.clone(),
            bindings: self.routine_assistant_bindings_compact(),
            transactional: false,
            validate_only: true,
        };
        match self.execute_shared_shell_command_json(&command) {
            Ok((output, _)) => {
                self.routine_assistant_preflight_output = Some(output.clone());
                self.routine_assistant_execute_output = None;
                self.routine_assistant_stage = RoutineAssistantStage::Preflight;
                let can_execute = output
                    .get("can_execute")
                    .and_then(|value| value.as_bool())
                    .unwrap_or(false);
                self.routine_assistant_status = if can_execute {
                    "Routine Assistant: preflight passed".to_string()
                } else {
                    "Routine Assistant: preflight reported blocking errors".to_string()
                };
            }
            Err(err) => {
                self.routine_assistant_status =
                    format!("Routine Assistant preflight failed: {err}");
            }
        }
    }

    fn run_routine_assistant_execute(&mut self) {
        let Some(routine) = self.routine_assistant_selected_routine() else {
            self.routine_assistant_status =
                "Routine Assistant: select a routine before execution".to_string();
            return;
        };
        if let Some(binding) = self.routine_assistant_gibson_circular_binding_for_routine(&routine)
        {
            self.routine_assistant_preflight_output = Some(
                self.routine_assistant_gibson_circular_blocking_preflight_output(
                    &routine, &binding,
                ),
            );
            self.routine_assistant_execute_output = None;
            self.routine_assistant_stage = RoutineAssistantStage::Preflight;
            self.routine_assistant_status = format!(
                "Routine Assistant execution blocked: '{}' on '{}' is circular",
                binding.seq_id, binding.port_id
            );
            return;
        }
        if let Err(err) = self.ensure_routine_assistant_template_imported(&routine) {
            self.routine_assistant_status = format!("Routine Assistant execution failed: {err}");
            return;
        }
        let command = ShellCommand::MacrosTemplateRun {
            name: routine.template_name.clone(),
            bindings: self.routine_assistant_bindings_compact(),
            transactional: true,
            validate_only: false,
        };
        match self.execute_shared_shell_command_json(&command) {
            Ok((output, _)) => {
                self.routine_assistant_execute_output = Some(output);
                self.routine_assistant_stage = RoutineAssistantStage::ExecuteAndExport;
                self.routine_assistant_status =
                    "Routine Assistant: transactional run completed".to_string();
            }
            Err(err) => {
                self.routine_assistant_status =
                    format!("Routine Assistant execution failed: {err}");
            }
        }
    }

    fn export_routine_assistant_run_bundle(&mut self) {
        let Some(path) = rfd::FileDialog::new()
            .set_file_name("run_bundle.routine_assistant.json")
            .add_filter("JSON", &["json"])
            .save_file()
        else {
            self.routine_assistant_status =
                "Routine Assistant: run-bundle export canceled".to_string();
            return;
        };
        let path_text = path.display().to_string();
        let command = ShellCommand::ExportRunBundle {
            output: path_text.clone(),
            run_id: None,
        };
        match self.execute_shared_shell_command_json(&command) {
            Ok(_) => {
                self.routine_assistant_status =
                    format!("Routine Assistant: exported run bundle to '{path_text}'");
            }
            Err(err) => {
                self.routine_assistant_status = format!(
                    "Routine Assistant: could not export run bundle '{}': {}",
                    path_text, err
                );
            }
        }
    }

    fn routine_assistant_can_execute(&self) -> bool {
        self.routine_assistant_preflight_output
            .as_ref()
            .and_then(|value| value.get("can_execute"))
            .and_then(|value| value.as_bool())
            .unwrap_or(false)
    }

    fn render_cloning_routine_menu_entries(
        ui: &mut Ui,
        routines: &[CloningRoutineCatalogRow],
        selected_template_path: &mut Option<String>,
        status_message: &mut Option<String>,
    ) {
        for routine in routines {
            let label = format!("{} [{}]", routine.title, routine.status);
            let tags = if routine.vocabulary_tags.is_empty() {
                "-".to_string()
            } else {
                routine.vocabulary_tags.join(", ")
            };
            let template_path = routine
                .template_path
                .as_deref()
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .unwrap_or("-");
            let details_url = routine
                .details_url
                .as_deref()
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .unwrap_or("-");
            let hover = format!(
                "routine_id: {}\nfamily: {}\nstatus: {}\ntemplate: {}\ntemplate_path: {}\ndetails_url: {}\ninput_ports: {}\noutput_ports: {}\ntags: {}\n{}",
                routine.routine_id,
                routine.family,
                routine.status,
                routine.template_name,
                template_path,
                details_url,
                routine.input_ports.len(),
                routine.output_ports.len(),
                tags,
                routine.summary.as_deref().unwrap_or("No summary")
            );
            let response = ui.button(label).on_hover_text(hover);
            if response.clicked() {
                if let Some(path) = routine
                    .template_path
                    .as_deref()
                    .map(str::trim)
                    .filter(|value| !value.is_empty())
                {
                    *selected_template_path = Some(path.to_string());
                    *status_message = Some(format!(
                        "Importing template '{}' for routine '{}'",
                        routine.template_name, routine.routine_id
                    ));
                } else {
                    *status_message = Some(format!(
                        "Routine '{}' uses template '{}' (no template_path specified)",
                        routine.routine_id, routine.template_name
                    ));
                }
            }
        }
    }

    fn save_current_project(&mut self) -> bool {
        if let Some(path) = self.current_project_path.clone() {
            if self.save_project_to_file(&path).is_ok() {
                self.record_recent_project_path(&path);
                self.mark_clean_snapshot();
                return true;
            }
            return false;
        }

        if let Some(path) = rfd::FileDialog::new()
            .set_file_name("project.gentle.json")
            .add_filter("GENtle project", &["json"])
            .save_file()
        {
            let path = path.display().to_string();
            if self.save_project_to_file(&path).is_ok() {
                self.set_current_project_path_and_track_recent(&path);
                self.mark_clean_snapshot();
                return true;
            }
        }
        false
    }

    fn execute_project_action(&mut self, action: ProjectAction) {
        match action {
            ProjectAction::New => self.new_project(),
            ProjectAction::Open => self.prompt_open_project(),
            ProjectAction::OpenPath(path) => self.open_project_path(&path),
            ProjectAction::OpenTutorialChapter(chapter_id) => {
                self.open_tutorial_project_chapter(&chapter_id)
            }
            ProjectAction::Close => self.close_project(),
        }
    }

    fn request_project_action(&mut self, action: ProjectAction) {
        if self.project_has_user_content() && self.is_project_dirty() {
            self.pending_project_action = Some(action);
        } else {
            self.execute_project_action(action);
        }
    }

    fn new_project(&mut self) {
        self.reset_to_empty_project();
    }

    fn close_project(&mut self) {
        self.reset_to_empty_project();
    }

    fn load_project_from_file_with_recent(&mut self, path: &str, track_recent: bool) -> Result<()> {
        let state = ProjectState::load_from_path(path).map_err(|e| anyhow!(e.to_string()))?;

        self.engine = Arc::new(RwLock::new(GentleEngine::from_state(state)));
        self.set_current_project_path(path, track_recent);
        self.lineage_cache_valid = false;
        self.lineage_rows.clear();
        self.lineage_edges.clear();
        self.lineage_op_label_by_id.clear();
        self.lineage_containers.clear();
        self.lineage_arrangements.clear();
        self.lineage_main_split_fraction = DEFAULT_LINEAGE_MAIN_SPLIT_FRACTION;
        self.lineage_graph_zoom = 1.0;
        self.lineage_graph_area_height = 420.0;
        self.lineage_container_area_height = 220.0;
        self.lineage_container_arrangement_split_fraction =
            DEFAULT_LINEAGE_CONTAINER_ARRANGEMENT_SPLIT_FRACTION;
        self.lineage_graph_scroll_offset = Vec2::ZERO;
        self.lineage_graph_pan_origin = None;
        self.lineage_graph_compact_labels = true;
        self.lineage_main_split_drag_origin = None;
        self.lineage_main_split_drag_start_y = None;
        self.lineage_container_arrangement_split_drag_origin = None;
        self.lineage_container_arrangement_split_drag_start_y = None;
        self.lineage_graph_selected_node_id = None;
        self.lineage_graph_node_offsets.clear();
        self.lineage_graph_drag_origin = None;
        self.lineage_graph_offsets_synced_stamp = 0;
        self.tracked_autosync_last_op_count = None;
        self.new_windows.clear();
        self.windows.clear();
        self.windows_to_close.write().unwrap().clear();
        self.pending_focus_viewports.clear();
        self.show_routine_assistant_dialog = false;
        self.routine_assistant_stage = RoutineAssistantStage::GoalAndCandidates;
        self.routine_assistant_goal.clear();
        self.routine_assistant_query.clear();
        self.routine_assistant_candidates.clear();
        self.routine_assistant_selected_routine_id.clear();
        self.routine_assistant_compare_routine_id.clear();
        self.routine_assistant_bindings.clear();
        self.routine_assistant_explain_output = None;
        self.routine_assistant_compare_output = None;
        self.routine_assistant_preflight_output = None;
        self.routine_assistant_execute_output = None;
        self.routine_assistant_status.clear();
        self.agent_task = None;
        self.agent_model_discovery_task = None;
        self.agent_status.clear();
        self.agent_last_invocation = None;
        self.agent_execution_log.clear();
        self.agent_discovered_models.clear();
        self.agent_discovered_model_pick.clear();
        self.agent_model_discovery_status.clear();
        self.agent_model_discovery_source_key.clear();
        self.load_bed_track_subscriptions_from_state();
        self.load_lineage_graph_workspace_from_state();
        self.load_background_job_history_from_state();

        self.mark_clean_snapshot();
        Ok(())
    }

    fn load_project_from_file(&mut self, path: &str) -> Result<()> {
        self.load_project_from_file_with_recent(path, true)
    }

    fn current_project_name(&self) -> String {
        match &self.current_project_path {
            Some(path) => Path::new(path)
                .file_name()
                .map(|s| s.to_string_lossy().to_string())
                .unwrap_or_else(|| path.clone()),
            None => "Untitled Project".to_string(),
        }
    }

    fn load_lineage_graph_workspace_from_state(&mut self) {
        let (workspace_serialized, legacy_offsets_serialized, legacy_groups_serialized) = {
            let engine = self.engine.read().unwrap();
            let metadata = &engine.state().metadata;
            (
                metadata.get(LINEAGE_GRAPH_WORKSPACE_METADATA_KEY).cloned(),
                metadata.get(LINEAGE_NODE_OFFSETS_METADATA_KEY).cloned(),
                metadata.get(LINEAGE_NODE_GROUPS_METADATA_KEY).cloned(),
            )
        };

        self.lineage_graph_zoom = 1.0;
        self.lineage_main_split_fraction = DEFAULT_LINEAGE_MAIN_SPLIT_FRACTION;
        self.lineage_graph_area_height = 420.0;
        self.lineage_container_area_height = 220.0;
        self.lineage_container_arrangement_split_fraction =
            DEFAULT_LINEAGE_CONTAINER_ARRANGEMENT_SPLIT_FRACTION;
        self.lineage_graph_scroll_offset = Vec2::ZERO;
        self.lineage_graph_pan_origin = None;
        self.lineage_graph_compact_labels = true;
        self.lineage_main_split_drag_origin = None;
        self.lineage_main_split_drag_start_y = None;
        self.lineage_container_arrangement_split_drag_origin = None;
        self.lineage_container_arrangement_split_drag_start_y = None;
        self.lineage_graph_selected_node_id = None;
        self.lineage_graph_node_offsets.clear();
        self.lineage_node_groups.clear();
        if let Some(serialized) = workspace_serialized {
            if let Ok(workspace) =
                serde_json::from_value::<PersistedLineageGraphWorkspace>(serialized)
            {
                if workspace.zoom.is_finite() {
                    self.lineage_graph_zoom = workspace.zoom.clamp(0.35, 4.0);
                }
                let mut loaded_main_split_fraction = workspace
                    .main_split_fraction
                    .filter(|value| value.is_finite())
                    .map(|value| value.clamp(0.2, 0.9));
                if workspace.graph_area_height.is_finite() {
                    self.lineage_graph_area_height =
                        workspace.graph_area_height.clamp(280.0, 2400.0);
                }
                if workspace.container_area_height.is_finite() {
                    self.lineage_container_area_height =
                        workspace.container_area_height.clamp(120.0, 1600.0);
                }
                if loaded_main_split_fraction.is_none() {
                    let combined_height =
                        self.lineage_graph_area_height + self.lineage_container_area_height;
                    if combined_height.is_finite() && combined_height > 1.0 {
                        loaded_main_split_fraction = Some(
                            (self.lineage_graph_area_height / combined_height).clamp(0.2, 0.9),
                        );
                    }
                }
                if let Some(main_split_fraction) = loaded_main_split_fraction {
                    self.lineage_main_split_fraction = main_split_fraction;
                }
                if let Some(container_arrangement_split_fraction) = workspace
                    .container_arrangement_split_fraction
                    .filter(|value| value.is_finite())
                    .map(|value| value.clamp(0.2, 0.8))
                {
                    self.lineage_container_arrangement_split_fraction =
                        container_arrangement_split_fraction;
                }
                if workspace.scroll_offset[0].is_finite() && workspace.scroll_offset[1].is_finite()
                {
                    self.lineage_graph_scroll_offset = Vec2::new(
                        workspace.scroll_offset[0].max(0.0),
                        workspace.scroll_offset[1].max(0.0),
                    );
                }
                self.lineage_graph_compact_labels = workspace.compact_labels;
                for (node_id, pair) in workspace.node_offsets {
                    if pair[0].is_finite() && pair[1].is_finite() {
                        self.lineage_graph_node_offsets
                            .insert(node_id, Vec2::new(pair[0], pair[1]));
                    }
                }
                self.lineage_node_groups = workspace.node_groups;
            }
        } else if let Some(serialized) = legacy_offsets_serialized {
            if let Ok(raw) = serde_json::from_value::<HashMap<String, [f32; 2]>>(serialized) {
                for (node_id, pair) in raw {
                    if pair[0].is_finite() && pair[1].is_finite() {
                        self.lineage_graph_node_offsets
                            .insert(node_id, Vec2::new(pair[0], pair[1]));
                    }
                }
            }
        }
        if self.lineage_node_groups.is_empty() {
            if let Some(serialized) = legacy_groups_serialized {
                if let Ok(groups) =
                    serde_json::from_value::<Vec<PersistedLineageNodeGroup>>(serialized)
                {
                    self.lineage_node_groups = groups;
                }
            }
        }
        self.lineage_graph_drag_origin = None;
        self.lineage_graph_offsets_synced_stamp = 0;
        self.lineage_group_form_editing_id = None;
        self.lineage_group_form_label.clear();
        self.lineage_group_form_members.clear();
        self.lineage_group_form_representative.clear();
        self.lineage_group_status.clear();
        self.lineage_group_marked_nodes.clear();
        self.lineage_node_rename_target_id = None;
        self.lineage_node_rename_text.clear();
        self.lineage_node_remove_target_id = None;
    }

    fn persist_lineage_graph_workspace_to_state(&mut self) {
        let mut raw: HashMap<String, [f32; 2]> = HashMap::new();
        for (node_id, offset) in &self.lineage_graph_node_offsets {
            if offset.x.is_finite() && offset.y.is_finite() {
                raw.insert(node_id.clone(), [offset.x, offset.y]);
            }
        }

        let workspace = PersistedLineageGraphWorkspace {
            main_split_fraction: Some(self.lineage_main_split_fraction.clamp(0.2, 0.9)),
            container_arrangement_split_fraction: Some(
                self.lineage_container_arrangement_split_fraction
                    .clamp(0.2, 0.8),
            ),
            zoom: self.lineage_graph_zoom.clamp(0.35, 4.0),
            graph_area_height: self.lineage_graph_area_height.clamp(280.0, 2400.0),
            container_area_height: self.lineage_container_area_height.clamp(120.0, 1600.0),
            scroll_offset: [
                self.lineage_graph_scroll_offset.x.max(0.0),
                self.lineage_graph_scroll_offset.y.max(0.0),
            ],
            compact_labels: self.lineage_graph_compact_labels,
            node_offsets: raw.clone(),
            node_groups: self.lineage_node_groups.clone(),
        };

        let workspace_is_default = (workspace.zoom - 1.0).abs() <= 0.0001
            && (workspace
                .main_split_fraction
                .unwrap_or(DEFAULT_LINEAGE_MAIN_SPLIT_FRACTION)
                - DEFAULT_LINEAGE_MAIN_SPLIT_FRACTION)
                .abs()
                <= 0.0001
            && (workspace.graph_area_height - 420.0).abs() <= 0.0001
            && (workspace.container_area_height - 220.0).abs() <= 0.0001
            && (workspace
                .container_arrangement_split_fraction
                .unwrap_or(DEFAULT_LINEAGE_CONTAINER_ARRANGEMENT_SPLIT_FRACTION)
                - DEFAULT_LINEAGE_CONTAINER_ARRANGEMENT_SPLIT_FRACTION)
                .abs()
                <= 0.0001
            && workspace.scroll_offset[0].abs() <= 0.0001
            && workspace.scroll_offset[1].abs() <= 0.0001
            && workspace.compact_labels
            && workspace.node_offsets.is_empty()
            && workspace.node_groups.is_empty();

        let mut engine = self.engine.write().unwrap();
        let state = engine.state_mut();
        if workspace_is_default {
            state.metadata.remove(LINEAGE_GRAPH_WORKSPACE_METADATA_KEY);
        } else if let Ok(value) = serde_json::to_value(&workspace) {
            if state.metadata.get(LINEAGE_GRAPH_WORKSPACE_METADATA_KEY) != Some(&value) {
                state
                    .metadata
                    .insert(LINEAGE_GRAPH_WORKSPACE_METADATA_KEY.to_string(), value);
            }
        }

        if raw.is_empty() {
            state.metadata.remove(LINEAGE_NODE_OFFSETS_METADATA_KEY);
        } else if let Ok(value) = serde_json::to_value(raw) {
            if state.metadata.get(LINEAGE_NODE_OFFSETS_METADATA_KEY) != Some(&value) {
                state
                    .metadata
                    .insert(LINEAGE_NODE_OFFSETS_METADATA_KEY.to_string(), value);
            }
        }
        if self.lineage_node_groups.is_empty() {
            state.metadata.remove(LINEAGE_NODE_GROUPS_METADATA_KEY);
        } else if let Ok(value) = serde_json::to_value(&self.lineage_node_groups) {
            if state.metadata.get(LINEAGE_NODE_GROUPS_METADATA_KEY) != Some(&value) {
                state
                    .metadata
                    .insert(LINEAGE_NODE_GROUPS_METADATA_KEY.to_string(), value);
            }
        }
    }

    fn collect_open_window_entries(&self) -> Vec<OpenWindowEntry> {
        let mut entries = vec![OpenWindowEntry {
            native_menu_key: Self::native_menu_key_for_viewport(ViewportId::ROOT),
            viewport_id: ViewportId::ROOT,
            title: format!("Main Window — {}", self.current_project_name()),
            detail: "Project workspace".to_string(),
        }];

        if self.show_configuration_dialog {
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(
                    Self::configuration_viewport_id(),
                ),
                viewport_id: Self::configuration_viewport_id(),
                title: "Configuration".to_string(),
                detail: "External tools and graphics defaults".to_string(),
            });
        }
        if self.show_help_dialog {
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(Self::help_viewport_id()),
                viewport_id: Self::help_viewport_id(),
                title: format!("Help — {}", self.active_help_title()),
                detail: "GUI/CLI manual".to_string(),
            });
        }
        if self.show_command_palette_dialog {
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(
                    Self::command_palette_viewport_id(),
                ),
                viewport_id: Self::command_palette_viewport_id(),
                title: "Command Palette".to_string(),
                detail: "Action launcher".to_string(),
            });
        }
        if self.show_history_panel {
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(Self::history_viewport_id()),
                viewport_id: Self::history_viewport_id(),
                title: "Operation History".to_string(),
                detail: "Undo/redo operation log".to_string(),
            });
        }
        if self.show_reference_genome_prepare_dialog {
            let scope = self.genome_dialog_scope;
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(
                    Self::prepare_genome_viewport_id(),
                ),
                viewport_id: Self::prepare_genome_viewport_id(),
                title: scope.prepare_title().to_string(),
                detail: format!("{} preparation", scope.description()),
            });
        }
        if self.show_reference_genome_retrieve_dialog {
            let scope = self.genome_dialog_scope;
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(
                    Self::retrieve_genome_viewport_id(),
                ),
                viewport_id: Self::retrieve_genome_viewport_id(),
                title: scope.retrieve_title().to_string(),
                detail: format!(
                    "Gene/region extraction from prepared {} indices",
                    scope.description()
                ),
            });
        }
        if self.show_reference_genome_blast_dialog {
            let scope = self.genome_dialog_scope;
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(
                    Self::blast_genome_viewport_id(),
                ),
                viewport_id: Self::blast_genome_viewport_id(),
                title: scope.blast_title().to_string(),
                detail: format!("BLAST against prepared {} indices", scope.description()),
            });
        }
        if self.show_genome_bed_track_dialog {
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(Self::bed_track_viewport_id()),
                viewport_id: Self::bed_track_viewport_id(),
                title: "Import Genome Tracks".to_string(),
                detail: "Import BED/BigWig/VCF track overlays".to_string(),
            });
        }
        if self.show_planning_dialog {
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(Self::planning_viewport_id()),
                viewport_id: Self::planning_viewport_id(),
                title: "Planning".to_string(),
                detail: "Planning profiles/objectives and sync suggestions".to_string(),
            });
        }
        if self.show_routine_assistant_dialog {
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(
                    Self::routine_assistant_viewport_id(),
                ),
                viewport_id: Self::routine_assistant_viewport_id(),
                title: "Routine Assistant".to_string(),
                detail: "Staged routine selection, preflight, and execution".to_string(),
            });
        }
        if self.show_agent_assistant_dialog {
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(
                    Self::agent_assistant_viewport_id(),
                ),
                viewport_id: Self::agent_assistant_viewport_id(),
                title: "Agent Assistant".to_string(),
                detail: "Agent chat and per-reply command execution".to_string(),
            });
        }
        if self.show_uniprot_dialog {
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(Self::uniprot_viewport_id()),
                viewport_id: Self::uniprot_viewport_id(),
                title: "UniProt Mapping".to_string(),
                detail: "UniProt entry fetch/import/projection tools".to_string(),
            });
        }
        if self.show_genbank_dialog {
            entries.push(OpenWindowEntry {
                native_menu_key: Self::native_menu_key_for_viewport(Self::genbank_viewport_id()),
                viewport_id: Self::genbank_viewport_id(),
                title: "GenBank Accession Fetch".to_string(),
                detail: "GenBank accession fetch/import tool".to_string(),
            });
        }

        let mut sequence_windows = self
            .windows
            .iter()
            .map(|(viewport_id, window)| {
                let title = window
                    .read()
                    .map(|w| w.name())
                    .unwrap_or_else(|_| "Sequence window".to_string());
                OpenWindowEntry {
                    native_menu_key: Self::native_menu_key_for_viewport(*viewport_id),
                    viewport_id: *viewport_id,
                    title,
                    detail: "Sequence map window".to_string(),
                }
            })
            .collect::<Vec<_>>();
        sequence_windows.sort_by(|left, right| left.title.cmp(&right.title));
        entries.extend(sequence_windows);

        let mut auxiliary_windows = Vec::new();
        for window in self.windows.values() {
            let Ok(window_guard) = window.read() else {
                continue;
            };
            for (viewport_id, title, detail) in window_guard.collect_open_auxiliary_window_entries()
            {
                auxiliary_windows.push(OpenWindowEntry {
                    native_menu_key: Self::native_menu_key_for_viewport(viewport_id),
                    viewport_id,
                    title,
                    detail,
                });
            }
        }
        auxiliary_windows.sort_by(|left, right| {
            left.title
                .cmp(&right.title)
                .then(left.detail.cmp(&right.detail))
        });
        entries.extend(auxiliary_windows);
        entries
    }

    fn focus_window_viewport(&mut self, ctx: &egui::Context, viewport_id: ViewportId) {
        if viewport_id == Self::configuration_viewport_id() {
            self.show_configuration_dialog = true;
        } else if viewport_id == Self::help_viewport_id() {
            self.show_help_dialog = true;
        } else if viewport_id == Self::command_palette_viewport_id() {
            self.show_command_palette_dialog = true;
            self.command_palette_focus_query = true;
        } else if viewport_id == Self::history_viewport_id() {
            self.show_history_panel = true;
        } else if viewport_id == Self::prepare_genome_viewport_id() {
            self.show_reference_genome_prepare_dialog = true;
        } else if viewport_id == Self::retrieve_genome_viewport_id() {
            self.show_reference_genome_retrieve_dialog = true;
        } else if viewport_id == Self::blast_genome_viewport_id() {
            self.show_reference_genome_blast_dialog = true;
        } else if viewport_id == Self::bed_track_viewport_id() {
            self.show_genome_bed_track_dialog = true;
        } else if viewport_id == Self::planning_viewport_id() {
            self.show_planning_dialog = true;
        } else if viewport_id == Self::routine_assistant_viewport_id() {
            self.show_routine_assistant_dialog = true;
        } else if viewport_id == Self::agent_assistant_viewport_id() {
            self.show_agent_assistant_dialog = true;
        } else if viewport_id == Self::uniprot_viewport_id() {
            self.show_uniprot_dialog = true;
        } else if viewport_id == Self::genbank_viewport_id() {
            self.show_genbank_dialog = true;
        }

        ctx.send_viewport_cmd_to(viewport_id, egui::ViewportCommand::Visible(true));
        ctx.send_viewport_cmd_to(viewport_id, egui::ViewportCommand::Focus);
        self.set_active_window_viewport(viewport_id);
    }

    fn render_specialist_window_nav(&mut self, ui: &mut Ui) {
        ui.horizontal(|ui| {
            if ui
                .button("Help")
                .on_hover_text("Open GUI help (F1 on Windows/Linux, Cmd+Shift+/ on macOS)")
                .clicked()
            {
                self.open_help_doc(HelpDoc::Gui);
            }
            if ui
                .button("Main")
                .on_hover_text("Bring the main project window to front")
                .clicked()
            {
                self.queue_focus_viewport(ViewportId::ROOT);
            }
        });
        ui.separator();
    }

    pub fn render_menu_bar(&mut self, ui: &mut Ui) {
        let open_window_entries = self.collect_open_window_entries();
        self.native_window_key_to_viewport = open_window_entries
            .iter()
            .map(|entry| (entry.native_menu_key, entry.viewport_id))
            .collect();
        let native_window_entries = open_window_entries
            .iter()
            .map(|entry| (entry.native_menu_key, entry.title.clone()))
            .collect::<Vec<_>>();
        let active_window_key = self
            .active_window_menu_key
            .or_else(|| Some(Self::native_menu_key_for_viewport(ViewportId::ROOT)));
        if self.last_native_window_entries != native_window_entries
            || self.last_native_active_window_key != active_window_key
        {
            if !self.native_window_menu_sync_blocked_by_open_probe() {
                let sync_started = Instant::now();
                about::sync_native_open_windows_menu(&native_window_entries, active_window_key);
                let sync_elapsed_ms = sync_started.elapsed().as_millis();
                if sync_elapsed_ms >= WINDOW_OPEN_SLOW_THRESHOLD_MS {
                    self.app_status = format!(
                        "Native windows menu sync took {sync_elapsed_ms} ms (entries={})",
                        native_window_entries.len()
                    );
                }
                self.last_native_window_entries = native_window_entries;
                self.last_native_active_window_key = active_window_key;
            }
        }
        let (undo_count, redo_count) = {
            let engine = self.engine.read().expect("Engine lock poisoned");
            (engine.undo_available(), engine.redo_available())
        };
        let history_ops_enabled = !self.has_active_background_jobs();
        egui::MenuBar::new().ui(ui, |ui| {
            ui.menu_button("File", |ui| {
                if ui
                    .button("New Project")
                    .on_hover_text("Create a new empty project state")
                    .clicked()
                {
                    self.request_project_action(ProjectAction::New);
                    ui.close();
                }
                if ui
                    .button("Open Project...")
                    .on_hover_text("Open an existing .gentle.json project")
                    .clicked()
                {
                    self.request_project_action(ProjectAction::Open);
                    ui.close();
                }
                ui.menu_button("Open Recent Project...", |ui| {
                    if self.recent_project_paths.is_empty() {
                        ui.add_enabled(false, egui::Button::new("No recent projects"));
                        return;
                    }

                    let recent_paths = self.recent_project_paths.clone();
                    let mut selected_recent_path: Option<String> = None;
                    for path in recent_paths {
                        let exists = Path::new(&path).is_file();
                        let mut label = Self::recent_project_menu_label(&path);
                        if !exists {
                            label.push_str(" [missing]");
                        }
                        let clicked = ui
                            .add_enabled(exists, egui::Button::new(label))
                            .on_hover_text(path.clone())
                            .clicked();
                        if clicked {
                            selected_recent_path = Some(path);
                        }
                    }

                    ui.separator();
                    if ui
                        .button("Clear Recent Projects")
                        .on_hover_text("Remove all items from Open Recent Project menu")
                        .clicked()
                    {
                        self.clear_recent_project_paths();
                        ui.close();
                        return;
                    }

                    if let Some(path) = selected_recent_path {
                        self.request_project_action(ProjectAction::OpenPath(path));
                        ui.close();
                    }
                });
                ui.menu_button("Open Tutorial Project...", |ui| {
                    let entries = match Self::load_tutorial_project_entries() {
                        Ok(entries) => entries,
                        Err(err) => {
                            ui.label("Tutorial catalog unavailable");
                            ui.small(err);
                            return;
                        }
                    };
                    if entries.is_empty() {
                        ui.add_enabled(false, egui::Button::new("No tutorial chapters"));
                        return;
                    }

                    let mut selected_chapter_id: Option<String> = None;
                    for tier in [
                        TutorialTier::Core,
                        TutorialTier::Advanced,
                        TutorialTier::Online,
                    ] {
                        let tier_entries = entries
                            .iter()
                            .filter(|entry| entry.tier == tier)
                            .collect::<Vec<_>>();
                        if tier_entries.is_empty() {
                            continue;
                        }
                        let tier_label = match tier {
                            TutorialTier::Core => "Core",
                            TutorialTier::Advanced => "Advanced",
                            TutorialTier::Online => "Online",
                        };
                        ui.menu_button(format!("{tier_label} ({})", tier_entries.len()), |ui| {
                            for entry in tier_entries {
                                let mut label =
                                    format!("{:02}. {}", entry.chapter_order, entry.chapter_title);
                                if entry.example.test_mode == ExampleTestMode::Online {
                                    label.push_str(" [online]");
                                }
                                let hover = format!(
                                    "chapter_id: {}\nexample_id: {}\ntier: {}\n{}",
                                    entry.chapter_id,
                                    entry.example.id,
                                    tier.as_str(),
                                    if entry.chapter_summary.trim().is_empty() {
                                        "No summary provided."
                                    } else {
                                        entry.chapter_summary.trim()
                                    }
                                );
                                if ui.button(label).on_hover_text(hover).clicked() {
                                    selected_chapter_id = Some(entry.chapter_id.clone());
                                }
                            }
                        });
                    }

                    if let Some(chapter_id) = selected_chapter_id {
                        self.request_project_action(ProjectAction::OpenTutorialChapter(chapter_id));
                        ui.close();
                    }
                });
                if ui
                    .add_enabled(self.can_close_project(), egui::Button::new("Close Project"))
                    .on_hover_text("Close the current project from the workspace")
                    .clicked()
                {
                    self.request_project_action(ProjectAction::Close);
                    ui.close();
                }
                ui.separator();
                if ui
                    .button("Open Sequence...")
                    .on_hover_text("Import a sequence file into the current project")
                    .clicked()
                {
                    self.prompt_open_sequence();
                    ui.close();
                }
                if ui
                    .button("UniProt Mapping...")
                    .on_hover_text(
                        "Fetch/import UniProt SWISS-PROT entries and map them onto sequences",
                    )
                    .clicked()
                {
                    self.open_uniprot_dialog();
                    ui.close();
                }
                if ui
                    .button("Fetch GenBank Accession...")
                    .on_hover_text("Fetch one GenBank accession and import it as a sequence")
                    .clicked()
                {
                    self.open_genbank_dialog();
                    ui.close();
                }
                ui.separator();
                if ui
                    .button("Configuration...")
                    .on_hover_text("Open global app configuration and graphics defaults")
                    .clicked()
                {
                    self.open_configuration_dialog();
                    ui.close();
                }
                if ui
                    .button("Agent Assistant...")
                    .on_hover_text(
                        "Ask configured agent systems and execute suggested shared-shell commands",
                    )
                    .clicked()
                {
                    self.open_agent_assistant_dialog();
                    ui.close();
                }
                if ui
                    .button("Import REBASE Data...")
                    .on_hover_text("Import restriction-enzyme definitions from REBASE JSON/TXT")
                    .clicked()
                {
                    self.prompt_import_rebase_resource();
                    ui.close();
                }
                if ui
                    .button("Import JASPAR Data...")
                    .on_hover_text("Import TF motif library from JASPAR JSON/TXT")
                    .clicked()
                {
                    self.prompt_import_jaspar_resource();
                    ui.close();
                }
                if ui
                    .button("Save Project...")
                    .on_hover_text("Save current project state to disk")
                    .clicked()
                {
                    self.prompt_save_project();
                    ui.close();
                }
                if ui
                    .button("Export DALG SVG...")
                    .on_hover_text("Export lineage graph as SVG")
                    .clicked()
                {
                    self.prompt_export_lineage_svg();
                    ui.close();
                }
            });
            ui.menu_button("Edit", |ui| {
                let undo_resp = self.track_hover_status(
                    ui.add_enabled(
                        history_ops_enabled && undo_count > 0,
                        egui::Button::new("Undo"),
                    )
                    .on_hover_text("Undo the most recent operation-level state change"),
                    "Edit > Undo",
                );
                if undo_resp.clicked() {
                    self.undo_last_operation();
                    ui.close();
                }
                let redo_resp = self.track_hover_status(
                    ui.add_enabled(
                        history_ops_enabled && redo_count > 0,
                        egui::Button::new("Redo"),
                    )
                    .on_hover_text("Redo the most recently undone operation"),
                    "Edit > Redo",
                );
                if redo_resp.clicked() {
                    self.redo_last_operation();
                    ui.close();
                }
                if !history_ops_enabled {
                    ui.small("Undo/redo disabled while background jobs are running.");
                } else {
                    ui.small(format!("Undo {undo_count} | Redo {redo_count}"));
                }
                ui.separator();
                let palette_resp = self.track_hover_status(
                    ui.button("Command Palette...")
                        .on_hover_text("Open searchable command palette (Cmd/Ctrl+K)"),
                    "Edit > Command Palette",
                );
                if palette_resp.clicked() {
                    self.open_command_palette_dialog();
                    ui.close();
                }
                let history_resp = self.track_hover_status(
                    ui.button("Operation History...")
                        .on_hover_text("Show operation history with undo/redo controls"),
                    "Edit > Operation History",
                );
                if history_resp.clicked() {
                    self.show_history_panel = true;
                    ui.close();
                }
            });
            ui.menu_button("Settings", |ui| {
                if ui
                    .button("Configuration...")
                    .on_hover_text("Open global app configuration and graphics defaults")
                    .clicked()
                {
                    self.open_configuration_dialog();
                    ui.close();
                }
            });
            ui.menu_button("Genome", |ui| {
                if ui
                    .button("Prepare Reference Genome...")
                    .on_hover_text(
                        "Download/index a reference genome for local extraction and BLAST",
                    )
                    .clicked()
                {
                    self.open_reference_genome_prepare_dialog();
                    ui.close();
                }
                if ui
                    .button("Prepared References...")
                    .on_hover_text("Inspect prepared reference/helper genome installations")
                    .clicked()
                {
                    self.open_reference_genome_inspector_dialog();
                    ui.close();
                }
                if ui
                    .button("Retrieve Genomic Sequence...")
                    .on_hover_text(
                        "Extract anchored region/gene sequence from a prepared reference",
                    )
                    .clicked()
                {
                    self.open_reference_genome_retrieve_dialog();
                    ui.close();
                }
                if ui
                    .button("BLAST Genome Sequence...")
                    .on_hover_text("Run BLAST against prepared reference genome indices")
                    .clicked()
                {
                    self.open_reference_genome_blast_dialog();
                    ui.close();
                }
                if ui
                    .button("Import Genome Track...")
                    .on_hover_text("Import BED/BigWig/VCF tracks onto anchored sequences")
                    .clicked()
                {
                    self.open_genome_bed_track_dialog();
                    ui.close();
                }
                ui.separator();
                if ui
                    .button("Prepare Helper Genome...")
                    .on_hover_text("Prepare helper catalog genomes for extraction and BLAST")
                    .clicked()
                {
                    self.open_helper_genome_prepare_dialog();
                    ui.close();
                }
                if ui
                    .button("Retrieve Helper Sequence...")
                    .on_hover_text("Extract sequence from prepared helper genomes")
                    .clicked()
                {
                    self.open_helper_genome_retrieve_dialog();
                    ui.close();
                }
                if ui
                    .button("BLAST Helper Sequence...")
                    .on_hover_text("Run BLAST against prepared helper genome indices")
                    .clicked()
                {
                    self.open_helper_genome_blast_dialog();
                    ui.close();
                }
            });
            ui.menu_button("Patterns", |ui| {
                if ui
                    .button("Import Pattern File...")
                    .on_hover_text("Import workflow macro templates from one JSON pattern file")
                    .clicked()
                {
                    self.prompt_import_workflow_macro_templates_file();
                    ui.close();
                }
                if ui
                    .button("Import Pattern Folder...")
                    .on_hover_text(
                        "Import workflow macro templates from all JSON files in one folder tree",
                    )
                    .clicked()
                {
                    self.prompt_import_workflow_macro_templates_directory();
                    ui.close();
                }
                if ui
                    .button("Import Built-in Legacy Pack")
                    .on_hover_text("Import templates from assets/cloning_patterns.json")
                    .clicked()
                {
                    self.import_workflow_macro_templates_from_path(
                        DEFAULT_CLONING_PATTERN_PACK_PATH,
                    );
                    ui.close();
                }
                ui.separator();

                let catalog_root = Path::new(DEFAULT_CLONING_PATTERN_CATALOG_DIR);
                match Self::collect_cloning_pattern_catalog_entries(catalog_root) {
                    Ok(entries) => {
                        if entries.is_empty() {
                            ui.add_enabled(false, egui::Button::new("Catalog is empty"));
                        } else {
                            if ui
                                .button("Import Full Catalog")
                                .on_hover_text(format!(
                                    "Import all catalog templates from {}",
                                    catalog_root.display()
                                ))
                                .clicked()
                            {
                                self.import_workflow_macro_templates_from_path(
                                    &catalog_root.display().to_string(),
                                );
                                ui.close();
                            }
                            ui.separator();
                            ui.small("Catalog hierarchy");
                            let mut selected_path: Option<String> = None;
                            Self::render_cloning_pattern_catalog_menu_entries(
                                ui,
                                &entries,
                                &mut selected_path,
                            );
                            if let Some(path) = selected_path {
                                self.import_workflow_macro_templates_from_path(&path);
                                ui.close();
                            }
                        }
                    }
                    Err(err) => {
                        ui.add_enabled(false, egui::Button::new("Catalog unavailable"));
                        ui.small(err);
                    }
                }

                ui.separator();
                if ui
                    .button("Routine Assistant...")
                    .on_hover_text(
                        "Open staged routine-selection workflow (goal, compare, parameters, preflight, run, export)",
                    )
                    .clicked()
                {
                    self.open_routine_assistant_dialog();
                    ui.close();
                }
                if ui
                    .button("Planning...")
                    .on_hover_text(
                        "Open planning profiles/objective editor and suggestion resolution view",
                    )
                    .clicked()
                {
                    self.open_planning_dialog();
                    ui.close();
                }
                ui.separator();
                ui.small("Routine catalog");
                match self.list_cloning_routines(None, None, None) {
                    Ok(mut routines) => {
                        if routines.is_empty() {
                            ui.add_enabled(false, egui::Button::new("No routines found"));
                        } else {
                            routines.sort_by(|left, right| {
                                left.family
                                    .to_ascii_lowercase()
                                    .cmp(&right.family.to_ascii_lowercase())
                                    .then(
                                        left.title
                                            .to_ascii_lowercase()
                                            .cmp(&right.title.to_ascii_lowercase()),
                                    )
                            });
                            if ui
                                .button("Show Routine Catalog Summary")
                                .on_hover_text(
                                    "Show current routine catalog location and routine count",
                                )
                                .clicked()
                            {
                                self.app_status = format!(
                                    "Loaded {} routine(s) from '{}'",
                                    routines.len(),
                                    DEFAULT_CLONING_ROUTINE_CATALOG_PATH
                                );
                                ui.close();
                            }

                            let mut selected_template_path: Option<String> = None;
                            let mut status_message: Option<String> = None;
                            let mut by_family: BTreeMap<String, Vec<CloningRoutineCatalogRow>> =
                                BTreeMap::new();
                            let mut by_status: BTreeMap<String, Vec<CloningRoutineCatalogRow>> =
                                BTreeMap::new();
                            for routine in routines {
                                by_family
                                    .entry(routine.family.clone())
                                    .or_default()
                                    .push(routine.clone());
                                by_status
                                    .entry(routine.status.clone())
                                    .or_default()
                                    .push(routine);
                            }

                            ui.menu_button("Browse by Family", |ui| {
                                for (family, rows) in &by_family {
                                    ui.menu_button(format!("{family} ({})", rows.len()), |ui| {
                                        Self::render_cloning_routine_menu_entries(
                                            ui,
                                            rows,
                                            &mut selected_template_path,
                                            &mut status_message,
                                        );
                                    });
                                }
                            });
                            ui.menu_button("Browse by Status", |ui| {
                                for (status, rows) in &by_status {
                                    ui.menu_button(format!("{status} ({})", rows.len()), |ui| {
                                        Self::render_cloning_routine_menu_entries(
                                            ui,
                                            rows,
                                            &mut selected_template_path,
                                            &mut status_message,
                                        );
                                    });
                                }
                            });

                            if let Some(path) = selected_template_path {
                                self.import_workflow_macro_templates_from_path(&path);
                                if let Some(message) = status_message {
                                    self.app_status = message;
                                }
                                ui.close();
                            } else if let Some(message) = status_message {
                                self.app_status = message;
                                ui.close();
                            }
                        }
                    }
                    Err(err) => {
                        ui.add_enabled(false, egui::Button::new("Routine catalog unavailable"));
                        ui.small(err);
                    }
                }
            });
            ui.menu_button("Windows", |ui| {
                let jobs_panel_resp = self.track_hover_status(
                    ui.button(if self.show_jobs_panel {
                        "Hide Background Jobs"
                    } else {
                        "Show Background Jobs"
                    })
                    .on_hover_text("Toggle centralized panel for progress/cancel/retry summaries"),
                    "Window > Background Jobs Panel",
                );
                if jobs_panel_resp.clicked() {
                    self.show_jobs_panel = !self.show_jobs_panel;
                    ui.close();
                }
                let history_panel_resp = self.track_hover_status(
                    ui.button(if self.show_history_panel {
                        "Hide Operation History"
                    } else {
                        "Show Operation History"
                    })
                    .on_hover_text("Toggle operation history panel with undo/redo"),
                    "Window > History Panel",
                );
                if history_panel_resp.clicked() {
                    self.show_history_panel = !self.show_history_panel;
                    ui.close();
                }
                ui.separator();
                for entry in &open_window_entries {
                    let label = if entry.viewport_id == ViewportId::ROOT {
                        format!("Main: {}", entry.title)
                    } else {
                        entry.title.clone()
                    };
                    if ui
                        .button(label)
                        .on_hover_text(format!("Raise window: {}", entry.detail))
                        .clicked()
                    {
                        self.focus_window_viewport(ui.ctx(), entry.viewport_id);
                        ui.close();
                    }
                }
            });
            ui.menu_button("Help", |ui| {
                if ui
                    .button("GUI Manual")
                    .on_hover_text("Open the GUI manual in the built-in help window")
                    .clicked()
                {
                    self.open_help_doc(HelpDoc::Gui);
                    ui.close();
                }
                if ui
                    .button("CLI Manual")
                    .on_hover_text("Open the CLI manual in the built-in help window")
                    .clicked()
                {
                    self.open_help_doc(HelpDoc::Cli);
                    ui.close();
                }
                if ui
                    .button("Agent Interface")
                    .on_hover_text("Open the agent interface guide (CLI, MCP, and Agent Assistant)")
                    .clicked()
                {
                    self.open_help_doc(HelpDoc::AgentInterface);
                    ui.close();
                }
                if ui
                    .button("Reviewer Quickstart")
                    .on_hover_text("Open internal preview guide with known limitations and reviewer walkthrough")
                    .clicked()
                {
                    self.open_help_doc(HelpDoc::ReviewerPreview);
                    ui.close();
                }
                if ui
                    .button("Shell Commands")
                    .on_hover_text("Open shell command reference generated from the glossary")
                    .clicked()
                {
                    self.open_help_doc(HelpDoc::Shell);
                    ui.close();
                }
                ui.menu_button("Tutorials", |ui| {
                    if self.help_tutorial_entries.is_empty() {
                        self.help_tutorial_entries = Self::discover_help_tutorial_entries();
                        self.set_help_tutorial_selected(self.help_tutorial_selected);
                    }
                    if self.help_tutorial_entries.is_empty() {
                        ui.add_enabled(false, egui::Button::new("No tutorial docs found"));
                        return;
                    }
                    let mut selected_tutorial: Option<usize> = None;
                    for (index, entry) in self.help_tutorial_entries.iter().enumerate() {
                        if ui
                            .button(entry.title.as_str())
                            .on_hover_text(format!("Open {}\n{}", entry.title, entry.summary))
                            .clicked()
                        {
                            selected_tutorial = Some(index);
                        }
                    }
                    if let Some(index) = selected_tutorial {
                        self.open_help_tutorial_doc(index);
                        ui.close();
                    }
                });
                ui.separator();
                if ui
                    .button("About GENtle")
                    .on_hover_text("Show version and build information")
                    .clicked()
                {
                    self.show_about_dialog = !about::show_native_about_panel();
                    ui.close();
                }
            });
        });
    }

    fn show_window(&self, ctx: &egui::Context, id: ViewportId, window: Arc<RwLock<Window>>) {
        let windows_to_close = self.windows_to_close.clone();
        let window_number = self.get_window_number_from_id(id);
        let window_pos = Pos2 {
            x: window_number as f32 * 200.0,
            y: window_number as f32 * 200.0,
        };
        let window_title = window
            .read()
            .map(|w| w.name())
            .unwrap_or_else(|_| "GENtle".to_string());
        ctx.show_viewport_deferred(
            id,
            egui::ViewportBuilder::default()
                .with_title(window_title)
                // .with_maximized(true),
                .with_position(window_pos),
            move |ctx, class| {
                if class != egui::ViewportClass::Deferred {
                    eprintln!(
                        "W GENtleApp: unexpected viewport class, skipping deferred window update"
                    );
                    return;
                }
                if ctx.input(|i| i.viewport().focused.unwrap_or(false)) {
                    report_active_viewport_from_ui(id);
                }

                // Draw the window
                let update_result = catch_unwind(AssertUnwindSafe(|| {
                    if let Ok(mut w) = window.write() {
                        w.update(ctx);
                    } else {
                        eprintln!("W GENtleApp: window lock poisoned; skipping update");
                    }
                }));
                if update_result.is_err() {
                    eprintln!("E GENtleApp: recovered from panic while updating window");
                }

                // "Close window" action
                if Self::viewport_close_requested_or_shortcut(ctx) {
                    if let Ok(mut to_close) = windows_to_close.write() {
                        to_close.push(id);
                    } else {
                        eprintln!("W GENtleApp: close-queue lock poisoned");
                    }
                }
            },
        );
    }

    fn get_window_number_from_id(&self, id: ViewportId) -> usize {
        self.windows
            .keys()
            .enumerate()
            .find(|(_num, viewport_id)| **viewport_id == id)
            .map(|(num, _viewport_id)| num)
            .unwrap_or(0)
    }

    fn refresh_lineage_cache_if_needed(&mut self) {
        let stamp = self.current_lineage_change_stamp();
        if self.lineage_cache_valid && self.lineage_cache_stamp == stamp {
            return;
        }

        let (rows, lineage_edges, op_label_by_id, containers, arrangements) = {
            let engine = self.engine.read().unwrap();
            let state = engine.state();
            let anchor_by_seq: HashMap<String, SequenceGenomeAnchorSummary> = engine
                .list_sequence_genome_anchor_summaries()
                .into_iter()
                .map(|summary| (summary.seq_id.clone(), summary))
                .collect();
            let anchor_provenance_by_seq = Self::latest_genome_anchor_provenance_by_seq(state);
            let mut chromosome_length_cache: HashMap<
                GenomeLengthCacheKey,
                Option<Vec<GenomeChromosomeRecord>>,
            > = HashMap::new();
            let mut op_created_count: HashMap<String, usize> = HashMap::new();
            let mut op_created_ids: HashMap<String, Vec<String>> = HashMap::new();
            let mut op_label_by_id: HashMap<String, String> = HashMap::new();
            let mut op_retrieval_by_id: HashMap<String, LineageRetrievalDescriptor> =
                HashMap::new();
            let mut dotplot_op_by_id: HashMap<String, (String, String, Option<String>)> =
                HashMap::new();
            let mut flex_track_op_by_id: HashMap<String, (String, String)> = HashMap::new();
            for rec in engine.operation_log() {
                op_created_count.insert(rec.result.op_id.clone(), rec.result.created_seq_ids.len());
                op_created_ids.insert(rec.result.op_id.clone(), rec.result.created_seq_ids.clone());
                op_label_by_id.insert(rec.result.op_id.clone(), Self::summarize_operation(&rec.op));
                if let Some(descriptor) = Self::lineage_retrieval_descriptor_from_operation(&rec.op)
                {
                    op_retrieval_by_id.insert(rec.result.op_id.clone(), descriptor);
                }
                match &rec.op {
                    Operation::ComputeDotplot {
                        seq_id,
                        reference_seq_id,
                        store_as,
                        ..
                    } => {
                        let dotplot_id =
                            Self::lineage_dotplot_id_for_operation(store_as, &rec.result.op_id);
                        dotplot_op_by_id.insert(
                            dotplot_id,
                            (
                                rec.result.op_id.clone(),
                                seq_id.clone(),
                                reference_seq_id.clone(),
                            ),
                        );
                    }
                    Operation::ComputeFlexibilityTrack {
                        seq_id, store_as, ..
                    } => {
                        let track_id =
                            Self::lineage_flex_track_id_for_operation(store_as, &rec.result.op_id);
                        flex_track_op_by_id
                            .insert(track_id, (rec.result.op_id.clone(), seq_id.clone()));
                    }
                    _ => {}
                }
            }

            let mut parents_by_node: HashMap<String, Vec<String>> = HashMap::new();
            for edge in &state.lineage.edges {
                let Some(parent_node) = state.lineage.nodes.get(&edge.from_node_id) else {
                    continue;
                };
                parents_by_node
                    .entry(edge.to_node_id.clone())
                    .or_default()
                    .push(parent_node.seq_id.clone());
            }

            let mut out: Vec<LineageRow> = state
                .lineage
                .nodes
                .values()
                .map(|node| {
                    let parents = parents_by_node
                        .get(&node.node_id)
                        .cloned()
                        .unwrap_or_default();
                    let (length, circular) = state
                        .sequences
                        .get(&node.seq_id)
                        .map(|dna| (dna.len(), dna.is_circular()))
                        .unwrap_or((0, false));
                    let display_name = state
                        .sequences
                        .get(&node.seq_id)
                        .and_then(|dna| dna.name().clone())
                        .unwrap_or_else(|| node.seq_id.clone());
                    let pool_size = node
                        .created_by_op
                        .as_ref()
                        .and_then(|op| op_created_count.get(op))
                        .cloned()
                        .unwrap_or(1);
                    let pool_members = node
                        .created_by_op
                        .as_ref()
                        .and_then(|op| op_created_ids.get(op))
                        .cloned()
                        .unwrap_or_else(|| vec![node.seq_id.clone()]);
                    let genome_anchor_summary = anchor_by_seq.get(&node.seq_id).cloned();
                    let genome_anchor_display = genome_anchor_summary
                        .as_ref()
                        .map(Self::format_genome_anchor_summary);
                    let is_full_genome_sequence = genome_anchor_summary
                        .as_ref()
                        .map(|anchor| {
                            let provenance = anchor_provenance_by_seq.get(&node.seq_id);
                            Self::sequence_represents_full_genome(
                                anchor,
                                length,
                                provenance,
                                &mut chromosome_length_cache,
                            )
                        })
                        .unwrap_or(false);
                    let retrieval_descriptor = node
                        .created_by_op
                        .as_ref()
                        .and_then(|op_id| op_retrieval_by_id.get(op_id))
                        .cloned();
                    LineageRow {
                        kind: LineageNodeKind::Sequence,
                        node_id: node.node_id.clone(),
                        seq_id: node.seq_id.clone(),
                        display_name,
                        origin: format!("{:?}", node.origin),
                        created_by_op: node
                            .created_by_op
                            .clone()
                            .unwrap_or_else(|| "-".to_string()),
                        created_at: node.created_at_unix_ms,
                        parents,
                        length,
                        circular,
                        pool_size,
                        pool_members,
                        arrangement_id: None,
                        arrangement_mode: None,
                        lane_container_ids: vec![],
                        ladders: vec![],
                        genome_anchor_summary,
                        genome_anchor_display,
                        is_full_genome_sequence,
                        retrieval_descriptor,
                        analysis_kind: None,
                        analysis_artifact_id: None,
                        analysis_reference_seq_id: None,
                        analysis_mode: None,
                        analysis_point_count: None,
                        analysis_bin_count: None,
                        macro_instance_id: None,
                        macro_routine_id: None,
                        macro_template_name: None,
                        macro_status: None,
                        macro_status_message: None,
                        macro_op_ids: vec![],
                        macro_inputs: vec![],
                        macro_outputs: vec![],
                    }
                })
                .collect();

            let mut lineage_edges: Vec<(String, String, String)> = state
                .lineage
                .edges
                .iter()
                .filter_map(|e| {
                    let from = state.lineage.nodes.get(&e.from_node_id)?.node_id.clone();
                    let to = state.lineage.nodes.get(&e.to_node_id)?.node_id.clone();
                    Some((from, to, e.op_id.clone()))
                })
                .collect();

            for instance in &state.lineage.macro_instances {
                let macro_node_id = format!("macro:{}", instance.macro_instance_id);
                let mut parent_labels: Vec<String> = vec![];
                let summarize_binding = |binding: &LineageMacroPortBinding| -> Option<String> {
                    if binding.values.is_empty() {
                        return None;
                    }
                    Some(format!("{}={}", binding.port_id, binding.values.join(",")))
                };
                let sequence_nodes_for_binding =
                    |binding: &LineageMacroPortBinding| -> Vec<String> {
                        let mut node_ids: Vec<String> = vec![];
                        let mut seen: HashSet<String> = HashSet::new();
                        match binding.kind.trim().to_ascii_lowercase().as_str() {
                            "sequence" => {
                                for seq_id in &binding.values {
                                    if let Some(node_id) = state.lineage.seq_to_node.get(seq_id) {
                                        if seen.insert(node_id.clone()) {
                                            node_ids.push(node_id.clone());
                                        }
                                    }
                                }
                            }
                            "container" => {
                                for container_id in &binding.values {
                                    let Some(container) =
                                        state.container_state.containers.get(container_id)
                                    else {
                                        continue;
                                    };
                                    for seq_id in &container.members {
                                        if let Some(node_id) = state.lineage.seq_to_node.get(seq_id)
                                        {
                                            if seen.insert(node_id.clone()) {
                                                node_ids.push(node_id.clone());
                                            }
                                        }
                                    }
                                }
                            }
                            _ => {}
                        }
                        node_ids
                    };

                for binding in &instance.bound_inputs {
                    if let Some(label) = summarize_binding(binding) {
                        parent_labels.push(label);
                    }
                    let from_nodes = sequence_nodes_for_binding(binding);
                    let edge_label_id = format!(
                        "macro:{}:in:{}",
                        instance.macro_instance_id, binding.port_id
                    );
                    op_label_by_id
                        .entry(edge_label_id.clone())
                        .or_insert_with(|| format!("Macro input {}", binding.port_id));
                    for from_node_id in from_nodes {
                        lineage_edges.push((
                            from_node_id,
                            macro_node_id.clone(),
                            edge_label_id.clone(),
                        ));
                    }
                }
                for binding in &instance.bound_outputs {
                    let to_nodes = sequence_nodes_for_binding(binding);
                    let edge_label_id = format!(
                        "macro:{}:out:{}",
                        instance.macro_instance_id, binding.port_id
                    );
                    op_label_by_id
                        .entry(edge_label_id.clone())
                        .or_insert_with(|| format!("Macro output {}", binding.port_id));
                    for to_node_id in to_nodes {
                        lineage_edges.push((
                            macro_node_id.clone(),
                            to_node_id,
                            edge_label_id.clone(),
                        ));
                    }
                }

                if parent_labels.is_empty() {
                    parent_labels.push("-".to_string());
                }

                let status_label = match instance.status {
                    crate::engine::MacroInstanceStatus::Ok => "ok",
                    crate::engine::MacroInstanceStatus::Failed => "failed",
                    crate::engine::MacroInstanceStatus::Cancelled => "cancelled",
                };
                let display_name = instance
                    .routine_title
                    .clone()
                    .or_else(|| instance.routine_id.clone())
                    .or_else(|| instance.template_name.clone())
                    .unwrap_or_else(|| "Macro".to_string());
                out.push(LineageRow {
                    kind: LineageNodeKind::Macro,
                    node_id: macro_node_id,
                    seq_id: instance.macro_instance_id.clone(),
                    display_name,
                    origin: format!("Macro ({status_label})"),
                    created_by_op: instance
                        .expanded_op_ids
                        .first()
                        .cloned()
                        .unwrap_or_else(|| "-".to_string()),
                    created_at: instance.created_at_unix_ms,
                    parents: parent_labels,
                    length: 0,
                    circular: false,
                    pool_size: 0,
                    pool_members: vec![],
                    arrangement_id: None,
                    arrangement_mode: None,
                    lane_container_ids: vec![],
                    ladders: vec![],
                    genome_anchor_summary: None,
                    genome_anchor_display: None,
                    is_full_genome_sequence: false,
                    retrieval_descriptor: None,
                    analysis_kind: None,
                    analysis_artifact_id: None,
                    analysis_reference_seq_id: None,
                    analysis_mode: None,
                    analysis_point_count: None,
                    analysis_bin_count: None,
                    macro_instance_id: Some(instance.macro_instance_id.clone()),
                    macro_routine_id: instance.routine_id.clone(),
                    macro_template_name: instance.template_name.clone(),
                    macro_status: Some(status_label.to_string()),
                    macro_status_message: instance.status_message.clone(),
                    macro_op_ids: instance.expanded_op_ids.clone(),
                    macro_inputs: instance.bound_inputs.clone(),
                    macro_outputs: instance.bound_outputs.clone(),
                });
            }

            let dotplot_summaries = engine.list_dotplot_views(None);
            for summary in dotplot_summaries {
                let node_id = format!("analysis:dotplot:{}", summary.dotplot_id);
                let op_binding = dotplot_op_by_id.get(&summary.dotplot_id).cloned();
                let created_by_op = op_binding
                    .as_ref()
                    .map(|(op_id, _, _)| op_id.clone())
                    .unwrap_or_else(|| "-".to_string());
                let edge_op_id = if created_by_op == "-" {
                    format!("analysis:dotplot:{}", summary.dotplot_id)
                } else {
                    created_by_op.clone()
                };
                op_label_by_id
                    .entry(edge_op_id.clone())
                    .or_insert_with(|| format!("Compute dotplot: id={}", summary.dotplot_id));
                let query_seq_id = summary.seq_id.clone();
                let reference_seq_id = summary.reference_seq_id.clone().or_else(|| {
                    op_binding
                        .as_ref()
                        .and_then(|(_, _, reference_seq_id)| reference_seq_id.clone())
                });
                let mut parents = vec![query_seq_id.clone()];
                if let Some(reference_seq_id) = reference_seq_id.as_ref() {
                    if !reference_seq_id.eq_ignore_ascii_case(&query_seq_id) {
                        parents.push(reference_seq_id.clone());
                    }
                }
                out.push(LineageRow {
                    kind: LineageNodeKind::Analysis,
                    node_id: node_id.clone(),
                    seq_id: query_seq_id.clone(),
                    display_name: summary.dotplot_id.clone(),
                    origin: "Dotplot".to_string(),
                    created_by_op,
                    created_at: summary.generated_at_unix_ms,
                    parents,
                    length: 0,
                    circular: false,
                    pool_size: 0,
                    pool_members: vec![],
                    arrangement_id: None,
                    arrangement_mode: None,
                    lane_container_ids: vec![],
                    ladders: vec![],
                    genome_anchor_summary: None,
                    genome_anchor_display: None,
                    is_full_genome_sequence: false,
                    retrieval_descriptor: None,
                    analysis_kind: Some(LineageAnalysisKind::Dotplot),
                    analysis_artifact_id: Some(summary.dotplot_id.clone()),
                    analysis_reference_seq_id: reference_seq_id.clone(),
                    analysis_mode: Some(summary.mode.as_str().to_string()),
                    analysis_point_count: Some(summary.point_count),
                    analysis_bin_count: None,
                    macro_instance_id: None,
                    macro_routine_id: None,
                    macro_template_name: None,
                    macro_status: None,
                    macro_status_message: None,
                    macro_op_ids: vec![],
                    macro_inputs: vec![],
                    macro_outputs: vec![],
                });
                let mut seen_sources: HashSet<String> = HashSet::new();
                let source_seq_ids = std::iter::once(query_seq_id)
                    .chain(reference_seq_id.into_iter())
                    .collect::<Vec<_>>();
                for source_seq_id in source_seq_ids {
                    let Some(source_node_id) = state.lineage.seq_to_node.get(&source_seq_id) else {
                        continue;
                    };
                    if seen_sources.insert(source_node_id.clone()) {
                        lineage_edges.push((
                            source_node_id.clone(),
                            node_id.clone(),
                            edge_op_id.clone(),
                        ));
                    }
                }
            }

            let flexibility_summaries = engine.list_flexibility_tracks(None);
            for summary in flexibility_summaries {
                let node_id = format!("analysis:flex:{}", summary.track_id);
                let op_binding = flex_track_op_by_id.get(&summary.track_id).cloned();
                let created_by_op = op_binding
                    .as_ref()
                    .map(|(op_id, _)| op_id.clone())
                    .unwrap_or_else(|| "-".to_string());
                let edge_op_id = if created_by_op == "-" {
                    format!("analysis:flex:{}", summary.track_id)
                } else {
                    created_by_op.clone()
                };
                op_label_by_id.entry(edge_op_id.clone()).or_insert_with(|| {
                    format!("Compute flexibility track: id={}", summary.track_id)
                });
                let seq_id = summary.seq_id.clone();
                out.push(LineageRow {
                    kind: LineageNodeKind::Analysis,
                    node_id: node_id.clone(),
                    seq_id: seq_id.clone(),
                    display_name: summary.track_id.clone(),
                    origin: "FlexibilityTrack".to_string(),
                    created_by_op,
                    created_at: summary.generated_at_unix_ms,
                    parents: vec![seq_id.clone()],
                    length: 0,
                    circular: false,
                    pool_size: 0,
                    pool_members: vec![],
                    arrangement_id: None,
                    arrangement_mode: None,
                    lane_container_ids: vec![],
                    ladders: vec![],
                    genome_anchor_summary: None,
                    genome_anchor_display: None,
                    is_full_genome_sequence: false,
                    retrieval_descriptor: None,
                    analysis_kind: Some(LineageAnalysisKind::FlexibilityTrack),
                    analysis_artifact_id: Some(summary.track_id.clone()),
                    analysis_reference_seq_id: None,
                    analysis_mode: Some(summary.model.as_str().to_string()),
                    analysis_point_count: None,
                    analysis_bin_count: Some(summary.bin_count),
                    macro_instance_id: None,
                    macro_routine_id: None,
                    macro_template_name: None,
                    macro_status: None,
                    macro_status_message: None,
                    macro_op_ids: vec![],
                    macro_inputs: vec![],
                    macro_outputs: vec![],
                });
                if let Some(source_node_id) = state.lineage.seq_to_node.get(&seq_id) {
                    lineage_edges.push((
                        source_node_id.clone(),
                        node_id.clone(),
                        edge_op_id.clone(),
                    ));
                }
            }

            out.sort_by(|a, b| {
                a.created_at
                    .cmp(&b.created_at)
                    .then(a.node_id.cmp(&b.node_id))
            });
            let mut containers: Vec<ContainerRow> = state
                .container_state
                .containers
                .iter()
                .map(|(id, c)| ContainerRow {
                    container_id: id.clone(),
                    kind: format!("{:?}", c.kind),
                    member_count: c.members.len(),
                    representative: c.members.first().cloned().unwrap_or_default(),
                    members: c.members.clone(),
                })
                .collect();
            containers.sort_by(|a, b| a.container_id.cmp(&b.container_id));
            let mut arrangements: Vec<ArrangementRow> = state
                .container_state
                .arrangements
                .iter()
                .map(|(id, arrangement)| ArrangementRow {
                    arrangement_id: id.clone(),
                    mode: format!("{:?}", arrangement.mode),
                    name: arrangement.name.clone().unwrap_or_default(),
                    created_by_op: arrangement
                        .created_by_op
                        .clone()
                        .unwrap_or_else(|| "CreateArrangementSerial".to_string()),
                    created_at: arrangement.created_at_unix_ms,
                    lane_count: arrangement.lane_container_ids.len(),
                    lane_container_ids: arrangement.lane_container_ids.clone(),
                    ladders: arrangement.ladders.clone(),
                })
                .collect();
            arrangements.sort_by(|a, b| a.arrangement_id.cmp(&b.arrangement_id));
            (out, lineage_edges, op_label_by_id, containers, arrangements)
        };

        self.lineage_rows = rows;
        self.lineage_edges = lineage_edges;
        self.lineage_op_label_by_id = op_label_by_id;
        self.lineage_containers = containers;
        self.lineage_arrangements = arrangements;
        self.lineage_cache_stamp = stamp;
        self.lineage_cache_valid = true;
    }

    fn lineage_layout_positions(
        order_by_layer: &BTreeMap<usize, Vec<String>>,
    ) -> HashMap<String, usize> {
        let mut positions = HashMap::new();
        for nodes in order_by_layer.values() {
            for (index, node_id) in nodes.iter().enumerate() {
                positions.insert(node_id.clone(), index);
            }
        }
        positions
    }

    fn compute_lineage_dag_layout(
        rows: &[LineageRow],
        lineage_edges: &[(String, String, String)],
    ) -> (HashMap<String, (usize, usize)>, usize, usize) {
        if rows.is_empty() {
            return (HashMap::new(), 1, 1);
        }

        let mut row_index: HashMap<String, usize> = HashMap::new();
        for (index, row) in rows.iter().enumerate() {
            row_index.insert(row.node_id.clone(), index);
        }

        let mut parents_by_node: HashMap<String, Vec<String>> = HashMap::new();
        let mut children_by_node: HashMap<String, Vec<String>> = HashMap::new();
        let mut indegree_by_node: HashMap<String, usize> = HashMap::new();
        for row in rows {
            parents_by_node.insert(row.node_id.clone(), Vec::new());
            children_by_node.insert(row.node_id.clone(), Vec::new());
            indegree_by_node.insert(row.node_id.clone(), 0);
        }

        let mut seen_edges: HashSet<(String, String)> = HashSet::new();
        for (from_node, to_node, _op_id) in lineage_edges {
            if !row_index.contains_key(from_node) || !row_index.contains_key(to_node) {
                continue;
            }
            if !seen_edges.insert((from_node.clone(), to_node.clone())) {
                continue;
            }
            if let Some(children) = children_by_node.get_mut(from_node) {
                children.push(to_node.clone());
            }
            if let Some(parents) = parents_by_node.get_mut(to_node) {
                parents.push(from_node.clone());
            }
            if let Some(indegree) = indegree_by_node.get_mut(to_node) {
                *indegree = indegree.saturating_add(1);
            }
        }

        for parents in parents_by_node.values_mut() {
            parents.sort_by_key(|node_id| row_index.get(node_id).copied().unwrap_or(usize::MAX));
        }
        for children in children_by_node.values_mut() {
            children.sort_by_key(|node_id| row_index.get(node_id).copied().unwrap_or(usize::MAX));
        }

        let mut ready: Vec<String> = indegree_by_node
            .iter()
            .filter_map(|(node_id, indegree)| {
                if *indegree == 0 {
                    Some(node_id.clone())
                } else {
                    None
                }
            })
            .collect();
        ready.sort_by_key(|node_id| row_index.get(node_id).copied().unwrap_or(usize::MAX));

        let mut topo_order: Vec<String> = Vec::with_capacity(rows.len());
        let mut topo_seen: HashSet<String> = HashSet::with_capacity(rows.len());
        while !ready.is_empty() {
            let node_id = ready.remove(0);
            if !topo_seen.insert(node_id.clone()) {
                continue;
            }
            topo_order.push(node_id.clone());
            if let Some(children) = children_by_node.get(&node_id) {
                for child_id in children {
                    if let Some(indegree) = indegree_by_node.get_mut(child_id) {
                        if *indegree > 0 {
                            *indegree -= 1;
                            if *indegree == 0 {
                                ready.push(child_id.clone());
                            }
                        }
                    }
                }
            }
            ready.sort_by_key(|candidate| row_index.get(candidate).copied().unwrap_or(usize::MAX));
        }

        for row in rows {
            if topo_seen.insert(row.node_id.clone()) {
                topo_order.push(row.node_id.clone());
            }
        }

        let mut layer_by_node: HashMap<String, usize> = HashMap::new();
        for node_id in &topo_order {
            let layer = parents_by_node
                .get(node_id)
                .map(|parents| {
                    parents
                        .iter()
                        .filter_map(|parent_id| layer_by_node.get(parent_id).copied())
                        .max()
                        .map(|max_parent_layer| max_parent_layer + 1)
                        .unwrap_or(0)
                })
                .unwrap_or(0);
            layer_by_node.insert(node_id.clone(), layer);
        }

        let mut order_by_layer: BTreeMap<usize, Vec<String>> = BTreeMap::new();
        for node_id in &topo_order {
            let layer = layer_by_node.get(node_id).copied().unwrap_or(0);
            order_by_layer
                .entry(layer)
                .or_default()
                .push(node_id.clone());
        }
        for nodes in order_by_layer.values_mut() {
            nodes.sort_by_key(|node_id| row_index.get(node_id).copied().unwrap_or(usize::MAX));
        }

        let max_layer = order_by_layer.keys().copied().max().unwrap_or(0);
        let barycenter =
            |neighbors: &[String], positions: &HashMap<String, usize>| -> Option<f32> {
                let mut sum = 0.0f32;
                let mut count = 0usize;
                for node_id in neighbors {
                    if let Some(pos) = positions.get(node_id) {
                        sum += *pos as f32;
                        count += 1;
                    }
                }
                if count == 0 {
                    None
                } else {
                    Some(sum / count as f32)
                }
            };

        for _ in 0..6 {
            for layer in 1..=max_layer {
                let positions = Self::lineage_layout_positions(&order_by_layer);
                let Some(mut nodes) = order_by_layer.remove(&layer) else {
                    continue;
                };
                nodes.sort_by(|left, right| {
                    let left_score = parents_by_node
                        .get(left)
                        .and_then(|parents| barycenter(parents, &positions));
                    let right_score = parents_by_node
                        .get(right)
                        .and_then(|parents| barycenter(parents, &positions));
                    let fallback = row_index
                        .get(left)
                        .copied()
                        .unwrap_or(usize::MAX)
                        .cmp(&row_index.get(right).copied().unwrap_or(usize::MAX));
                    match (left_score, right_score) {
                        (Some(l), Some(r)) => l
                            .partial_cmp(&r)
                            .unwrap_or(std::cmp::Ordering::Equal)
                            .then(fallback),
                        (Some(_), None) => std::cmp::Ordering::Less,
                        (None, Some(_)) => std::cmp::Ordering::Greater,
                        (None, None) => fallback,
                    }
                });
                order_by_layer.insert(layer, nodes);
            }

            if max_layer == 0 {
                break;
            }

            for layer in (0..max_layer).rev() {
                let positions = Self::lineage_layout_positions(&order_by_layer);
                let Some(mut nodes) = order_by_layer.remove(&layer) else {
                    continue;
                };
                nodes.sort_by(|left, right| {
                    let left_score = children_by_node
                        .get(left)
                        .and_then(|children| barycenter(children, &positions));
                    let right_score = children_by_node
                        .get(right)
                        .and_then(|children| barycenter(children, &positions));
                    let fallback = row_index
                        .get(left)
                        .copied()
                        .unwrap_or(usize::MAX)
                        .cmp(&row_index.get(right).copied().unwrap_or(usize::MAX));
                    match (left_score, right_score) {
                        (Some(l), Some(r)) => l
                            .partial_cmp(&r)
                            .unwrap_or(std::cmp::Ordering::Equal)
                            .then(fallback),
                        (Some(_), None) => std::cmp::Ordering::Less,
                        (None, Some(_)) => std::cmp::Ordering::Greater,
                        (None, None) => fallback,
                    }
                });
                order_by_layer.insert(layer, nodes);
            }
        }

        let mut layout_by_node: HashMap<String, (usize, usize)> = HashMap::new();
        let mut max_rank_seen = 0usize;
        for (layer, nodes) in &order_by_layer {
            for node_id in nodes {
                let rank = row_index.get(node_id).copied().unwrap_or(0);
                max_rank_seen = max_rank_seen.max(rank);
                layout_by_node.insert(node_id.clone(), (*layer, rank));
            }
        }

        for row in rows {
            let fallback_rank = row_index.get(&row.node_id).copied().unwrap_or(0);
            max_rank_seen = max_rank_seen.max(fallback_rank);
            layout_by_node
                .entry(row.node_id.clone())
                .or_insert((0, fallback_rank));
        }

        let max_nodes_in_layer = max_rank_seen.saturating_add(1);
        (layout_by_node, max_layer + 1, max_nodes_in_layer)
    }

    fn compact_lineage_node_label(raw: &str, max_chars: usize) -> String {
        if max_chars == 0 {
            return String::new();
        }
        let char_count = raw.chars().count();
        if char_count <= max_chars {
            return raw.to_string();
        }
        let keep = max_chars.saturating_sub(3).max(1);
        let prefix: String = raw.chars().take(keep).collect();
        format!("{prefix}...")
    }

    fn compact_lineage_op_label(raw: &str) -> String {
        let mut head = raw.split(':').next().unwrap_or(raw).trim().to_string();
        if head.eq_ignore_ascii_case("Molecular weight filter (container)") {
            return "MW filter".to_string();
        }
        if head.eq_ignore_ascii_case("Merge containers by id") {
            return "Merge by id".to_string();
        }
        if head.len() > 20 {
            head.truncate(17);
            head.push_str("...");
        }
        head
    }

    fn normalize_lineage_analysis_id(raw: &str) -> String {
        let trimmed = raw.trim();
        if trimmed.is_empty() {
            return String::new();
        }
        let mut out = String::with_capacity(trimmed.len());
        for ch in trimmed.chars() {
            if ch.is_ascii_alphanumeric() || matches!(ch, '_' | '-' | '.') {
                out.push(ch);
            } else {
                out.push('_');
            }
        }
        out
    }

    fn lineage_dotplot_id_for_operation(store_as: &Option<String>, op_id: &str) -> String {
        store_as
            .as_deref()
            .map(Self::normalize_lineage_analysis_id)
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| format!("dotplot_{op_id}"))
    }

    fn lineage_flex_track_id_for_operation(store_as: &Option<String>, op_id: &str) -> String {
        store_as
            .as_deref()
            .map(Self::normalize_lineage_analysis_id)
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| format!("flex_{op_id}"))
    }

    fn lineage_operation_family(raw: &str) -> &'static str {
        let head = raw.split(':').next().unwrap_or(raw).trim();
        let lower = head.to_ascii_lowercase();
        if lower.contains("reverse complement") {
            return "reverse_complement";
        }
        if lower.contains("digest") {
            return "digest";
        }
        if lower.contains("ligation") {
            return "ligation";
        }
        if lower.contains("pcr") {
            return "pcr";
        }
        if lower.contains("extract") {
            return "extract";
        }
        if lower.contains("merge") {
            return "merge";
        }
        if lower.contains("filter") {
            return "filter";
        }
        if lower.contains("annotate") {
            return "annotate";
        }
        if lower.contains("dotplot") {
            return "dotplot";
        }
        if lower.contains("flexibility track") {
            return "flexibility";
        }
        if lower.contains("load") || lower.contains("import") {
            return "import";
        }
        if lower.contains("set parameter") {
            return "set_parameter";
        }
        if lower.contains("branch") {
            return "branch";
        }
        if lower.contains("reverse") {
            return "reverse";
        }
        if lower.contains("complement") {
            return "complement";
        }
        "other"
    }

    fn lineage_operation_symbol_for_family(family: &str) -> &'static str {
        match family {
            "reverse_complement" => "RC",
            "digest" => "D",
            "ligation" => "L",
            "pcr" => "P",
            "extract" => "E",
            "merge" => "M",
            "filter" => "F",
            "annotate" => "A",
            "dotplot" => "DP",
            "flexibility" => "FX",
            "import" => "I",
            "set_parameter" => "S",
            "branch" => "B",
            "reverse" => "R",
            "complement" => "C",
            _ => "O",
        }
    }

    fn lineage_operation_symbol(raw: &str) -> String {
        let family = Self::lineage_operation_family(raw);
        if family != "other" {
            return Self::lineage_operation_symbol_for_family(family).to_string();
        }
        let head = raw.split(':').next().unwrap_or(raw).trim();
        for ch in head.chars() {
            if ch.is_ascii_alphabetic() {
                return ch.to_ascii_uppercase().to_string();
            }
        }
        "O".to_string()
    }

    fn lineage_operation_color_for_family(family: &str) -> egui::Color32 {
        match family {
            "reverse_complement" => egui::Color32::from_rgb(84, 118, 172),
            "digest" => egui::Color32::from_rgb(176, 126, 70),
            "ligation" => egui::Color32::from_rgb(78, 144, 108),
            "pcr" => egui::Color32::from_rgb(72, 124, 186),
            "extract" => egui::Color32::from_rgb(153, 121, 74),
            "merge" => egui::Color32::from_rgb(96, 146, 88),
            "filter" => egui::Color32::from_rgb(120, 120, 120),
            "annotate" => egui::Color32::from_rgb(74, 150, 156),
            "dotplot" => egui::Color32::from_rgb(148, 92, 172),
            "flexibility" => egui::Color32::from_rgb(132, 104, 186),
            "import" => egui::Color32::from_rgb(111, 131, 170),
            "set_parameter" => egui::Color32::from_rgb(128, 109, 82),
            "branch" => egui::Color32::from_rgb(130, 110, 152),
            "reverse" => egui::Color32::from_rgb(108, 130, 174),
            "complement" => egui::Color32::from_rgb(108, 137, 176),
            _ => egui::Color32::from_rgb(102, 102, 102),
        }
    }

    fn lineage_operation_color(raw: &str) -> egui::Color32 {
        let family = Self::lineage_operation_family(raw);
        Self::lineage_operation_color_for_family(family)
    }

    fn lineage_operation_glyph(op_labels: &[String]) -> (String, egui::Color32) {
        if op_labels.is_empty() {
            return ("O".to_string(), egui::Color32::from_rgb(102, 102, 102));
        }
        let first_symbol = Self::lineage_operation_symbol(&op_labels[0]);
        let first_color = Self::lineage_operation_color(&op_labels[0]);
        let all_same = op_labels
            .iter()
            .all(|label| Self::lineage_operation_symbol(label) == first_symbol);
        if all_same {
            return (first_symbol, first_color);
        }
        let count = op_labels.len().min(99);
        (count.to_string(), egui::Color32::from_rgb(102, 102, 102))
    }

    fn lineage_edge_groups(
        lineage_edges: &[(String, String, String)],
    ) -> Vec<(String, String, Vec<String>)> {
        let mut edge_groups: Vec<(String, String, Vec<String>)> = vec![];
        let mut by_pair: HashMap<(String, String), usize> = HashMap::new();
        for (from_node, to_node, op_id) in lineage_edges {
            let key = (from_node.clone(), to_node.clone());
            if let Some(group_idx) = by_pair.get(&key).copied() {
                let group = &mut edge_groups[group_idx].2;
                if !group.iter().any(|existing| existing == op_id) {
                    group.push(op_id.clone());
                }
                continue;
            }
            by_pair.insert(key, edge_groups.len());
            edge_groups.push((from_node.clone(), to_node.clone(), vec![op_id.clone()]));
        }
        edge_groups
    }

    fn lineage_edge_operation_labels(
        op_ids: &[String],
        op_label_by_id: &HashMap<String, String>,
    ) -> Vec<String> {
        let mut labels: Vec<String> = op_ids
            .iter()
            .map(|op_id| {
                op_label_by_id
                    .get(op_id)
                    .cloned()
                    .unwrap_or_else(|| op_id.clone())
            })
            .collect();
        labels.sort();
        labels.dedup();
        labels
    }

    fn lineage_edge_display_label(op_labels: &[String]) -> String {
        match op_labels.len() {
            0 => "Operation".to_string(),
            1 => op_labels[0].clone(),
            count => format!("{count} operations"),
        }
    }

    fn lineage_edge_accessible_name(op_labels: &[String]) -> String {
        match op_labels.len() {
            0 => "operation".to_string(),
            1 => op_labels[0].clone(),
            count => {
                let preview = op_labels
                    .iter()
                    .take(3)
                    .cloned()
                    .collect::<Vec<_>>()
                    .join(", ");
                if op_labels.len() <= 3 {
                    format!("{count} operations: {preview}")
                } else {
                    format!("{count} operations: {preview}, ...")
                }
            }
        }
    }

    fn lineage_collapsed_group_hidden_op_badges(
        edges: &[(String, String, String)],
        groups: &[PersistedLineageNodeGroup],
        op_label_by_id: &HashMap<String, String>,
    ) -> HashMap<String, LineageGroupHiddenOpBadge> {
        let mut badges: HashMap<String, LineageGroupHiddenOpBadge> = HashMap::new();
        for group in groups {
            if !group.collapsed || group.member_node_ids.is_empty() {
                continue;
            }
            let member_node_ids: HashSet<&str> = group
                .member_node_ids
                .iter()
                .map(|node_id| node_id.as_str())
                .collect();
            let mut seen_op_ids: HashSet<String> = HashSet::new();
            let mut family_counts: HashMap<String, usize> = HashMap::new();
            for (from_node, to_node, op_id) in edges {
                if !member_node_ids.contains(from_node.as_str())
                    && !member_node_ids.contains(to_node.as_str())
                {
                    continue;
                }
                if !seen_op_ids.insert(op_id.clone()) {
                    continue;
                }
                let op_label = op_label_by_id
                    .get(op_id)
                    .cloned()
                    .unwrap_or_else(|| op_id.clone());
                let family = Self::lineage_operation_family(&op_label).to_string();
                *family_counts.entry(family).or_insert(0) += 1;
            }
            if family_counts.is_empty() {
                continue;
            }
            let total_ops = seen_op_ids.len();
            let mut families: Vec<(String, usize)> = family_counts.into_iter().collect();
            families.sort_by(|left, right| right.1.cmp(&left.1).then(left.0.cmp(&right.0)));
            badges.insert(
                group.representative_node_id.clone(),
                LineageGroupHiddenOpBadge {
                    total_ops,
                    families,
                },
            );
        }
        badges
    }

    fn lineage_hidden_op_families_summary(
        badge: &LineageGroupHiddenOpBadge,
        max_families: usize,
    ) -> String {
        if badge.families.is_empty() {
            return "none".to_string();
        }
        let mut entries: Vec<String> = badge
            .families
            .iter()
            .take(max_families)
            .map(|(family, count)| {
                let symbol = Self::lineage_operation_symbol_for_family(family);
                if *count > 1 {
                    format!("{symbol}{count}")
                } else {
                    symbol.to_string()
                }
            })
            .collect();
        if badge.families.len() > max_families {
            entries.push(format!("+{}", badge.families.len() - max_families));
        }
        entries.join(" ")
    }

    fn parse_lineage_group_node_list(raw: &str) -> Vec<String> {
        let mut out = vec![];
        let mut seen: HashSet<String> = HashSet::new();
        for token in raw.split(|c: char| c == ',' || c == ';' || c.is_whitespace()) {
            let trimmed = token.trim();
            if trimmed.is_empty() {
                continue;
            }
            if seen.insert(trimmed.to_string()) {
                out.push(trimmed.to_string());
            }
        }
        out
    }

    fn next_lineage_group_id(groups: &[PersistedLineageNodeGroup]) -> String {
        let existing: HashSet<String> = groups.iter().map(|group| group.group_id.clone()).collect();
        let mut next = 1usize;
        loop {
            let candidate = format!("grp-{next}");
            if !existing.contains(&candidate) {
                return candidate;
            }
            next += 1;
        }
    }

    fn sanitize_lineage_node_groups(
        groups: &[PersistedLineageNodeGroup],
        valid_node_ids: &HashSet<String>,
    ) -> Vec<PersistedLineageNodeGroup> {
        let mut out = vec![];
        let mut used_group_ids: HashSet<String> = HashSet::new();
        let mut used_node_ids: HashSet<String> = HashSet::new();
        for (index, group) in groups.iter().enumerate() {
            let mut group_id = group.group_id.trim().to_string();
            if group_id.is_empty() {
                group_id = format!("grp-{}", index + 1);
            }
            if used_group_ids.contains(&group_id) {
                let base = group_id.clone();
                let mut suffix = 2usize;
                loop {
                    let candidate = format!("{base}-{suffix}");
                    if !used_group_ids.contains(&candidate) {
                        group_id = candidate;
                        break;
                    }
                    suffix += 1;
                }
            }
            used_group_ids.insert(group_id.clone());

            let mut label = group.label.trim().to_string();
            if label.is_empty() {
                label = format!("Group {}", index + 1);
            }

            let mut seen_members: HashSet<String> = HashSet::new();
            let mut members: Vec<String> = vec![];
            for node_id in &group.member_node_ids {
                let trimmed = node_id.trim();
                if trimmed.is_empty() || !valid_node_ids.contains(trimmed) {
                    continue;
                }
                if seen_members.insert(trimmed.to_string()) {
                    members.push(trimmed.to_string());
                }
            }

            let mut representative = group.representative_node_id.trim().to_string();
            if representative.is_empty() || !valid_node_ids.contains(&representative) {
                representative = members.first().cloned().unwrap_or_default();
            }
            if representative.is_empty() {
                continue;
            }
            members.retain(|node_id| node_id != &representative);

            if used_node_ids.contains(&representative) {
                if let Some(index_unused) = members
                    .iter()
                    .position(|node_id| !used_node_ids.contains(node_id))
                {
                    representative = members.remove(index_unused);
                } else {
                    continue;
                }
            }

            members.retain(|node_id| !used_node_ids.contains(node_id));
            if members.is_empty() {
                continue;
            }

            used_node_ids.insert(representative.clone());
            for node_id in &members {
                used_node_ids.insert(node_id.clone());
            }

            out.push(PersistedLineageNodeGroup {
                group_id,
                label,
                representative_node_id: representative,
                member_node_ids: members,
                collapsed: group.collapsed,
            });
        }
        out
    }

    fn lineage_node_group_maps(
        groups: &[PersistedLineageNodeGroup],
    ) -> (
        HashMap<String, PersistedLineageNodeGroup>,
        HashMap<String, String>,
    ) {
        let mut by_group_id: HashMap<String, PersistedLineageNodeGroup> = HashMap::new();
        let mut node_to_group_id: HashMap<String, String> = HashMap::new();
        for group in groups {
            by_group_id.insert(group.group_id.clone(), group.clone());
            node_to_group_id.insert(group.representative_node_id.clone(), group.group_id.clone());
            for node_id in &group.member_node_ids {
                node_to_group_id.insert(node_id.clone(), group.group_id.clone());
            }
        }
        (by_group_id, node_to_group_id)
    }

    fn project_lineage_graph_by_groups(
        rows: &[LineageRow],
        edges: &[(String, String, String)],
        groups: &[PersistedLineageNodeGroup],
    ) -> (Vec<LineageRow>, Vec<(String, String, String)>) {
        let (group_by_id, node_to_group_id) = Self::lineage_node_group_maps(groups);
        let projected_rows: Vec<LineageRow> = rows
            .iter()
            .filter_map(|row| {
                let group = node_to_group_id
                    .get(&row.node_id)
                    .and_then(|group_id| group_by_id.get(group_id));
                if let Some(group) = group {
                    if group.collapsed && row.node_id != group.representative_node_id {
                        return None;
                    }
                }
                Some(row.clone())
            })
            .collect();

        let project_node_id = |node_id: &str| -> String {
            let group = node_to_group_id
                .get(node_id)
                .and_then(|group_id| group_by_id.get(group_id));
            if let Some(group) = group {
                if group.collapsed {
                    return group.representative_node_id.clone();
                }
            }
            node_id.to_string()
        };

        let mut projected_edges: Vec<(String, String, String)> = vec![];
        let mut seen_edges: HashSet<(String, String, String)> = HashSet::new();
        for (from_node, to_node, op_id) in edges {
            let from = project_node_id(from_node);
            let to = project_node_id(to_node);
            if from == to {
                continue;
            }
            let key = (from, to, op_id.clone());
            if seen_edges.insert(key.clone()) {
                projected_edges.push(key);
            }
        }
        (projected_rows, projected_edges)
    }

    fn build_lineage_table_entries(
        rows: &[LineageRow],
        groups: &[PersistedLineageNodeGroup],
    ) -> Vec<LineageTableEntry> {
        let (group_by_id, node_to_group_id) = Self::lineage_node_group_maps(groups);
        let row_by_node: HashMap<String, LineageRow> = rows
            .iter()
            .map(|row| (row.node_id.clone(), row.clone()))
            .collect();
        let row_order: HashMap<String, usize> = rows
            .iter()
            .enumerate()
            .map(|(index, row)| (row.node_id.clone(), index))
            .collect();

        let mut emitted: HashSet<String> = HashSet::new();
        let mut entries: Vec<LineageTableEntry> = vec![];

        for row in rows {
            if emitted.contains(&row.node_id) {
                continue;
            }

            let Some(group_id) = node_to_group_id.get(&row.node_id).cloned() else {
                entries.push(LineageTableEntry {
                    row: row.clone(),
                    indent_level: 0,
                    group_id: None,
                    group_label: None,
                    is_group_representative: false,
                    hidden_group_member_count: 0,
                });
                emitted.insert(row.node_id.clone());
                continue;
            };

            let Some(group) = group_by_id.get(&group_id) else {
                entries.push(LineageTableEntry {
                    row: row.clone(),
                    indent_level: 0,
                    group_id: None,
                    group_label: None,
                    is_group_representative: false,
                    hidden_group_member_count: 0,
                });
                emitted.insert(row.node_id.clone());
                continue;
            };

            if row.node_id != group.representative_node_id {
                continue;
            }

            entries.push(LineageTableEntry {
                row: row.clone(),
                indent_level: 0,
                group_id: Some(group.group_id.clone()),
                group_label: Some(group.label.clone()),
                is_group_representative: true,
                hidden_group_member_count: if group.collapsed {
                    group.member_node_ids.len()
                } else {
                    0
                },
            });
            emitted.insert(row.node_id.clone());

            if group.collapsed {
                for member_id in &group.member_node_ids {
                    emitted.insert(member_id.clone());
                }
            } else {
                let mut members = group.member_node_ids.clone();
                members
                    .sort_by_key(|node_id| row_order.get(node_id).copied().unwrap_or(usize::MAX));
                for member_id in members {
                    if emitted.contains(&member_id) {
                        continue;
                    }
                    if let Some(member_row) = row_by_node.get(&member_id) {
                        entries.push(LineageTableEntry {
                            row: member_row.clone(),
                            indent_level: 1,
                            group_id: Some(group.group_id.clone()),
                            group_label: Some(group.label.clone()),
                            is_group_representative: false,
                            hidden_group_member_count: 0,
                        });
                        emitted.insert(member_id);
                    }
                }
            }
        }

        for row in rows {
            if emitted.contains(&row.node_id) {
                continue;
            }
            entries.push(LineageTableEntry {
                row: row.clone(),
                indent_level: 0,
                group_id: None,
                group_label: None,
                is_group_representative: false,
                hidden_group_member_count: 0,
            });
            emitted.insert(row.node_id.clone());
        }

        entries
    }

    fn lineage_group_color(group_id: &str) -> egui::Color32 {
        let palette = [
            egui::Color32::from_rgb(115, 146, 186),
            egui::Color32::from_rgb(173, 132, 84),
            egui::Color32::from_rgb(120, 156, 106),
            egui::Color32::from_rgb(163, 118, 143),
            egui::Color32::from_rgb(119, 155, 160),
            egui::Color32::from_rgb(174, 148, 88),
        ];
        let mut hasher = DefaultHasher::new();
        group_id.hash(&mut hasher);
        let index = (hasher.finish() as usize) % palette.len();
        palette[index]
    }

    fn start_lineage_group_draft_from_marked(
        &mut self,
        representative_node_id: &str,
        valid_node_ids: &HashSet<String>,
    ) -> Result<usize, String> {
        let representative = representative_node_id.trim();
        if representative.is_empty() {
            return Err("Representative node id is required".to_string());
        }
        if !valid_node_ids.contains(representative) {
            return Err(format!(
                "Representative node '{representative}' is not present in current lineage"
            ));
        }
        let mut members: Vec<String> = self
            .lineage_group_marked_nodes
            .iter()
            .filter(|node_id| valid_node_ids.contains(*node_id))
            .cloned()
            .collect();
        members.retain(|node_id| node_id != representative);
        members.sort();
        members.dedup();
        if members.is_empty() {
            return Err(
                "No marked members available. Mark one or more nodes first via context menu."
                    .to_string(),
            );
        }
        self.lineage_group_form_editing_id = None;
        self.lineage_group_form_representative = representative.to_string();
        self.lineage_group_form_members = members.join(", ");
        if self.lineage_group_form_label.trim().is_empty() {
            self.lineage_group_form_label = format!("Group {}", representative);
        }
        Ok(members.len())
    }

    fn apply_lineage_group_form(
        &mut self,
        valid_node_ids: &HashSet<String>,
    ) -> Result<String, String> {
        let representative = self.lineage_group_form_representative.trim().to_string();
        if representative.is_empty() {
            return Err("Representative node id is required".to_string());
        }
        if !valid_node_ids.contains(&representative) {
            return Err(format!(
                "Representative node '{representative}' is not present in current lineage"
            ));
        }

        let mut label = self.lineage_group_form_label.trim().to_string();
        if label.is_empty() {
            label = format!("Group {}", representative);
        }

        let mut members = Self::parse_lineage_group_node_list(&self.lineage_group_form_members);
        members.retain(|node_id| node_id != &representative);
        if members.is_empty() {
            return Err("At least one member node id is required".to_string());
        }

        let mut draft_groups = self.lineage_node_groups.clone();
        if let Some(group_id) = self.lineage_group_form_editing_id.clone() {
            if let Some(group) = draft_groups
                .iter_mut()
                .find(|group| group.group_id == group_id)
            {
                group.label = label.clone();
                group.representative_node_id = representative.clone();
                group.member_node_ids = members.clone();
            } else {
                draft_groups.push(PersistedLineageNodeGroup {
                    group_id,
                    label: label.clone(),
                    representative_node_id: representative.clone(),
                    member_node_ids: members.clone(),
                    collapsed: false,
                });
            }
        } else {
            draft_groups.push(PersistedLineageNodeGroup {
                group_id: Self::next_lineage_group_id(&draft_groups),
                label: label.clone(),
                representative_node_id: representative.clone(),
                member_node_ids: members.clone(),
                collapsed: false,
            });
        }

        let sanitized_draft = Self::sanitize_lineage_node_groups(&draft_groups, valid_node_ids);
        let adjusted = sanitized_draft != draft_groups;
        self.lineage_node_groups = sanitized_draft;
        self.lineage_group_form_editing_id = None;
        self.lineage_group_form_label.clear();
        self.lineage_group_form_members.clear();
        self.lineage_group_form_representative.clear();
        self.lineage_group_marked_nodes.clear();

        if adjusted {
            Ok("Group saved with normalization (overlaps/invalid nodes were removed)".to_string())
        } else {
            Ok(format!("Saved group '{label}'"))
        }
    }

    fn render_lineage_group_context_menu(
        &mut self,
        ui: &mut Ui,
        node_id: &str,
        context_row: Option<&LineageRow>,
        leaf_node_ids: &HashSet<String>,
        valid_node_ids: &HashSet<String>,
        persist_workspace_after_frame: &mut bool,
    ) {
        ui.label(format!("Node: {node_id}"));
        ui.separator();
        let marked = self.lineage_group_marked_nodes.contains(node_id);
        if !marked {
            if ui
                .button("Mark for node-group")
                .on_hover_text("Mark this node as a candidate member for new node groups")
                .clicked()
            {
                self.lineage_group_marked_nodes.insert(node_id.to_string());
                self.lineage_group_status = format!("Marked node '{node_id}' for grouping");
                ui.close();
            }
        } else if ui
            .button("Unmark for node-group")
            .on_hover_text("Remove this node from marked candidate members")
            .clicked()
        {
            self.lineage_group_marked_nodes.remove(node_id);
            self.lineage_group_status = format!("Unmarked node '{node_id}'");
            ui.close();
        }

        if ui
            .button("Use as draft representative")
            .on_hover_text("Fill node-group form from currently marked nodes")
            .clicked()
        {
            match self.start_lineage_group_draft_from_marked(node_id, valid_node_ids) {
                Ok(count) => {
                    self.lineage_group_status = format!(
                        "Draft prepared with representative '{node_id}' and {count} member(s)"
                    );
                }
                Err(err) => {
                    self.lineage_group_status = err;
                }
            }
            ui.close();
        }

        if ui
            .button("Create group now (representative)")
            .on_hover_text("Create a new group immediately from marked nodes")
            .clicked()
        {
            let status = match self.start_lineage_group_draft_from_marked(node_id, valid_node_ids) {
                Ok(_) => match self.apply_lineage_group_form(valid_node_ids) {
                    Ok(status) => {
                        *persist_workspace_after_frame = true;
                        status
                    }
                    Err(err) => err,
                },
                Err(err) => err,
            };
            self.lineage_group_status = status;
            ui.close();
        }

        ui.separator();
        let is_sequence_node = context_row
            .map(|row| matches!(row.kind, LineageNodeKind::Sequence))
            .unwrap_or(false);
        let is_leaf = leaf_node_ids.contains(node_id);
        if is_sequence_node {
            if ui
                .add_enabled(is_leaf, egui::Button::new("Rename (leaf only)"))
                .on_hover_text(if is_leaf {
                    "Rename this leaf node (display name only)"
                } else {
                    "Rename is allowed only for leaf nodes in this first implementation"
                })
                .clicked()
            {
                self.lineage_node_rename_target_id = Some(node_id.to_string());
                self.lineage_node_rename_text = context_row
                    .map(|row| row.display_name.clone())
                    .unwrap_or_default();
                ui.close();
            }
            if ui
                .add_enabled(is_leaf, egui::Button::new("Remove (leaf only)"))
                .on_hover_text(if is_leaf {
                    "Remove this leaf node and its sequence from project state"
                } else {
                    "Remove is allowed only for leaf nodes in this first implementation"
                })
                .clicked()
            {
                self.lineage_group_status = match self.request_remove_leaf_lineage_node(node_id) {
                    Ok(status) => status,
                    Err(err) => err,
                };
                ui.close();
            }
        } else {
            ui.label("Rename/remove is currently available for sequence leaf nodes only.");
        }
    }

    fn lineage_leaf_node_ids(
        rows: &[LineageRow],
        lineage_edges: &[(String, String, String)],
    ) -> HashSet<String> {
        let mut node_ids: HashSet<String> = rows.iter().map(|row| row.node_id.clone()).collect();
        let mut non_leaf_ids: HashSet<String> = HashSet::new();
        for (from_node, to_node, _) in lineage_edges {
            if node_ids.contains(from_node) && node_ids.contains(to_node) {
                non_leaf_ids.insert(from_node.clone());
            }
        }
        node_ids.retain(|node_id| !non_leaf_ids.contains(node_id));
        node_ids
    }

    fn request_remove_leaf_lineage_node(&mut self, node_id: &str) -> Result<String, String> {
        let node_id = node_id.trim();
        if node_id.is_empty() {
            return Err("Node id cannot be empty".to_string());
        }
        let is_leaf = {
            let engine = self.engine.read().unwrap();
            let state = engine.state();
            if !state.lineage.nodes.contains_key(node_id) {
                return Err(format!("Node '{}' not found", node_id));
            }
            !state
                .lineage
                .edges
                .iter()
                .any(|edge| edge.from_node_id == node_id)
        };
        if !is_leaf {
            return Err(format!(
                "Node '{}' is not a leaf; remove downstream nodes first",
                node_id
            ));
        }
        self.lineage_node_remove_target_id = Some(node_id.to_string());
        Ok(format!(
            "Removal requested for leaf node '{}'; confirm in dialog.",
            node_id
        ))
    }

    fn remove_leaf_lineage_node(&mut self, node_id: &str) -> Result<String, String> {
        let node_id = node_id.trim();
        if node_id.is_empty() {
            return Err("Node id cannot be empty".to_string());
        }
        let seq_id = {
            let mut engine = self.engine.write().unwrap();
            let state = engine.state_mut();
            let Some(node) = state.lineage.nodes.get(node_id).cloned() else {
                return Err(format!("Node '{}' not found", node_id));
            };
            if state
                .lineage
                .edges
                .iter()
                .any(|edge| edge.from_node_id == node_id)
            {
                return Err(format!(
                    "Node '{}' is not a leaf; remove downstream nodes first",
                    node_id
                ));
            }
            let seq_id = node.seq_id.clone();
            if state.sequences.remove(&seq_id).is_none() {
                return Err(format!(
                    "Sequence '{}' for node '{}' is missing",
                    seq_id, node_id
                ));
            }
            state.lineage.seq_to_node.remove(&seq_id);
            state.lineage.nodes.remove(node_id);
            state
                .lineage
                .edges
                .retain(|edge| edge.from_node_id != node_id && edge.to_node_id != node_id);

            let mut empty_container_ids: HashSet<String> = HashSet::new();
            for (container_id, container) in state.container_state.containers.iter_mut() {
                container.members.retain(|member| member != &seq_id);
                if container.members.is_empty() {
                    empty_container_ids.insert(container_id.clone());
                }
            }
            for container_id in &empty_container_ids {
                state.container_state.containers.remove(container_id);
            }
            for arrangement in state.container_state.arrangements.values_mut() {
                arrangement
                    .lane_container_ids
                    .retain(|container_id| !empty_container_ids.contains(container_id));
            }
            state
                .container_state
                .arrangements
                .retain(|_, arrangement| !arrangement.lane_container_ids.is_empty());
            let live_sequence_ids: HashSet<String> =
                state.sequences.keys().cloned().collect::<HashSet<_>>();
            let container_members_by_id: HashMap<String, HashSet<String>> = state
                .container_state
                .containers
                .iter()
                .map(|(container_id, container)| {
                    (
                        container_id.clone(),
                        container.members.iter().cloned().collect::<HashSet<_>>(),
                    )
                })
                .collect();
            state
                .container_state
                .seq_to_latest_container
                .retain(|member_seq, container_id| {
                    member_seq != &seq_id
                        && live_sequence_ids.contains(member_seq)
                        && container_members_by_id
                            .get(container_id)
                            .map(|members| members.contains(member_seq))
                            .unwrap_or(false)
                });
            seq_id
        };

        if let Some(viewport_id) = self.find_open_sequence_viewport_id(&seq_id) {
            if let Ok(mut to_close) = self.windows_to_close.write()
                && !to_close.contains(&viewport_id)
            {
                to_close.push(viewport_id);
            }
            self.pending_focus_viewports.retain(|id| *id != viewport_id);
        }
        self.new_windows
            .retain(|window| window.sequence_id().as_deref() != Some(seq_id.as_str()));
        self.lineage_group_marked_nodes.remove(node_id);
        if self
            .lineage_graph_selected_node_id
            .as_deref()
            .is_some_and(|selected| selected == node_id)
        {
            self.lineage_graph_selected_node_id = None;
        }
        if self
            .lineage_node_rename_target_id
            .as_deref()
            .is_some_and(|target| target == node_id)
        {
            self.lineage_node_rename_target_id = None;
            self.lineage_node_rename_text.clear();
        }
        if self
            .lineage_node_remove_target_id
            .as_deref()
            .is_some_and(|target| target == node_id)
        {
            self.lineage_node_remove_target_id = None;
        }
        self.lineage_cache_valid = false;
        Ok(format!(
            "Removed leaf node '{}' (sequence '{}')",
            node_id, seq_id
        ))
    }

    fn rename_leaf_lineage_node(
        &mut self,
        node_id: &str,
        new_name: &str,
    ) -> Result<String, String> {
        let node_id = node_id.trim();
        let new_name = new_name.trim();
        if node_id.is_empty() {
            return Err("Node id cannot be empty".to_string());
        }
        if new_name.is_empty() {
            return Err("New name cannot be empty".to_string());
        }
        let seq_id = {
            let mut engine = self.engine.write().unwrap();
            let state = engine.state_mut();
            let Some(node) = state.lineage.nodes.get(node_id).cloned() else {
                return Err(format!("Node '{}' not found", node_id));
            };
            if state
                .lineage
                .edges
                .iter()
                .any(|edge| edge.from_node_id == node_id)
            {
                return Err(format!(
                    "Node '{}' is not a leaf; rename is leaf-only in this first implementation",
                    node_id
                ));
            }
            let seq_id = node.seq_id.clone();
            let Some(dna) = state.sequences.get_mut(&seq_id) else {
                return Err(format!(
                    "Sequence '{}' for node '{}' is missing",
                    seq_id, node_id
                ));
            };
            dna.set_name(new_name.to_string());
            seq_id
        };
        self.lineage_cache_valid = false;
        Ok(format!(
            "Renamed leaf node '{}' (sequence '{}') to '{}'",
            node_id, seq_id, new_name
        ))
    }

    fn render_lineage_node_rename_window(
        &mut self,
        ctx: &egui::Context,
        persist_workspace_after_frame: &mut bool,
    ) {
        let Some(target_node_id) = self.lineage_node_rename_target_id.clone() else {
            return;
        };
        let mut open = true;
        let mut apply_clicked = false;
        egui::Window::new("Rename Leaf Node")
            .open(&mut open)
            .collapsible(false)
            .resizable(false)
            .default_size(Vec2::new(420.0, 120.0))
            .show(ctx, |ui| {
                ui.monospace(format!("node: {}", target_node_id));
                ui.horizontal(|ui| {
                    ui.label("new_name");
                    ui.text_edit_singleline(&mut self.lineage_node_rename_text)
                        .on_hover_text("Display name shown in lineage graph/table");
                });
                ui.horizontal(|ui| {
                    if ui
                        .button("Apply")
                        .on_hover_text("Apply leaf-node rename")
                        .clicked()
                    {
                        apply_clicked = true;
                    }
                    if ui
                        .button("Cancel")
                        .on_hover_text("Close rename window without changes")
                        .clicked()
                    {
                        self.lineage_node_rename_target_id = None;
                        self.lineage_node_rename_text.clear();
                    }
                });
            });
        if !open {
            self.lineage_node_rename_target_id = None;
            self.lineage_node_rename_text.clear();
            return;
        }
        if apply_clicked {
            let rename_text = self.lineage_node_rename_text.clone();
            self.lineage_group_status =
                match self.rename_leaf_lineage_node(&target_node_id, &rename_text) {
                    Ok(status) => {
                        *persist_workspace_after_frame = true;
                        self.lineage_node_rename_target_id = None;
                        self.lineage_node_rename_text.clear();
                        status
                    }
                    Err(err) => err,
                };
        }
    }

    fn render_lineage_node_remove_confirm_window(
        &mut self,
        ctx: &egui::Context,
        persist_workspace_after_frame: &mut bool,
    ) {
        let Some(target_node_id) = self.lineage_node_remove_target_id.clone() else {
            return;
        };
        let seq_id_hint = {
            let engine = self.engine.read().unwrap();
            let state = engine.state();
            state
                .lineage
                .nodes
                .get(&target_node_id)
                .map(|node| node.seq_id.clone())
                .unwrap_or_else(|| "-".to_string())
        };
        let mut open = true;
        let mut remove_clicked = false;
        egui::Window::new("Remove Leaf Node")
            .open(&mut open)
            .collapsible(false)
            .resizable(false)
            .default_size(Vec2::new(460.0, 130.0))
            .show(ctx, |ui| {
                ui.colored_label(
                    egui::Color32::from_rgb(150, 20, 20),
                    "This action removes the sequence/node from the current project.",
                );
                ui.monospace(format!("node: {}", target_node_id));
                ui.monospace(format!("sequence: {}", seq_id_hint));
                ui.horizontal(|ui| {
                    if ui
                        .button("Remove")
                        .on_hover_text("Confirm removal of this leaf node")
                        .clicked()
                    {
                        remove_clicked = true;
                    }
                    if ui
                        .button("Cancel")
                        .on_hover_text("Cancel removal")
                        .clicked()
                    {
                        self.lineage_node_remove_target_id = None;
                    }
                });
            });
        if !open {
            self.lineage_node_remove_target_id = None;
            return;
        }
        if remove_clicked {
            self.lineage_group_status = match self.remove_leaf_lineage_node(&target_node_id) {
                Ok(status) => {
                    *persist_workspace_after_frame = true;
                    self.lineage_node_remove_target_id = None;
                    status
                }
                Err(err) => err,
            };
        }
    }

    fn normalized_lineage_panel_heights(
        total_available_height: f32,
        preferred_split_fraction: f32,
    ) -> (f32, f32, f32) {
        let min_graph_height = 280.0;
        let min_container_height = 120.0;
        let min_total_height = min_graph_height + min_container_height;
        let total_height = if total_available_height.is_finite() {
            total_available_height.clamp(min_total_height, 4000.0)
        } else {
            min_total_height
        };
        let clamped_split = preferred_split_fraction.clamp(0.2, 0.9);
        let graph_height = (total_height * clamped_split)
            .clamp(min_graph_height, total_height - min_container_height);
        let container_height = (total_height - graph_height)
            .clamp(min_container_height, total_height - min_graph_height);
        let realized_split = (graph_height / total_height.max(1.0)).clamp(0.2, 0.9);
        (graph_height, container_height, realized_split)
    }

    fn normalized_lineage_container_subpanel_heights(
        total_available_height: f32,
        preferred_split_fraction: f32,
    ) -> (f32, f32, f32) {
        let min_containers_height = 80.0;
        let min_arrangements_height = 80.0;
        let min_total_height = min_containers_height + min_arrangements_height;
        let total_height = if total_available_height.is_finite() {
            total_available_height.clamp(min_total_height, 2400.0)
        } else {
            min_total_height
        };
        let clamped_split = preferred_split_fraction.clamp(0.2, 0.8);
        let containers_height = (total_height * clamped_split).clamp(
            min_containers_height,
            total_height - min_arrangements_height,
        );
        let arrangements_height = (total_height - containers_height).clamp(
            min_arrangements_height,
            total_height - min_containers_height,
        );
        let realized_split = (containers_height / total_height.max(1.0)).clamp(0.2, 0.8);
        (containers_height, arrangements_height, realized_split)
    }

    fn render_main_lineage(&mut self, ui: &mut Ui) {
        self.refresh_lineage_cache_if_needed();

        ui.heading("Lineage Graph");
        ui.label(format!("Project: {}", self.current_project_name()));
        ui.label("Project-level sequence lineage (branch and merge aware)");
        ui.horizontal_wrapped(|ui| {
            let table = self.track_hover_status(
                ui.selectable_label(!self.lineage_graph_view, "Table")
                    .on_hover_text("Show lineage as table"),
                "Lineage > View Table",
            );
            if table.clicked() {
                self.lineage_graph_view = false;
            }
            let graph = self.track_hover_status(
                ui.selectable_label(self.lineage_graph_view, "Graph")
                    .on_hover_text("Show lineage as node graph"),
                "Lineage > View Graph",
            );
            if graph.clicked() {
                self.lineage_graph_view = true;
            }
        });
        ui.separator();

        let mut open_seq: Option<String> = None;
        let mut open_pool: Option<(String, Vec<String>)> = None;
        let mut open_lineage_retrieval: Option<LineageRetrievalDescriptor> = None;
        let mut open_lane_containers: Option<Vec<String>> = None;
        let mut export_container_gel: Option<(String, Vec<String>)> = None;
        let mut export_arrangement_gel: Option<(String, String)> = None;
        let mut select_candidate_from: Option<String> = None;
        let mut graph_zoom = self.lineage_graph_zoom.clamp(0.35, 4.0);
        let mut graph_area_height = self.lineage_graph_area_height.clamp(280.0, 2400.0);
        let mut container_area_height = self.lineage_container_area_height.clamp(120.0, 1600.0);
        let mut container_arrangement_split_fraction = self
            .lineage_container_arrangement_split_fraction
            .clamp(0.2, 0.8);
        let mut main_split_fraction = self.lineage_main_split_fraction.clamp(0.2, 0.9);
        let mut graph_scroll_offset = Vec2::new(
            if self.lineage_graph_scroll_offset.x.is_finite() {
                self.lineage_graph_scroll_offset.x.max(0.0)
            } else {
                0.0
            },
            if self.lineage_graph_scroll_offset.y.is_finite() {
                self.lineage_graph_scroll_offset.y.max(0.0)
            } else {
                0.0
            },
        );
        let mut graph_compact_labels = self.lineage_graph_compact_labels;
        let mut persist_workspace_after_frame = false;
        let mut graph_rows = self.lineage_rows.clone();
        let mut graph_edges = self.lineage_edges.clone();
        let mut graph_op_label_by_id = self.lineage_op_label_by_id.clone();
        let seq_node_by_seq_id: HashMap<String, String> = self
            .lineage_rows
            .iter()
            .filter(|row| row.kind == LineageNodeKind::Sequence)
            .map(|row| (row.seq_id.clone(), row.node_id.clone()))
            .collect();
        let container_members_by_id: HashMap<String, Vec<String>> = self
            .lineage_containers
            .iter()
            .map(|row| (row.container_id.clone(), row.members.clone()))
            .collect();
        for arrangement in &self.lineage_arrangements {
            let arrangement_node_id = format!("arr:{}", arrangement.arrangement_id);
            let mut source_node_ids: Vec<String> = vec![];
            let mut seen_sources: HashSet<String> = HashSet::new();
            for container_id in &arrangement.lane_container_ids {
                if let Some(members) = container_members_by_id.get(container_id) {
                    for seq_id in members {
                        if let Some(source_node_id) = seq_node_by_seq_id.get(seq_id).cloned() {
                            if seen_sources.insert(source_node_id.clone()) {
                                source_node_ids.push(source_node_id.clone());
                                graph_edges.push((
                                    source_node_id,
                                    arrangement_node_id.clone(),
                                    arrangement.created_by_op.clone(),
                                ));
                            }
                        }
                    }
                }
            }
            graph_op_label_by_id
                .entry(arrangement.created_by_op.clone())
                .or_insert_with(|| "Arrange serial lanes".to_string());
            graph_rows.push(LineageRow {
                kind: LineageNodeKind::Arrangement,
                node_id: arrangement_node_id,
                seq_id: arrangement.arrangement_id.clone(),
                display_name: if arrangement.name.trim().is_empty() {
                    arrangement.arrangement_id.clone()
                } else {
                    arrangement.name.clone()
                },
                origin: "Arrangement".to_string(),
                created_by_op: arrangement.created_by_op.clone(),
                created_at: arrangement.created_at,
                parents: source_node_ids,
                length: 0,
                circular: false,
                pool_size: 1,
                pool_members: vec![],
                arrangement_id: Some(arrangement.arrangement_id.clone()),
                arrangement_mode: Some(arrangement.mode.clone()),
                lane_container_ids: arrangement.lane_container_ids.clone(),
                ladders: arrangement.ladders.clone(),
                genome_anchor_summary: None,
                genome_anchor_display: None,
                is_full_genome_sequence: false,
                retrieval_descriptor: None,
                analysis_kind: None,
                analysis_artifact_id: None,
                analysis_reference_seq_id: None,
                analysis_mode: None,
                analysis_point_count: None,
                analysis_bin_count: None,
                macro_instance_id: None,
                macro_routine_id: None,
                macro_template_name: None,
                macro_status: None,
                macro_status_message: None,
                macro_op_ids: vec![],
                macro_inputs: vec![],
                macro_outputs: vec![],
            });
        }
        graph_rows.sort_by(|a, b| {
            a.created_at
                .cmp(&b.created_at)
                .then(a.node_id.cmp(&b.node_id))
        });

        let valid_lineage_node_ids: HashSet<String> =
            graph_rows.iter().map(|row| row.node_id.clone()).collect();
        self.lineage_group_marked_nodes
            .retain(|node_id| valid_lineage_node_ids.contains(node_id));
        let mut sanitized_groups =
            Self::sanitize_lineage_node_groups(&self.lineage_node_groups, &valid_lineage_node_ids);
        if sanitized_groups != self.lineage_node_groups {
            self.lineage_node_groups = sanitized_groups.clone();
            if self
                .lineage_group_form_editing_id
                .as_ref()
                .is_some_and(|group_id| {
                    !self
                        .lineage_node_groups
                        .iter()
                        .any(|group| &group.group_id == group_id)
                })
            {
                self.lineage_group_form_editing_id = None;
            }
            persist_workspace_after_frame = true;
        }

        let mut splitter_dragging = false;
        egui::ScrollArea::vertical()
            .id_salt("lineage_main_scroll")
            .auto_shrink([false, false])
            .scroll_source(egui::containers::scroll_area::ScrollSource {
                drag: false,
                ..Default::default()
            })
            .show(ui, |ui| {
                scroll_input_policy::apply_scrollarea_keyboard_navigation(
                    ui,
                    scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                );
                ui.collapsing("Node Groups", |ui| {
                    ui.small(
                        "Group lineage nodes into disjoint sets. Members are shown indented in table view and can collapse to the representative node in graph view.",
                    );
                    if self.lineage_group_marked_nodes.is_empty() {
                        ui.small("Marked nodes: none");
                    } else {
                        let mut marked = self
                            .lineage_group_marked_nodes
                            .iter()
                            .cloned()
                            .collect::<Vec<_>>();
                        marked.sort();
                        ui.horizontal_wrapped(|ui| {
                            ui.small(format!("Marked nodes ({})", marked.len()));
                            ui.monospace(marked.join(", "));
                            if ui
                                .small_button("Clear marked")
                                .on_hover_text("Clear marked candidate nodes for grouping")
                                .clicked()
                            {
                                self.lineage_group_marked_nodes.clear();
                                self.lineage_group_status = "Cleared marked nodes".to_string();
                            }
                        });
                    }
                    if !self.lineage_group_status.trim().is_empty() {
                        ui.small(self.lineage_group_status.clone());
                    }
                    if self.lineage_node_groups.is_empty() {
                        ui.small("No node groups yet.");
                    } else {
                        egui::Grid::new("lineage_node_groups_grid")
                            .striped(true)
                            .min_col_width(48.0)
                            .show(ui, |ui| {
                                ui.strong("Collapse");
                                ui.strong("Group");
                                ui.strong("Representative");
                                ui.strong("Members");
                                ui.strong("Actions");
                                ui.end_row();
                                let mut edit_group_id: Option<String> = None;
                                let mut delete_group_id: Option<String> = None;
                                for group in &mut self.lineage_node_groups {
                                    if ui.checkbox(&mut group.collapsed, "").changed() {
                                        persist_workspace_after_frame = true;
                                    }
                                    ui.label(format!("{} ({})", group.label, group.group_id));
                                    ui.monospace(group.representative_node_id.clone());
                                    ui.monospace(group.member_node_ids.join(", "));
                                    ui.horizontal(|ui| {
                                        if ui
                                            .small_button("Edit")
                                            .on_hover_text("Edit this node group")
                                            .clicked()
                                        {
                                            edit_group_id = Some(group.group_id.clone());
                                        }
                                        if ui
                                            .small_button("Delete")
                                            .on_hover_text("Delete this node group")
                                            .clicked()
                                        {
                                            delete_group_id = Some(group.group_id.clone());
                                        }
                                    });
                                    ui.end_row();
                                }
                                if let Some(group_id) = edit_group_id {
                                    if let Some(group) = self
                                        .lineage_node_groups
                                        .iter()
                                        .find(|group| group.group_id == group_id)
                                    {
                                        self.lineage_group_form_editing_id =
                                            Some(group.group_id.clone());
                                        self.lineage_group_form_label = group.label.clone();
                                        self.lineage_group_form_representative =
                                            group.representative_node_id.clone();
                                        self.lineage_group_form_members =
                                            group.member_node_ids.join(", ");
                                        self.lineage_group_status =
                                            format!("Editing group '{}'", group.label);
                                    }
                                }
                                if let Some(group_id) = delete_group_id {
                                    let before = self.lineage_node_groups.len();
                                    self.lineage_node_groups
                                        .retain(|group| group.group_id != group_id);
                                    if self.lineage_node_groups.len() != before {
                                        if self
                                            .lineage_group_form_editing_id
                                            .as_ref()
                                            .is_some_and(|editing_id| editing_id == &group_id)
                                        {
                                            self.lineage_group_form_editing_id = None;
                                        }
                                        self.lineage_group_status =
                                            format!("Deleted group '{group_id}'");
                                        persist_workspace_after_frame = true;
                                    }
                                }
                            });
                    }
                    ui.separator();
                    let editing = self.lineage_group_form_editing_id.is_some();
                    ui.label(if editing {
                        "Edit node group"
                    } else {
                        "Create node group"
                    });
                    ui.horizontal(|ui| {
                        ui.label("Label");
                        ui.text_edit_singleline(&mut self.lineage_group_form_label);
                    });
                    ui.horizontal(|ui| {
                        ui.label("Representative");
                        ui.text_edit_singleline(&mut self.lineage_group_form_representative);
                        if ui
                            .small_button("Use selected")
                            .on_hover_text("Use currently selected graph node as representative")
                            .clicked()
                        {
                            if let Some(selected_node_id) = &self.lineage_graph_selected_node_id {
                                self.lineage_group_form_representative = selected_node_id.clone();
                            }
                        }
                    });
                    ui.horizontal(|ui| {
                        ui.label("Members");
                        ui.text_edit_singleline(&mut self.lineage_group_form_members);
                    });
                    ui.small(
                        "Members: comma/space/newline separated node ids (representative excluded).",
                    );
                    ui.horizontal(|ui| {
                        let save_label = if editing { "Apply Group" } else { "Add Group" };
                        if ui.button(save_label).clicked() {
                            match self.apply_lineage_group_form(&valid_lineage_node_ids) {
                                Ok(status) => {
                                    self.lineage_group_status = status;
                                    persist_workspace_after_frame = true;
                                }
                                Err(err) => {
                                    self.lineage_group_status = err;
                                }
                            }
                        }
                        if ui.button("Clear Form").clicked() {
                            self.lineage_group_form_editing_id = None;
                            self.lineage_group_form_label.clear();
                            self.lineage_group_form_members.clear();
                            self.lineage_group_form_representative.clear();
                            self.lineage_group_status.clear();
                            self.lineage_group_marked_nodes.clear();
                        }
                    });
                });
                ui.separator();

                sanitized_groups = Self::sanitize_lineage_node_groups(
                    &self.lineage_node_groups,
                    &valid_lineage_node_ids,
                );
                if sanitized_groups != self.lineage_node_groups {
                    self.lineage_node_groups = sanitized_groups.clone();
                    persist_workspace_after_frame = true;
                }
                let lineage_groups = self.lineage_node_groups.clone();
                let (group_by_id, node_to_group_id) = Self::lineage_node_group_maps(&lineage_groups);
                let (projected_graph_rows, projected_graph_edges) =
                    Self::project_lineage_graph_by_groups(&graph_rows, &graph_edges, &lineage_groups);
                let collapsed_group_badges = Self::lineage_collapsed_group_hidden_op_badges(
                    &graph_edges,
                    &lineage_groups,
                    &graph_op_label_by_id,
                );
                let table_entries = Self::build_lineage_table_entries(&graph_rows, &lineage_groups);
                let leaf_node_ids = Self::lineage_leaf_node_ids(&graph_rows, &graph_edges);
                let visible_node_ids: HashSet<String> = projected_graph_rows
                    .iter()
                    .map(|row| row.node_id.clone())
                    .collect();
                if let Some(selected_node_id) = self.lineage_graph_selected_node_id.clone() {
                    if !visible_node_ids.contains(&selected_node_id) {
                        let remapped = node_to_group_id
                            .get(&selected_node_id)
                            .and_then(|group_id| group_by_id.get(group_id))
                            .map(|group| group.representative_node_id.clone());
                        self.lineage_graph_selected_node_id = remapped;
                    }
                }
                // Keep graph + containers filling the lineage viewport proportionally.
                let visible_height = ui.clip_rect().height();
                let panel_budget_height = if visible_height.is_finite() && visible_height > 0.0 {
                    ui.available_height().min(visible_height)
                } else {
                    ui.available_height()
                };
                let (target_graph_height, target_container_height, normalized_split) =
                    Self::normalized_lineage_panel_heights(panel_budget_height, main_split_fraction);
                graph_area_height = target_graph_height;
                container_area_height = target_container_height;
                main_split_fraction = normalized_split;

                if self.lineage_graph_view {
            if self.lineage_graph_offsets_synced_stamp != self.lineage_cache_stamp {
                let offset_count_before = self.lineage_graph_node_offsets.len();
                let active_node_ids = graph_rows
                    .iter()
                    .map(|row| row.node_id.clone())
                    .collect::<std::collections::HashSet<_>>();
                self.lineage_graph_node_offsets
                    .retain(|node_id, _| active_node_ids.contains(node_id));
                if self
                    .lineage_graph_drag_origin
                    .as_ref()
                    .is_some_and(|(node_id, _)| !active_node_ids.contains(node_id))
                {
                    self.lineage_graph_drag_origin = None;
                }
                if self
                    .lineage_graph_pan_origin
                    .as_ref()
                    .is_some_and(|_| active_node_ids.is_empty())
                {
                    self.lineage_graph_pan_origin = None;
                }
                if self
                    .lineage_graph_selected_node_id
                    .as_ref()
                    .is_some_and(|node_id| !active_node_ids.contains(node_id))
                {
                    self.lineage_graph_selected_node_id = None;
                }
                if self.lineage_graph_node_offsets.len() != offset_count_before {
                    persist_workspace_after_frame = true;
                }
                self.lineage_graph_offsets_synced_stamp = self.lineage_cache_stamp;
            }
            let mut request_fit_zoom = false;
            let mut request_fit_origin = false;
            ui.horizontal_wrapped(|ui| {
                ui.label("Legend:");
                ui.colored_label(egui::Color32::from_rgb(90, 140, 210), "● single sequence");
                ui.colored_label(egui::Color32::from_rgb(180, 120, 70), "◆ pool");
                ui.colored_label(egui::Color32::from_rgb(98, 98, 108), "▭ macro run");
                ui.colored_label(egui::Color32::from_rgb(108, 154, 122), "▭ arrangement");
                ui.colored_label(egui::Color32::from_rgb(188, 146, 48), "▣ retrieval pattern");
                ui.colored_label(egui::Color32::from_rgb(145, 145, 145), "◻ node group");
            });
            ui.horizontal_wrapped(|ui| {
                let zoom_out_resp = self.track_hover_status(
                    ui.button("−").on_hover_text("Zoom out"),
                    "Lineage Graph > Zoom Out",
                );
                if zoom_out_resp.clicked() {
                    graph_zoom = (graph_zoom / 1.15).clamp(0.35, 4.0);
                }
                let zoom_in_resp = self.track_hover_status(
                    ui.button("+").on_hover_text("Zoom in"),
                    "Lineage Graph > Zoom In",
                );
                if zoom_in_resp.clicked() {
                    graph_zoom = (graph_zoom * 1.15).clamp(0.35, 4.0);
                }
                let zoom_reset_resp = self.track_hover_status(
                    ui.button("Reset").on_hover_text("Reset zoom"),
                    "Lineage Graph > Zoom Reset",
                );
                if zoom_reset_resp.clicked() {
                    graph_zoom = 1.0;
                }
                let fit_resp = self.track_hover_status(
                    ui.button("Fit")
                        .on_hover_text("Fit full graph content into current graph area"),
                    "Lineage Graph > Fit",
                );
                if fit_resp.clicked() {
                    request_fit_zoom = true;
                    request_fit_origin = true;
                }
                let reset_layout_resp = self.track_hover_status(
                    ui.button("Reset Layout")
                        .on_hover_text("Reset manually moved node positions"),
                    "Lineage Graph > Reset Layout",
                );
                if reset_layout_resp.clicked() {
                    self.lineage_graph_node_offsets.clear();
                    self.lineage_graph_drag_origin = None;
                    self.lineage_graph_pan_origin = None;
                    persist_workspace_after_frame = true;
                }
                if ui
                    .checkbox(&mut graph_compact_labels, "Compact labels")
                    .on_hover_text(
                        "Reduce label density in crowded graphs by simplifying operation and node labels",
                    )
                    .changed()
                {
                    persist_workspace_after_frame = true;
                }
                ui.add(
                    egui::Slider::new(&mut graph_zoom, 0.35..=4.0)
                        .logarithmic(true)
                        .text("Zoom"),
                );
                ui.label(format!("{:.0}%", graph_zoom * 100.0));
            });
            ui.separator();
            let rows = &projected_graph_rows;
            let lineage_edges = &projected_graph_edges;
            let op_label_by_id = &graph_op_label_by_id;
            let graph_panel_width = ui.available_width().max(1.0);
            let graph_panel_height = graph_area_height.max(280.0);
            ui.allocate_ui_with_layout(
                egui::vec2(graph_panel_width, graph_panel_height),
                egui::Layout::top_down(egui::Align::Min),
                |ui| {
                    ui.set_min_width(graph_panel_width);
                    ui.set_max_width(graph_panel_width);
                    ui.small(
                        "Shift+scroll zooms (Cmd/Ctrl+scroll still works). Option+drag pans; Space+drag pans on background. Drag nodes to reposition.",
                    );
                    let graph_scroll_output = egui::ScrollArea::both()
                        .id_salt("lineage_graph_scroll")
                        .auto_shrink([false, false])
                        .scroll_offset(graph_scroll_offset)
                        .scroll_source(egui::containers::scroll_area::ScrollSource { drag: false, ..Default::default() })
                        .max_height(ui.available_height())
                        .show(ui, |ui| {
                            let (layout_by_node, layer_count, max_nodes_in_layer) =
                                Self::compute_lineage_dag_layout(rows, lineage_edges);
                            let base_width = (layer_count.max(1) as f32) * 220.0 + 220.0;
                            let base_height = (max_nodes_in_layer.max(1) as f32) * 110.0 + 300.0;
                            if request_fit_zoom {
                                let available = ui.available_size();
                                let fit_x = ((available.x - 24.0).max(120.0) / base_width.max(1.0))
                                    .max(0.01);
                                let fit_y =
                                    ((available.y - 24.0).max(120.0) / base_height.max(1.0))
                                        .max(0.01);
                                graph_zoom = fit_x.min(fit_y).clamp(0.35, 4.0);
                                request_fit_zoom = false;
                            }
                            if request_fit_origin {
                                graph_scroll_offset = Vec2::ZERO;
                                self.lineage_graph_pan_origin = None;
                                request_fit_origin = false;
                            }
                            let width = (base_width * graph_zoom + 280.0 * graph_zoom)
                                .max(ui.available_width());
                            let height = base_height * graph_zoom;
                            let (resp, painter) = ui.allocate_painter(
                                Vec2::new(width, height),
                                egui::Sense::click_and_drag(),
                            );
                            let mut graph_wheel_intent = WheelIntent::None;
                            if resp.hovered() {
                                let (wheel_delta, modifiers) =
                                    ui.input(|i| (i.smooth_scroll_delta, i.modifiers));
                                graph_wheel_intent = scroll_input_policy::lineage_graph_wheel_intent(
                                    wheel_delta,
                                    modifiers,
                                );
                                if let WheelIntent::Zoom { direction, amount } = graph_wheel_intent
                                {
                                    let signed_amount = if direction == ZoomDirection::In {
                                        amount
                                    } else {
                                        -amount
                                    };
                                    let factor = (1.0 + signed_amount * 0.0015).clamp(0.8, 1.25);
                                    graph_zoom = (graph_zoom * factor).clamp(0.35, 4.0);
                                }
                                if !ui.ctx().wants_keyboard_input() {
                                    let keyboard_pan_delta = ui.input(|i| {
                                        scroll_input_policy::canvas_keyboard_pan_delta(
                                            i,
                                            scroll_input_policy::DEFAULT_CANVAS_PAN_STEP,
                                        )
                                    });
                                    if keyboard_pan_delta != Vec2::ZERO {
                                        graph_scroll_offset.x =
                                            (graph_scroll_offset.x + keyboard_pan_delta.x).max(0.0);
                                        graph_scroll_offset.y =
                                            (graph_scroll_offset.y + keyboard_pan_delta.y).max(0.0);
                                    }
                                    let zoom_steps =
                                        ui.input(scroll_input_policy::canvas_keyboard_zoom_steps);
                                    if zoom_steps != 0 {
                                        for _ in 0..zoom_steps.unsigned_abs() {
                                            graph_zoom = if zoom_steps > 0 {
                                                (graph_zoom * 1.12).clamp(0.35, 4.0)
                                            } else {
                                                (graph_zoom / 1.12).clamp(0.35, 4.0)
                                            };
                                        }
                                    }
                                }
                            }
                            let dense_graph = rows.len() >= 22 || lineage_edges.len() >= 30;
                            let simplify_labels = graph_compact_labels && dense_graph;
                            let edge_label_stride = if simplify_labels {
                                if lineage_edges.len() > 180 {
                                    4
                                } else if lineage_edges.len() > 120 {
                                    3
                                } else if lineage_edges.len() > 60 {
                                    2
                                } else {
                                    1
                                }
                            } else {
                                1
                            };
                            let rect = resp.rect;
                            let edge_stroke_width = (1.0 * graph_zoom).clamp(1.0, 2.5);
                            let node_id_font_size = (10.0 * graph_zoom).clamp(8.0, 15.0);
                            let op_font_size = if simplify_labels {
                                (9.0 * graph_zoom).clamp(8.0, 14.0)
                            } else {
                                (10.0 * graph_zoom).clamp(9.0, 16.0)
                            };
                            let name_font_size = if simplify_labels {
                                (11.0 * graph_zoom).clamp(9.0, 15.0)
                            } else {
                                (12.0 * graph_zoom).clamp(10.0, 18.0)
                            };
                            let details_font_size = (10.0 * graph_zoom).clamp(9.0, 15.0);
                            let node_radius = 16.0 * graph_zoom;
                            let mut pos_by_node: HashMap<String, Pos2> = HashMap::new();
                            for (fallback_rank, row) in rows.iter().enumerate() {
                                let (layer, rank) = layout_by_node
                                    .get(&row.node_id)
                                    .copied()
                                    .unwrap_or((0, fallback_rank));
                                let manual_offset = self
                                    .lineage_graph_node_offsets
                                    .get(&row.node_id)
                                    .copied()
                                    .unwrap_or(Vec2::ZERO);
                                let x = rect.left()
                                    + (120.0 + layer as f32 * 220.0) * graph_zoom
                                    + manual_offset.x;
                                let y = rect.top()
                                    + (120.0 + rank as f32 * 110.0) * graph_zoom
                                    + manual_offset.y;
                                pos_by_node.insert(row.node_id.clone(), Pos2::new(x, y));
                            }
                            for group in &lineage_groups {
                                let mut group_nodes: Vec<String> =
                                    Vec::with_capacity(group.member_node_ids.len() + 1);
                                group_nodes.push(group.representative_node_id.clone());
                                group_nodes.extend(group.member_node_ids.clone());
                                let mut bounds: Option<egui::Rect> = None;
                                let mut visible_nodes = 0usize;
                                for node_id in group_nodes {
                                    let Some(pos) = pos_by_node.get(&node_id).copied() else {
                                        continue;
                                    };
                                    visible_nodes += 1;
                                    let glyph_rect = egui::Rect::from_center_size(
                                        pos,
                                        Vec2::new(52.0 * graph_zoom, 42.0 * graph_zoom),
                                    );
                                    bounds = Some(if let Some(existing) = bounds {
                                        existing.union(glyph_rect)
                                    } else {
                                        glyph_rect
                                    });
                                }
                                let Some(mut bounds) = bounds else {
                                    continue;
                                };
                                bounds = bounds.expand(24.0 * graph_zoom);
                                let group_color = Self::lineage_group_color(&group.group_id);
                                painter.rect_filled(
                                    bounds,
                                    10.0 * graph_zoom,
                                    egui::Color32::from_rgba_premultiplied(
                                        group_color.r(),
                                        group_color.g(),
                                        group_color.b(),
                                        18,
                                    ),
                                );
                                painter.rect_stroke(
                                    bounds,
                                    10.0 * graph_zoom,
                                    egui::Stroke::new((1.4 * graph_zoom).clamp(1.0, 2.2), group_color),
                                    egui::StrokeKind::Inside,
                                );
                                let mut label = group.label.clone();
                                if group.collapsed {
                                    label.push_str(&format!(" (collapsed, {} hidden)", group.member_node_ids.len()));
                                } else {
                                    label.push_str(&format!(" ({visible_nodes} node(s))"));
                                }
                                painter.text(
                                    Pos2::new(bounds.left() + 8.0 * graph_zoom, bounds.top() - 2.0 * graph_zoom),
                                    egui::Align2::LEFT_BOTTOM,
                                    label,
                                    egui::FontId::proportional((10.0 * graph_zoom).clamp(9.0, 14.0)),
                                    group_color,
                                );
                            }
                            let pointer = resp.interact_pointer_pos();
                            let is_node_hit = |row: &LineageRow, pointer: Pos2| -> bool {
                                let Some(pos) = pos_by_node.get(&row.node_id).copied() else {
                                    return false;
                                };
                                let glyph_hit = match row.kind {
                                    LineageNodeKind::Arrangement => egui::Rect::from_center_size(
                                        pos,
                                        Vec2::new(56.0 * graph_zoom, 28.0 * graph_zoom),
                                    )
                                    .contains(pointer),
                                    LineageNodeKind::Macro => egui::Rect::from_center_size(
                                        pos,
                                        Vec2::new(64.0 * graph_zoom, 30.0 * graph_zoom),
                                    )
                                    .contains(pointer),
                                    LineageNodeKind::Analysis => egui::Rect::from_center_size(
                                        pos,
                                        Vec2::new(62.0 * graph_zoom, 28.0 * graph_zoom),
                                    )
                                    .contains(pointer),
                                    LineageNodeKind::Sequence if row.pool_size > 1 => {
                                        egui::Rect::from_center_size(
                                            pos,
                                            Vec2::new(34.0 * graph_zoom, 28.0 * graph_zoom),
                                        )
                                        .contains(pointer)
                                    }
                                    LineageNodeKind::Sequence => pointer.distance(pos) <= 19.0 * graph_zoom,
                                };
                                if glyph_hit {
                                    return true;
                                }
                                let display_name = if simplify_labels {
                                    Self::compact_lineage_node_label(&row.display_name, 26)
                                } else {
                                    row.display_name.clone()
                                };
                                let name_galley = painter.layout_no_wrap(
                                    display_name,
                                    egui::FontId::proportional(name_font_size),
                                    egui::Color32::BLACK,
                                );
                                let name_anchor = pos + Vec2::new(22.0 * graph_zoom, -4.0 * graph_zoom);
                                let name_rect = egui::Rect::from_min_size(
                                    Pos2::new(name_anchor.x, name_anchor.y - name_galley.size().y),
                                    name_galley.size(),
                                )
                                .expand(3.0 * graph_zoom);
                                if name_rect.contains(pointer) {
                                    return true;
                                }
                                if !simplify_labels {
                                    let detail_text = match row.kind {
                                        LineageNodeKind::Arrangement => {
                                            let ladders = if row.ladders.is_empty() {
                                                "auto".to_string()
                                            } else {
                                                row.ladders.join(" + ")
                                            };
                                            format!(
                                                "{} lane(s) | mode={} | ladders={}",
                                                row.lane_container_ids.len(),
                                                row.arrangement_mode
                                                    .as_deref()
                                                    .unwrap_or("Serial")
                                                    .to_lowercase(),
                                                ladders
                                            )
                                        }
                                        LineageNodeKind::Macro => format!(
                                            "ops={} | template={} | status={}",
                                            row.macro_op_ids.len(),
                                            row.macro_template_name
                                                .as_deref()
                                                .unwrap_or("-"),
                                            row.macro_status.as_deref().unwrap_or("ok")
                                        ),
                                        LineageNodeKind::Analysis => {
                                            let artifact_id = row
                                                .analysis_artifact_id
                                                .as_deref()
                                                .unwrap_or(&row.display_name);
                                            let mode = row.analysis_mode.as_deref().unwrap_or("-");
                                            match row.analysis_kind {
                                                Some(LineageAnalysisKind::Dotplot) => format!(
                                                    "{} | mode={} | points={}",
                                                    artifact_id,
                                                    mode,
                                                    row.analysis_point_count.unwrap_or(0)
                                                ),
                                                Some(LineageAnalysisKind::FlexibilityTrack) => {
                                                    format!(
                                                        "{} | model={} | bins={}",
                                                        artifact_id,
                                                        mode,
                                                        row.analysis_bin_count.unwrap_or(0)
                                                    )
                                                }
                                                None => artifact_id.to_string(),
                                            }
                                        }
                                        LineageNodeKind::Sequence if row.pool_size > 1 => {
                                            format!(
                                                "{} ({} bp) | pool={}",
                                                row.seq_id, row.length, row.pool_size
                                            )
                                        }
                                        LineageNodeKind::Sequence => {
                                            format!("{} ({} bp)", row.seq_id, row.length)
                                        }
                                    };
                                    let details_galley = painter.layout_no_wrap(
                                        detail_text,
                                        egui::FontId::proportional(details_font_size),
                                        egui::Color32::BLACK,
                                    );
                                    let details_anchor =
                                        pos + Vec2::new(22.0 * graph_zoom, 10.0 * graph_zoom);
                                    let details_rect =
                                        egui::Rect::from_min_size(details_anchor, details_galley.size())
                                            .expand(3.0 * graph_zoom);
                                    if details_rect.contains(pointer) {
                                        return true;
                                    }
                                }
                                false
                            };
                            let hovered_node_id = pointer.and_then(|pointer| {
                                rows.iter()
                                    .filter_map(|row| {
                                        if !is_node_hit(row, pointer) {
                                            return None;
                                        }
                                        pos_by_node
                                            .get(&row.node_id)
                                            .map(|pos| (row.node_id.clone(), pointer.distance_sq(*pos)))
                                    })
                                    .min_by(|a, b| {
                                        a.1.partial_cmp(&b.1)
                                            .unwrap_or(std::cmp::Ordering::Equal)
                                    })
                                    .map(|(node_id, _)| node_id)
                            });
                            let mut used_label_rects: Vec<egui::Rect> = Vec::new();
                            let mut op_label_galleys: HashMap<String, Arc<egui::Galley>> =
                                HashMap::new();
                            let mut retrieval_badge_rects: HashMap<String, egui::Rect> =
                                HashMap::new();
                            let edge_groups = Self::lineage_edge_groups(lineage_edges);
                            for (edge_idx, (from_node, to_node, op_ids)) in
                                edge_groups.iter().enumerate()
                            {
                                let Some(from) = pos_by_node.get(from_node) else {
                                    continue;
                                };
                                let Some(to) = pos_by_node.get(to_node) else {
                                    continue;
                                };
                                let mid = Pos2::new((from.x + to.x) * 0.5, (from.y + to.y) * 0.5);
                                let op_labels = Self::lineage_edge_operation_labels(op_ids, op_label_by_id);
                                let op_label = Self::lineage_edge_display_label(&op_labels);
                                let edge = *to - *from;
                                let edge_len = edge.length();
                                if edge_len < 0.1 {
                                    continue;
                                }
                                let edge_dir = edge / edge_len;
                                let op_node_size = (14.0 * graph_zoom).clamp(10.0, 20.0);
                                let op_rect =
                                    egui::Rect::from_center_size(mid, Vec2::splat(op_node_size));
                                let op_gap = op_node_size * 0.5 + 2.0 * graph_zoom;
                                if edge_len > op_gap * 2.0 + 2.0 * graph_zoom {
                                    painter.line_segment(
                                        [*from, mid - edge_dir * op_gap],
                                        egui::Stroke::new(edge_stroke_width, egui::Color32::GRAY),
                                    );
                                    painter.line_segment(
                                        [mid + edge_dir * op_gap, *to],
                                        egui::Stroke::new(edge_stroke_width, egui::Color32::GRAY),
                                    );
                                } else {
                                    painter.line_segment(
                                        [*from, *to],
                                        egui::Stroke::new(edge_stroke_width, egui::Color32::GRAY),
                                    );
                                }
                                let (op_symbol, op_fill_color) = Self::lineage_operation_glyph(&op_labels);
                                painter.rect_filled(op_rect, 2.0 * graph_zoom, op_fill_color);
                                painter.rect_stroke(
                                    op_rect,
                                    2.0 * graph_zoom,
                                    egui::Stroke::new(
                                        (1.1 * graph_zoom).clamp(1.0, 2.0),
                                        egui::Color32::from_rgb(55, 55, 55),
                                    ),
                                    egui::StrokeKind::Inside,
                                );
                                let op_symbol_font_size = if op_symbol.len() > 1 {
                                    (8.4 * graph_zoom).clamp(7.0, 10.5)
                                } else {
                                    (9.4 * graph_zoom).clamp(7.8, 11.8)
                                };
                                painter.text(
                                    mid,
                                    egui::Align2::CENTER_CENTER,
                                    op_symbol,
                                    egui::FontId::monospace(op_symbol_font_size),
                                    egui::Color32::WHITE,
                                );
                                used_label_rects.push(op_rect.expand(2.0 * graph_zoom));
                                if edge_label_stride > 1 && edge_idx % edge_label_stride != 0 {
                                    continue;
                                }
                                let display = if simplify_labels {
                                    Self::compact_lineage_op_label(&op_label)
                                } else {
                                    Self::lineage_edge_accessible_name(&op_labels)
                                };
                                let galley = op_label_galleys
                                    .entry(display.clone())
                                    .or_insert_with(|| {
                                        painter.layout_no_wrap(
                                            display.clone(),
                                            egui::FontId::proportional(op_font_size),
                                            egui::Color32::BLACK,
                                        )
                                    })
                                    .clone();
                                let perp = Vec2::new(-edge_dir.y, edge_dir.x);
                                let mut placed = None;
                                for idx in 0..14 {
                                    let sign = if idx % 2 == 0 { 1.0 } else { -1.0 };
                                    let step = (idx / 2) as f32;
                                    let candidate_center =
                                        mid + perp * (12.0 + step * 12.0) * graph_zoom * sign;
                                    let candidate_rect = egui::Rect::from_center_size(
                                        candidate_center,
                                        Vec2::new(
                                            galley.size().x + 10.0 * graph_zoom,
                                            galley.size().y + 6.0 * graph_zoom,
                                        ),
                                    );
                                    if !used_label_rects
                                        .iter()
                                        .any(|r| r.intersects(candidate_rect))
                                    {
                                        placed = Some((candidate_center, candidate_rect));
                                        break;
                                    }
                                }
                                let (label_center, bg_rect) = placed.unwrap_or_else(|| {
                                    let fallback_center = mid + perp * 12.0 * graph_zoom;
                                    let rect = egui::Rect::from_center_size(
                                        fallback_center,
                                        Vec2::new(
                                            galley.size().x + 10.0 * graph_zoom,
                                            galley.size().y + 6.0 * graph_zoom,
                                        ),
                                    );
                                    (fallback_center, rect)
                                });
                                used_label_rects.push(bg_rect);
                                painter.rect_filled(
                                    bg_rect,
                                    3.0 * graph_zoom,
                                    egui::Color32::from_rgba_premultiplied(245, 245, 245, 235),
                                );
                                painter.text(
                                    label_center,
                                    egui::Align2::CENTER_CENTER,
                                    display,
                                    egui::FontId::proportional(op_font_size),
                                    egui::Color32::BLACK,
                                );
                            }
                            for row in rows {
                                let Some(pos) = pos_by_node.get(&row.node_id).cloned() else {
                                    continue;
                                };
                                let is_selected = self
                                    .lineage_graph_selected_node_id
                                    .as_ref()
                                    .is_some_and(|node_id| node_id == &row.node_id);
                                let is_hovered = hovered_node_id
                                    .as_ref()
                                    .is_some_and(|node_id| node_id == &row.node_id);
                                let highlight_stroke = if is_selected {
                                    egui::Stroke::new(
                                        (2.4 * graph_zoom).clamp(1.6, 4.0),
                                        egui::Color32::from_rgb(250, 220, 80),
                                    )
                                } else if is_hovered {
                                    egui::Stroke::new(
                                        (2.0 * graph_zoom).clamp(1.4, 3.2),
                                        egui::Color32::from_rgb(230, 230, 150),
                                    )
                                } else {
                                    egui::Stroke::new(
                                        edge_stroke_width,
                                        egui::Color32::from_rgb(235, 196, 150),
                                    )
                                };
                                match row.kind {
                                    LineageNodeKind::Arrangement => {
                                        let rect = egui::Rect::from_center_size(
                                            pos,
                                            Vec2::new(56.0 * graph_zoom, 28.0 * graph_zoom),
                                        );
                                        painter.rect_filled(
                                            rect,
                                            5.0 * graph_zoom,
                                            if is_selected {
                                                egui::Color32::from_rgb(98, 140, 112)
                                            } else {
                                                egui::Color32::from_rgb(108, 154, 122)
                                            },
                                        );
                                        painter.rect_stroke(
                                            rect,
                                            5.0 * graph_zoom,
                                            highlight_stroke,
                                            egui::StrokeKind::Inside,
                                        );
                                    }
                                    LineageNodeKind::Macro => {
                                        let rect = egui::Rect::from_center_size(
                                            pos,
                                            Vec2::new(64.0 * graph_zoom, 30.0 * graph_zoom),
                                        );
                                        painter.rect_filled(
                                            rect,
                                            4.0 * graph_zoom,
                                            if is_selected {
                                                egui::Color32::from_rgb(118, 118, 128)
                                            } else {
                                                egui::Color32::from_rgb(98, 98, 108)
                                            },
                                        );
                                        painter.rect_stroke(
                                            rect,
                                            4.0 * graph_zoom,
                                            highlight_stroke,
                                            egui::StrokeKind::Inside,
                                        );
                                    }
                                    LineageNodeKind::Analysis => {
                                        let rect = egui::Rect::from_center_size(
                                            pos,
                                            Vec2::new(62.0 * graph_zoom, 28.0 * graph_zoom),
                                        );
                                        painter.rect_filled(
                                            rect,
                                            4.0 * graph_zoom,
                                            if is_selected {
                                                egui::Color32::from_rgb(156, 112, 184)
                                            } else {
                                                egui::Color32::from_rgb(140, 98, 172)
                                            },
                                        );
                                        painter.rect_stroke(
                                            rect,
                                            4.0 * graph_zoom,
                                            highlight_stroke,
                                            egui::StrokeKind::Inside,
                                        );
                                    }
                                    LineageNodeKind::Sequence if row.pool_size > 1 => {
                                        let points = vec![
                                            pos + Vec2::new(0.0, -16.0 * graph_zoom),
                                            pos + Vec2::new(16.0 * graph_zoom, 0.0),
                                            pos + Vec2::new(0.0, 16.0 * graph_zoom),
                                            pos + Vec2::new(-16.0 * graph_zoom, 0.0),
                                        ];
                                        painter.add(egui::Shape::convex_polygon(
                                            points,
                                            if is_selected {
                                                egui::Color32::from_rgb(205, 140, 80)
                                            } else {
                                                egui::Color32::from_rgb(180, 120, 70)
                                            },
                                            highlight_stroke,
                                        ));
                                    }
                                    LineageNodeKind::Sequence => {
                                        painter.circle_filled(
                                            pos,
                                            node_radius,
                                            if is_selected {
                                                egui::Color32::from_rgb(70, 125, 215)
                                            } else {
                                                egui::Color32::from_rgb(90, 140, 210)
                                            },
                                        );
                                        painter.circle_stroke(pos, node_radius, highlight_stroke);
                                    }
                                }
                                let node_id_label = match row.kind {
                                    LineageNodeKind::Arrangement => row
                                        .arrangement_id
                                        .as_ref()
                                        .map(|id| Self::compact_lineage_node_label(id, 12))
                                        .unwrap_or_else(|| {
                                            Self::compact_lineage_node_label(&row.node_id, 12)
                                        }),
                                    LineageNodeKind::Macro => row
                                        .macro_instance_id
                                        .as_ref()
                                        .map(|id| Self::compact_lineage_node_label(id, 12))
                                        .unwrap_or_else(|| {
                                            Self::compact_lineage_node_label(&row.node_id, 12)
                                        }),
                                    LineageNodeKind::Analysis => row
                                        .analysis_artifact_id
                                        .as_ref()
                                        .map(|id| Self::compact_lineage_node_label(id, 12))
                                        .unwrap_or_else(|| {
                                            Self::compact_lineage_node_label(&row.node_id, 12)
                                        }),
                                    LineageNodeKind::Sequence => {
                                        Self::compact_lineage_node_label(&row.node_id, 10)
                                    }
                                };
                                painter.text(
                                    pos,
                                    egui::Align2::CENTER_CENTER,
                                    node_id_label,
                                    egui::FontId::monospace(node_id_font_size),
                                    egui::Color32::WHITE,
                                );
                                if let Some(descriptor) = &row.retrieval_descriptor {
                                    let badge_center = pos + Vec2::new(16.0 * graph_zoom, -18.0 * graph_zoom);
                                    let badge_rect = egui::Rect::from_center_size(
                                        badge_center,
                                        Vec2::new(
                                            (28.0 * graph_zoom).clamp(18.0, 36.0),
                                            (14.0 * graph_zoom).clamp(10.0, 20.0),
                                        ),
                                    );
                                    painter.rect_filled(
                                        badge_rect,
                                        3.0 * graph_zoom,
                                        egui::Color32::from_rgb(188, 146, 48),
                                    );
                                    painter.rect_stroke(
                                        badge_rect,
                                        3.0 * graph_zoom,
                                        egui::Stroke::new(
                                            (1.0 * graph_zoom).clamp(0.8, 1.8),
                                            egui::Color32::from_rgb(80, 62, 20),
                                        ),
                                        egui::StrokeKind::Inside,
                                    );
                                    painter.text(
                                        badge_rect.center(),
                                        egui::Align2::CENTER_CENTER,
                                        Self::lineage_retrieval_pattern_label(descriptor),
                                        egui::FontId::monospace((8.0 * graph_zoom).clamp(6.8, 10.5)),
                                        egui::Color32::BLACK,
                                    );
                                    retrieval_badge_rects.insert(row.node_id.clone(), badge_rect);
                                }
                                if let Some(badge) = collapsed_group_badges.get(&row.node_id) {
                                    let chip_font =
                                        egui::FontId::monospace((8.2 * graph_zoom).clamp(6.8, 10.8));
                                    let chip_spacing = 3.0 * graph_zoom;
                                    let mut chips: Vec<(String, egui::Color32)> =
                                        Vec::with_capacity(5);
                                    chips.push((
                                        badge.total_ops.min(99).to_string(),
                                        egui::Color32::from_rgb(52, 52, 52),
                                    ));
                                    for (family, count) in badge.families.iter().take(3) {
                                        let symbol = Self::lineage_operation_symbol_for_family(family);
                                        let label = if *count > 1 {
                                            format!("{}{}", symbol, (*count).min(99))
                                        } else {
                                            symbol.to_string()
                                        };
                                        chips.push((label, Self::lineage_operation_color_for_family(family)));
                                    }
                                    if badge.families.len() > 3 {
                                        chips.push((
                                            format!("+{}", badge.families.len() - 3),
                                            egui::Color32::from_rgb(95, 95, 95),
                                        ));
                                    }

                                    let mut chip_sizes: Vec<Vec2> = Vec::with_capacity(chips.len());
                                    let mut total_width = 0.0f32;
                                    for (label, _) in &chips {
                                        let galley = painter.layout_no_wrap(
                                            label.clone(),
                                            chip_font.clone(),
                                            egui::Color32::WHITE,
                                        );
                                        let size = Vec2::new(
                                            (galley.size().x + 8.0 * graph_zoom)
                                                .max(12.0 * graph_zoom),
                                            (galley.size().y + 4.0 * graph_zoom)
                                                .max(10.0 * graph_zoom),
                                        );
                                        total_width += size.x;
                                        chip_sizes.push(size);
                                    }
                                    total_width += chip_spacing * chips.len().saturating_sub(1) as f32;
                                    let mut chip_x = pos.x - total_width * 0.5;
                                    let chip_y = pos.y - 24.0 * graph_zoom;
                                    for ((label, fill), size) in chips.into_iter().zip(chip_sizes) {
                                        let chip_rect = egui::Rect::from_min_size(
                                            Pos2::new(chip_x, chip_y),
                                            size,
                                        );
                                        painter.rect_filled(chip_rect, 2.8 * graph_zoom, fill);
                                        painter.rect_stroke(
                                            chip_rect,
                                            2.8 * graph_zoom,
                                            egui::Stroke::new(
                                                (0.9 * graph_zoom).clamp(0.7, 1.6),
                                                egui::Color32::from_rgb(40, 40, 40),
                                            ),
                                            egui::StrokeKind::Inside,
                                        );
                                        painter.text(
                                            chip_rect.center(),
                                            egui::Align2::CENTER_CENTER,
                                            label,
                                            chip_font.clone(),
                                            egui::Color32::WHITE,
                                        );
                                        chip_x += size.x + chip_spacing;
                                    }
                                }
                                let display_name = if simplify_labels {
                                    Self::compact_lineage_node_label(&row.display_name, 26)
                                } else {
                                    row.display_name.clone()
                                };
                                painter.text(
                                    pos + Vec2::new(22.0 * graph_zoom, -4.0 * graph_zoom),
                                    egui::Align2::LEFT_BOTTOM,
                                    display_name,
                                    egui::FontId::proportional(name_font_size),
                                    egui::Color32::BLACK,
                                );
                                if !simplify_labels {
                                    let detail_text = match row.kind {
                                        LineageNodeKind::Arrangement => {
                                            let ladders = if row.ladders.is_empty() {
                                                "auto".to_string()
                                            } else {
                                                row.ladders.join(" + ")
                                            };
                                            format!(
                                                "{} lane(s) | mode={} | ladders={}",
                                                row.lane_container_ids.len(),
                                                row.arrangement_mode
                                                    .as_deref()
                                                    .unwrap_or("Serial")
                                                    .to_lowercase(),
                                                ladders
                                            )
                                        }
                                        LineageNodeKind::Macro => format!(
                                            "ops={} | template={} | status={}",
                                            row.macro_op_ids.len(),
                                            row.macro_template_name
                                                .as_deref()
                                                .unwrap_or("-"),
                                            row.macro_status.as_deref().unwrap_or("ok")
                                        ),
                                        LineageNodeKind::Analysis => {
                                            let artifact_id = row
                                                .analysis_artifact_id
                                                .as_deref()
                                                .unwrap_or(&row.display_name);
                                            let mode = row.analysis_mode.as_deref().unwrap_or("-");
                                            match row.analysis_kind {
                                                Some(LineageAnalysisKind::Dotplot) => format!(
                                                    "dotplot={} | mode={} | points={}",
                                                    artifact_id,
                                                    mode,
                                                    row.analysis_point_count.unwrap_or(0)
                                                ),
                                                Some(LineageAnalysisKind::FlexibilityTrack) => {
                                                    format!(
                                                        "track={} | model={} | bins={}",
                                                        artifact_id,
                                                        mode,
                                                        row.analysis_bin_count.unwrap_or(0)
                                                    )
                                                }
                                                None => format!("analysis={artifact_id}"),
                                            }
                                        }
                                        LineageNodeKind::Sequence if row.pool_size > 1 => {
                                            format!(
                                                "{} ({} bp) | pool={}",
                                                row.seq_id, row.length, row.pool_size
                                            )
                                        }
                                        LineageNodeKind::Sequence => {
                                            format!("{} ({} bp)", row.seq_id, row.length)
                                        }
                                    };
                                    painter.text(
                                        pos + Vec2::new(22.0 * graph_zoom, 10.0 * graph_zoom),
                                        egui::Align2::LEFT_TOP,
                                        detail_text,
                                        egui::FontId::proportional(details_font_size),
                                        egui::Color32::BLACK,
                                    );
                                }
                            }

                            let hit_row = hovered_node_id
                                .as_ref()
                                .and_then(|node_id| rows.iter().find(|row| &row.node_id == node_id));
                            let hovered_retrieval_node_id = pointer.and_then(|pointer| {
                                retrieval_badge_rects
                                    .iter()
                                    .find_map(|(node_id, rect)| rect.contains(pointer).then_some(node_id.clone()))
                            });
                            let hovered_retrieval_row = hovered_retrieval_node_id
                                .as_ref()
                                .and_then(|node_id| rows.iter().find(|row| &row.node_id == node_id));
                            let hover_row = hit_row.or(hovered_retrieval_row);
                            if let Some(row) = hover_row {
                                let mut hover_pool_range: Option<(usize, usize)> = None;
                                let mut hover_ladder_hint: Option<String> = None;
                                if row.kind == LineageNodeKind::Sequence && row.pool_size > 1 {
                                    let member_lengths: Vec<(String, usize)> = {
                                        let engine = self.engine.read().unwrap();
                                        row.pool_members
                                            .iter()
                                            .filter_map(|seq_id| {
                                                engine
                                                    .state()
                                                    .sequences
                                                    .get(seq_id)
                                                    .map(|dna| (seq_id.clone(), dna.len()))
                                            })
                                            .collect()
                                    };
                                    if !member_lengths.is_empty() {
                                        let min_bp = member_lengths
                                            .iter()
                                            .map(|(_, bp)| *bp)
                                            .min()
                                            .unwrap_or(0);
                                        let max_bp = member_lengths
                                            .iter()
                                            .map(|(_, bp)| *bp)
                                            .max()
                                            .unwrap_or(min_bp);
                                        hover_pool_range = Some((min_bp, max_bp));
                                        if let Ok(layout) =
                                            crate::pool_gel::build_pool_gel_layout(&member_lengths, &[])
                                        {
                                            if !layout.selected_ladders.is_empty() {
                                                hover_ladder_hint = Some(layout.selected_ladders.join(" + "));
                                            }
                                        }
                                    }
                                }
                                let tooltip_member_preview = if row.kind == LineageNodeKind::Sequence
                                    && row.pool_size > 1
                                {
                                    row.pool_members
                                        .iter()
                                        .take(6)
                                        .cloned()
                                        .collect::<Vec<_>>()
                                        .join(", ")
                                } else {
                                    String::new()
                                };
                                resp.clone().on_hover_ui_at_pointer(|ui| {
                                    ui.strong(&row.display_name);
                                    match row.kind {
                                        LineageNodeKind::Arrangement => {
                                            let ladders = if row.ladders.is_empty() {
                                                "auto".to_string()
                                            } else {
                                                row.ladders.join(" + ")
                                            };
                                            ui.monospace(format!(
                                                "{} | mode={} | lanes={} | ladders={}",
                                                row.arrangement_id
                                                    .as_deref()
                                                    .unwrap_or(&row.seq_id),
                                                row.arrangement_mode
                                                    .as_deref()
                                                    .unwrap_or("Serial")
                                                    .to_lowercase(),
                                                row.lane_container_ids.len(),
                                                ladders
                                            ));
                                        }
                                        LineageNodeKind::Macro => {
                                            ui.monospace(format!(
                                                "{} | template={} | status={} | ops={}",
                                                row.macro_instance_id
                                                    .as_deref()
                                                    .unwrap_or(&row.seq_id),
                                                row.macro_template_name
                                                    .as_deref()
                                                    .unwrap_or("-"),
                                                row.macro_status.as_deref().unwrap_or("ok"),
                                                row.macro_op_ids.len()
                                            ));
                                            if let Some(routine_id) = &row.macro_routine_id {
                                                ui.small(format!("routine_id={routine_id}"));
                                            }
                                            if let Some(status_message) = &row.macro_status_message {
                                                ui.small(format!("status_message={status_message}"));
                                            }
                                        }
                                        LineageNodeKind::Analysis => {
                                            let artifact_id = row
                                                .analysis_artifact_id
                                                .as_deref()
                                                .unwrap_or(&row.display_name);
                                            let mode = row.analysis_mode.as_deref().unwrap_or("-");
                                            let analysis_kind = row
                                                .analysis_kind
                                                .map(LineageAnalysisKind::as_str)
                                                .unwrap_or("analysis");
                                            ui.monospace(format!(
                                                "{} | kind={} | mode={}",
                                                artifact_id, analysis_kind, mode
                                            ));
                                            match row.analysis_kind {
                                                Some(LineageAnalysisKind::Dotplot) => {
                                                    ui.small(format!(
                                                        "query={} | reference={} | points={}",
                                                        row.seq_id,
                                                        row.analysis_reference_seq_id
                                                            .as_deref()
                                                            .unwrap_or(&row.seq_id),
                                                        row.analysis_point_count.unwrap_or(0)
                                                    ));
                                                }
                                                Some(LineageAnalysisKind::FlexibilityTrack) => {
                                                    ui.small(format!(
                                                        "seq={} | bins={}",
                                                        row.seq_id,
                                                        row.analysis_bin_count.unwrap_or(0)
                                                    ));
                                                }
                                                None => {}
                                            }
                                        }
                                        LineageNodeKind::Sequence => {
                                            ui.monospace(format!(
                                                "{} | {} bp | {}",
                                                row.seq_id,
                                                row.length,
                                                if row.circular { "circular" } else { "linear" }
                                            ));
                                        }
                                    }
                                    ui.small(format!("node={} | origin={}", row.node_id, row.origin));
                                    ui.small(format!("parents={} | op={}", row.parents.len(), row.created_by_op));
                                    if let Some(badge) = collapsed_group_badges.get(&row.node_id) {
                                        ui.separator();
                                        ui.small(format!(
                                            "collapsed hidden operations={}",
                                            badge.total_ops
                                        ));
                                        ui.small(format!(
                                            "hidden families={}",
                                            Self::lineage_hidden_op_families_summary(badge, 5)
                                        ));
                                    }
                                    if let Some(anchor) = &row.genome_anchor_summary {
                                        let strand = anchor.strand.unwrap_or('+');
                                        let mut anchor_text = format!(
                                            "anchor={} {}:{}-{} (strand {})",
                                            anchor.genome_id,
                                            anchor.chromosome,
                                            anchor.start_1based,
                                            anchor.end_1based,
                                            strand
                                        );
                                        if row.is_full_genome_sequence {
                                            anchor_text
                                                .push_str(" | full chromosome/genome sequence");
                                        }
                                        ui.small(anchor_text);
                                    }
                                    if let Some(descriptor) = row.retrieval_descriptor.as_ref() {
                                        ui.separator();
                                        ui.small(Self::lineage_retrieval_pattern_tooltip(
                                            descriptor,
                                            row.genome_anchor_summary.as_ref(),
                                        ));
                                    }
                                    match row.kind {
                                        LineageNodeKind::Arrangement => {
                                            if !row.lane_container_ids.is_empty() {
                                                ui.separator();
                                                let preview = row
                                                    .lane_container_ids
                                                    .iter()
                                                    .take(6)
                                                    .cloned()
                                                    .collect::<Vec<_>>()
                                                    .join(", ");
                                                ui.small(format!("lane containers: {preview}"));
                                                if row.lane_container_ids.len() > 6 {
                                                    ui.small(format!(
                                                        "... and {} more",
                                                        row.lane_container_ids.len() - 6
                                                    ));
                                                }
                                            }
                                        }
                                        LineageNodeKind::Macro => {
                                            if !row.macro_inputs.is_empty() || !row.macro_outputs.is_empty() {
                                                ui.separator();
                                                if !row.macro_inputs.is_empty() {
                                                    let preview = row
                                                        .macro_inputs
                                                        .iter()
                                                        .map(|binding| {
                                                            format!(
                                                                "{}={}",
                                                                binding.port_id,
                                                                binding.values.join(",")
                                                            )
                                                        })
                                                        .take(4)
                                                        .collect::<Vec<_>>()
                                                        .join(" | ");
                                                    if !preview.is_empty() {
                                                        ui.small(format!("inputs: {preview}"));
                                                    }
                                                }
                                                if !row.macro_outputs.is_empty() {
                                                    let preview = row
                                                        .macro_outputs
                                                        .iter()
                                                        .map(|binding| {
                                                            format!(
                                                                "{}={}",
                                                                binding.port_id,
                                                                binding.values.join(",")
                                                            )
                                                        })
                                                        .take(4)
                                                        .collect::<Vec<_>>()
                                                        .join(" | ");
                                                    if !preview.is_empty() {
                                                        ui.small(format!("outputs: {preview}"));
                                                    }
                                                }
                                            }
                                            if !row.macro_op_ids.is_empty() {
                                                let preview = row
                                                    .macro_op_ids
                                                    .iter()
                                                    .take(6)
                                                    .cloned()
                                                    .collect::<Vec<_>>()
                                                    .join(", ");
                                                ui.small(format!("op_ids: {preview}"));
                                            }
                                        }
                                        LineageNodeKind::Analysis => {
                                            if let Some(artifact_id) =
                                                row.analysis_artifact_id.as_deref()
                                            {
                                                ui.separator();
                                                ui.small(format!("artifact_id={artifact_id}"));
                                            }
                                            if let Some(reference_seq_id) =
                                                row.analysis_reference_seq_id.as_deref()
                                            {
                                                ui.small(format!("reference_seq_id={reference_seq_id}"));
                                            }
                                        }
                                        LineageNodeKind::Sequence if row.pool_size > 1 => {
                                            ui.separator();
                                            ui.small(format!("pool members={}", row.pool_size));
                                            if let Some((min_bp, max_bp)) = hover_pool_range {
                                                ui.small(format!(
                                                    "pool range={}..{} bp",
                                                    min_bp, max_bp
                                                ));
                                            }
                                            if let Some(ladders) = &hover_ladder_hint {
                                                ui.small(format!("suggested ladders={}", ladders));
                                            }
                                            if !tooltip_member_preview.is_empty() {
                                                ui.small(format!(
                                                    "members: {}",
                                                    tooltip_member_preview
                                                ));
                                            }
                                        }
                                        LineageNodeKind::Sequence => {}
                                    }
                                });
                            }
                            let context_node_id = hover_row.map(|row| row.node_id.clone());
                            let context_row = hover_row.cloned();
                            resp.clone().context_menu(|ui| {
                                if let Some(node_id) = context_node_id.as_ref() {
                                    self.render_lineage_group_context_menu(
                                        ui,
                                        node_id,
                                        context_row.as_ref(),
                                        &leaf_node_ids,
                                        &valid_lineage_node_ids,
                                        &mut persist_workspace_after_frame,
                                    );
                                } else {
                                    ui.label("No node under cursor");
                                }
                            });
                            let (space_pan_requested, option_pan_requested, modifiers) = ui
                                .input(|i| {
                                    (
                                        i.key_down(Key::Space),
                                        scroll_input_policy::option_pan_modifier_active(i.modifiers),
                                        i.modifiers,
                                    )
                                });
                            if resp.drag_started() {
                                if option_pan_requested || (space_pan_requested && hover_row.is_none())
                                {
                                    self.lineage_graph_pan_origin = Some(graph_scroll_offset);
                                    self.lineage_graph_drag_origin = None;
                                } else if let Some(row) = hover_row {
                                    let start_offset = self
                                        .lineage_graph_node_offsets
                                        .get(&row.node_id)
                                        .copied()
                                        .unwrap_or(Vec2::ZERO);
                                    self.lineage_graph_drag_origin =
                                        Some((row.node_id.clone(), start_offset));
                                    self.lineage_graph_pan_origin = None;
                                    self.lineage_graph_selected_node_id = Some(row.node_id.clone());
                                } else {
                                    self.lineage_graph_drag_origin = None;
                                    self.lineage_graph_pan_origin = None;
                                }
                            }
                            if let Some(start_scroll_offset) = self.lineage_graph_pan_origin {
                                if resp.dragged() {
                                    let next_offset = start_scroll_offset - resp.drag_delta();
                                    graph_scroll_offset = Vec2::new(
                                        next_offset.x.max(0.0),
                                        next_offset.y.max(0.0),
                                    );
                                }
                                if resp.drag_stopped() {
                                    self.lineage_graph_pan_origin = None;
                                    persist_workspace_after_frame = true;
                                }
                            }
                            if self.lineage_graph_pan_origin.is_none() {
                                if let Some((node_id, start_offset)) =
                                    self.lineage_graph_drag_origin.clone()
                                {
                                    if resp.dragged() {
                                        self.lineage_graph_node_offsets
                                            .insert(node_id.clone(), start_offset + resp.drag_delta());
                                    }
                                    if resp.drag_stopped() {
                                        self.lineage_graph_drag_origin = None;
                                        persist_workspace_after_frame = true;
                                    }
                                }
                            }
                            if let Some(cursor) = scroll_input_policy::canvas_hover_cursor(
                                modifiers,
                                true,
                                self.lineage_graph_pan_origin.is_some(),
                                self.lineage_graph_drag_origin.is_some(),
                                graph_wheel_intent,
                            ) {
                                ui.output_mut(|o| o.cursor_icon = cursor);
                            } else if space_pan_requested && hover_row.is_none() {
                                ui.output_mut(|o| o.cursor_icon = egui::CursorIcon::Grab);
                            }
                            if self.lineage_graph_pan_origin.is_none()
                                && self.lineage_graph_drag_origin.is_none()
                            {
                                let mut retrieval_click_consumed = false;
                                if resp.clicked() {
                                    if let Some(row) = hovered_retrieval_row {
                                        if let Some(descriptor) = row.retrieval_descriptor.clone() {
                                            self.lineage_graph_selected_node_id =
                                                Some(row.node_id.clone());
                                            open_lineage_retrieval = Some(descriptor);
                                            retrieval_click_consumed = true;
                                        }
                                    }
                                }
                                if !retrieval_click_consumed {
                                    if resp.clicked() {
                                        self.lineage_graph_selected_node_id =
                                            hover_row.map(|row| row.node_id.clone());
                                    }
                                    if let Some(row) = hover_row {
                                        if resp.double_clicked() {
                                            match row.kind {
                                                LineageNodeKind::Arrangement => {
                                                    if !row.lane_container_ids.is_empty() {
                                                        open_lane_containers =
                                                            Some(row.lane_container_ids.clone());
                                                    }
                                                }
                                                LineageNodeKind::Macro => {}
                                                LineageNodeKind::Analysis => {
                                                    open_seq = Some(row.seq_id.clone());
                                                }
                                                LineageNodeKind::Sequence if row.pool_size > 1 => {
                                                    open_pool = Some((
                                                        row.seq_id.clone(),
                                                        row.pool_members.clone(),
                                                    ));
                                                }
                                                LineageNodeKind::Sequence => {
                                                    open_seq = Some(row.seq_id.clone());
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                            if self.lineage_graph_drag_origin.is_some()
                                && !ui.input(|i| i.pointer.primary_down())
                            {
                                self.lineage_graph_drag_origin = None;
                                persist_workspace_after_frame = true;
                            }
                            if self.lineage_graph_pan_origin.is_some()
                                && !ui.input(|i| i.pointer.primary_down())
                            {
                                self.lineage_graph_pan_origin = None;
                                persist_workspace_after_frame = true;
                            }
                        });
                    let max_scroll_x =
                        (graph_scroll_output.content_size.x - graph_scroll_output.inner_rect.width())
                            .max(0.0);
                    let max_scroll_y = (graph_scroll_output.content_size.y
                        - graph_scroll_output.inner_rect.height())
                    .max(0.0);
                    if self.lineage_graph_pan_origin.is_some() {
                        graph_scroll_offset.x = graph_scroll_offset.x.clamp(0.0, max_scroll_x);
                        graph_scroll_offset.y = graph_scroll_offset.y.clamp(0.0, max_scroll_y);
                    } else {
                        let mut measured_offset = graph_scroll_output.state.offset;
                        measured_offset.x = measured_offset.x.clamp(0.0, max_scroll_x);
                        measured_offset.y = measured_offset.y.clamp(0.0, max_scroll_y);
                        graph_scroll_offset = measured_offset;
                    }
                },
            );
        } else {
            let table_panel_width = ui.available_width().max(1.0);
            let table_panel_height = graph_area_height.max(280.0);
            let mut toggle_group_collapse_id: Option<String> = None;
            ui.allocate_ui_with_layout(
                egui::vec2(table_panel_width, table_panel_height),
                egui::Layout::top_down(egui::Align::Min),
                |ui| {
                    ui.set_min_width(table_panel_width);
                    ui.set_max_width(table_panel_width);
                    egui::ScrollArea::both()
                        .id_salt("lineage_table_scroll")
                        .auto_shrink([false, false])
                        .max_height(ui.available_height())
                        .show(ui, |ui| {
                    scroll_input_policy::apply_scrollarea_keyboard_navigation(
                        ui,
                        scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                    );
                    ui.set_min_width(1080.0);
                    egui::Grid::new("lineage_table_grid")
                        .striped(true)
                        .min_col_width(72.0)
                        .spacing(egui::vec2(10.0, 6.0))
                        .show(ui, |ui| {
                            ui.strong("Node");
                            ui.strong("Sequence");
                            ui.strong("Parents");
                            ui.strong("Origin");
                            ui.strong("Op");
                            ui.strong("Length");
                            ui.strong("Topology");
                            ui.strong("Genome anchor");
                            ui.strong("Pattern");
                            ui.strong("Action");
                            ui.end_row();
                            for entry in &table_entries {
                                let row = &entry.row;
                                let node_display = Self::compact_lineage_node_label(&row.node_id, 10);
                                let mut node_response = ui
                                    .allocate_ui_with_layout(
                                        egui::vec2(160.0, ui.spacing().interact_size.y),
                                        egui::Layout::left_to_right(egui::Align::Center),
                                        |ui| {
                                            ui.horizontal(|ui| {
                                                ui.add_space(14.0 * entry.indent_level as f32);
                                                if entry.is_group_representative {
                                                    if let Some(group_id) = entry.group_id.as_ref()
                                                    {
                                                        let collapsed =
                                                            entry.hidden_group_member_count > 0;
                                                        if ui
                                                            .small_button(if collapsed {
                                                                "▸"
                                                            } else {
                                                                "▾"
                                                            })
                                                            .on_hover_text(
                                                                "Collapse/expand this node group",
                                                            )
                                                            .clicked()
                                                        {
                                                            toggle_group_collapse_id =
                                                                Some(group_id.clone());
                                                        }
                                                    }
                                                } else if entry.indent_level > 0 {
                                                    ui.label("↳");
                                                }
                                                ui.add(
                                                    egui::Label::new(
                                                        egui::RichText::new(node_display.clone())
                                                            .monospace(),
                                                    )
                                                    .truncate(),
                                                );
                                            });
                                        },
                                    )
                                    .response;
                                if node_display != row.node_id {
                                    node_response = node_response.on_hover_text(row.node_id.clone());
                                }
                                node_response.context_menu(|ui| {
                                    self.render_lineage_group_context_menu(
                                        ui,
                                        &row.node_id,
                                        Some(row),
                                        &leaf_node_ids,
                                        &valid_lineage_node_ids,
                                        &mut persist_workspace_after_frame,
                                    );
                                });
                                if node_response.clicked() {
                                    self.lineage_graph_selected_node_id = Some(row.node_id.clone());
                                }
                                match row.kind {
                                    LineageNodeKind::Arrangement => {
                                        ui.monospace(
                                            row.arrangement_id
                                                .as_deref()
                                                .unwrap_or(&row.seq_id)
                                                .to_string(),
                                        );
                                    }
                                    LineageNodeKind::Macro => {
                                        ui.monospace(
                                            row.macro_instance_id
                                                .as_deref()
                                                .unwrap_or(&row.seq_id)
                                                .to_string(),
                                        );
                                    }
                                    LineageNodeKind::Analysis => {
                                        ui.vertical(|ui| {
                                            ui.monospace(
                                                row.analysis_artifact_id
                                                    .as_deref()
                                                    .unwrap_or(&row.display_name),
                                            );
                                            if ui
                                                .small_button(row.seq_id.clone())
                                                .on_hover_text(
                                                    "Open the query/source sequence in a dedicated window",
                                                )
                                                .clicked()
                                            {
                                                open_seq = Some(row.seq_id.clone());
                                            }
                                        });
                                    }
                                    LineageNodeKind::Sequence => {
                                        if ui
                                            .button(&row.seq_id)
                                            .on_hover_text("Open this sequence in a dedicated window")
                                            .clicked()
                                        {
                                            open_seq = Some(row.seq_id.clone());
                                        }
                                    }
                                }
                                ui.label(if row.parents.is_empty() {
                                    "-".to_string()
                                } else {
                                    row.parents.join(" + ")
                                });
                                if entry.is_group_representative {
                                    if let Some(group_label) = entry.group_label.as_ref() {
                                        if entry.hidden_group_member_count > 0 {
                                            ui.label(format!(
                                                "{} [{} | {} hidden]",
                                                row.origin, group_label, entry.hidden_group_member_count
                                            ));
                                        } else {
                                            ui.label(format!("{} [{}]", row.origin, group_label));
                                        }
                                    } else {
                                        ui.label(&row.origin);
                                    }
                                } else {
                                    ui.label(&row.origin);
                                }
                                let op_display = Self::compact_lineage_node_label(&row.created_by_op, 11);
                                let op_response = ui
                                    .allocate_ui_with_layout(
                                        egui::vec2(92.0, ui.spacing().interact_size.y),
                                        egui::Layout::left_to_right(egui::Align::Center),
                                        |ui| {
                                            ui.add(
                                                egui::Label::new(
                                                    egui::RichText::new(op_display.clone())
                                                        .monospace(),
                                                )
                                                .truncate(),
                                            )
                                        },
                                    )
                                    .inner;
                                if op_display != row.created_by_op {
                                    op_response.on_hover_text(row.created_by_op.clone());
                                }
                                if row.kind == LineageNodeKind::Arrangement
                                    || row.kind == LineageNodeKind::Macro
                                    || row.kind == LineageNodeKind::Analysis
                                {
                                    ui.label("-");
                                    ui.label("-");
                                } else {
                                    ui.monospace(format!("{} bp", row.length));
                                    ui.label(if row.circular { "circular" } else { "linear" });
                                }
                                match row.kind {
                                    LineageNodeKind::Arrangement => {
                                        ui.label("-");
                                    }
                                    LineageNodeKind::Macro => {
                                        if ui
                                            .button("Inspect")
                                            .on_hover_text(
                                                "Show persistent details for this macro node below",
                                            )
                                            .clicked()
                                        {
                                            self.lineage_graph_selected_node_id =
                                                Some(row.node_id.clone());
                                        }
                                    }
                                    LineageNodeKind::Analysis => {
                                        ui.monospace(
                                            row.analysis_reference_seq_id
                                                .as_ref()
                                                .map(|reference| {
                                                    format!("query={} ref={reference}", row.seq_id)
                                                })
                                                .unwrap_or_else(|| {
                                                    format!("seq={}", row.seq_id)
                                                }),
                                        );
                                    }
                                    LineageNodeKind::Sequence => {
                                        let mut anchor_text = row
                                            .genome_anchor_display
                                            .clone()
                                            .unwrap_or_else(|| "-".to_string());
                                        if row.is_full_genome_sequence {
                                            anchor_text.push_str(" [full chromosome/genome]");
                                        }
                                        let response = ui.monospace(anchor_text);
                                        if let Some(anchor) = &row.genome_anchor_summary {
                                            let strand = anchor.strand.unwrap_or('+');
                                            let mut hover = format!(
                                                "Genome anchor: {}:{}-{} (strand {}, genome '{}')",
                                                anchor.chromosome,
                                                anchor.start_1based,
                                                anchor.end_1based,
                                                strand,
                                                anchor.genome_id
                                            );
                                            if row.is_full_genome_sequence {
                                                hover.push_str(
                                                    "\nCovers full chromosome/genome length in prepared reference.",
                                                );
                                            }
                                            response.on_hover_text(hover);
                                        }
                                    }
                                }
                                if let Some(descriptor) = row.retrieval_descriptor.as_ref() {
                                    let button = ui
                                        .small_button(Self::lineage_retrieval_pattern_label(
                                            descriptor,
                                        ))
                                        .on_hover_text(Self::lineage_retrieval_pattern_tooltip(
                                            descriptor,
                                            row.genome_anchor_summary.as_ref(),
                                        ));
                                    if button.clicked() {
                                        open_lineage_retrieval = Some(descriptor.clone());
                                        self.lineage_graph_selected_node_id =
                                            Some(row.node_id.clone());
                                    }
                                } else {
                                    ui.label("-");
                                }
                                match row.kind {
                                    LineageNodeKind::Arrangement => {
                                        if !row.lane_container_ids.is_empty()
                                            && ui
                                                .button("Open Lanes")
                                                .on_hover_text(
                                                    "Open windows for the lane containers in this arrangement",
                                                )
                                                .clicked()
                                        {
                                            open_lane_containers =
                                                Some(row.lane_container_ids.clone());
                                        } else {
                                            ui.label("-");
                                        }
                                    }
                                    LineageNodeKind::Macro => {
                                        ui.label("-");
                                    }
                                    LineageNodeKind::Analysis => {
                                        if ui
                                            .button("Open Seq")
                                            .on_hover_text(
                                                "Open the query/source sequence in a dedicated window",
                                            )
                                            .clicked()
                                        {
                                            open_seq = Some(row.seq_id.clone());
                                        }
                                    }
                                    LineageNodeKind::Sequence => {
                                        ui.allocate_ui_with_layout(
                                            egui::vec2(280.0, ui.spacing().interact_size.y),
                                            egui::Layout::left_to_right(egui::Align::Center),
                                            |ui| {
                                                if ui
                                                    .button("Select")
                                                    .on_hover_text(
                                                        "Run candidate selection operation using this sequence as input",
                                                    )
                                                    .clicked()
                                                {
                                                    select_candidate_from = Some(row.seq_id.clone());
                                                }
                                                if ui
                                                    .button("Copy")
                                                    .on_hover_text(
                                                        "Copy this sequence as plain DNA/RNA text",
                                                    )
                                                    .clicked()
                                                {
                                                    self.copy_project_sequence_to_clipboard(
                                                        ui.ctx(),
                                                        &row.seq_id,
                                                        false,
                                                    );
                                                }
                                                if ui
                                                    .button("FASTA")
                                                    .on_hover_text(
                                                        "Copy this sequence as FASTA text",
                                                    )
                                                    .clicked()
                                                {
                                                    self.copy_project_sequence_to_clipboard(
                                                        ui.ctx(),
                                                        &row.seq_id,
                                                        true,
                                                    );
                                                }
                                                if ui
                                                    .button("Remove")
                                                    .on_hover_text(
                                                        "Sequence-removal from lineage table is not yet implemented in engine operations.",
                                                    )
                                                    .clicked()
                                                {
                                                    self.app_status = format!(
                                                        "Remove for '{}' is not yet available",
                                                        row.seq_id
                                                    );
                                                }
                                            },
                                        );
                                    }
                                }
                                ui.end_row();
                            }
                        });
                });
                },
            );
            if let Some(group_id) = toggle_group_collapse_id {
                if let Some(group) = self
                    .lineage_node_groups
                    .iter_mut()
                    .find(|group| group.group_id == group_id)
                {
                    group.collapsed = !group.collapsed;
                    persist_workspace_after_frame = true;
                }
            }
        }
        if let Some(selected_node_id) = self.lineage_graph_selected_node_id.as_ref() {
            if let Some(selected_row) = graph_rows
                .iter()
                .find(|row| row.node_id == *selected_node_id)
                .cloned()
            {
                if selected_row.kind == LineageNodeKind::Macro {
                    ui.separator();
                    ui.heading("Selected Macro Node");
                    ui.small(format!(
                        "{} ({})",
                        selected_row
                            .macro_instance_id
                            .as_deref()
                            .unwrap_or(&selected_row.node_id),
                        selected_row.display_name
                    ));
                    ui.small(format!(
                        "status={} | template={} | routine={} | ops={}",
                        selected_row.macro_status.as_deref().unwrap_or("ok"),
                        selected_row
                            .macro_template_name
                            .as_deref()
                            .unwrap_or("-"),
                        selected_row
                            .macro_routine_id
                            .as_deref()
                            .unwrap_or("-"),
                        selected_row.macro_op_ids.len()
                    ));
                    if let Some(status_message) = &selected_row.macro_status_message {
                        ui.colored_label(
                            egui::Color32::from_rgb(150, 20, 20),
                            format!("status message: {status_message}"),
                        );
                    }
                    let render_bindings = |ui: &mut Ui,
                                           title: &str,
                                           bindings: &[LineageMacroPortBinding]| {
                        ui.label(title);
                        if bindings.is_empty() {
                            ui.small("- none -");
                            return;
                        }
                        egui::Grid::new(format!(
                            "lineage_macro_bindings_{}_{}",
                            selected_row.node_id, title
                        ))
                        .striped(true)
                        .min_col_width(64.0)
                        .show(ui, |ui| {
                            ui.strong("Port");
                            ui.strong("Kind");
                            ui.strong("Values");
                            ui.end_row();
                            for binding in bindings {
                                ui.monospace(&binding.port_id);
                                ui.label(binding.kind.clone());
                                let values = if binding.values.is_empty() {
                                    "-".to_string()
                                } else {
                                    binding.values.join(", ")
                                };
                                ui.monospace(values);
                                ui.end_row();
                            }
                        });
                    };
                    render_bindings(ui, "Inputs", &selected_row.macro_inputs);
                    render_bindings(ui, "Outputs", &selected_row.macro_outputs);

                    ui.label("Emitted operations");
                    if selected_row.macro_op_ids.is_empty() {
                        ui.small("- none -");
                    } else {
                        egui::Grid::new(format!("lineage_macro_ops_{}", selected_row.node_id))
                            .striped(true)
                            .min_col_width(64.0)
                            .show(ui, |ui| {
                                ui.strong("Op ID");
                                ui.strong("Summary");
                                ui.end_row();
                                for op_id in &selected_row.macro_op_ids {
                                    ui.monospace(op_id);
                                    ui.label(
                                        graph_op_label_by_id
                                            .get(op_id)
                                            .cloned()
                                            .unwrap_or_else(|| "-".to_string()),
                                    );
                                    ui.end_row();
                                }
                            });
                    }

                    let mut output_sequences = selected_row
                        .macro_outputs
                        .iter()
                        .filter(|binding| binding.kind.eq_ignore_ascii_case("sequence"))
                        .flat_map(|binding| binding.values.iter().cloned())
                        .collect::<Vec<_>>();
                    output_sequences.sort();
                    output_sequences.dedup();
                    if !output_sequences.is_empty() {
                        ui.label("Open output sequence");
                        ui.horizontal_wrapped(|ui| {
                            for seq_id in output_sequences {
                                if ui
                                    .small_button(seq_id.clone())
                                    .on_hover_text(
                                        "Open this sequence output in a dedicated sequence window",
                                    )
                                    .clicked()
                                {
                                    open_seq = Some(seq_id);
                                }
                            }
                        });
                    }
                } else if selected_row.kind == LineageNodeKind::Analysis {
                    ui.separator();
                    ui.heading("Selected Analysis Node");
                    let kind = selected_row
                        .analysis_kind
                        .map(LineageAnalysisKind::as_str)
                        .unwrap_or("analysis");
                    ui.small(format!(
                        "{} ({})",
                        selected_row
                            .analysis_artifact_id
                            .as_deref()
                            .unwrap_or(&selected_row.node_id),
                        kind
                    ));
                    ui.small(format!("source sequence={}", selected_row.seq_id));
                    if let Some(reference_seq_id) = selected_row.analysis_reference_seq_id.as_deref()
                    {
                        ui.small(format!("reference sequence={reference_seq_id}"));
                    }
                    if let Some(mode) = selected_row.analysis_mode.as_deref() {
                        ui.small(format!("mode/model={mode}"));
                    }
                    if let Some(points) = selected_row.analysis_point_count {
                        ui.small(format!("point_count={points}"));
                    }
                    if let Some(bin_count) = selected_row.analysis_bin_count {
                        ui.small(format!("bin_count={bin_count}"));
                    }
                    ui.horizontal(|ui| {
                        if ui
                            .button("Open Source Sequence")
                            .on_hover_text("Open the analysis source sequence")
                            .clicked()
                        {
                            open_seq = Some(selected_row.seq_id.clone());
                        }
                        if let Some(reference_seq_id) =
                            selected_row.analysis_reference_seq_id.as_deref()
                        {
                            if ui
                                .button("Open Reference Sequence")
                                .on_hover_text("Open the analysis reference sequence")
                                .clicked()
                            {
                                open_seq = Some(reference_seq_id.to_string());
                            }
                        }
                    });
                }
            }
        }
        ui.separator();
        let splitter_width = ui.available_width().max(1.0);
        let splitter_response = ui
            .add_sized(
                egui::vec2(splitter_width, 14.0),
                egui::Label::new(egui::RichText::new("⋮⋮").monospace())
                    .sense(egui::Sense::click_and_drag()),
            )
            .on_hover_text("Drag to resize graph/table and container sections");
        let splitter_rect = splitter_response.rect;
        let splitter_active = splitter_response.hovered() || splitter_response.dragged();
        let splitter_color = if splitter_active {
            egui::Color32::from_rgb(120, 120, 120)
        } else {
            egui::Color32::from_rgb(150, 150, 150)
        };
        ui.painter().line_segment(
            [
                egui::pos2(splitter_rect.left(), splitter_rect.center().y),
                egui::pos2(splitter_rect.right(), splitter_rect.center().y),
            ],
            egui::Stroke::new(1.2, splitter_color),
        );
        ui.painter().text(
            splitter_rect.center(),
            egui::Align2::CENTER_CENTER,
            "⋮⋮",
            egui::FontId::monospace(10.0),
            splitter_color,
        );
        if splitter_active {
            ui.output_mut(|o| o.cursor_icon = egui::CursorIcon::ResizeVertical);
        }
        if splitter_response.drag_started() {
            self.lineage_main_split_drag_origin =
                Some(self.lineage_main_split_fraction.clamp(0.2, 0.9));
            self.lineage_main_split_drag_start_y =
                ui.input(|i| i.pointer.interact_pos().map(|pos| pos.y));
        }
        let pointer_down = ui.input(|i| i.pointer.primary_down());
        let pointer_y = ui.input(|i| i.pointer.interact_pos().map(|pos| pos.y));
        splitter_dragging =
            splitter_response.dragged() || (pointer_down && self.lineage_main_split_drag_origin.is_some());
        let splitter_drag_finished = splitter_response.drag_stopped();
        let splitter_drag_active = splitter_dragging || splitter_drag_finished;
        if splitter_drag_active {
            if let (Some(drag_origin_split), Some(start_y), Some(current_y)) = (
                self.lineage_main_split_drag_origin,
                self.lineage_main_split_drag_start_y,
                pointer_y,
            ) {
                let drag_delta_y = current_y - start_y;
                let total_height = (graph_area_height + container_area_height).max(400.0);
                let drag_base_graph_height =
                    (total_height * drag_origin_split.clamp(0.2, 0.9)).clamp(280.0, total_height - 80.0);
                let next_graph_height =
                    (drag_base_graph_height + drag_delta_y).clamp(280.0, total_height - 80.0);
                if (next_graph_height - graph_area_height).abs() > f32::EPSILON {
                    graph_area_height = next_graph_height;
                    container_area_height =
                        (total_height - graph_area_height).clamp(80.0, total_height - 280.0);
                    main_split_fraction = (graph_area_height / total_height).clamp(0.2, 0.9);
                    self.lineage_main_split_fraction = main_split_fraction;
                }
            }
        }
        if splitter_drag_finished || (!pointer_down && self.lineage_main_split_drag_origin.is_some()) {
            self.lineage_main_split_drag_origin = None;
            self.lineage_main_split_drag_start_y = None;
            persist_workspace_after_frame = true;
        }
        ui.small("Drag split bar to resize graph/table and container sections");
        let container_panel_width = ui.available_width().max(1.0);
        let subpanel_total_height = container_area_height.max(220.0);
        let (mut containers_panel_height, mut arrangements_panel_height, normalized_subsplit) =
            Self::normalized_lineage_container_subpanel_heights(
                subpanel_total_height,
                container_arrangement_split_fraction,
            );
        container_arrangement_split_fraction = normalized_subsplit;

        ui.allocate_ui_with_layout(
            egui::vec2(container_panel_width, containers_panel_height),
            egui::Layout::top_down(egui::Align::Min),
            |ui| {
                ui.set_min_width(container_panel_width);
                ui.set_max_width(container_panel_width);
                ui.heading("Containers");
                ui.label("Container-level view of candidate sequence sets");
                egui::ScrollArea::both()
                    .id_salt("lineage_container_grid_scroll")
                    .auto_shrink([false, false])
                    .max_height(ui.available_height().max(40.0))
                    .show(ui, |ui| {
                        scroll_input_policy::apply_scrollarea_keyboard_navigation(
                            ui,
                            scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                        );
                        egui::Grid::new("container_grid")
                            .striped(true)
                            .show(ui, |ui| {
                                ui.strong("Container");
                                ui.strong("Kind");
                                ui.strong("Members");
                                ui.strong("Representative");
                                ui.strong("Action");
                                ui.end_row();
                                for c in &self.lineage_containers {
                                    ui.monospace(&c.container_id);
                                    ui.label(&c.kind);
                                    ui.monospace(format!("{}", c.member_count));
                                    ui.monospace(&c.representative);
                                    ui.horizontal(|ui| {
                                        if c.member_count > 1 {
                                            if ui
                                                .button("Open Pool")
                                                .on_hover_text("Open this container as a pool view")
                                                .clicked()
                                            {
                                                open_pool = Some((
                                                    c.representative.clone(),
                                                    c.members.clone(),
                                                ));
                                            }
                                        } else if !c.representative.is_empty() {
                                            if ui
                                                .button("Open Seq")
                                                .on_hover_text(
                                                    "Open this representative sequence",
                                                )
                                                .clicked()
                                            {
                                                open_seq = Some(c.representative.clone());
                                            }
                                        } else {
                                            ui.label("-");
                                        }
                                        if c.member_count > 0
                                            && ui
                                                .button("Gel SVG")
                                                .on_hover_text(
                                                    "Export a serial gel lane for this container",
                                                )
                                                .clicked()
                                        {
                                            export_container_gel = Some((
                                                c.container_id.clone(),
                                                vec![c.container_id.clone()],
                                            ));
                                        }
                                    });
                                    ui.end_row();
                                }
                            });
                    });
            },
        );

        let sub_split_response = ui
            .add_sized(
                egui::vec2(container_panel_width, 14.0),
                egui::Label::new(egui::RichText::new("⋮⋮").monospace())
                    .sense(egui::Sense::click_and_drag()),
            )
            .on_hover_text("Drag to resize containers and arrangements");
        let sub_split_rect = sub_split_response.rect;
        let sub_split_active = sub_split_response.hovered() || sub_split_response.dragged();
        let sub_split_color = if sub_split_active {
            egui::Color32::from_rgb(120, 120, 120)
        } else {
            egui::Color32::from_rgb(150, 150, 150)
        };
        ui.painter().line_segment(
            [
                egui::pos2(sub_split_rect.left(), sub_split_rect.center().y),
                egui::pos2(sub_split_rect.right(), sub_split_rect.center().y),
            ],
            egui::Stroke::new(1.2, sub_split_color),
        );
        ui.painter().text(
            sub_split_rect.center(),
            egui::Align2::CENTER_CENTER,
            "⋮⋮",
            egui::FontId::monospace(10.0),
            sub_split_color,
        );
        if sub_split_active {
            ui.output_mut(|o| o.cursor_icon = egui::CursorIcon::ResizeVertical);
        }
        if sub_split_response.drag_started() {
            self.lineage_container_arrangement_split_drag_origin =
                Some(container_arrangement_split_fraction.clamp(0.2, 0.8));
            self.lineage_container_arrangement_split_drag_start_y =
                ui.input(|i| i.pointer.interact_pos().map(|pos| pos.y));
        }
        let sub_pointer_down = ui.input(|i| i.pointer.primary_down());
        let sub_pointer_y = ui.input(|i| i.pointer.interact_pos().map(|pos| pos.y));
        let sub_split_dragging = sub_split_response.dragged()
            || (sub_pointer_down && self.lineage_container_arrangement_split_drag_origin.is_some());
        let sub_split_finished = sub_split_response.drag_stopped();
        let sub_split_active_drag = sub_split_dragging || sub_split_finished;
        if sub_split_active_drag {
            if let (Some(drag_origin_split), Some(start_y), Some(current_y)) = (
                self.lineage_container_arrangement_split_drag_origin,
                self.lineage_container_arrangement_split_drag_start_y,
                sub_pointer_y,
            ) {
                let drag_delta_y = current_y - start_y;
                let total_height = (containers_panel_height + arrangements_panel_height).max(160.0);
                let drag_base_containers_height =
                    (total_height * drag_origin_split.clamp(0.2, 0.8)).clamp(80.0, total_height - 80.0);
                let next_containers_height =
                    (drag_base_containers_height + drag_delta_y).clamp(80.0, total_height - 80.0);
                if (next_containers_height - containers_panel_height).abs() > f32::EPSILON {
                    containers_panel_height = next_containers_height;
                    arrangements_panel_height =
                        (total_height - containers_panel_height).clamp(80.0, total_height - 80.0);
                    container_arrangement_split_fraction =
                        (containers_panel_height / total_height).clamp(0.2, 0.8);
                }
            }
        }
        if sub_split_finished
            || (!sub_pointer_down
                && self.lineage_container_arrangement_split_drag_origin.is_some())
        {
            self.lineage_container_arrangement_split_drag_origin = None;
            self.lineage_container_arrangement_split_drag_start_y = None;
            persist_workspace_after_frame = true;
        }
        ui.small("Drag split bar to resize containers and arrangements");

        ui.allocate_ui_with_layout(
            egui::vec2(container_panel_width, arrangements_panel_height),
            egui::Layout::top_down(egui::Align::Min),
            |ui| {
                ui.set_min_width(container_panel_width);
                ui.set_max_width(container_panel_width);
                ui.heading("Arrangements");
                ui.label("Serial lane setups from one or more containers");
                egui::ScrollArea::both()
                    .id_salt("lineage_arrangement_grid_scroll")
                    .auto_shrink([false, false])
                    .max_height(ui.available_height().max(40.0))
                    .show(ui, |ui| {
                        scroll_input_policy::apply_scrollarea_keyboard_navigation(
                            ui,
                            scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                        );
                        if self.lineage_arrangements.is_empty() {
                            ui.label("No arrangements recorded");
                        } else {
                            egui::Grid::new("arrangement_grid")
                                .striped(true)
                                .show(ui, |ui| {
                                    ui.strong("Arrangement");
                                    ui.strong("Mode");
                                    ui.strong("Name");
                                    ui.strong("Lanes");
                                    ui.strong("Lane containers");
                                    ui.strong("Ladders");
                                    ui.strong("Action");
                                    ui.end_row();
                                    for arrangement in &self.lineage_arrangements {
                                        ui.monospace(&arrangement.arrangement_id);
                                        ui.label(&arrangement.mode);
                                        ui.label(if arrangement.name.trim().is_empty() {
                                            "-".to_string()
                                        } else {
                                            arrangement.name.clone()
                                        });
                                        ui.monospace(arrangement.lane_count.to_string());
                                        ui.label(if arrangement.lane_container_ids.is_empty() {
                                            "-".to_string()
                                        } else {
                                            arrangement.lane_container_ids.join(", ")
                                        });
                                        ui.label(if arrangement.ladders.is_empty() {
                                            "auto".to_string()
                                        } else {
                                            arrangement.ladders.join(", ")
                                        });
                                        ui.horizontal(|ui| {
                                            if ui
                                                .button("Export Gel")
                                                .on_hover_text(
                                                    "Export one serial gel using this arrangement",
                                                )
                                                .clicked()
                                            {
                                                let stem = if arrangement.name.trim().is_empty() {
                                                    arrangement.arrangement_id.clone()
                                                } else {
                                                    arrangement.name.clone()
                                                };
                                                export_arrangement_gel = Some((
                                                    stem,
                                                    arrangement.arrangement_id.clone(),
                                                ));
                                            }
                                            if !arrangement.lane_container_ids.is_empty()
                                                && ui
                                                    .button("Open Lanes")
                                                    .on_hover_text(
                                                        "Open windows for the lane containers in this arrangement",
                                                    )
                                                    .clicked()
                                            {
                                                open_lane_containers =
                                                    Some(arrangement.lane_container_ids.clone());
                                            }
                                        });
                                        ui.end_row();
                                    }
                                });
                        }
                    });
            },
        );
            });

        if let Some((stem, container_ids)) = export_container_gel.take() {
            self.prompt_export_serial_gel_svg(&stem, Some(container_ids), None, None);
        }
        if let Some((stem, arrangement_id)) = export_arrangement_gel.take() {
            self.prompt_export_serial_gel_svg(&stem, None, Some(arrangement_id), None);
        }
        if let Some(container_ids) = open_lane_containers.take() {
            for container_id in &container_ids {
                if let Some(container_row) = self
                    .lineage_containers
                    .iter()
                    .find(|row| row.container_id == *container_id)
                    .cloned()
                {
                    if container_row.member_count > 1 {
                        self.open_pool_window(
                            &container_row.representative,
                            container_row.members.clone(),
                        );
                    } else if !container_row.representative.is_empty() {
                        self.open_sequence_window(&container_row.representative);
                    }
                }
            }
        }

        if (self.lineage_graph_zoom - graph_zoom).abs() > 0.0001 {
            self.lineage_graph_zoom = graph_zoom;
            persist_workspace_after_frame = true;
        }
        if (self.lineage_graph_area_height - graph_area_height).abs() > 0.5 {
            self.lineage_graph_area_height = graph_area_height;
            persist_workspace_after_frame = true;
        }
        if (self.lineage_container_area_height - container_area_height).abs() > 0.5 {
            self.lineage_container_area_height = container_area_height;
            persist_workspace_after_frame = true;
        }
        if (self.lineage_container_arrangement_split_fraction
            - container_arrangement_split_fraction)
            .abs()
            > 0.0001
        {
            self.lineage_container_arrangement_split_fraction =
                container_arrangement_split_fraction;
            persist_workspace_after_frame = true;
        }
        let combined_panel_height =
            (graph_area_height.max(0.0) + container_area_height.max(0.0)).max(1.0);
        let computed_main_split_fraction =
            (graph_area_height.max(0.0) / combined_panel_height).clamp(0.2, 0.9);
        main_split_fraction = computed_main_split_fraction;
        if !splitter_dragging
            && (self.lineage_main_split_fraction - main_split_fraction).abs() > 0.0001
        {
            self.lineage_main_split_fraction = main_split_fraction;
            persist_workspace_after_frame = true;
        }
        if self.lineage_graph_compact_labels != graph_compact_labels {
            self.lineage_graph_compact_labels = graph_compact_labels;
            persist_workspace_after_frame = true;
        }
        if (self.lineage_graph_scroll_offset - graph_scroll_offset).length_sq() > 0.25 {
            self.lineage_graph_scroll_offset = graph_scroll_offset;
            persist_workspace_after_frame = true;
        }
        self.render_lineage_node_rename_window(ui.ctx(), &mut persist_workspace_after_frame);
        self.render_lineage_node_remove_confirm_window(
            ui.ctx(),
            &mut persist_workspace_after_frame,
        );
        if persist_workspace_after_frame {
            self.persist_lineage_graph_workspace_to_state();
        }

        if let Some(input) = select_candidate_from {
            let criterion = format!("gui_lineage_select:{input}");
            let result = self
                .engine
                .write()
                .unwrap()
                .apply(Operation::SelectCandidate {
                    input: input.clone(),
                    criterion,
                    output_id: None,
                });
            if let Ok(op_result) = result {
                if let Some(seq_id) = op_result.created_seq_ids.first() {
                    open_seq = Some(seq_id.clone());
                }
            }
        }

        if let Some(descriptor) = open_lineage_retrieval {
            self.open_lineage_retrieval_descriptor(&descriptor);
        }
        if let Some(seq_id) = open_seq {
            self.open_sequence_window(&seq_id);
        }
        if let Some((representative, pool_members)) = open_pool {
            self.open_pool_window(&representative, pool_members);
        }
    }

    fn apply_configuration_external_apps(&mut self) {
        self.configuration_rnapkin_executable =
            self.configuration_rnapkin_executable.trim().to_string();
        self.configuration_makeblastdb_executable =
            self.configuration_makeblastdb_executable.trim().to_string();
        self.configuration_blastn_executable =
            self.configuration_blastn_executable.trim().to_string();
        self.configuration_bigwig_to_bedgraph_executable = self
            .configuration_bigwig_to_bedgraph_executable
            .trim()
            .to_string();

        self.sync_runtime_tool_overrides_from_configuration();

        let rnapkin_status =
            tool_overrides::active_resolution_label("GENTLE_RNAPKIN_BIN", "rnapkin");
        let makeblastdb_status =
            tool_overrides::active_resolution_label(MAKEBLASTDB_ENV_BIN, DEFAULT_MAKEBLASTDB_BIN);
        let blastn_status =
            tool_overrides::active_resolution_label(BLASTN_ENV_BIN, DEFAULT_BLASTN_BIN);
        let bigwig_status = tool_overrides::active_resolution_label(
            BIGWIG_TO_BEDGRAPH_ENV_BIN,
            DEFAULT_BIGWIG_TO_BEDGRAPH_BIN,
        );
        self.configuration_status = format!(
            "External app settings applied (rnapkin: {}, makeblastdb: {}, blastn: {}, bigWigToBedGraph: {})",
            rnapkin_status, makeblastdb_status, blastn_status, bigwig_status
        );

        self.validate_rnapkin_executable();
        self.validate_blast_executables();
        match self.write_persisted_configuration_to_disk() {
            Ok(()) => {
                self.configuration_status
                    .push_str(" | persisted to app settings");
            }
            Err(e) => {
                self.configuration_status
                    .push_str(&format!(" | persistence failed: {e}"));
            }
        }
    }

    fn apply_configuration_graphics(&mut self) {
        self.apply_configuration_graphics_to_engine_state();
        self.configuration_status =
            "Graphics settings applied globally to the project display state".to_string();
        match self.write_persisted_configuration_to_disk() {
            Ok(()) => {
                self.configuration_status
                    .push_str(" | persisted to app settings");
            }
            Err(e) => {
                self.configuration_status
                    .push_str(&format!(" | persistence failed: {e}"));
            }
        }
    }

